export const recipes=[{"id":1,"servings":4,"tipType":"pasta","pairingsType":"pasta","nutrition":{"cal":784,"prot":33,"carb":76,"fat":38,"fib":3},"origin":{"en":"Italy","ro":"Italia"},"name":{"en":"Spaghetti Carbonara","ro":"Spaghete Carbonara"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["400g spaghetti","200g guanciale (or pancetta), cut into 1cm cubes","4 large egg yolks + 1 whole egg","80g Pecorino Romano, finely grated","40g Parmigiano Reggiano, finely grated","1 tsp freshly cracked black pepper","Fine sea salt for pasta water"],"ro":["400g spaghete","200g guanciale (sau pancetta), tăiat cuburi de 1 cm","4 gălbenușuri de ou mari + 1 ou întreg","80g Pecorino Romano, ras fin","40g Parmigiano Reggiano, ras fin","1 linguriță piper negru proaspăt măcinat","Sare de mare fină pentru apa de fiert"]},"howIsMade":{"en":"Bring 4 litres of water to a rolling boil, salt it generously until it tastes pleasantly of the sea, then cook the spaghetti for 2 minutes less than the packet's al dente time — it will finish in the sauce. Meanwhile, place the guanciale in a cold, wide pan over medium-low heat and let the fat render slowly for 8–10 minutes until it turns golden and the edges crisp; starting from cold prevents burning and draws out maximum flavour. While the guanciale renders, beat the egg yolks and whole egg with both cheeses and a generous amount of coarsely cracked pepper until you have a thick, pale, creamy paste — this is the sauce. Just before draining, scoop out at least 250 ml of the cloudy pasta water and keep it within reach; the dissolved starch is what makes a smooth emulsion possible. Take the guanciale pan completely off the heat — this step is non-negotiable — then add the drained, steaming spaghetti directly into it and toss for 30 seconds so every strand absorbs the rendered fat. Pour the egg cream over the pasta, then add pasta water a small splash at a time, tossing and folding constantly; the residual heat sets the egg into a smooth, glossy sauce — stop adding water when the sauce coats the pasta without pooling. Taste and adjust salt — the guanciale and Pecorino are already salty — then add a little more pasta water if the sauce tightens as you plate. Serve immediately in warm bowls, finish with an extra shaving of Pecorino and several confident turns of the pepper mill."}},{"id":2,"origin":{"en":"Romania","ro":"România"},"name":{"en":"Tripe Soup","ro":"Ciorbă de burtă"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"soup","pairingsType":"soup","nutrition":{"cal":320,"prot":27,"carb":8,"fat":20,"fib":1},"ingredients":{"en":["800g pre-cleaned beef tripe, cut into 5×1 cm strips","2 medium carrots (about 200g)","1 parsley root","1 piece celeriac (about 150g)","1 large onion","4 garlic cloves, crushed","3 large eggs, yolks only","300ml full-fat sour cream (min. 20%)","3 tbsp white wine vinegar","salt and white pepper to taste","fresh lovage leaves (optional)"],"ro":["800g burtă de vită (precurățată și fiartă), tăiată fâșii de 5×1 cm","2 morcovi medii (aprox. 200g)","1 rădăcină de pătrunjel","1 bucată țelină rădăcină (aprox. 150g)","1 ceapă mare","4 căței de usturoi, pisați","3 ouă mari, gălbenușurile separate","300ml smântână grasă (min. 20%)","3 linguri oțet de vin alb","sare și piper alb după gust","frunze de leuștean proaspăt (opțional)"]},"howIsMade":{"en":"If tripe is not pre-cleaned, rub thoroughly with coarse salt under cold running water and rinse 3–4 times. Boil tripe in salted water for 2–3 hours on low heat until easily pierced with a fork — or 40–50 minutes in a pressure cooker. Drain and cut into 5×1 cm strips. Simmer carrots, parsley root, celeriac, and onion in 2L salted water for 40 minutes, then discard the vegetables (or blend and return for a thicker soup). Add the tripe strips to the broth and simmer 15 minutes. Whisk egg yolks with sour cream until smooth. Temper the mixture: ladle several spoonfuls of hot broth into the cream gradually, whisking constantly before pouring it back into the pot — this prevents curdling. Stir in crushed garlic, vinegar, salt, and white pepper. Do not boil again after adding the liaison — it will curdle. Serve piping hot with chilli and garlic sauce on the side."}},{"id":3,"servings":6,"tipType":"def","pairingsType":"def","nutrition":{"cal":770,"prot":21,"carb":27,"fat":62,"fib":1},"origin":{"en":"France","ro":"Franța"},"name":{"en":"Quiche Lorraine","ro":"Quiche Lorraine"},"category":{"en":"Breakfast","ro":"Mic dejun"},"ingredients":{"en":["200g shortcrust pastry (1 sheet), blind-baked","200g smoked lardons or diced smoked bacon","3 large eggs","300ml double cream (min. 35% fat)","60g Gruyère cheese, finely grated","1/4 tsp freshly grated nutmeg","salt and white pepper to taste","butter for greasing"],"ro":["200g aluat scurt (1 foaie), copt în alb","200g lardon afumat sau bacon afumat, tocat cuburi","3 ouă mari","300ml smântână grasă (min. 35%)","60g Gruyère, ras fin","1/4 linguriță nucșoară rasă proaspăt","sare și piper alb după gust","unt pentru uns forma"]},"howIsMade":{"en":"Roll out the pastry and line a 23cm tart tin, pressing firmly into the edges. Chill 20 minutes. Blind-bake at 180°C: line with baking paper, fill with baking beans, bake 15 minutes; remove beans and paper and bake a further 5 minutes until pale golden. Meanwhile, cook the lardons in a dry pan until golden and the fat is rendered, about 5 minutes; drain on paper. Whisk together eggs, cream, nutmeg, salt and white pepper. Scatter the lardons evenly over the base, pour the egg mixture over, and sprinkle with Gruyère. Bake 25–30 minutes at 180°C until just set — the centre should tremble slightly when you shake the tin. Cool 10 minutes before slicing. A true Quiche Lorraine contains no onion or vegetables, only lardons and the classic custard."}},{"id":4,"origin":{"en":"Spain","ro":"Spania"},"name":{"en":"Gazpacho","ro":"Gazpacho"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"veg","nutrition":{"cal":260,"prot":4,"carb":24,"fat":16,"fib":3},"ingredients":{"en":["800g ripe tomatoes (San Marzano or plum), roughly chopped","1 red bell pepper (about 200g), deseeded and chopped","1 medium cucumber (about 200g), peeled and chopped","2 garlic cloves","100g day-old white bread, crusts removed","60ml extra-virgin olive oil","2 tbsp red wine vinegar","1 tsp fine salt","200ml cold water"],"ro":["800g roșii coapte (San Marzano sau roșii de câmp), tăiate cuburi","1 ardei gras roșu (aprox. 200g), curățat de semințe și tocat","1 castravete mediu (aprox. 200g), curățat și tocat","2 căței de usturoi","100g pâine albă veche de o zi, fără coajă","60ml ulei de măsline extravirgin","2 linguri oțet de vin roșu","1 linguriță sare fină","200ml apă rece"]},"howIsMade":{"en":"Tear the bread into pieces and soak in 200ml cold water for 10 minutes. Put tomatoes, pepper, cucumber, and garlic into a blender and blitz for 1 minute on high. Add the soaked bread along with its soaking water, vinegar, and salt; blitz again. With the motor running, pour olive oil in a thin stream — this emulsification gives the soup its silky texture. Taste and adjust salt and vinegar. Pass through a fine-mesh sieve for a smoother result, or leave it rustic. Chill at least 2 hours — gazpacho at 6–8°C is vastly more flavourful than at room temperature. Serve in chilled bowls with a drizzle of olive oil on top."}},{"id":5,"origin":{"en":"Japan","ro":"Japonia"},"name":{"en":"Sushi","ro":"Sushi"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":430,"prot":15,"carb":51,"fat":14,"fib":3},"ingredients":{"en":["2 cups Japanese short-grain sushi rice","2½ cups water","60ml rice vinegar","1 tbsp sugar","1 tsp salt","4 nori sheets (20×18 cm)","200g sashimi-grade salmon fillet, thinly sliced","1 ripe avocado, sliced","½ small cucumber, julienned","soy sauce to serve","wasabi and pickled ginger (gari) to serve"],"ro":["2 căni orez japonez pentru sushi (bob scurt)","2½ căni apă","60ml oțet de orez","1 lingură zahăr","1 linguriță sare","4 foi nori (20×18 cm)","200g file de somon sashimi-grade, feliat subțire","1 avocado copt, feliat","½ castravete mic, julienizat","sos de soia pentru servire","wasabi și ghimbir murat (gari) pentru servire"]},"howIsMade":{"en":"Cook the rice: rinse under cold water until the water runs clear (4–5 washes). Bring rice and 2½ cups water to a boil, cover, reduce to lowest heat for 12 minutes, then rest off heat 10 minutes. Dissolve vinegar, sugar, and salt in a small bowl. Spread cooked rice onto a large tray and fold the dressing in using a wooden paddle with cutting motions — do not stir in circles or the rice turns mushy. Cover with a damp cloth and cool to room temperature (not fridge). Lay a nori sheet shiny-side down on the bamboo mat. Spread seasoned rice over ¾ of the nori (leaving a 3 cm gap at the far edge). Arrange salmon, avocado, and cucumber along the near edge in a single row. Roll firmly from the near edge, pressing as you go; seal the bare nori with a few rice grains. Slice with a sharp, lightly wet knife into 8 rounds. Serve at once with soy sauce, wasabi, and pickled ginger."}},{"id":7,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":775,"prot":40,"carb":39,"fat":49,"fib":1},"origin":{"en":"USA","ro":"SUA"},"name":{"en":"Cheeseburger","ro":"Cheeseburger"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["500g ground beef (80% lean, 20% fat)","4 brioche buns, halved and toasted","4 slices American cheddar","2 ripe tomatoes, thickly sliced","4 large iceberg lettuce leaves","1 medium onion, thinly sliced into rings","2 tbsp burger sauce (mayo, ketchup, mustard, diced pickles)","salt and freshly ground black pepper"],"ro":["500g carne de vită tocată (80% carne / 20% grăsime)","4 chifle brioche, tăiate și prăjite","4 felii cheddar american","2 roșii coapte, tăiate felii groase","4 frunze de salată iceberg","1 ceapă medie, tăiată rondele subțiri","2 linguri sos de burger (maioneză, ketchup, muștar, castraveți murați tocați)","sare și piper negru proaspăt măcinat"]},"howIsMade":{"en":"Season the ground beef with salt and pepper and divide into four 125g balls. Heat a cast-iron skillet over high heat until smoking. Press each ball flat on the pan with a firm spatula — the smash technique creates a crisp, lacy crust in about 90 seconds. Flip, add a slice of cheddar, and cover for 30 seconds to melt. Toast the buns cut-side down for 1 minute. Assemble: bottom bun, burger sauce, lettuce, tomato, patty with melted cheese, onion rings, top bun. Serve immediately — the crust fades fast."}},{"id":8,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":390,"prot":26,"carb":32,"fat":18,"fib":4},"origin":{"en":"Mexico","ro":"Mexic"},"name":{"en":"Tacos","ro":"Tacos"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["500g ground beef (80% lean)","8 small corn tortillas (15cm)","1 tsp ground cumin","1 tsp smoked paprika","2 ripe tomatoes, finely diced (for pico de gallo)","1 small white onion, finely diced","fresh cilantro, lime wedges, salsa, and sour cream for serving","salt and black pepper"],"ro":["500g carne de vită tocată (80% carne)","8 tortilla mici din porumb (15cm)","1 linguriță chimion măcinat","1 linguriță boia afumată","2 roșii coapte, tocate mărunt (pico de gallo)","1 ceapă albă mică, tocată mărunt","coriandru proaspăt, felii de lime, sos salsa și smântână pentru servit","sare și piper negru"]},"howIsMade":{"en":"Brown the ground beef in a dry skillet over high heat, breaking it into fine crumbles — do not stir too much at first so the meat develops colour. Drain excess fat. Add cumin, paprika, salt and pepper; cook 2 more minutes. Warm the corn tortillas: hold them directly over a gas flame for 15 seconds per side until they blister and char lightly, or dry-toast in a hot pan. For quick pico de gallo: toss diced tomato with diced onion, a pinch of salt, and a squeeze of lime. Double-stack two tortillas per taco to prevent splitting. Spoon on the seasoned beef, then top with pico de gallo, cilantro leaves, a squeeze of lime, and salsa or sour cream to taste."}},{"id":9,"servings":4,"tipType":"meat","pairingsType":"meat","nutrition":{"cal":375,"prot":23,"carb":11,"fat":19,"fib":3},"origin":{"en":"India","ro":"India"},"name":{"en":"Chicken Curry","ro":"Curry de pui"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["800g bone-in chicken thighs and drumsticks, skin removed","2 large onions (about 350g), finely diced","400g canned crushed tomatoes","1 tbsp ginger paste (from a 3cm piece)","1 tbsp garlic paste (from 5 cloves)","3 tbsp sunflower oil","1 tsp cumin seeds","2 tsp ground coriander","1 tsp garam masala","½ tsp turmeric","1 tsp Kashmiri chili powder (or mild paprika)","200ml full-fat yogurt, whisked","Salt to taste","Fresh coriander leaves to finish"],"ro":["800g pulpe de pui cu os, fără piele","2 cepe mari (aprox. 350g), tăiate mărunt","400g roșii tocate din conservă","1 lingură pastă de ghimbir (bucată de 3 cm)","1 lingură pastă de usturoi (5 căței)","3 linguri ulei de floarea-soarelui","1 linguriță semințe de chimen","2 lingurițe coriandru măcinat","1 linguriță garam masala","½ linguriță turmeric","1 linguriță praf de ardei Kashmiri (sau boia dulce)","200ml iaurt gras, bătut","Sare după gust","Frunze de coriandru proaspăt pentru finisare"]},"howIsMade":{"en":"Heat oil in a heavy-bottomed pot over medium-high heat. Add cumin seeds and let sizzle 30 seconds. Add diced onions and fry, stirring often, for 15–18 minutes until deep golden — this caramelisation builds the flavour base. Stir in ginger and garlic paste; cook 2 minutes until the raw smell disappears. Add ground coriander, turmeric, and Kashmiri chili; stir 1 minute. Pour in crushed tomatoes and cook over medium heat, stirring often, for 10 minutes until the oil separates to the sides. Add chicken pieces, coat in masala, and sear 5 minutes. Remove from heat; stir in whisked yogurt one tablespoon at a time to prevent curdling. Return to medium-low heat, cover, and simmer 25–30 minutes until the chicken falls easily from the bone. Stir in garam masala, adjust salt, finish with fresh coriander. Serve with basmati rice or naan."}},{"id":10,"servings":4,"tipType":"def","pairingsType":"veg","nutrition":{"cal":215,"prot":4,"carb":19,"fat":13,"fib":4},"origin":{"en":"France","ro":"Franța"},"name":{"en":"Ratatouille","ro":"Ratatouille"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["1 medium aubergine (about 300g), cut into 2cm cubes","2 medium courgettes (about 400g), cut into 2cm rounds","1 red bell pepper, deseeded and diced","1 yellow bell pepper, deseeded and diced","4 ripe plum tomatoes (about 400g), roughly chopped","1 large onion, diced","4 garlic cloves, thinly sliced","4 tbsp extra-virgin olive oil","1 tsp dried herbes de Provence","salt and black pepper to taste"],"ro":["1 vânătă medie (aprox. 300g), cuburi de 2cm","2 dovlecei medii (aprox. 400g), rondele de 2cm","1 ardei gras roșu, curățat și tocat","1 ardei gras galben, curățat și tocat","4 roșii prune coapte (aprox. 400g), tocate grosier","1 ceapă mare, tocată","4 căței de usturoi, feliați subțire","4 linguri ulei de măsline extravirgin","1 linguriță herbes de Provence uscate","sare și piper negru după gust"]},"howIsMade":{"en":"Lightly salt the aubergine cubes and set aside for 15 minutes to draw out bitterness, then pat dry. Heat 1 tbsp oil in a wide pan over medium-high heat. Saute the aubergine until lightly golden, about 5 minutes; remove and set aside. Saute the courgettes 3 minutes, then the peppers 4 minutes; remove each in turn. In the same pan, heat the remaining oil and sweat the onion until soft and translucent, 5 minutes. Add garlic and cook 1 minute. Add the tomatoes and herbes de Provence; cook 10 minutes until the tomatoes collapse into a sauce. Return all vegetables, stir gently, season with salt and pepper, and simmer uncovered 15–20 minutes until everything is tender and fragrant. Serve warm or at room temperature — ratatouille tastes even better the next day."}},{"id":11,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Greece","ro":"Grecia"},"name":{"en":"Souvlaki","ro":"Souvlaki"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["700g pork shoulder, cut into 3cm cubes","3 tbsp extra-virgin olive oil","juice of 1 lemon","3 garlic cloves, crushed","2 tsp dried Greek oregano","1 tsp dried thyme","salt and freshly ground black pepper","wooden or metal skewers"],"ro":["700g ceafă de porc, tăiată cuburi de 3 cm","3 linguri ulei de măsline extravirgin","sucul de la 1 lămâie","3 căței de usturoi, zdrobiți","2 linguriță oregano grecesc uscat","1 linguriță cimbru uscat","sare și piper negru proaspăt măcinat","frigărui de lemn sau metal"]},"howIsMade":{"en":"Combine olive oil, lemon juice, crushed garlic, oregano and thyme in a bowl. Add the pork cubes, toss to coat thoroughly, cover and refrigerate for at least 1 hour — overnight is better. If using wooden skewers, soak them in water for 30 minutes. Thread 5-6 cubes per skewer, leaving small gaps between pieces. Grill over high heat (charcoal is ideal) for 8-10 minutes total, turning every 2 minutes, until the outside is charred and the juices run clear. The meat should be firm but not dry — pull it at 70°C internal. Serve immediately in warm pita with tzatziki, sliced tomatoes and red onion."},"nutrition":{"cal":420,"prot":35,"carb":3,"fat":29,"fib":0}},{"id":12,"origin":{"en":"India","ro":"India"},"name":{"en":"Dhal","ro":"Dhal"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"veg","ingredients":{"en":["300g dried red lentils (masoor dal)","2 tbsp ghee (or vegetable oil)","1 large onion, finely chopped","4 garlic cloves, minced","2 cm fresh ginger, grated","400g canned chopped tomatoes (or 3 large fresh tomatoes)","1 tsp ground turmeric","1 tsp ground cumin","1 tsp ground coriander","½ tsp garam masala","½ tsp ground red chilli","400ml coconut milk (or water)","salt to taste","fresh coriander and lemon wedges to serve"],"ro":["300g linte roșie uscată (masoor dal)","2 linguri ghee (sau ulei vegetal)","1 ceapă mare, tocată fin","4 căței de usturoi, tocați","2 cm ghimbir proaspăt, ras","400g roșii din conservă, tăiate cuburi (sau 3 roșii mari proaspete)","1 linguriță turmeric măcinat","1 linguriță chimen măcinat","1 linguriță coriandru măcinat","½ linguriță garam masala","½ linguriță ardei iute roșu măcinat","400ml lapte de nucă de cocos (sau apă)","sare după gust","coriandru proaspăt și felii de lămâie pentru servire"]},"howIsMade":{"en":"Rinse the red lentils under cold water 3–4 times until the water runs clear. In a large pan melt ghee over medium heat. Add the onion and cook, stirring often, for 10–12 minutes until golden and soft — do not skip this step, the caramelised base is the backbone of flavour. Add garlic and ginger, fry 1 minute. Add turmeric, cumin, coriander, and red chilli, stir 30 seconds until fragrant. Add tomatoes, simmer 3–4 minutes until slightly thickened. Add the rinsed lentils and coconut milk (or water), reduce to a gentle simmer and cook uncovered for 20–25 minutes, stirring occasionally, until lentils collapse and the dhal is thick and creamy. Stir in garam masala and adjust salt. Thin with a little hot water if needed. Serve with rice or naan, topped with fresh coriander and a squeeze of lemon."},"nutrition":{"cal":490,"prot":21,"carb":56,"fat":19,"fib":13}},{"id":13,"timeMins":{"total":20,"active":20},"servings":4,"tipType":"def","pairingsType":"veg","origin":{"en":"Mexico","ro":"Mexic"},"name":{"en":"Guacamole","ro":"Guacamole"},"category":{"en":"Snack","ro":"Gustare"},"ingredients":{"en":["3 ripe Hass avocados","juice of 2 limes (about 3 tbsp)","1 small red onion, finely diced","2 ripe Roma tomatoes, deseeded and diced","1 small jalapeño, finely chopped (seeds removed for mild heat)","15g fresh cilantro, roughly chopped","1/2 tsp fine sea salt, plus more to taste"],"ro":["3 avocado Hass coapte","sucul a 2 lime (aprox. 3 linguri)","1 ceapă roșie mică, tocată mărunt","2 roșii Roma coapte, curățate de semințe și tocate","1 ardei jalapeno mic, tocat fin (fără semințe pentru mai puțin iute)","15g coriandru proaspăt, tocat grosier","1/2 linguriță sare fină de mare"]},"howIsMade":{"en":"Halve and stone the avocados. Scoop the flesh into a bowl and add the lime juice immediately — the acid slows browning. Mash with a fork to your preferred texture: very chunky or almost smooth. Fold in the diced onion, tomato, jalapeño, and cilantro. Season with salt. Taste and adjust lime and salt. To store, press cling film directly onto the surface of the guacamole to exclude air — the lime juice prevents browning far better than the avocado stone. Serve within 2 hours for best colour and flavour."},"nutrition":{"cal":200,"prot":3,"carb":13,"fat":17,"fib":9}},{"id":14,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"en":"Russia","ro":"Rusia"},"name":{"en":"Borscht","ro":"Bors"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["500g raw beetroot, peeled and coarsely grated","300g white cabbage, thinly shredded","300g waxy potatoes, cut into 2cm cubes","2 medium carrots, julienned","1 large onion, diced","3 garlic cloves, minced","2 tbsp tomato paste","1.5 litres beef or vegetable broth","2 tbsp sunflower oil","1 tbsp apple cider vinegar (to fix the deep red colour)","Salt and black pepper to taste","Sour cream and fresh dill to serve"],"ro":["500g sfeclă roșie crudă, curățată și rasă grosier","300g varză albă, feliată subțire","300g cartofi waxy, cuburi de 2 cm","2 morcovi medii, julien","1 ceapă mare, tocată","3 căței de usturoi, tocați","2 linguri pastă de roșii","1,5 litri supă de vită sau legume","2 linguri ulei de floarea-soarelui","1 lingură oțet de mere (pentru culoare vie)","Sare și piper după gust","Smântână și mărar proaspăt pentru servire"]},"howIsMade":{"en":"Heat oil over medium heat, add onion and carrots, and sauté 7–8 minutes until softened. Stir in tomato paste and garlic; cook 2 minutes. Add the grated beetroot and apple cider vinegar; cook 5 minutes — the vinegar fixes the deep red colour. Pour in the hot broth and add potatoes. Bring to a boil, reduce heat and simmer 15 minutes. Add shredded cabbage and simmer another 10 minutes until the cabbage is just tender and the potatoes are soft but not falling apart. Taste for salt, add pepper and extra vinegar if the soup needs brightness. Ladle into deep bowls and top with a generous spoonful of sour cream and fresh chopped dill."},"nutrition":{"cal":260,"prot":5,"carb":28,"fat":9,"fib":7}},{"id":15,"servings":4,"tipType":"dessert","pairingsType":"dessert","origin":{"en":"USA","ro":"SUA"},"name":{"en":"Pancakes","ro":"Clătite americane"},"category":{"en":"Breakfast","ro":"Mic dejun"},"ingredients":{"en":["200g plain flour","2 tsp baking powder","1 tbsp sugar","1/2 tsp salt","240ml whole milk","2 large eggs","30g melted butter, plus extra for the pan","1 tsp vanilla extract"],"ro":["200g făină albă","2 linguriță praf de copt","1 lingură zahăr","1/2 linguriță sare","240ml lapte integral","2 ouă mari","30g unt topit, plus extra pentru tigaie","1 linguriță extract de vanilie"]},"howIsMade":{"en":"In a large bowl, whisk together flour, baking powder, sugar and salt. In a second bowl, whisk milk, eggs, melted butter and vanilla. Pour the wet ingredients into the dry and fold gently with a spatula — a few lumps are fine and even desirable; over-mixing develops gluten and makes the pancakes tough. Rest the batter 5 minutes: the baking powder bubbles will rise to the surface. Heat a non-stick pan over medium heat, add a small knob of butter and wipe away the excess. Pour one ladle (about 80ml) of batter per pancake. Cook 2-3 minutes until bubbles break on the surface and the edges look set and dry. Flip and cook 1-2 minutes more until golden on the underside. Serve immediately — pancakes deflate as they cool. Top with real maple syrup, fresh butter and seasonal fruit."},"nutrition":{"cal":340,"prot":10,"carb":45,"fat":13,"fib":1}},{"id":16,"servings":4,"tipType":"def","pairingsType":"fish","origin":{"en":"Thailand","ro":"Thailanda"},"name":{"en":"Pad Thai","ro":"Pad Thai"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["200g dried flat rice noodles (soaked 30 min)","200g raw medium prawns, peeled and deveined","2 eggs","2 tbsp tamarind paste","2 tbsp fish sauce","1 tbsp oyster sauce","1 tsp palm sugar or brown sugar","2 tbsp neutral oil","2 cloves garlic, minced","1 shallot, thinly sliced","100g bean sprouts","3 spring onions, cut into 3cm pieces","3 tbsp roasted peanuts, roughly crushed","1 lime, cut into wedges","Dried chili flakes to serve"],"ro":["200g tăiței lat de orez (înmuiați 30 min)","200g creveți cruzi, curățați","2 ouă","2 linguri pastă de tamarind","2 linguri sos de pește","1 lingură sos de stridii","1 linguriță zahăr de palmier","2 linguri ulei neutru","2 căței de usturoi, tocați","1 șalotă, feliată","100g germeni de fasole","3 cepe verzi, tăiate 3cm","3 linguri alune prăjite, zdrobite","1 lime, pentru servire","Fulgi de ardei iute, după gust"]},"howIsMade":{"en":"Soak rice noodles in cold water for 30 minutes, then drain. Mix tamarind paste, fish sauce, oyster sauce and sugar in a small bowl to make the sauce. Heat oil in a wok over very high heat until just smoking; fry garlic and shallot for 30 seconds, add prawns and cook 2 minutes until just pink. Push everything to the side, crack in eggs and scramble lightly for 30 seconds, then toss everything together. Add drained noodles and pour the sauce over; toss constantly for 2–3 minutes until the noodles absorb the sauce and begin to caramelise at the edges. Remove from heat, fold in bean sprouts and spring onions; serve immediately topped with crushed peanuts, a lime wedge and chili flakes to taste."},"nutrition":{"cal":380,"prot":18,"carb":40,"fat":13,"fib":2}},{"id":17,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Germany","ro":"Germania"},"name":{"en":"Schnitzel","ro":"Schnitzel"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["4 boneless pork loin chops (about 150g each), trimmed","80g plain flour, seasoned with salt and pepper","2 large eggs, beaten","150g fine dry breadcrumbs (Semmelbrösel)","200ml neutral oil (sunflower or rapeseed) for frying","1 lemon, cut into wedges for serving","salt and white pepper"],"ro":["4 cotlete de porc din spată (aprox. 150g fiecare), dezosate și degresate","80g făină simplă, condimentată cu sare și piper","2 ouă mari, bătute","150g pesmet fin uscat (Semmelbrösel)","200ml ulei neutru (floarea-soarelui sau rapiță) pentru prăjit","1 lămâie, tăiată fâșii pentru servit","sare și piper alb"]},"howIsMade":{"en":"Place each pork chop between two sheets of cling film and beat with a meat mallet or rolling pin until evenly 4–5mm thick — the thin, even cut is the defining feature of a proper schnitzel. Pat dry and season with salt and white pepper. Set up three shallow dishes: seasoned flour, beaten eggs, breadcrumbs. Coat each schnitzel in flour (shake off the excess), dip in egg, then press firmly into breadcrumbs to coat evenly — do not press the crumb down too hard; it should stay airy so it puffs and blisters in hot oil. Pour oil into a wide pan to a depth of 1cm and heat to 170–180°C. Fry 2–3 minutes per side until deep golden and crisp. Drain on a wire rack — never on paper towel, which traps steam and kills the crust. Serve immediately with lemon wedges."},"nutrition":{"cal":570,"prot":45,"carb":15,"fat":35,"fib":1}},{"id":18,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Brazil","ro":"Brazilia"},"name":{"en":"Feijoada","ro":"Feijoada"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["400g dried black beans, soaked overnight","400g smoked pork ribs","200g chourico or smoked sausage, sliced","200g smoked bacon, diced","1 large onion, chopped","4 garlic cloves, minced","2 bay leaves","3 tbsp olive oil","salt, pepper and chilli flakes to taste"],"ro":["400g fasole neagră uscată, înmuiată 12 ore","400g coaste de porc afumate","200g chouriço sau cârnați afumați, feliați","200g bacon afumat, tăiat cuburi","1 ceapă mare, tocată","4 căței de usturoi, tocați","2 foi de dafin","3 linguri ulei de măsline","sare, piper și fulgi de ardei iute după gust"]},"howIsMade":{"en":"Drain the soaked beans and place in a large pot with fresh cold water to cover by 5cm. Add the smoked ribs and bay leaves. Bring to a boil, then simmer over medium heat for 1 hour, skimming any foam. Meanwhile, heat olive oil in a skillet, saute onion 8 minutes until soft and golden, add garlic and cook 2 minutes more. Add chourico and bacon, brown for 5 minutes. Transfer everything to the bean pot, stir well and simmer on low heat for 45-60 minutes until the beans are completely tender and the broth has thickened. Crush a handful of beans against the pot side with a wooden spoon — this thickens the stew naturally. Adjust salt and pepper. Serve in deep bowls with white rice, fresh orange slices and farofa (toasted manioc flour)."},"nutrition":{"cal":620,"prot":38,"carb":45,"fat":32,"fib":14}},{"id":19,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"China","ro":"China"},"name":{"en":"Kung Pao Chicken","ro":"Pui Gong Bao"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["500g chicken breast, cut into 2cm cubes","100g unsalted roasted peanuts","8–10 dried Chinese chili peppers (Sichuan or similar)","4 spring onions, cut into 3cm pieces","3 garlic cloves, thinly sliced","2cm piece of ginger, thinly sliced","2 tbsp Sichuan chili oil or sunflower oil","Marinade: 1 tbsp soy sauce, 1 tsp cornstarch, 1 tsp sesame oil","Sauce: 2 tbsp soy sauce, 1 tbsp black rice vinegar (Chinkiang), 1 tbsp sugar, 1 tsp cornstarch, 2 tbsp water"],"ro":["500g piept de pui, tăiat cuburi de 2 cm","100g arahide prăjite nesărate","8–10 ardei iuți uscați chinezești (chili Sichuan)","4 cepe verzi, tăiate bucăți de 3 cm","3 căței de usturoi, feliați subțire","1 bucată ghimbir de 2 cm, feliată subțire","2 linguri ulei cu ardei Sichuan sau ulei de floarea-soarelui","Marinată: 1 lingură sos de soia, 1 linguriță amidon de porumb, 1 linguriță ulei de susan","Sos: 2 linguri sos de soia, 1 lingură oțet de orez negru (Chinkiang), 1 lingură zahăr, 1 linguriță amidon de porumb, 2 linguri apă"]},"howIsMade":{"en":"Toss chicken with marinade ingredients and leave for 15 minutes. Combine sauce ingredients in a small bowl. Heat wok over highest heat until smoking; add oil and fry dried chilis and Sichuan peppercorns 30 seconds until darkened but not black — they should smell toasted, not burnt. Add chicken pieces and sear 3–4 minutes without stirring, until golden on one side; toss and cook 2 more minutes. Add garlic, ginger, and the white parts of the spring onion; stir-fry 1 minute. Pour in the sauce, toss vigorously for 1 minute until thickened and clinging to the chicken. Throw in peanuts and green spring onion tops; toss 30 seconds. Serve immediately with jasmine rice."},"nutrition":{"cal":400,"prot":32,"carb":11,"fat":22,"fib":2}},{"id":20,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"en":"United Kingdom","ro":"Marea Britanie"},"name":{"en":"Fish and Chips","ro":"Fish and Chips"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["4 cod or haddock fillets (about 180g each), skin removed","1kg floury potatoes (Maris Piper or King Edward), cut into thick chips","Vegetable oil for deep-frying (about 2 litres)","Batter: 180g plain flour, plus extra for dusting","1 tsp baking powder","1 tsp fine salt","300ml ice-cold lager or pale ale","Salt and malt vinegar to serve"],"ro":["4 fileuri de cod sau haddock (aprox. 180g fiecare), fără piele","1 kg cartofi floury (Maris Piper sau King Edward), tăiați bețe groase","Ulei vegetal pentru prăjit (aprox. 2 litri)","Pentru aluat: 180g făină tip 550 + extra pentru tăvălit","1 linguriță praf de copt","1 linguriță sare fină","300ml bere blondă rece (lager sau ale)","Sare și oțet de malt pentru servire"]},"howIsMade":{"en":"Cook chips in two stages: fry at 140°C for 8 minutes until soft but not coloured; drain and cool on a rack. Make the batter by whisking flour, baking powder, and salt together, then gradually whisk in ice-cold beer until the consistency of double cream — do not overmix. Pat fish fillets completely dry with paper towels. Heat oil to 185°C. Dust each fillet in the extra flour, shake off excess, dip into batter and let it drip for a few seconds. Fry 6–8 minutes — halfway through, spoon hot oil over the top for even crisping — until the batter is deep golden and crunchy. Drain on paper. Raise oil to 200°C and fry chips a second time for 3–4 minutes until golden and crisp all over. Serve immediately with salt and malt vinegar."},"nutrition":{"cal":850,"prot":35,"carb":85,"fat":42,"fib":5}},{"id":21,"origin":{"en":"Vietnam","ro":"Vietnam"},"name":{"en":"Pho","ro":"Pho"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","timeMins":{"total":225,"active":75},"pairingsType":"def","ingredients":{"en":["400g dried rice noodles (banh pho, 5mm width)","500g beef brisket or flank (for the broth)","1kg beef bones (marrow or knuckle)","2 medium onions, halved","5 cm fresh ginger, halved lengthways","3 star anise","1 cinnamon stick (5 cm)","3 cloves","2 tbsp fish sauce (nuoc mam)","1 tsp sugar","salt to taste","200g fresh bean sprouts","fresh coriander and Thai basil","2 red chillies, sliced (at the table)","2 limes, quartered (at the table)","hoisin sauce and sriracha (at the table)"],"ro":["400g tăiței de orez (banh pho, lățime 5mm), uscați","500g piept de vită sau flacără (pentru supă)","1kg oase de vită (măduvă sau coadă)","2 cepe medii, înjumătățite","5 cm ghimbir proaspăt, înjumătățit","3 anasoane stelate","1 baton de scorțișoară (5 cm)","3 cuișoare","2 linguri sos de pește (nuoc mam)","1 linguriță zahăr","sare după gust","200g muguri de soia proaspeți","coriandru proaspăt și busuioc thai","2 ardei iuți roșii, feliați (la masă)","2 lămâi verzi, tăiate în sferturi (la masă)","sos hoisin și sos sriracha (la masă)"]},"howIsMade":{"en":"Blanch beef bones in boiling water for 5 minutes, discard water, rinse well — this removes impurities and keeps the broth clear. Char the onion halves and ginger directly over a gas flame or under the grill until lightly blackened on the edges (2–3 minutes per side) — this gives the broth its golden colour and depth. Fill a large pot with 3L cold water, add bones, brisket, charred onion, ginger, star anise, cinnamon, and cloves. Bring to a boil, reduce to a bare simmer, cook uncovered for 3 hours, skimming fat periodically. Remove the brisket after 1½ hours, let cool, slice thinly. Strain broth through a fine sieve, season with fish sauce, sugar, and salt. Soak noodles in cold water 20 minutes, boil 30 seconds, drain. Divide noodles into bowls, ladle boiling broth over, add meat slices. Serve with bean sprouts, coriander, basil, chilli, lime, and sauces at the table."},"nutrition":{"cal":380,"prot":28,"carb":42,"fat":10,"fib":2}},{"id":22,"origin":{"en":"Spain","ro":"Spania"},"name":{"en":"Paella","ro":"Paella"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"fish","ingredients":{"en":["300g bomba rice (or short-grain rice)","400g boneless chicken thighs, cut into pieces","300g raw prawns (shell-on or peeled)","400g mussels, scrubbed and debearded","1 large onion, finely chopped","4 garlic cloves, minced","1 red bell pepper, diced","400g canned crushed tomatoes","½ tsp saffron threads (soaked in 2 tbsp warm water)","1 tsp smoked paprika (pimentón de la Vera)","800ml warm chicken stock","3 tbsp olive oil","salt and black pepper to taste","fresh parsley and lemon wedges to serve"],"ro":["300g orez bomba (sau orez cu bob scurt)","400g pulpe de pui dezosate, tăiate în bucăți","300g creveți crudi (cu coajă sau fără)","400g midii, spălate și curățate","1 ceapă mare, tocată","4 căței de usturoi, tocați","1 ardei gras roșu, tăiat cuburi","400g roșii din conservă, concasate","½ linguriță șofran (înmuiat în 2 linguri apă caldă)","1 linguriță boia de ardei afumată (pimentón de la Vera)","800ml fond de pui cald","3 linguri ulei de măsline","sare și piper negru după gust","pătrunjel proaspăt și felii de lămâie pentru servire"]},"howIsMade":{"en":"Soak saffron in 2 tbsp warm water; heat olive oil in a paella pan (or wide shallow pan) over medium-high heat. Season chicken, sear 4–5 minutes per side until deeply golden; remove and set aside; in the same pan fry onion 5 minutes, add garlic and red pepper, cook 3 more minutes. Add crushed tomatoes and smoked paprika, cook 3–4 minutes until thickened — this is the sofrito, the soul of the paella; add the rice, stir 1 minute to toast lightly. Pour in the warm stock with the saffron and its soaking water, spread evenly; return the chicken. Adjust to medium heat and do not stir again — never stir paella once the stock is added; cook uncovered for 10 minutes. Place prawns and mussels on top, pressing gently into the rice; cook 8–10 minutes more until prawns are pink and mussels open (discard any that stay shut). For socarrat (the coveted crispy bottom crust), raise to high heat the last 2 minutes — listen for a light crackling; rest 5 minutes; garnish with parsley and serve with lemon wedges."},"nutrition":{"cal":520,"prot":32,"carb":58,"fat":16,"fib":3}},{"id":23,"servings":4,"tipType":"def","pairingsType":"korean","origin":{"en":"South Korea","ro":"Coreea de Sud"},"name":{"en":"Bibimbap","ro":"Bibimbap"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["2 cups short-grain white rice","200g beef sirloin, thinly sliced against the grain","1 medium courgette, julienned","1 medium carrot, julienned","200g baby spinach","100g bean sprouts","4 shiitake mushrooms, stems removed","4 eggs","4 tbsp gochujang (Korean chili paste)","3 tbsp sesame oil","2 tbsp soy sauce","1 tsp sugar","3 cloves garlic, minced","Sesame seeds to garnish"],"ro":["2 căni orez cu bob scurt","200g vită (antricot), felii subțiri","1 dovlecel mediu, julien","1 morcov mediu, julien","200g spanac baby","100g germeni de fasole","4 ciuperci shiitake, fără codiță","4 ouă","4 linguri gochujang (pastă de ardei coreean)","3 linguri ulei de susan","2 linguri sos de soia","1 linguriță zahăr","3 căței de usturoi, tocați","Semințe de susan, pentru decor"]},"howIsMade":{"en":"Cook rice in 2.5 cups water: bring to a boil, cover and simmer on the lowest heat for 12 minutes, then rest off the heat for 10 minutes. Marinate beef with 1 tbsp soy sauce, 1 tbsp sesame oil, 1 tsp sugar and half the garlic for 15 minutes. Blanch spinach 30 seconds in boiling salted water, squeeze dry, season with 1 tsp sesame oil and salt; sauté bean sprouts 2 minutes with garlic and salt; stir-fry carrot and courgette separately for 2 minutes each with a drizzle of sesame oil. Sear marinated beef over high heat 3–4 minutes until caramelised; slice shiitake and sauté 2 minutes with a splash of soy sauce; fry eggs sunny-side up in sesame oil. Divide rice among 4 bowls, arrange vegetables and beef in sections, place an egg in the centre, add 1 tbsp gochujang per bowl, drizzle with sesame oil and scatter sesame seeds — mix everything together before eating."},"nutrition":{"cal":450,"prot":22,"carb":65,"fat":12,"fib":5}},{"id":24,"servings":4,"tipType":"def","pairingsType":"veg","origin":{"en":"Syria","ro":"Siria"},"name":{"en":"Hummus","ro":"Hummus"},"category":{"en":"Snack","ro":"Gustare"},"ingredients":{"en":["400g (1 can) cooked chickpeas, skins removed","80g tahini (good quality, stirred well)","juice of 2 lemons (about 4 tbsp)","2 garlic cloves, grated","1/2 tsp fine salt","3–5 tbsp ice-cold water","2 tbsp extra-virgin olive oil for finishing"],"ro":["400g năut gătit (1 conservă), coaja îndepărtată","80g pastă de susan (tahini de calitate, bine amestecată)","sucul a 2 lămâi (aprox. 4 linguri)","2 căței de usturoi, rași","1/2 linguriță sare fină","3–5 linguri apă rece cu gheață","2 linguri ulei de măsline extravirgin pentru finalizare"]},"howIsMade":{"en":"For the smoothest hummus, pop the skins off the chickpeas by gently squeezing each one — a small step that makes a big difference. In a food processor, blitz tahini and lemon juice alone for 1 minute until pale and creamy. Add garlic and salt; blitz 30 seconds. Add the chickpeas and process 1 minute. With the machine running, drizzle in ice-cold water tablespoon by tablespoon — the cold water aerates and lightens the hummus. Process 3–5 minutes total, scraping down the sides, until completely smooth. Taste and adjust lemon and salt. Spread in a bowl, drizzle with olive oil, and finish with smoked paprika or sumac. Keeps refrigerated up to 5 days."},"nutrition":{"cal":220,"prot":8,"carb":22,"fat":12,"fib":6}},{"id":25,"servings":4,"tipType":"def","pairingsType":"veg","origin":{"en":"Lebanon","ro":"Liban"},"name":{"en":"Tabbouleh","ro":"Tabbouleh"},"category":{"en":"Salad","ro":"Salate"},"ingredients":{"en":["200g flat-leaf parsley, leaves only, finely chopped","50g fine bulgur wheat, soaked in cold water 20 min then squeezed dry","3 ripe tomatoes (about 300g), finely diced","4 spring onions, finely sliced","20g fresh mint leaves, finely chopped","juice of 2 lemons (about 80ml)","4 tbsp extra-virgin olive oil, salt and black pepper to taste"],"ro":["200g pătrunjel plat, frunze tocate mărunt","50g bulgur fin, înmuiat 20 min în apă rece, stors bine","3 roșii coapte (cca 300g), tăiate cuburi mici","4 cepe verzi, tocate fin","20g frunze de mentă proaspătă, tocate mărunt","sucul de la 2 lămâi (cca 80ml)","4 linguri ulei de măsline extravirgin, sare și piper negru după gust"]},"howIsMade":{"en":"Soak the bulgur in cold water for 20 minutes, then drain and squeeze out as much water as possible with your hands — it should be dry, not wet. Chop the parsley as finely as you can; authentic tabbouleh is herb-forward, not grain-forward. Combine parsley, mint, spring onions, tomatoes and squeezed bulgur in a large bowl. Add lemon juice and olive oil, toss well and let rest 10 minutes — the lemon juice continues to soften the bulgur and blooms the herbs. Adjust salt and pepper. Serve at room temperature. True tabbouleh is a parsley salad with bulgur, not a bulgur salad with a little parsley."},"nutrition":{"cal":180,"prot":4,"carb":20,"fat":10,"fib":4}},{"id":26,"servings":4,"tipType":"pasta","pairingsType":"pasta","origin":{"en":"Italy","ro":"Italia"},"name":{"en":"Risotto","ro":"Risotto"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["320g Arborio or Carnaroli rice","1 large shallot or small onion, finely diced","50g unsalted butter, divided","100ml dry white wine","1.2L warm chicken or vegetable stock","40g Parmigiano-Reggiano, freshly grated","1 tbsp extra-virgin olive oil","salt and white pepper to taste"],"ro":["320g orez Arborio sau Carnaroli","1 șalotă sau ceapă mică, tocată fin","50g unt nesărat, împărțit","100ml vin alb sec","1,2L supă caldă de pui sau legume","40g Parmigiano-Reggiano, ras proaspăt","1 lingură ulei de măsline extravirgin","sare și piper alb după gust"]},"howIsMade":{"en":"Keep the stock warm over low heat throughout cooking — adding cold stock stops the cooking and ruins the creaminess. Heat oil and half the butter in a wide, heavy pan over medium heat. Sweat the shallot until soft, 3 minutes. Add the rice and toast, stirring, for 2 minutes until grains are slightly translucent at the edges. Pour in the wine and stir until completely absorbed. Add warm stock one ladleful at a time, stirring constantly and waiting for each ladleful to be absorbed before adding the next — this is the essential step and takes 16–18 minutes. The rice should be al dente with a creamy coating. Off the heat, beat in the remaining cold butter and the Parmigiano vigorously — the fat emulsifies into the starches creating a glossy sauce (this is called mantecatura). Rest 1 minute, then serve immediately in warm bowls."}},{"id":27,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Sweden","ro":"Suedia"},"name":{"en":"Swedish Meatballs","ro":"Chifteluțe suedeze"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["500g mixed ground pork and beef (50/50)","1 medium onion, grated","1 slice white bread, crusts removed, soaked in 3 tbsp milk","1 large egg","1/4 tsp ground allspice","1/4 tsp freshly grated nutmeg","2 tbsp butter for frying","250ml beef stock","150ml double cream"],"ro":["500g carne tocată amestecată porc și vită (50/50)","1 ceapă medie, rasă","1 felie de pâine albă fără coajă, înmuiată în 3 linguri lapte","1 ou mare","1/4 linguriță ienibahar măcinat","1/4 linguriță nucșoară rasă","2 linguri unt pentru prăjit","250ml supă de vită","150ml smântână pentru frișcă"]},"howIsMade":{"en":"Squeeze the soaked bread to remove excess milk, then mix with the ground meat, grated onion (squeeze out excess liquid), egg, allspice, nutmeg, salt and pepper. Mix well but do not overwork — overworking makes the meatballs tough. With wet hands, roll into balls about 3cm in diameter, yielding about 20–24 meatballs. Melt butter in a wide skillet over medium heat. Fry the meatballs in batches, rolling gently to brown all sides evenly, 6–8 minutes per batch. Remove and set aside. In the same pan, stir in the beef stock, scraping up the fond, and bring to a simmer. Add the cream and simmer 5 minutes until slightly thickened. Return the meatballs to the sauce and cook on low heat 5 more minutes. Serve with lingonberry jam, boiled or mashed potatoes, and pickled cucumber."}},{"id":28,"servings":4,"tipType":"meat","timeMins":{"total":720,"active":75},"pairingsType":"japanese","origin":{"en":"Japan","ro":"Japonia"},"name":{"en":"Classic Japanese Ramen","ro":"Ramen clasic japonez"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["4 portions fresh or dried ramen noodles (about 400g total)","1L chicken or pork bone broth","100ml soy sauce (or to taste)","2 tbsp mirin","200g pork belly or shoulder, thinly sliced (chashu)","4 soft-boiled eggs (marinated overnight in soy sauce and mirin)","2 sheets nori (dried seaweed), halved","4 tbsp bamboo shoots (menma)","2 spring onions, thinly sliced","1 tbsp sesame oil"],"ro":["4 porții tăiței ramen proaspeți sau uscați (aprox. 400g total)","1L supă de pui sau os de porc","100ml sos de soia (sau după gust)","2 linguri mirin","200g burtă de porc sau pulpă, feliată subțire (chashu)","4 ouă fierte moi (marinate în soia și mirin peste noapte)","2 foi nori (alge uscate), tăiate în jumătate","4 linguri mlădițe de bambus (menma)","2 cepe verzi, feliați subțire","1 lingură ulei de susan"]},"howIsMade":{"en":"Combine the broth with soy sauce and mirin; simmer 10 minutes and taste — the broth should be deeply savoury, slightly salty, with a hint of sweetness. Ramen eggs (best made the night before): boil eggs for exactly 6 minutes 30 seconds, shock in ice water, peel, and marinate overnight in 3 tbsp soy sauce, 2 tbsp mirin, and 50ml water. Chashu pork: roll pork belly tightly, tie with kitchen string, and braise in soy sauce, mirin, sake, and sugar over a gentle simmer for 2 hours until tender. Slice when cool. Cook noodles per package directions (usually 2–3 minutes), drain, and portion into warmed bowls. Ladle hot broth over. Top with 2–3 slices of chashu pork, a halved ramen egg, a piece of nori standing upright, bamboo shoots, spring onions, and a drop of sesame oil. Serve immediately."}},{"id":29,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"en":"Argentina","ro":"Argentina"},"name":{"en":"Empanadas","ro":"Empanadas"},"category":{"en":"Snack","ro":"Gustare"},"ingredients":{"en":["400g plain flour","100g lard or cold butter, diced","150ml warm water","1 tsp salt","300g ground beef","1 medium onion, finely chopped","2 hard-boiled eggs, chopped","12 green olives, pitted and sliced","1 tsp ground cumin","1 tsp sweet paprika"],"ro":["400g făină albă","100g untură sau unt rece, cuburi","150ml apă caldă","1 linguriță sare","300g carne de vită tocată","1 ceapă medie, tocată fin","2 ouă fierte tari, tăiate","12 măsline verzi, fără sâmburi și tăiate","1 linguriță chimen măcinat","1 linguriță boia dulce"]},"howIsMade":{"en":"Make the dough: combine flour and salt, rub in the lard or cold butter with your fingertips until the mixture resembles breadcrumbs, then add warm water gradually and knead 5 minutes to a smooth, elastic dough. Wrap and rest 30 minutes. For the filling, saute onion in a little oil for 8 minutes, add ground beef and cook 10 minutes over medium heat, breaking it up well. Season with cumin, paprika, salt and pepper. Cool completely, then fold in the chopped boiled eggs and olives. Roll dough to 3mm thick and cut 12cm circles. Place a tablespoon of filling in the centre, moisten the edges, fold into a half-moon and seal with a twisted rope border (repulge). Bake at 200 degrees C for 20-25 minutes until golden, or deep-fry at 180 degrees C for 3-4 minutes per side."}},{"id":30,"servings":4,"tipType":"def","pairingsType":"mediterranean","origin":{"en":"Greece","ro":"Grecia"},"name":{"en":"Tzatziki","ro":"Tzatziki"},"category":{"en":"Snack","ro":"Gustare"},"ingredients":{"en":["500g full-fat Greek yogurt (strained overnight if possible)","1 large cucumber (about 300g), grated and well squeezed","2 garlic cloves, finely grated","2 tbsp extra-virgin olive oil, plus a drizzle to serve","1 tbsp fresh dill, finely chopped","juice of half a lemon","fine sea salt to taste"],"ro":["500g iaurt grecesc integral (scurs peste noapte dacă e posibil)","1 castravete mare (cca 300g), ras și bine stors","2 căței de usturoi, rași fin","2 linguri ulei de măsline extravirgin, plus un pic pentru servit","1 lingură mărar proaspăt, tocat mărunt","sucul de la jumătate de lămâie","sare fină după gust"]},"howIsMade":{"en":"The most important step: grate the cucumber on the coarse side of a box grater and place in a clean tea towel or colander. Sprinkle with a little salt, leave 10 minutes, then squeeze out hard — the cucumber will shed almost half its weight in water. Excess moisture is what makes tzatziki watery and weak. Combine the yogurt with the well-squeezed cucumber, grated garlic, olive oil, lemon juice and dill. Taste and adjust salt. Cover and refrigerate at least 30 minutes before serving — the flavours deepen as it rests. Serve drizzled with olive oil and a few fresh dill sprigs, alongside warm pita bread or souvlaki."}},{"id":31,"servings":4,"tipType":"soup","pairingsType":"french","origin":{"en":"France","ro":"Franța"},"name":{"en":"French Onion Soup","ro":"Supă de ceapă franțuzească"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["1kg yellow onions, thinly sliced","60g unsalted butter","1 tbsp plain flour","200ml dry white wine","1.2 litres good beef stock","4 thick slices baguette, toasted","150g Gruyere, grated","salt, black pepper and fresh thyme sprigs"],"ro":["1kg ceapă galbenă, tăiată julienne","60g unt nesărat","1 lingură făină","200ml vin alb sec","1,2 litri supă bună de vită","4 felii groase de baghetă, prăjite","150g Gruyère, ras","sare, piper negru și crenguțe de cimbru proaspăt"]},"howIsMade":{"en":"Melt the butter in a heavy-bottomed pot over medium-low heat. Add the onions with a pinch of salt and cook for 45-60 minutes, stirring every 5 minutes — patience is everything here. The onions must turn the colour of caramel, not burnt. Add a splash of water whenever they stick. Add the thyme and flour, stir for 1 minute. Pour in the wine and let it bubble for 3 minutes. Add the beef stock, bring to a simmer and cook 20 minutes. Taste and adjust salt and pepper. Ladle into oven-safe bowls, float a slice of toasted baguette in each, pile on the Gruyere and grill (broil) for 3-4 minutes until the cheese is bubbling and golden brown. Serve immediately — the cheese will set as it cools."}},{"id":32,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Hungary","ro":"Ungaria"},"name":{"en":"Goulash","ro":"Gulaș"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["700g beef chuck or shin, cut into 3cm cubes","400g waxy potatoes, peeled and diced","2 large onions, finely chopped","2 red bell peppers, diced","3 tbsp sweet Hungarian paprika","400g canned chopped tomatoes","1 litre beef stock","3 tbsp lard or vegetable oil","2 tsp caraway seeds, salt and black pepper to taste"],"ro":["700g carne de vită (spată sau greabăn), cuburi de 3 cm","400g cartofi cerosi, curățați și tăiați cuburi","2 cepe mari, tocate mărunt","2 ardei grași roșii, tăiați cuburi","3 linguri boia ungurească dulce","400g roșii tocate la conservă","1 litru supă de vită","3 linguri untură sau ulei vegetal","2 linguriță semințe de chimen, sare și piper negru după gust"]},"howIsMade":{"en":"Pat the beef cubes dry and season with salt and pepper. Heat the lard or oil in a heavy pot over high heat and brown the meat in batches — do not stir too much; you want a crust, not steamed meat. Remove and set aside. Reduce heat to medium, add the onions and cook 10 minutes. Add the paprika and stir for 1 minute — do not let it burn or it turns bitter. Add the peppers, tomatoes, caraway seeds and beef stock. Return the beef, bring to a boil, cover and simmer on low heat for 60-75 minutes. Add the potatoes and simmer 25 more minutes until tender and the beef flakes easily under pressure. Taste and adjust salt. Serve in deep bowls with crusty bread to mop up the rich broth."}},{"id":33,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"en":"Egypt","ro":"Egipt"},"name":{"en":"Koshari","ro":"Koshari"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["200g long-grain white rice","200g green lentils","150g small macaroni or ditalini","400g canned chickpeas, drained","800g canned crushed tomatoes","3 large onions (2 for sauce, 1 for crispy topping)","4 tbsp vegetable oil","3 garlic cloves, minced, salt, cumin and vinegar to taste"],"ro":["200g orez cu bob lung","200g linte verde","150g macaroane mici sau ditalini","400g năut la conservă, scurs","800g roșii tocate la conservă","3 cepe mari (2 pentru sos, 1 pentru topping crocant)","4 linguri ulei vegetal","3 căței de usturoi, tocați, sare, chimen și oțet după gust"]},"howIsMade":{"en":"Cook the lentils in unsalted water for 20 minutes until al dente, then drain. Cook the rice in salted water for 15 minutes. Cook the pasta al dente and drain. Slice the third onion into thin rings and fry in oil over medium-high heat for 15-20 minutes, stirring often, until deep golden brown and crispy — this is the prized topping. Drain on paper towels. In the same oil, saute the remaining chopped onions 10 minutes, add garlic, cumin, canned tomatoes, a splash of vinegar and salt. Simmer the sauce 20-25 minutes until thick. Add the chickpeas and simmer 5 more minutes. Mix lentils into the rice. To serve, layer rice-lentil mixture, pasta, tomato-chickpea sauce, and top with the crispy onion rings. Koshari is eaten at room temperature."}},{"id":35,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"en":"Turkey","ro":"Turcia"},"name":{"en":"Baklava","ro":"Baklava"},"category":{"en":"Dessert","ro":"Desert"},"ingredients":{"en":["500g phyllo pastry sheets, thawed","200g unsalted butter, melted","200g walnuts, finely chopped","100g pistachios, finely chopped","1 tsp ground cinnamon","300g sugar","200ml water","2 tbsp honey plus 1 tbsp lemon juice"],"ro":["500g foi de plăcintă (phyllo), dezghețate","200g unt nesărat, topit","200g nuci, tocate mărunt","100g fistic, tocat mărunt","1 linguriță scorțișoară măcinată","300g zahăr","200ml apă","2 linguri miere plus 1 lingură suc de lămâie"]},"howIsMade":{"en":"Make the syrup first: dissolve sugar in water, boil 5 minutes, add honey and lemon juice, boil 5 more minutes; leave to cool completely — the syrup must be cold when poured over hot baklava. Mix the walnuts with pistachios and cinnamon; grease a 33x23cm baking tray with melted butter. Layer 8 phyllo sheets, brushing each with butter; scatter a generous layer of nut mixture. Cover with 4 buttered phyllo sheets, then another nut layer; repeat until the nuts are used up, finishing with 8 buttered phyllo sheets. Cut into diamonds or squares before baking; bake at 160 degrees C for 45-50 minutes until pale golden. The moment it comes out of the oven, pour the cold syrup all over — the temperature contrast helps the baklava absorb every drop; leave to rest 2-3 hours before serving."}},{"id":36,"servings":4,"tipType":"meat","pairingsType":"mexican","origin":{"en":"Mexico","ro":"Mexic"},"name":{"en":"Chili con carne","ro":"Chili con carne"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["500g beef mince (min. 20% fat)","400g canned red kidney beans, drained","400g canned chopped tomatoes","2 large onions, chopped","3 garlic cloves, minced","2 tbsp chipotle paste or 2 dried chipotle chillies, rehydrated","1 tbsp ground cumin and 1 tbsp smoked paprika","2 tbsp vegetable oil","salt and black pepper"],"ro":["500g carne de vită tocată (min. 20% grăsime)","400g fasole roșie kidney la conservă, scursă","400g roșii tocate la conservă","2 cepe mari, tocate","3 căței de usturoi, tocați","2 linguri pastă de chipotle sau 2 ardei iuți uscați","1 lingură chimen măcinat și 1 lingură boia afumată","2 linguri ulei vegetal","sare și piper negru"]},"howIsMade":{"en":"Heat the oil in a large pot over high heat. Brown the mince in two batches, breaking it up well — you want small caramelised pieces, not a grey steamed mass. Remove the meat and in the same oil, saute the onion for 8 minutes. Add garlic, cumin and smoked paprika, stir for 1 minute. Add chipotle paste, canned tomatoes, drained beans, the browned meat and 200ml water. Bring to a boil, reduce to low, partially cover and simmer 45-60 minutes, stirring occasionally. Chili should be thick, not watery — uncover for the last 15 minutes if too thin. Taste and adjust salt. Serve in bowls with sour cream, grated cheddar, sliced jalapeños, fresh coriander and tortilla chips."}},{"id":37,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"China","ro":"China"},"name":{"en":"Sweet and Sour Chicken","ro":"Pui dulce-acrișor"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["500g chicken breast, cut into 3cm pieces","1 tbsp cornstarch (for coating)","200g canned pineapple chunks, juice reserved","1 red and 1 green bell pepper, diced","1 small onion, diced","3 tbsp rice vinegar","2 tbsp sugar, 2 tbsp soy sauce, 1 tbsp ketchup","2 tbsp vegetable oil plus 1 tsp sesame oil"],"ro":["500g piept de pui, tăiat cuburi de 3 cm","1 lingură amidon de porumb (pentru acoperire)","200g bucăți de ananas la conservă, sucul rezervat","1 ardei roșu și 1 ardei verde, tăiați cuburi","1 ceapă mică, tăiată cuburi","3 linguri oțet de orez","2 linguri zahăr, 2 linguri sos de soia, 1 lingură ketchup","2 linguri ulei vegetal plus 1 linguriță ulei de susan"]},"howIsMade":{"en":"Make the sauce first: mix rice vinegar, sugar, soy sauce, ketchup and 3 tbsp of the pineapple juice. Toss the chicken pieces in cornstarch and shake off excess. Heat vegetable oil in a wok or large skillet over high heat. Fry the chicken in batches for 4-5 minutes until crisp and golden — do not crowd the pan. Set aside. In the same wok, add a little more oil and stir-fry the onion 2 minutes, add the peppers and cook 2 more minutes on high — they should stay crisp. Add the pineapple, pour in the sauce and bubble for 1-2 minutes until thick and glossy. Return the chicken and toss everything together. Finish with sesame oil. Serve immediately over steamed rice."}},{"id":38,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"en":"Australia","ro":"Australia"},"name":{"en":"Pavlova","ro":"Pavlova"},"category":{"en":"Dessert","ro":"Desert"},"ingredients":{"en":["4 large egg whites, room temperature","220g caster sugar","2 tsp cornstarch","1 tsp white wine vinegar","1 tsp vanilla extract","300ml double cream, for whipping","200g fresh strawberries, sliced","2 passion fruits, pulp scooped"],"ro":["4 albușuri mari, la temperatura camerei","220g zahăr fin (caster sugar)","2 lingurițe amidon de porumb","1 linguriță oțet de vin alb","1 linguriță extract de vanilie","300ml smântână pentru frișcă (min. 35% grăsime)","200g căpșuni proaspete, feliate","2 fructe ale pasiunii, pulpă"]},"howIsMade":{"en":"Preheat oven to 120°C and trace a 22cm circle on baking paper. Whisk egg whites with a pinch of salt to soft peaks. Add caster sugar one tablespoon at a time, whisking well after each addition — takes 8-10 minutes until the meringue is glossy, stiff, and has no sugar grains when rubbed between fingers. Fold in cornstarch, vinegar, and vanilla with a spatula. Mound the meringue onto the paper circle, building the sides slightly higher than the centre. Bake 90 minutes — the shell should be dry and faintly cream-coloured. Turn off oven and leave the pavlova to cool completely inside with the door ajar, at least 2 hours. Just before serving, whip cream to soft peaks and spread over the meringue. Top with strawberries and passion fruit pulp."}},{"id":39,"servings":4,"tipType":"def","pairingsType":"def","origin":{"en":"Canada","ro":"Canada"},"name":{"en":"Poutine","ro":"Poutine"},"category":{"en":"Snack","ro":"Gustare"},"ingredients":{"en":["800g Russet or Maris Piper potatoes, peeled","150g fresh cheese curds, room temperature","2 tbsp unsalted butter","2 tbsp plain flour","500ml beef stock, hot","1 tsp Worcestershire sauce","vegetable oil for frying","salt and black pepper"],"ro":["800g cartofi Russet sau Desiree, curatati","150g cas proaspat (cheese curds), la temperatura camerei","2 linguri unt nesarat","2 linguri făină alba","500ml supa de vita, fierbinte","1 lingurita sos Worcestershire","ulei vegetal pentru prajit","sare si piper negru"]},"howIsMade":{"en":"Cut potatoes into 1cm batons and soak in cold water for 30 minutes to remove starch — this is what makes them crispy. Dry thoroughly. First fry: heat oil to 150°C and fry potatoes 5-6 minutes until cooked through but without colour. Drain and rest 10 minutes. Second fry: heat oil to 190°C and fry 3-4 minutes until golden and very crispy. Season immediately with salt. For the gravy: melt butter over medium heat, add flour and cook 2 minutes stirring — it should turn pale golden. Add hot stock gradually, whisking constantly until thickened, 3-4 minutes. Add Worcestershire, season. Pile hot fries into a deep bowl, scatter room-temperature cheese curds over, and immediately pour the hot gravy on top — the heat partially melts the curds while keeping their signature squeak."}},{"id":40,"servings":4,"tipType":"def","pairingsType":"def","origin":{"en":"Poland","ro":"Polonia"},"name":{"en":"Pierogi","ro":"Pierogi"},"category":{"en":"Dinner","ro":"Cina"},"ingredients":{"en":["300g plain flour, plus extra for dusting","1 large egg plus 150ml warm water (for dough)","500g floury potatoes, boiled and mashed","200g farmer's cheese (twarog) or dry cottage cheese","2 medium onions, finely diced","40g unsalted butter","100g smoked bacon lardons","salt, white pepper and fresh chives to serve"],"ro":["300g făină alba, plus extra pentru intins","1 ou mare plus 150ml apa calda (pentru aluat)","500g cartofi fainosi, fierti si zdrobiti","200g branza de vaci (twarog) sau branza proaspata","2 cepe medii, taiate marunt","40g unt nesarat","100g bacon afumat, taiat cubulete","sare, piper alb si ceapa verde proaspata pentru servit"]},"howIsMade":{"en":"Mix flour with egg and warm water, knead 5 minutes to a smooth, elastic dough, cover and rest 30 minutes. Boil potatoes until tender, mash with farmer's cheese, salt and white pepper. In a pan, fry half the onion in butter until golden (10 min), stir into filling. Roll dough to 3mm, cut 8cm circles. Place a teaspoon of filling on each disc, fold in half and seal the edges firmly by pressing with fingers or a fork. Boil in salted water 3-4 minutes — they float when done. Meanwhile, fry bacon until crisp, add remaining onion and brown. Pan-fry the boiled pierogi in butter 2-3 minutes per side until golden patches appear. Serve with bacon, fried onion and sour cream."}},{"id":41,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Indonesia","ro":"Indonezia"},"name":{"en":"Nasi Goreng","ro":"Nasi Goreng"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["4 cups day-old cooked jasmine rice","300 g boneless chicken thigh, cut into 1 cm cubes","4 eggs","4 shallots, thinly sliced","4 garlic cloves, minced","2 red bird's eye chillies, thinly sliced","2 tbsp kecap manis (sweet soy sauce)","1 tbsp soy sauce","1 tsp shrimp paste (terasi), toasted","3 tbsp vegetable oil","salt and white pepper to taste","cucumber slices and fried shallots to serve"],"ro":["4 căni orez jasmin fiert în ziua precedentă","300 g pulpă de pui dezosată, tăiată cubulețe de 1 cm","4 ouă","4 eșalote, feliate subțire","4 căței de usturoi, tocați","2 ardei iuți roșii, feliați subțire","2 linguri kecap manis (sos de soia dulce)","1 lingură sos de soia","1 linguriță pastă de creveți (terasi), prăjită","3 linguri ulei vegetal","sare și piper alb după gust","felii de castravete și eșalote prăjite pentru servire"]},"howIsMade":{"en":"Break up the cold rice with your hands to separate any clumps. Heat 1 tbsp of oil in a wok over high heat until smoking. Add the chicken cubes and stir-fry for 3–4 minutes until cooked through and lightly golden; remove and set aside. Add the remaining 2 tbsp of oil to the wok. Add the shallots and stir-fry for 2 minutes until softened. Add the garlic, chilli, and shrimp paste and stir-fry for 1 minute until fragrant. Add the rice, spread into an even layer, and leave untouched for 1 minute to form a slight crust, then toss vigorously for 2–3 minutes. Return the chicken, add the kecap manis and soy sauce, and toss to coat evenly. Season with salt and white pepper. Push the rice to the side, crack in the eggs, scramble briefly, then fold into the rice and cook for 1 minute until just set. Serve in bowls topped with cucumber slices and fried shallots."}},{"id":42,"servings":4,"tipType":"def","pairingsType":"def","origin":{"en":"Switzerland","ro":"Elveția"},"name":{"en":"Fondue","ro":"Fondue"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["400 g Gruyère, coarsely grated","200 g Emmental, coarsely grated","1 garlic clove, halved","300 ml dry white wine (Fendant or Chasselas)","1 tbsp cornstarch","2 tbsp kirsch (cherry brandy)","a pinch of freshly grated nutmeg","freshly ground black pepper to taste","1 large crusty baguette (about 500 g), cut into 2 cm cubes","cornichons and boiled new potatoes to serve"],"ro":["400 g Gruyère, ras grosier","200 g Emmental, ras grosier","1 cățel de usturoi, tăiat pe jumătate","300 ml vin alb sec (Fendant sau Chasselas)","1 lingură amidon de porumb","2 linguri kirsch (rachiu de cireșe)","un praf de nucșoară rasă proaspăt","piper negru proaspăt măcinat după gust","1 baghetă mare crocantă (cca. 500 g), tăiată cubulețe de 2 cm","cornișoni și cartofi noi fierți pentru servire"]},"howIsMade":{"en":"Rub the inside of a fondue pot with the cut sides of the garlic clove; discard the garlic. Pour the wine into the pot and heat over medium heat until just below simmering. Toss the grated Gruyère and Emmental with the cornstarch until evenly coated. Add the cheese to the warm wine in three batches, stirring in a figure-eight motion after each addition until fully melted and smooth, about 8–10 minutes total. Stir in the kirsch, nutmeg, and a grind of black pepper; the fondue should be thick enough to coat a spoon. Place the pot over a fondue burner set to low to keep it gently bubbling. Spear bread cubes on fondue forks and swirl into the cheese, reaching the bottom of the pot to prevent a crust from forming. Serve with cornichons and boiled new potatoes."}},{"id":43,"servings":4,"tipType":"fish","pairingsType":"middle-eastern","origin":{"en":"Iraq","ro":"Irak"},"name":{"en":"Masgouf","ro":"Masgouf"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["1 whole carp or sea bass (about 1.5 kg), gutted and cleaned","4 tbsp olive oil","1 tsp salt","1 tsp ground turmeric","1 tsp ground cumin","2 tomatoes, roughly chopped","1 lemon, sliced","4 garlic cloves, minced","1 small onion, roughly chopped","2 tbsp tomato paste","freshly ground black pepper to taste","4 flatbreads to serve","sliced onion, tomato, and pickles to serve"],"ro":["1 crap sau biban întreg (cca. 1,5 kg), curățat și eviscerat","4 linguri ulei de măsline","1 linguriță sare","1 linguriță turmeric măcinat","1 linguriță chimen măcinat","2 roșii, tăiate grosier","1 lămâie, feliată","4 căței de usturoi, tocați","1 ceapă mică, tocată grosier","2 linguri pastă de roșii","piper negru proaspăt măcinat după gust","4 pâini plate pentru servire","ceapă feliată, roșii și murături pentru servire"]},"howIsMade":{"en":"Using a sharp knife, make a deep cut along the backbone to butterfly the fish open flat. Score the flesh diagonally every 4 cm. Mix the olive oil, turmeric, cumin, salt, and pepper; rub all over the flesh and inside the cavity. Leave to marinate for 20 minutes at room temperature. Meanwhile, combine the tomatoes, onion, garlic, lemon slices, and tomato paste to make the basting sauce. Thread the fish onto two long skewers (or use a fish grill basket) to hold it flat. Grill over glowing wood embers or charcoal (not open flames) for 30–40 minutes: flesh side down for the first 20 minutes until the flesh is opaque and pulls away from the bone, then skin side down for 10–15 minutes until the skin is crisp. Baste with the sauce every 5 minutes. Serve immediately with flatbread, sliced onion, tomato, and pickles."}},{"id":44,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"en":"Israel","ro":"Israel"},"name":{"en":"Shakshuka","ro":"Shakshuka"},"category":{"en":"Breakfast","ro":"Mic dejun"},"ingredients":{"en":["2 tbsp olive oil","1 large onion, finely diced","1 red bell pepper, finely diced","4 garlic cloves, minced","1 tsp ground cumin","1 tsp sweet paprika","½ tsp smoked paprika","¼ tsp chilli flakes","2 x 400 g cans crushed tomatoes","1 tsp sugar","salt and freshly ground black pepper to taste","6 eggs","a small handful of fresh flat-leaf parsley or coriander, roughly chopped","crusty bread or pita to serve"],"ro":["2 linguri ulei de măsline","1 ceapă mare, tăiată mărunt","1 ardei kapia roșu, tăiat mărunt","4 căței de usturoi, tocați","1 linguriță chimen măcinat","1 linguriță boia dulce","½ linguriță boia afumată","¼ linguriță fulgi de ardei iute","2 x 400 g roșii zdrobite la conservă","1 linguriță zahăr","sare și piper negru proaspăt măcinat după gust","6 ouă","o mână de frunze de pătrunjel sau coriandru, tocate grosier","pâine crocantă sau pita pentru servire"]},"howIsMade":{"en":"Heat the olive oil in a wide, deep frying pan over medium heat. Add the onion and red pepper and cook, stirring occasionally, for 8 minutes until softened and beginning to colour. Add the garlic, cumin, sweet paprika, smoked paprika, and chilli flakes and stir for 1 minute until fragrant. Pour in the crushed tomatoes, add the sugar, and season generously with salt and pepper. Simmer for 10 minutes, stirring occasionally, until the sauce thickens and deepens in colour. Make 6 wells in the sauce with a spoon. Crack one egg into each well, then cover the pan with a lid and cook for 8–10 minutes until the whites are just set but the yolks are still runny. Scatter the parsley or coriander over the top and serve immediately from the pan with crusty bread or pita."}},{"id":45,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"en":"Finland","ro":"Finlanda"},"name":{"en":"Salmon Soup","ro":"Lohikeitto"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["600 g fresh salmon fillet, skin removed, cut into 3 cm chunks","500 g waxy potatoes (Charlotte or similar), peeled and cut into 2 cm cubes","1 large leek, white and pale-green parts, thinly sliced into rings","2 medium carrots, peeled and sliced 5 mm thick","1 litre good-quality fish stock","200 ml double cream","1 bay leaf","5 whole allspice berries","1 tsp fine sea salt, plus more to taste","¼ tsp ground white pepper","1 large bunch fresh dill (about 30 g), roughly chopped"],"ro":["600 g file de somon proaspăt, fără piele, tăiat cuburi de 3 cm","500 g cartofi cu pulpă fermă (Charlotte sau similari), curățați, cuburi de 2 cm","1 praz mare, partea albă și verde deschis, tăiat rondele subțiri","2 morcovi medii, curățați, rondele de 5 mm","1 litru supă de pește bine aromatizată","200 ml smântână dulce pentru gătit","1 frunză de dafin","5 boabe de ienibahar","1 linguriță sare fină, plus după gust","¼ linguriță piper alb măcinat","1 mănunchi mare de mărar proaspăt (cca 30 g), tocat grosier"]},"howIsMade":{"en":"Pour the fish stock into a large pot and bring to a gentle simmer over medium heat. Add the potatoes, carrots, leek, bay leaf, and allspice berries. Cook at a gentle simmer for 12–15 minutes until the potatoes are just tender when pierced with a knife. Lower the heat so the stock barely trembles — do not boil. Add the salmon chunks and cook for 4–5 minutes until the fish is just opaque and flakes easily when nudged. Stir in the cream and heat for 2 minutes without letting it boil. Season with salt and white pepper. Remove the bay leaf and allspice berries. Ladle into warmed bowls and heap each portion with a generous amount of fresh dill. Serve with dark rye bread alongside."}},{"id":46,"servings":4,"tipType":"meat","timeMins":{"total":300,"active":60},"pairingsType":"middle-eastern","origin":{"en":"Iran","ro":"Iran"},"name":{"en":"Ghormeh Sabzi","ro":"Ghormeh Sabzi"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["700 g boneless lamb shoulder (or beef chuck), cut into 4 cm cubes","200 g dried red kidney beans, soaked overnight and drained (or 400 g canned, drained)","1 large onion, finely diced","80 g fresh fenugreek leaves (or 3 tbsp dried fenugreek / kasuri methi)","100 g fresh flat-leaf parsley, finely chopped","80 g fresh coriander (cilantro), finely chopped","50 g fresh spinach, finely chopped","4 dried Persian limes (limoo amani), pierced with a skewer","1 tsp ground turmeric","½ tsp ground black pepper","1 tsp fine sea salt, plus more to taste","3 tbsp vegetable oil, divided"],"ro":["700 g carne de miel fără os (spată) sau vită pentru tocăniță, tăiată cuburi de 4 cm","200 g fasole boabe roșie uscată, hidratată peste noapte și scursă (sau 400 g la conservă, scursă)","1 ceapă mare, tăiată mărunt","80 g frunze proaspete de schinduf (sau 3 linguri schinduf uscat / kasoori methi)","100 g pătrunjel frunze plate proaspăt, tocat mărunt","80 g coriandru proaspăt, tocat mărunt","50 g spanac proaspăt, tocat mărunt","4 lămâi persane uscate (limoo amani), înțepate cu un frigărui","1 linguriță turmeric măcinat","½ linguriță piper negru măcinat","1 linguriță sare fină, plus după gust","3 linguri ulei vegetal, separat"]},"howIsMade":{"en":"Heat 1 tbsp oil in a large heavy pot over medium-high heat; brown the meat in two batches, 3–4 minutes per batch, until deep brown on all sides. Remove and set aside; in the same pot, cook the onion over medium heat for 8 minutes until golden. Add the turmeric and black pepper; stir for 1 minute; return the meat to the pot. Add the drained kidney beans and pierced dried limes; pour over just enough water to barely cover. Bring to the boil, skim the foam, then reduce to the lowest possible simmer; meanwhile, heat the remaining 2 tbsp oil in a large frying pan over medium-high heat. Add all the herbs (fenugreek, parsley, coriander, spinach) and stir-fry for 15–20 minutes, until the herbs turn very dark green and all moisture has fully evaporated — this step is critical and builds the stew's characteristic deep flavour; stir the fried herbs into the stew. Season with salt; cover and simmer on the lowest heat for 2–2.5 hours (if using dried beans) or 1.5 hours (canned beans), stirring occasionally, until the meat is very tender and pulls apart easily. The stew should be thick and deeply coloured; serve over steamed basmati rice."}},{"id":47,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"en":"Portugal","ro":"Portugalia"},"name":{"en":"Bacalhau à Brás","ro":"Bacalhau à Brás"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["500g salted cod (bacalhau), soaked 24–48h in cold water and shredded into flakes","600g waxy potatoes, peeled and cut into very thin matchstick strips","6 large eggs, lightly beaten","2 medium white onions, thinly sliced","4 tbsp extra-virgin olive oil","3 garlic cloves, thinly sliced","Small bunch of fresh flat-leaf parsley, roughly chopped","80g black olives, pitted, to serve","Salt and white pepper to taste"],"ro":["500g cod sărat (bacalhau), înmuiat 24–48h și desfăcut în fâșii","600g cartofi cerați, curățați și tăiați în bețișoare foarte subțiri","6 ouă mari, ușor bătute","2 cepe medii albe, tăiate felii subțiri","4 linguri ulei de măsline extravirgin","3 căței de usturoi, tăiați felii subțiri","Legătură mică de pătrunjel proaspăt, tocat grosier","80g măsline negre, fără sâmburi","Sare și piper alb"]},"howIsMade":{"en":"Soak the shredded cod in cold water, changing the water four times over 24–48 hours until a small piece tastes pleasantly savoury rather than sharp; drain and pat dry. Cut potatoes into very thin matchstick strips; heat 2cm of neutral oil in a deep frying pan to 170°C and fry the potato strips in batches for 3–4 minutes until pale golden; drain on paper. Discard the frying oil and wipe the pan; heat olive oil over medium-low heat and cook the onion and garlic, stirring often, for 12–15 minutes until very soft and lightly golden. Add the cod flakes and stir for 2 minutes until warmed through; tip in the potato strips and toss once. Pour in the beaten eggs seasoned with white pepper; stir continuously over low heat with slow, wide folds for 2–3 minutes — the eggs should set in soft, creamy layers, never dry or granular. Remove from heat while the eggs still look slightly underdone; residual heat finishes the dish; taste for salt before adding any — the cod may already hold enough; scatter with parsley and serve straight from the pan with black olives alongside."}},{"id":48,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Philippines","ro":"Filipine"},"name":{"en":"Adobo","ro":"Adobo"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["1.2 kg chicken thighs and drumsticks, bone-in skin-on (or 1 kg pork belly cut into 4 cm cubes)","6 garlic cloves, crushed","125 ml cane vinegar or white wine vinegar","80 ml soy sauce","3 bay leaves","1 tsp whole black peppercorns","80 ml water","2 tbsp vegetable oil"],"ro":["1,2 kg pulpe și tobe de pui (cu os, cu piele) sau 1 kg burtă de porc tăiată cuburi de 4 cm","6 căței de usturoi, zdrobiți","125 ml oțet de trestie sau oțet alb de vin","80 ml sos de soia","3 frunze de dafin","1 linguriță boabe de piper negru","80 ml apă","2 linguri ulei vegetal"]},"howIsMade":{"en":"Combine the chicken (or pork), garlic, vinegar, soy sauce, bay leaves, peppercorns, and water in a large pot. Marinate for 30 minutes at room temperature. Bring to the boil over medium-high heat without stirring. Once boiling, reduce heat to low, cover, and simmer for 30 minutes (chicken) or 45 minutes (pork) until the meat is tender. Uncover and increase heat to medium. Continue simmering, turning the meat occasionally, for 15–20 minutes until the sauce reduces to a glossy, thick glaze that coats the back of a spoon. In a separate pan, heat the oil over high heat. Add the cooked pieces skin-side down and fry for 3–4 minutes until the skin is golden brown and crisp. Return to the sauce and toss to coat. Discard bay leaves. Serve over steamed white rice."}},{"id":49,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Jamaica","ro":"Jamaica"},"name":{"en":"Jerk Chicken","ro":"Jerk Chicken"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["1.5kg chicken thighs and drumsticks, skin-on, scored deeply with a knife","6 spring onions, roughly chopped","3 Scotch bonnet chilies or habaneros, seeds removed for moderate heat","5 garlic cloves","2cm piece fresh ginger, peeled","2 tbsp dark soy sauce","2 tbsp brown sugar","1 tbsp ground allspice","1 tsp dried thyme","½ tsp ground cinnamon","½ tsp black pepper","2 tbsp vegetable oil","Juice of 2 limes, plus wedges to serve"],"ro":["1,5 kg pulpe și copane de pui, cu piele, crestați adânc","6 fire ceapă verde, tăiate grosier","3 ardei Scotch bonnet (sau habanero), semințele îndepărtate","5 căței de usturoi","Bucată de 2cm ghimbir proaspăt, curățat","2 linguri sos de soia închis la culoare","2 linguri zahăr brun","1 lingură ienibahar măcinat","1 linguriță cimbru uscat","½ linguriță scorțișoară măcinată","½ linguriță piper negru","2 linguri ulei vegetal","Suc de la 2 lămi verzi, plus felii pentru servire"]},"howIsMade":{"en":"Blend spring onions, Scotch bonnets, garlic, ginger, soy sauce, brown sugar, allspice, thyme, cinnamon, black pepper, oil, and lime juice in a food processor until a rough paste forms. Score the chicken pieces deeply down to the bone — jerk only works if the marinade penetrates inside the meat. Rub the paste all over and into every cut. Cover and marinate in the refrigerator for at least 4 hours, ideally overnight. Remove from the fridge 30 minutes before cooking. To grill over charcoal: cook over medium-hot coals for 35–45 minutes, turning every 10 minutes, until the juices run clear and the exterior is deeply charred in places. To oven-roast: place on a rack over a baking tray at 200°C for 40 minutes, then finish under a hot grill for 5 minutes to char the skin. Allspice is the defining spice — do not substitute with mixed spice. Rest 5 minutes before serving. Serve with rice and peas, fried plantain, and lime wedges."}},{"id":50,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Ethiopia","ro":"Etiopia"},"name":{"en":"Doro Wat","ro":"Doro Wat"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["1.2 kg chicken pieces (thighs and drumsticks, bone-in)","3 tbsp lemon juice","4 large onions (about 800 g), very finely diced","80 g niter kibbeh (Ethiopian spiced butter) or clarified butter","6 garlic cloves, minced","2 tbsp fresh ginger, finely grated (about 3 cm piece)","4 tbsp berbere spice blend","1 tsp ground cardamom","½ tsp ground fenugreek","250 ml water or chicken stock","4 hard-boiled eggs, shelled and scored all over with a fork","salt to taste"],"ro":["1,2 kg piese de pui (pulpe și tobe cu os)","3 linguri suc de lămâie","4 cepe mari (cca 800 g), tăiate mărunt fin","80 g unt etiopian niter kibbeh (sau unt clarificat)","6 căței de usturoi, tocați mărunt","2 linguri ghimbir proaspăt ras (cca 3 cm bucată)","4 linguri amestec de condimente berbere","1 linguriță cardamom măcinat","½ linguriță schinduf măcinat","250 ml apă sau supă de pui","4 ouă fierte tari, curățate, înțepate cu furculița","sare după gust"]},"howIsMade":{"en":"Prick the chicken all over with a fork and rub with lemon juice; put the finely diced onions into a large heavy pot over low heat with no oil or fat. Cook, stirring often, for 25–30 minutes until the onions are very soft, deep golden-brown, and smell caramel-like — this long dry fry builds the stew's flavour base; add the niter kibbeh and stir to coat. Add the garlic, ginger, berbere, cardamom, and fenugreek; cook for 5 minutes, stirring constantly, until the spices bloom and the butter turns deep red-orange. Add the chicken pieces and turn to coat completely; cook 5 minutes, turning, until sealed on all sides. Pour in the water or stock; bring to the boil, then reduce to the lowest simmer. Cover and cook for 40–45 minutes, turning the chicken halfway through, until the meat is very tender and nearly falling off the bone; score the eggs all over with a fork and nestle them into the sauce. Simmer uncovered for 10 more minutes until the eggs are stained red from the sauce and the sauce has thickened; season with salt; serve on injera flatbread or steamed rice."}},{"id":51,"servings":4,"tipType":"meat","pairingsType":"middle-eastern","origin":{"en":"Syria","ro":"Siria"},"name":{"en":"Kibbeh","ro":"Kibbeh"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["Shell: 300 g fine bulgur wheat (#1 grade), rinsed and drained","400 g very lean lamb (or beef) mince, chilled","1 medium onion, finely grated","1 tsp ground allspice","1 tsp ground cinnamon","1 tsp fine salt","½ tsp ground black pepper","Filling: 300 g lamb (or beef) mince","1 medium onion, finely diced","80 g pine nuts (or cashews)","1 tsp ground allspice","½ tsp ground cinnamon","1 tbsp vegetable oil","Vegetable oil for deep-frying (about 1 litre)"],"ro":["Coajă: 300 g bulgur fin (#1), clătit și scurs bine","400 g carne de miel sau vită slabă, tocată fin și răcită","1 ceapă medie, rasă sau blenderizată","1 linguriță condiment allspice (ienibahar măcinat)","1 linguriță scorțișoară măcinată","1 linguriță sare fină","½ linguriță piper negru măcinat","Umplutură: 300 g carne de miel sau vită tocată","1 ceapă medie, tăiată mărunt","80 g nuci de pin (sau nuci caju)","1 linguriță allspice","½ linguriță scorțișoară","1 lingură ulei vegetal","Ulei vegetal pentru prăjit adânc (cca 1 litru)"]},"howIsMade":{"en":"Soak the bulgur in cold water for 15 minutes, then drain and squeeze out all moisture firmly with your hands; combine with the chilled lean mince, grated onion, allspice, cinnamon, salt, and pepper in a food processor. Process for 3–4 minutes, adding ice water a tablespoon at a time if needed, until you have a smooth, stiff dough; refrigerate for 30 minutes. Make the filling: heat the oil over medium heat; cook the onion for 5 minutes until soft. Add the mince and brown, breaking it up, for 6–8 minutes; stir in allspice, cinnamon, pepper, and pine nuts; cook 2 minutes. Cool completely; shape: wet your hands with cold water. Take a 60 g piece of dough and mould it around your index finger into a hollow torpedo shape with 5 mm thick walls; fill the hollow with about 1 tablespoon of filling. Pinch the open end firmly to seal it into a pointed torpedo; repeat with the remaining dough and filling. Refrigerate for at least 30 minutes; fry: heat oil to 175°C. Fry in batches of 4–5 for 4–5 minutes, turning gently, until deep golden brown all over; drain on paper; serve warm with yoghurt or garlic sauce and pita bread."}},{"id":52,"servings":4,"tipType":"veg","pairingsType":"veg","origin":{"en":"Netherlands","ro":"Olanda"},"name":{"en":"Stamppot","ro":"Stamppot"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["1 kg floury potatoes (such as Maris Piper or Russet), peeled and quartered","400 g curly kale (boerenkool), tough stems removed, leaves roughly chopped","400 g smoked pork sausage (rookworst) or bratwurst","80 g unsalted butter, cut into cubes","100 ml whole milk, warmed","1/4 tsp freshly grated nutmeg","1 1/2 tsp fine sea salt, divided","1/2 tsp freshly ground black pepper"],"ro":["1 kg cartofi făinoși (tip Maris Piper sau Russet), curățați și tăiați în sferturi","400 g varză creață (boerenkool), tulpini dure îndepărtate, frunze tocate grosier","400 g cârnați afumați din porc (rookworst) sau bratwurst","80 g unt nesărat, tăiat cubulețe","100 ml lapte integral, încălzit","1/4 linguriță nucșoară proaspăt rasă","1 1/2 linguriță sare fină de mare, împărțită","1/2 linguriță piper negru proaspăt măcinat"]},"howIsMade":{"en":"Bring a large pot of water with 1 tsp salt to the boil, add the potatoes, and cook for 18-20 minutes until completely tender when pierced with a knife. While the potatoes cook, bring a separate pot of salted water to the boil, add the kale, and blanch for 5-6 minutes until wilted and tender; drain well, squeeze out excess water, and chop roughly. Place the smoked sausage in a pan, add enough water to just cover, and simmer over medium heat for 20 minutes until heated through — or pan-fry in a little oil over medium heat for 8-10 minutes, turning halfway, until browned on all sides. Drain the potatoes and return them to the hot pot over low heat for 1-2 minutes, shaking the pot to steam-dry them and prevent a watery mash. Add the butter and warm milk and mash vigorously with a potato masher until smooth and creamy. Fold in the drained kale, season with the remaining salt, black pepper, and nutmeg, and stir until evenly combined. Serve immediately in deep bowls with the sliced sausage on top."}},{"id":53,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"New Zealand","ro":"Noua Zeelandă"},"name":{"en":"Hangi","ro":"Hangi"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["600 g bone-in lamb shoulder or ribs, cut into 4 cm pieces","4 chicken drumsticks (about 600 g total), skin-on","500 g waxy potatoes, peeled and halved","300 g kumara (orange sweet potato), peeled and cut into 4 cm cubes","300 g butternut pumpkin, peeled and cut into 4 cm cubes","1/4 head savoy cabbage (about 300 g), cut into 4 wedges","3 tbsp vegetable oil","1 1/2 tsp fine salt","1/2 tsp ground black pepper"],"ro":["600 g carne de miel cu os (spată sau coaste), tăiată în bucăți de 4 cm","4 pulpe inferioare de pui (cca 600 g total), cu os și piele","500 g cartofi waxy, curățați și tăiați în jumătăți","300 g kumara (batată portocalie), curățată și tăiată cubulețe de 4 cm","300 g dovleac butternut, curățat și tăiat cubulețe de 4 cm","1/4 dintr-un cap de varză Savoy (cca 300 g), tăiată în 4 sferturi","3 linguri ulei vegetal","1 1/2 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"en":"Heat the oven to 180°C (160°C fan). Season the lamb and chicken all over with salt and pepper. Heat the oil in a large flameproof casserole over high heat and brown the lamb pieces for 3-4 minutes per side until deeply coloured, then transfer to a plate. In the same pot, brown the chicken drumsticks skin-side down for 4-5 minutes until the skin is golden and crisp, then set aside. Arrange all the browned meat in the casserole and tuck the potatoes, kumara, pumpkin, and cabbage wedges snugly around and between the pieces. Pour in 200 ml of water, then seal the casserole very tightly with a double layer of foil pressed against the rim and put the lid on. Cook in the oven for 2 hours until the lamb is completely tender and pulls away from the bone easily, and all the vegetables are soft when pierced with a fork — if not quite done, cover again and cook for 30 minutes more. Remove the lid and foil, raise the oven to 220°C, and roast uncovered for 15 minutes until the skin crisps. Rest for 10 minutes before transferring everything to a large platter and spooning the collected juices over the top."}},{"id":54,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"en":"Belgium","ro":"Belgia"},"name":{"en":"Moules-frites","ro":"Moules-frites"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["2kg fresh live mussels, scrubbed and beards removed","800g floury potatoes, peeled and cut into thick batons","50g unsalted butter","4 shallots, finely diced","4 garlic cloves, thinly sliced","200ml dry white wine","2 celery stalks, finely sliced","Small bunch of fresh parsley, finely chopped","Vegetable oil or beef dripping, for deep-frying","Salt and black pepper"],"ro":["2 kg midii proaspete vii, curățate și cu beard-ul îndepărtat","800g cartofi făinoși, curățați și tăiați bețe groase","50g unt nesărat","4 șalote, tocate mărunt","4 căței de usturoi, felii subțiri","200ml vin alb sec","2 tulpini de țelină, feliate subțire","Legătură mică de pătrunjel proaspăt, tocat mărunt","Ulei vegetal sau grăsime de vită, pentru prăjit","Sare și piper negru"]},"howIsMade":{"en":"For the frites: cut potatoes into thick batons and soak in cold water for 30 minutes to remove surface starch, then drain and dry thoroughly; first fry at 140°C for 6–8 minutes until cooked through but uncoloured; drain and cool completely. Tap each open mussel on the counter — discard any that do not close; melt butter in a large heavy pot over medium-high heat. Add shallots and celery and cook for 3 minutes until softened; add garlic and cook for 1 minute. Pour in the white wine, bring to a boil, then add the mussels and cover tightly; steam for 4–5 minutes, shaking the pot once or twice, until the shells have opened wide. Discard any that remain shut; stir in most of the parsley and season the broth. Raise the frying oil to 190°C and fry the blanched batons in batches for 2–3 minutes until golden and very crisp; drain and season immediately with salt; serve the mussels in wide bowls in their broth, the frites alongside, with the remaining parsley and mayonnaise on the side."}},{"id":55,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Greece","ro":"Grecia"},"name":{"en":"Moussaka","ro":"Moussaka"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["2 large eggplants (about 1 kg total), sliced 1 cm thick","500 g lamb mince (or beef mince)","1 large onion, finely diced","3 garlic cloves, minced","400 g chopped tomatoes (1 can)","2 tbsp tomato paste","100 ml red wine","1 tsp dried oregano","1/2 tsp ground cinnamon","60 g butter (for the bechamel)","60 g plain flour (for the bechamel)","700 ml warm milk","2 egg yolks","80 g grated kefalotyri (or parmesan)","3 tbsp olive oil","Salt and freshly ground black pepper"],"ro":["2 vinete mari (aproximativ 1 kg in total), feliate de 1 cm grosime","500 g carne tocata de miel (sau de vita)","1 ceapa mare, tocata marunt","3 căței de usturoi, zdrobiti","400 g rosii tocate in conserva (1 conserva)","2 linguri pasta de rosii","100 ml vin rosu","1 lingurita oregano uscat","1/2 lingurita scortisoara macinata","60 g unt (pentru bechamel)","60 g făină alba (pentru bechamel)","700 ml lapte cald","2 galbenusuri de ou","80 g kefalotyri ras (sau parmezan)","3 linguri ulei de masline","Sare si piper negru proaspat macinat"]},"howIsMade":{"en":"Slice 2 large eggplants into 1 cm rounds, salt them generously and let them sit in a colander for 30 minutes to draw out the bitter water; pat dry with paper towels. Brush the slices with olive oil and roast at 200 C for 20-25 minutes, turning once, until golden and tender. In a wide pan heat 2 tbsp oil over medium-high and brown 500 g minced lamb with one chopped onion and 3 garlic cloves for 8-10 minutes, then deglaze with 100 ml red wine and let it reduce. Add 400 g chopped tomatoes, 2 tbsp tomato paste, half a tsp cinnamon and 1 tsp oregano; simmer 20 minutes until thick and no excess liquid pools at the edge. For the bechamel melt 60 g butter in a saucepan, whisk in 60 g flour and cook 2 minutes until blond, then gradually add 700 ml warm milk whisking constantly until thick; off the heat, let it cool 30 seconds and beat in 2 egg yolks with 80 g grated kefalotyri or parmesan. In a 30x20 cm baking dish layer half the eggplant, all the lamb sauce, the remaining eggplant, then pour the bechamel on top and level it with a spatula. Bake at 180 C for 40-45 minutes until the top is deeply golden and the sauce bubbles at the edges. Rest the moussaka for 15-20 minutes before cutting; this step is non-negotiable so the layers set and the slices hold their shape."},"timeMins":{"total":105,"active":35}},{"id":56,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Czech Republic","ro":"Republica Cehă"},"name":{"en":"Svíčková","ro":"Svíčková"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["1.2 kg beef sirloin (top round or topside)","100 g smoked bacon, cut in thin strips for larding (optional)","30 g butter","1 tbsp neutral oil","1 large onion, diced","2 large carrots, diced","1 parsnip, diced","150 g celeriac, diced","2 bay leaves","6 allspice berries","10 black peppercorns","Zest of 1/2 lemon","1 tbsp Dijon mustard","2 tbsp tomato paste","200 ml dry white wine","500 ml beef stock","200 ml heavy cream (33% fat)","1 tbsp plain flour (optional, for thickening)","1 tsp sugar","Juice of 1/2 lemon","Salt, to taste","To serve: whipped cream, cranberry compote, lemon slice, knedliky"],"ro":["1,2 kg mușchi de vită (vrabia sau pulpă top)","100 g bacon afumat, tăiat fâșii subțiri pentru lardonare (opțional)","30 g unt","1 lingură ulei neutru","1 ceapă mare, tăiată cuburi","2 morcovi mari, tăiați cuburi","1 rădăcină de păstârnac, tăiată cuburi","150 g țelină rădăcină, tăiată cuburi","2 foi de dafin","6 boabe de ienibahar","10 boabe de piper negru","Coaja de la 1/2 lămâie","1 lingură de muștar Dijon","2 linguri de pastă de roșii","200 ml vin alb sec","500 ml supă de vită","200 ml smântână grasă (33% grăsime)","1 lingură de făină albă (opțional, pentru îngroșare)","1 linguriță de zahăr","Zeama de la 1/2 lămâie","Sare, după gust","Pentru servire: frișcă bătută, dulceață de merișoare, felie de lămâie, knedlíky"]},"howIsMade":{"en":"Lard the beef sirloin (1.2 kg) with thin strips of smoked bacon, or truss it tightly with kitchen twine; season generously with salt and freshly ground pepper on all sides. Heat 30 g butter and 1 tbsp oil in a heavy Dutch oven over medium-high and sear the beef on every side for 8-10 minutes until a deep brown crust forms, then transfer to a plate. In the same pot brown the mirepoix (1 large carrot, 1 parsnip, 150 g celeriac, 1 large onion, all diced) for 10-12 minutes until caramelised at the edges; add 2 bay leaves, 6 allspice berries, 10 whole black peppercorns, the zest of half a lemon and 1 tbsp mustard. Stir in 2 tbsp tomato paste and cook 2 minutes until it darkens, then deglaze with 200 ml dry white wine and 500 ml beef stock, scraping the bottom, and nestle the beef back in on top of the vegetables. Cover and braise at 160°C for 1.5 to 2 hours, turning the beef every 30 minutes, until a fork slides in with no resistance. Lift the beef onto a board and tent with foil to rest; blend the cooking liquid and vegetables with a stick blender until smooth and pass the sauce through a fine sieve back into the pot. Stir in 200 ml heavy cream and, if needed, 1 tbsp flour slaked in a little cold water; simmer 5 minutes until the sauce coats the back of a spoon glossily, then adjust with salt, 1 tsp sugar and a squeeze of lemon to balance the sweet-sour. Slice the beef against the grain into 1 cm slices, ladle the warm sauce over the top and garnish with a spoon of whipped cream, cranberry compote and a lemon slice; serve with houskove knedliky (bread dumplings)."}},{"id":57,"servings":4,"tipType":"meat","timeMins":{"total":195,"active":45},"pairingsType":"meat","origin":{"en":"Norway","ro":"Norvegia"},"name":{"en":"Fårikål","ro":"Fårikål"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["1.2 kg bone-in lamb shoulder or neck, cut into 5 cm pieces","1.2 kg white cabbage (about 1 large head), cored and cut into 8 thick wedges","1 tbsp whole black peppercorns","600 ml cold water","1 1/2 tsp fine salt"],"ro":["1,2 kg carne de miel cu os (spata sau gat), taiata in bucati de 5 cm","1,2 kg varza alba (1 cap mare), miezul indepartat, taiata in 8 sferturi groase","1 lingura boabe intregi de piper negru","600 ml apa rece","1 1/2 lingurita sare fina"]},"howIsMade":{"en":"Season the lamb pieces all over with 1 tsp of the salt. Arrange half the cabbage wedges in an even layer at the bottom of a large, heavy pot. Lay the lamb pieces on top, scatter over the peppercorns and the remaining 1/2 tsp salt, then arrange the remaining cabbage on top. Pour the cold water carefully down the inside wall of the pot — do not stir. Cover tightly and bring to a gentle boil over medium heat, about 8-10 minutes. Reduce the heat to the lowest possible simmer and cook undisturbed for 2 to 2.5 hours until the lamb is completely tender and falls off the bone, and the cabbage has collapsed and fully absorbed the meat juices. After 2 hours check that the lamb pulls away from the bone with no resistance and the broth is rich and fragrant — if not quite done, cover and simmer for 30 minutes more. Taste and adjust salt. Ladle into deep bowls with the broth, ensuring each serving has both lamb and cabbage."}},{"id":58,"servings":4,"tipType":"veg","pairingsType":"middle-eastern","origin":{"en":"Sudan","ro":"Sudan"},"name":{"en":"Ful Medames","ro":"Ful Medames"},"category":{"en":"Breakfast","ro":"Mic dejun"},"ingredients":{"en":["400 g dried small fava beans, soaked overnight in cold water (or 800 g canned fava beans, rinsed and drained)","4 garlic cloves, finely minced","60 ml fresh lemon juice (about 1 large lemon), plus more to taste","4 tbsp extra-virgin olive oil, divided","1 tsp ground cumin","1/2 tsp ground coriander","1/2 tsp fine sea salt, plus more to taste","1/4 tsp cayenne pepper or hot paprika","2 medium ripe tomatoes (about 250 g), finely diced","1 small red onion (about 100 g), finely diced","20 g flat-leaf parsley, leaves roughly chopped"],"ro":["400 g fasole fava uscata, inmuiata peste noapte in apa rece (sau 800 g fasole fava la conserva, clatita si scursa)","4 căței de usturoi, tocati marunt","60 ml suc proaspat de lamaie (cca 1 lamaie mare), plus dupa gust","4 linguri ulei de masline extravirgin, impartit","1 lingurita chimen macinat","1/2 lingurita coriandru macinat","1/2 lingurita sare fina de mare, plus dupa gust","1/4 lingurita ardei iute macinat sau boia picanta","2 rosii mijlocii coapte (cca 250 g), taiate marunt","1 ceapa rosie mica (cca 100 g), taiata marunt","20 g patrunjel plat, frunzele tocate grosier"]},"howIsMade":{"en":"If using dried beans, drain the soaked beans and cover with fresh cold water by 4-5 cm; bring to the boil and simmer for 1.5 to 2 hours until the beans are completely soft when pressed between fingers, then drain, reserving 100 ml of cooking liquid. If using canned beans, rinse, drain, and use 100 ml of water as the liquid. Return the beans to the pot over low heat and add the garlic, lemon juice, 3 tbsp of the olive oil, cumin, coriander, salt, and cayenne. Cook for 3-4 minutes, mashing about half the beans with a fork to create a creamy, partly chunky texture, adding reserved cooking liquid a splash at a time if too thick. Taste and adjust lemon, salt, and spice — the ful should be tangy and warmly spiced. Divide into shallow bowls and scatter the diced tomatoes, red onion, and parsley over the top. Drizzle the remaining 1 tbsp olive oil over each serving and serve immediately with warm pita bread."}},{"id":59,"servings":4,"tipType":"fish","timeMins":{"total":50,"active":40},"pairingsType":"mediterranean","origin":{"en":"Croatia","ro":"Croația"},"name":{"en":"Crni Rizot","ro":"Crni Rižot"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["500 g fresh or thawed squid, cleaned, with 2-3 ink sacs reserved","300 g arborio or carnaroli rice","1 medium onion (about 150 g), finely chopped","3 garlic cloves, finely minced","100 ml dry Dalmatian white wine (or Pošip)","1 litre warm fish stock (or water with 1 fish stock cube)","60 ml extra-virgin olive oil","30 g cold butter, cubed","2 tbsp fresh parsley, chopped","1/2 lemon, juice only","1 tsp fine sea salt","1/2 tsp ground black pepper"],"ro":["500 g calmari proaspeti sau decongelati, curatati, cu 2-3 saculeti de cerneala separati","300 g orez arborio sau carnaroli","1 ceapa medie (cca 150 g), tocata marunt","3 căței de usturoi, tocati marunt","100 ml vin alb sec dalmatian (sau Pošip)","1 litru fond de peste cald (sau apa cu 1 cub de fond de peste)","60 ml ulei de masline extravirgin","30 g unt rece, taiat cubulete","2 linguri patrunjel proaspat, tocat","1/2 lamaie, doar zeama","1 lingurita sare fina de mare","1/2 lingurita piper negru macinat"]},"howIsMade":{"en":"Clean the squid carefully: lift out the ink sacs intact into a small bowl with a splash of water, then cut the bodies into 1 cm rings and halve the tentacles. In a wide heavy pan, heat 4 tbsp olive oil over medium heat and sauté the onion for 4-5 minutes until soft, then add the garlic for 1 minute more. Add the squid rings and tentacles, sauté for 2-3 minutes until just opaque, then pour in the wine and let it evaporate completely (about 2 minutes). Add the rice and stir for 1 minute to coat with fat, then begin adding the hot fish stock one ladle at a time, stirring constantly for 16-18 minutes total. Halfway through, break the ink sacs into the remaining stock and pour it in — the risotto turns deep jet black instantly and gains a profound oceanic depth. When the rice is al dente and creamy with a little stock still pooling, kill the heat and add the cold butter, the remaining 2 tbsp olive oil, the lemon juice, and the parsley. Stir vigorously for 30 seconds for the mantecatura, then cover and rest for 2 minutes. Serve immediately in shallow bowls with extra parsley on top and a wedge of lemon alongside."}},{"id":60,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Mongolia","ro":"Mongolia"},"name":{"en":"Buuz","ro":"Buuz"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["Dough: 300 g all-purpose flour, plus extra for dusting","150 ml warm water (about 50 C)","1/2 tsp fine salt","Filling: 400 g ground lamb (or half lamb, half beef)","1 medium onion (about 150 g), finely diced","3 garlic cloves, finely minced","2 tbsp sunflower oil","1 tsp ground cumin","1 tsp fine sea salt","1/2 tsp ground black pepper","50 ml cold water"],"ro":["Aluat: 300 g făină alba, plus extra pentru intins","150 ml apa calda (cca 50 C)","1/2 lingurita sare fina","Umplutura: 400 g carne de miel tocata (sau amestec miel-vita)","1 ceapa medie (cca 150 g), taiata marunt","3 căței de usturoi, tocati marunt","2 linguri ulei de floarea-soarelui","1 lingurita chimen macinat","1 lingurita sare fina de mare","1/2 lingurita piper negru macinat","50 ml apa rece"]},"howIsMade":{"en":"Make the dough: mix flour and salt, pour in the warm water, and knead for 5-6 minutes until smooth and elastic. Cover with a damp cloth and rest for 30 minutes. Make the filling: combine the lamb, onion, garlic, oil, cumin, salt, pepper, and cold water in a bowl and mix well with your hands until evenly combined and slightly sticky. Divide the dough into 20-24 equal pieces (about 20 g each) and roll each into a thin round about 10 cm across, keeping the centre slightly thicker than the edges. Place 1 heaped tablespoon (about 25 g) of filling in the centre of each round. Lift the edges up around the filling and pleat them together at the top, leaving a small steam hole in the centre — the classic Mongolian shape. Line a bamboo steamer with parchment paper or cabbage leaves and arrange the buuz in a single layer with 2 cm between each. Fill a wok or wide pot with water and bring to a rolling boil; set the steamer basket over the boiling water and steam for 20-22 minutes until the dough is cooked through and the filling is no longer pink inside. Serve immediately."}},{"id":61,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Pakistan","ro":"Pakistan"},"name":{"en":"Biryani","ro":"Biryani"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["800g boneless chicken thighs (or lamb shoulder), cut into large pieces, bone-in if possible","200g plain whole-milk yoghurt, whisked","2 tbsp ginger-garlic paste","1 tsp garam masala","1 tsp chilli powder","1/2 tsp turmeric","1 tsp salt","3 tbsp warm milk + a pinch of saffron threads","400g basmati rice","2.5 litres water (for par-boiling the rice)","4 tbsp ghee","4 green cardamom pods","2 black cardamom pods","1 cinnamon stick","6 cloves","2 bay leaves","2 large onions, thinly sliced","2 medium tomatoes, grated","2 tbsp chopped fresh mint","2 tbsp chopped fresh coriander","1 tbsp extra ghee, melted (to drizzle)","To serve: cold yoghurt raita, lemon wedges"],"ro":["800 g pulpe de pui dezosate (sau spata de miel), taiate cuburi mari, cu os daca este posibil","200 g iaurt gras de vaca, batut","2 linguri pasta de ghimbir-usturoi","1 lingurita garam masala","1 lingurita pudra de chili","1/2 lingurita turmeric","1 lingurita sare","3 linguri lapte cald + un varf de fire de sofran","400 g orez basmati","2,5 l apa (pentru fierberea partiala a orezului)","4 linguri ghee","4 capsule cardamom verde","2 capsule cardamom negru","1 bat de scortisoara","6 cuișoare","2 foi de dafin","2 cepe mari, taiate solzi subtiri","2 rosii medii, rase","2 linguri menta proaspata, tocata","2 linguri coriandru proaspat, tocat","1 lingura ghee suplimentar, topit (pentru stropit)","Pentru servit: raita de iaurt rece, felii de lamaie"]},"howIsMade":{"en":"Mix 800 g chicken (or lamb) with 200 g whisked yoghurt, 2 tbsp ginger-garlic paste, 1 tsp garam masala, 1 tsp chilli powder, 1/2 tsp turmeric, 1 tsp salt and a pinch of saffron threads soaked in 3 tbsp warm milk; cover and marinate at least 1 hour, ideally 4 hours in the fridge. Melt 4 tbsp ghee or oil in a heavy-bottomed pot over medium heat; when it shimmers, add 4 green cardamom pods, 2 black cardamom pods, 1 cinnamon stick, 4 cloves and 1 bay leaf and let them bloom for 30 seconds until they crackle lightly. Add 2 large onions sliced thin and fry for 12-15 minutes, stirring often, until deep brown and crisp; lift out half onto kitchen paper for garnish and leave the rest in the pot with the aromatic oil. Slide the marinated meat into the pot with 2 grated tomatoes and cook 8-10 minutes over medium heat, stirring until the yoghurt breaks and the oil rises to the edges; lower the heat and simmer covered another 15 minutes until the meat is almost tender but the sauce stays thick. Meanwhile rinse 400 g basmati rice until the water runs clear and soak for 30 minutes; bring 2.5 litres of water to the boil with 2 tsp salt, 3 cardamom pods, 1 cinnamon stick and 2 bay leaves, slip in the rice with a few drops of oil and cook for exactly 5-6 minutes until the grains are 70% done — still firm in the centre; drain at once. Spread half of the drained rice over the meat masala, scatter half of the fried onions, 2 tbsp chopped mint and 2 tbsp coriander, then layer the remaining rice on top; drizzle with 4 tbsp warm saffron milk and 2 tbsp melted ghee, and finish with the remaining onions, mint and coriander. Seal the pot with a tight lid (or cover with foil and press the lid down), set it on the lowest possible flame, ideally over a heat diffuser or a cast-iron tava, and dum cook for 25 minutes without lifting the lid — the trapped steam finishes the rice and meat together. Turn off the heat and let the sealed pot rest for 10 minutes; open, gently fluff from the side inwards to fold the meat and rice layers, and serve straight away with cold yoghurt raita and lemon wedges."},"timeMins":{"total":105,"active":50}},{"id":62,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"en":"Tunisia","ro":"Tunisia"},"name":{"en":"Brik","ro":"Brik"},"category":{"en":"Snack","ro":"Gustare"},"ingredients":{"en":["4 sheets of brik pastry (or malsouka/ouarka), about 30 cm in diameter (or spring roll wrappers as substitute)","4 large eggs (1 per brik)","160 g canned tuna in olive oil, well drained","1 small onion (about 80 g), finely diced","3 tbsp small capers, rinsed and roughly chopped","20 g flat-leaf parsley, finely chopped","1/2 tsp ground cumin","1/2 tsp fine sea salt","1/4 tsp cayenne pepper or harissa paste","500 ml vegetable oil for deep-frying","1 lemon, cut into 4 wedges, to serve"],"ro":["4 foi de brik (sau malsouka/ouarka), cca 30 cm diametru (sau foi de spring roll ca substitut)","4 oua mari (1 pe brik)","160 g ton la conserva in ulei de masline, bine scurs","1 ceapa mica (cca 80 g), taiata marunt","3 linguri capere mici, clatite si tocate grosier","20 g patrunjel plat, tocat marunt","1/2 lingurita chimen macinat","1/2 lingurita sare fina de mare","1/4 lingurita ardei iute macinat sau harissa","500 ml ulei vegetal pentru prajit adanc","1 lamaie, taiata in 4, pentru servire"]},"howIsMade":{"en":"Combine the drained tuna, onion, capers, parsley, cumin, salt, and cayenne in a bowl and mix well to make the filling. Pour the vegetable oil into a deep, wide pan to a depth of 3-4 cm and heat to 175°C. Lay a brik pastry sheet flat on a clean surface and spoon a quarter of the tuna filling onto the lower half, creating a slight hollow in the centre. Crack 1 egg into the hollow. Working quickly, fold the pastry in half to form a half-moon, pressing the edges firmly together to seal and prevent the egg from escaping. Carefully slide the brik into the hot oil and fry for 1.5-2 minutes per side until deep golden and crisp all over, flipping once with a wide spatula. Lift out with a slotted spoon and drain on paper towels for 30 seconds. Serve immediately — the yolk should be runny to lightly set and the pastry crackling crisp. Squeeze a lemon wedge over the top."}},{"id":63,"servings":4,"tipType":"def","pairingsType":"def","origin":{"en":"Georgia","ro":"Georgia"},"name":{"en":"Khachapuri","ro":"Khachapuri"},"category":{"en":"Breakfast","ro":"Mic dejun"},"ingredients":{"en":["500 g plain flour (all-purpose), plus extra for dusting","7 g instant yeast (1 sachet)","1 tsp caster sugar","1 tsp fine sea salt","250 ml warm water (about 40°C / 105°F)","2 tbsp olive oil","400 g sulguni or mozzarella, coarsely grated","200 g feta cheese, crumbled","4 large eggs (1 per khachapuri)","40 g unsalted butter, cut into 4 equal pieces"],"ro":["500 g făină albă, plus extra pentru pudrare","7 g drojdie instant (1 plic)","1 linguriță zahăr","1 linguriță sare fină de mare","250 ml apă caldă (aproximativ 40°C)","2 linguri ulei de măsline","400 g suluguni sau mozzarella, ras grosier","200 g brânză feta, sfărâmată","4 ouă mari (câte 1 pentru fiecare khachapuri)","40 g unt nesărat, tăiat în 4 bucăți egale"]},"howIsMade":{"en":"Mix the flour, yeast, sugar, and salt in a large bowl, add the warm water and olive oil and stir to a rough dough, then knead on a lightly floured surface for 8-10 minutes until smooth and slightly tacky. Shape into a ball, place in an oiled bowl, cover with a damp cloth, and leave in a warm place for 1 hour until doubled in size. While the dough rises, mix the grated sulguni (or mozzarella) and crumbled feta together in a bowl; heat the oven to 250°C (230°C fan) with a heavy baking tray or pizza stone inside. Divide the risen dough into 4 equal pieces and roll each on a lightly floured surface into an oval about 25 x 15 cm. Fold the long edges inward by 3 cm and roll them up into a thick raised border, then pinch both short ends firmly together to form a boat shape. Arrange the boats on baking parchment, fill each cavity completely with a quarter of the cheese mixture, then slide onto the hot tray and bake for 12-14 minutes until the crust is golden and the cheese is bubbling and lightly browned. Remove from the oven, press a small hollow in the centre of each cheese filling, crack 1 egg into each hollow, and return to the oven for 3-4 minutes until the white is just set but the yolk remains runny. Place a piece of butter on top of each egg and serve immediately — tear strips of the border and dip into the melted cheese and yolk."}},{"id":64,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"South Africa","ro":"Africa de Sud"},"name":{"en":"Bobotie","ro":"Bobotie"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["750 g lean beef or lamb mince","2 medium onions (about 300 g total), finely diced","2 slices white bread (about 60 g), crusts removed","125 ml whole milk, divided","2 large eggs","50 g sultanas (golden raisins)","30 g dried apricots (about 6), finely chopped","2 tbsp apricot jam or sweet chutney","2 tbsp mild curry powder","1 tsp ground turmeric","2 tbsp vegetable oil","1 tsp fine sea salt","1/2 tsp ground black pepper","4 fresh or dried bay leaves"],"ro":["750 g carne tocată de vită sau miel, slabă","2 cepe medii (aproximativ 300 g), fin tocate","2 felii pâine albă (aproximativ 60 g), fără coajă","125 ml lapte integral, împărțit","2 ouă mari","50 g stafide galbene (sultane)","30 g caise uscate (aproximativ 6 bucăți), fin tocate","2 linguri gem de caise sau chutney dulce-picant","2 linguri pudră de curry blând","1 linguriță turmeric măcinat","2 linguri ulei vegetal","1 linguriță sare fină de mare","1/2 linguriță piper negru măcinat","4 foi de dafin proaspete sau uscate"]},"howIsMade":{"en":"Soak the bread in 60 ml of the milk for 5 minutes, then squeeze out the excess liquid and crumble into a small bowl. Heat the oil in a large frying pan over medium-high heat, add the onions and cook, stirring, for 8-10 minutes until soft and golden. Add the curry powder and turmeric and stir for 1 minute until fragrant, then add the mince and cook for 8-10 minutes, breaking up any lumps, until browned and all liquid has evaporated. Remove from the heat and mix in the soaked bread, sultanas, dried apricots, apricot jam, salt, and pepper until evenly combined. Heat the oven to 180°C (160°C fan) and lightly grease a medium baking dish (about 25 x 20 cm). Transfer the meat mixture into the dish, press it into an even layer, and tuck the bay leaves into the surface. Beat the eggs with the remaining 65 ml milk and a pinch of salt until smooth, then pour evenly over the meat. Bake for 35-40 minutes until the custard topping is set and golden brown with no wobble in the centre. Rest for 5 minutes before serving with yellow rice, chutney, and sambals."}},{"id":65,"servings":4,"tipType":"fish","pairingsType":"latin","origin":{"en":"Peru","ro":"Peru"},"name":{"en":"Ceviche","ro":"Ceviche"},"category":{"en":"Snack","ro":"Gustare"},"ingredients":{"en":["700 g very fresh white fish fillets (sea bass, sole, or halibut), skin and bones removed","180 ml fresh lime juice (about 8-10 limes), plus more to taste","1 small red onion (about 150 g), halved and thinly sliced into half-moons","1-2 ají amarillo chillies or 1 jalapeño, deseeded and finely diced","1 garlic clove, finely grated","1 tsp fresh ginger (about 1 cm piece), finely grated","30 g fresh coriander (cilantro), leaves and fine stems, roughly chopped","1 tsp fine sea salt","1/4 tsp ground white pepper","2 ears of corn, boiled and cut into 5 cm rounds","2 small sweet potatoes (about 400 g), boiled until tender, peeled and sliced"],"ro":["700 g file de pește alb foarte proaspăt (biban de mare, limbă sau halibut), fără piele și oase","180 ml suc proaspăt de lime (aproximativ 8-10 lime-uri), plus extra după gust","1 ceapă roșie mică (aproximativ 150 g), tăiată felii subțiri în jumătate de lună","1-2 ardei ají amarillo sau 1 jalapeño, fără semințe, fin tocați","1 căței de usturoi, fin ras","1 linguriță ghimbir proaspăt (aproximativ 1 cm), fin ras","30 g coriandru proaspăt, frunze și tulpini subțiri, grosier tocat","1 linguriță sare fină de mare","1/4 linguriță piper alb măcinat","2 știuleți de porumb, fierți și tăiați în rondele de 5 cm","2 cartofi dulci mici (aproximativ 400 g), fierți, curățați și feliați"]},"howIsMade":{"en":"Pat the fish dry with paper towels and cut into 2 cm cubes, removing any remaining pin bones, then place in a non-reactive bowl (glass or ceramic). Season with the salt and white pepper and toss to coat. Add the red onion, chilli, garlic, and ginger and mix gently. Pour over the lime juice — it should nearly cover the fish — then stir gently and press the fish down to submerge it as much as possible. Cover and refrigerate for 10-15 minutes, stirring once halfway through, until the outside of each cube is opaque and just firm to the touch while the very centre remains slightly translucent — the classic Peruvian style, not fully cooked through. Taste and adjust salt and lime juice. Stir in most of the coriander, reserving a little for garnish. Serve immediately in chilled bowls alongside the corn rounds and sweet potato slices, with the remaining coriander scattered over the top."}},{"id":66,"servings":8,"tipType":"korean","pairingsType":"korean","origin":{"en":"South Korea","ro":"Coreea de Sud"},"name":{"en":"Kimchi","ro":"Kimchi"},"category":{"en":"Side dish","ro":"Garnitură"},"ingredients":{"en":["1 large napa cabbage (about 2 kg)","3 tbsp sea salt (non-iodised)","4 tbsp gochugaru (Korean red pepper flakes)","5 cloves garlic, finely minced","1 tsp fresh ginger, grated","1 tbsp fish sauce (or soy sauce for vegan)","1 tsp sugar","6 spring onions, cut into 3cm pieces","1 medium carrot, julienned"],"ro":["1 varză napa mare (aprox. 2 kg)","3 linguri sare de mare (fără iod)","4 linguri gochugaru (fulgi de ardei coreean)","5 căței de usturoi, tocați mărunt","1 linguriță ghimbir proaspăt, ras","1 lingură sos de pește (sau sos de soia pentru variantă vegană)","1 linguriță zahăr","6 cepe verzi, tăiate în bucăți de 3 cm","1 morcov mediu, julien"]},"howIsMade":{"en":"Quarter the napa cabbage lengthwise, then cut crosswise into 5cm pieces. Toss with sea salt and massage 2–3 minutes, let sit 1–2 hours turning occasionally until the cabbage has wilted and released water. Rinse the cabbage thoroughly in cold water 2–3 times, drain and squeeze firmly to remove excess moisture; it should taste pleasantly salty — rinse once more if too salty. Mix gochugaru, garlic, ginger, fish sauce and sugar in a bowl; add spring onions and carrot. Add drained cabbage to the paste and mix thoroughly with your hands (wear gloves) — every piece should be evenly coated in red paste. Pack tightly into clean 1-litre jars, press down firmly to eliminate air pockets, leaving 3–4 cm of headspace; leave at room temperature for 1–2 days, then refrigerate — kimchi is ready in 3–5 days and best after 1 week."}},{"id":67,"servings":4,"tipType":"meat","timeMins":{"total":285,"active":60},"pairingsType":"vietnamese","origin":{"en":"Vietnam","ro":"Vietnam"},"name":{"en":"Banh Mi","ro":"Banh Mi"},"category":{"en":"Snack","ro":"Gustare"},"ingredients":{"en":["4 small baguettes or demi-baguettes (about 20 cm each), halved lengthwise","400 g pork tenderloin, thinly sliced (about 5 mm)","2 tbsp soy sauce","1 tbsp fish sauce","1 tsp sesame oil + 1 tsp sugar + 1/4 tsp black pepper (marinade)","2 medium carrots (about 200 g), peeled and julienned","100 g daikon, peeled and julienned (or extra carrot)","3 tbsp rice vinegar","1 tbsp sugar + 1/2 tsp fine salt (for pickling)","60 g chicken liver pâté","4 tbsp mayonnaise","1 large cucumber, cut into thin batons","2 jalapeños or red chillies, thinly sliced","20 g fresh coriander, sprigs"],"ro":["4 baghetele mici (de circa 20 cm), tăiate pe lungime","400 g mușchi de porc, tăiat felii subțiri (circa 5 mm)","2 linguri sos de soia","1 lingură sos de pește","1 linguriță ulei de susan + 1 linguriță zahăr + 1/4 linguriță piper negru (pentru marinadă)","2 morcovi medii (aproximativ 200 g), curățați și tăiați julienne","100 g daikon (ridiche asiatică), curățat și juliennat (sau morcov în plus)","3 linguri oțet de orez","1 lingură zahăr + 1/2 linguriță sare (pentru murat)","60 g pate de ficat de pui","4 linguri maioneză","1 castravete mare, tăiat bețe subțiri","2 jalapeño sau ardei roșii, tăiați rondele","20 g coriandru proaspăt, crenguțe"]},"howIsMade":{"en":"Combine the carrots and daikon with the rice vinegar, sugar, and salt, toss well, and leave to pickle for at least 20 minutes (or up to 4 hours in the fridge) until slightly softened but still crunchy. Mix the soy sauce, fish sauce, sesame oil, sugar, and black pepper in a bowl, add the sliced pork, and toss to coat; marinate for 15-20 minutes at room temperature. Heat a heavy frying pan or griddle over high heat until smoking, add the pork in a single layer in 2-3 batches, and cook for 1-2 minutes per side until caramelised and golden brown at the edges. Toast the baguettes in a 200°C oven for 4-5 minutes until the crust is crisp. Spread the cut sides generously with pâté and mayonnaise. Layer in the warm pork slices, the drained pickled carrots and daikon, cucumber batons, jalapeño slices, and generous sprigs of coriander. Press gently and serve immediately."}},{"id":68,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Indonesia","ro":"Indonezia"},"name":{"en":"Satay","ro":"Satay"},"category":{"en":"Snack","ro":"Gustare"},"ingredients":{"en":["700 g boneless skinless chicken thighs, cut into 2 cm cubes","3 tbsp soy sauce","2 tbsp coconut milk","1 tbsp light brown sugar","2 tsp ground coriander","1 tsp ground cumin","1 tsp ground turmeric","2 garlic cloves, finely grated","1 lemongrass stalk, pale part only, finely minced","200 g smooth peanut butter","200 ml coconut milk (for sauce)","2 tbsp kecap manis (sweet soy sauce)","1 tbsp lime juice","1 tsp sambal oelek or sriracha","20 bamboo skewers, soaked in cold water for 30 minutes"],"ro":["700 g pulpe de pui dezosate și fără piele, tăiate cubulețe de 2 cm","3 linguri sos de soia","2 linguri lapte de cocos","1 lingură zahăr brun pal","2 lingurițe coriandru măcinat","1 linguriță chimen măcinat","1 linguriță turmeric măcinat","2 căței de usturoi, fin rași","1 tulpină lemongrass, partea palidă, fin tocată","200 g unt de arahide cremos","200 ml lapte de cocos (pentru sos)","2 linguri kecap manis (sos de soia dulce)","1 lingură suc de lime","1 linguriță sambal oelek sau sriracha","20 bețișoare de bambus, înmuiate în apă rece 30 de minute"]},"howIsMade":{"en":"Mix the soy sauce, coconut milk, brown sugar, ground coriander, cumin, turmeric, garlic, and lemongrass in a bowl to make the marinade. Add the chicken cubes, toss to coat, and marinate for at least 30 minutes at room temperature or up to 4 hours in the refrigerator. Make the peanut sauce: combine the peanut butter, coconut milk, kecap manis, lime juice, and sambal in a small saucepan over low heat and stir for 3-4 minutes until smooth and silky; thin with a splash of water if too thick. Thread 4-5 chicken pieces onto each soaked skewer, pressing them close together. Heat a charcoal grill, cast-iron griddle, or grill pan over high heat and brush lightly with oil. Grill the skewers for 3-4 minutes per side, turning once, until deeply charred in spots and the chicken pulls away from the skewer easily — internal temperature should reach 75°C. Serve immediately with the warm peanut sauce for dipping and sliced cucumber alongside."}},{"id":69,"servings":4,"tipType":"def","pairingsType":"soup","origin":{"en":"Malaysia","ro":"Malaysia"},"name":{"en":"Laksa","ro":"Laksa"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["3 tbsp laksa paste (or red curry paste with 1 tsp shrimp paste added)","2 tbsp vegetable oil","800 ml coconut milk (2 x 400 ml cans)","600 ml chicken stock or water","2 tbsp fish sauce","1 tsp sugar","400 g raw medium prawns, peeled and deveined","200 g firm tofu, drained and cut into 2 cm cubes","200 g fresh bean sprouts","200 g rice vermicelli noodles, soaked in boiling water 3 minutes and drained","4 large eggs, hard-boiled (7 minutes), peeled and halved","100 g green beans, trimmed and halved","2 limes, cut into wedges","20 g fresh coriander, leaves only","2 spring onions, thinly sliced"],"ro":["3 linguri pastă laksa (sau pastă de curry roșu cu 1 linguriță pastă de creveți)","2 linguri ulei vegetal","800 ml lapte de cocos (2 conserve de 400 ml)","600 ml supă de pui sau apă","2 linguri sos de pește","1 linguriță zahăr","400 g creveți cruzi medii, curățați și devenați","200 g tofu ferm, scurs și tăiat cuburi de 2 cm","200 g muguri de soia proaspeți","200 g vermicelli de orez, înmuiați în apă clocotită 3 minute și scurși","4 ouă mari, fierte tari (7 minute), decojite și tăiate jumătate","100 g fasole verde, curățată și tăiată în jumătăți","2 lime, tăiate felii","20 g coriandru proaspăt, frunze","2 cepe verzi, feliate subțire"]},"howIsMade":{"en":"Soak the rice vermicelli in boiling water for 3 minutes, drain, rinse under cold water, and set aside. Hard-boil the eggs for 7 minutes, cool in iced water, peel, and halve. Heat the oil in a large wok or saucepan over medium heat, add the laksa paste, and fry, stirring constantly, for 2-3 minutes until fragrant and the oil begins to separate. Pour in the coconut milk and chicken stock and bring to a steady simmer. Add the fish sauce and sugar, taste, and adjust — the broth should be rich and slightly salty. Add the green beans and cook for 3 minutes, then add the prawns and tofu and cook for 2-3 minutes until the prawns are pink and just cooked through. Divide the noodles between 4 deep bowls and ladle the hot broth with prawns, tofu, and beans on top. Finish each bowl with bean sprouts, 2 halved eggs, spring onions, and coriander. Serve immediately with lime wedges on the side."}},{"id":70,"servings":4,"tipType":"def","pairingsType":"mexican","origin":{"en":"El Salvador","ro":"El Salvador"},"name":{"en":"Pupusa","ro":"Pupusa"},"category":{"en":"Snack","ro":"Gustare"},"ingredients":{"en":["400 g masa harina (nixtamalized corn flour, such as Maseca), plus extra","350 ml warm water (about 40°C), plus more if needed","1 tsp fine sea salt","200 g canned refried black or pinto beans, warmed","200 g queso quesillo or mozzarella, coarsely grated","2 tbsp vegetable oil (for cooking)","300 g white cabbage (about 1/4 head), very finely shredded","1 small carrot (about 80 g), peeled and coarsely grated","1/2 small white onion (about 60 g), thinly sliced","100 ml apple cider vinegar or white vinegar","100 ml water (for curtido)","1 tsp fine salt + 1 tsp sugar (for curtido)","1/2 tsp dried oregano","200 ml tomato salsa, to serve"],"ro":["400 g masa harina (făină de porumb nixtamalizată, ex. Maseca), plus extra","350 ml apă caldă (circa 40°C), plus dacă e nevoie","1 linguriță sare fină de mare","200 g fasole neagră sau pinto refulată (din conservă, încălzită)","200 g queso quesillo sau mozzarella, ras grosier","2 linguri ulei vegetal (pentru prăjit)","300 g varză albă (aprox. 1/4 căpățână), fin feliată","1 morcov mic (aprox. 80 g), curățat și ras","1/2 ceapă albă mică (aprox. 60 g), felii subțiri","100 ml oțet de mere sau oțet alb","100 ml apă (pentru curtido)","1 linguriță sare fină + 1 linguriță zahăr (pentru curtido)","1/2 linguriță oregano uscat","200 ml salsa de roșii pentru servit"]},"howIsMade":{"en":"Make the curtido first: combine the cabbage, carrot, and onion in a bowl, mix the vinegar, water, salt, sugar, and oregano, pour over the vegetables, toss well, and set aside to pickle for at least 30 minutes (or overnight in the fridge). Make the dough: combine the masa harina and salt in a large bowl, pour in the warm water gradually, and mix with your hands until a smooth, pliable dough forms — it should hold together without cracking; add a tablespoon of water at a time if needed. Mix the refried beans and grated cheese together to make the filling. Divide the dough into 8 equal balls (about 90 g each). Press a ball flat in your damp palm into a disc about 12 cm across, place 2 heaped tablespoons of filling in the centre, then fold the edges up over the filling and pinch firmly to seal; gently re-flatten into a disc about 1 cm thick and 12 cm wide, patching any cracks. Heat a heavy griddle or cast-iron skillet over medium-high heat and brush with oil. Cook the pupusas in batches for 3-4 minutes per side until dark golden-brown patches appear and the dough feels dry rather than tacky. Serve hot with the curtido piled on top and salsa alongside."}},{"id":72,"servings":4,"tipType":"fish","pairingsType":"vietnamese","origin":{"en":"Cambodia","ro":"Cambodgia"},"name":{"en":"Amok","ro":"Amok"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["600 g white fish fillets (tilapia, snapper, or catfish), skin removed, cut into 3 cm pieces","400 ml coconut milk (1 x 400 ml can)","2 large eggs, lightly beaten","3 tbsp fish sauce","1 tsp caster sugar","2 lemongrass stalks, pale parts only, very finely minced","3 garlic cloves, finely minced","3 shallots (about 100 g), finely minced","1 tsp galangal paste (or 1 cm fresh galangal, grated)","1/2 tsp ground turmeric","1/2 tsp dried chilli flakes or 1 fresh red chilli, finely sliced","4 kaffir lime leaves, stems removed, very finely shredded","4 large banana leaf squares (30 x 30 cm), softened over a flame, or 4 ramekins","20 g fresh basil or Thai basil leaves, to garnish"],"ro":["600 g file de pește alb (tilapia, biban sau somn), fără piele, tăiat bucăți de 3 cm","400 ml lapte de cocos (1 conservă de 400 ml)","2 ouă mari, ușor bătute","3 linguri sos de pește","1 linguriță zahăr","2 tulpini lemongrass, doar partea palidă, fin tocate","3 căței de usturoi, fin tocați","3 șalote (aproximativ 100 g), fin tocate","1 linguriță pastă de galangal (sau 1 cm galangal proaspăt, ras)","1/2 linguriță turmeric măcinat","1/2 linguriță fulgi de ardei iute uscat sau 1 ardei roșu, fin tocat","4 frunze de kaffir lime, cotoare îndepărtate, fin feliate","4 pătrate mari de frunze de bananier (30 x 30 cm), înmuiate, sau ramekine","20 g frunze de busuioc proaspăt sau busuioc thai, pentru garnitură"]},"howIsMade":{"en":"Pound or blend the lemongrass, garlic, shallots, galangal, turmeric, and chilli into a smooth paste. In a large bowl, whisk together the coconut milk, beaten eggs, fish sauce, and sugar until combined. Stir in the spice paste and half the shredded kaffir lime leaves. Add the fish pieces and fold gently to coat; marinate for 15 minutes. Soften the banana leaf squares over a gas flame or in hot water for 30 seconds until pliable. Fold each into a cup shape about 12 cm across and 4 cm deep, securing with a toothpick. Divide the fish mixture evenly among the 4 banana leaf cups, filling each about two-thirds full, then scatter the remaining kaffir lime leaves on top. Set the cups in a bamboo steamer over boiling water, cover tightly, and steam for 18-20 minutes until the amok is just set — no longer liquid when the cup is gently tilted — and the top is slightly firm to the touch. Garnish with fresh basil leaves and serve immediately with steamed jasmine rice."}},{"id":73,"servings":4,"tipType":"meat","pairingsType":"indian","origin":{"en":"Nepal","ro":"Nepal"},"name":{"en":"Momo","ro":"Momo"},"category":{"en":"Snack","ro":"Gustare"},"ingredients":{"en":["300 g plain flour (all-purpose), plus extra for dusting","150 ml warm water","500 g ground chicken or pork","1 medium onion (about 120 g), very finely diced","3 garlic cloves, finely minced","1 tbsp fresh ginger (about 2 cm piece), finely grated","30 g fresh coriander (cilantro), finely chopped","1 tsp ground cumin","1/2 tsp ground coriander","1/4 tsp ground turmeric","1 tsp fine sea salt, divided","4 medium tomatoes (about 400 g), halved","2 dried red chillies or 1/2 tsp chilli flakes","1 tbsp vegetable oil"],"ro":["300 g făină albă (tip 550), plus extra pentru pudrat","150 ml apă caldă","500 g carne tocată de pui sau porc","1 ceapă medie (circa 120 g), tocată mărunt","3 căței de usturoi, tocați mărunt","1 lingură ghimbir proaspăt (circa 2 cm), ras fin","30 g coriandru proaspăt, tocat mărunt","1 linguriță chimen măcinat","1/2 linguriță coriandru măcinat","1/4 linguriță turmeric","1 linguriță sare fină, împărțită","4 roșii medii (circa 400 g), tăiate în jumătăți","2 ardei iuți uscați sau 1/2 linguriță fulgi de ardei iute","1 lingură ulei vegetal"]},"howIsMade":{"en":"Combine flour and 1/2 tsp of the salt in a bowl, then add warm water a little at a time, mixing until a rough dough forms; knead for 5-6 minutes until smooth, firm, and no longer sticky, then cover with a damp cloth and rest for 30 minutes. In a separate bowl, mix the ground meat, onion, garlic, ginger, coriander leaves, cumin, ground coriander, turmeric, the remaining 1/2 tsp salt, and oil until well combined; refrigerate for 15 minutes to let the flavours meld. Meanwhile, make the dipping sauce: char the tomato halves and dried chillies in a dry heavy skillet over high heat for 4-5 minutes until softened and blackened in spots, then blend with the garlic and remaining salt until smooth. Divide the rested dough into 24 equal pieces (about 15 g each) and roll each into a thin round about 8 cm across. Place a heaped teaspoon of filling in the centre of each round, then gather the edges and pleat them together with small overlapping folds, pinching firmly at the top to seal. Line a bamboo or metal steamer with lightly oiled parchment paper and arrange the momo at least 1 cm apart. Set over a pot of vigorously boiling water, cover tightly, and steam for 12-15 minutes until the wrappers turn translucent and a gently pressed momo springs back without feeling doughy inside. Serve immediately with the tomato-chilli sauce."}},{"id":74,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"en":"Ecuador","ro":"Ecuador"},"name":{"en":"Encebollado","ro":"Encebollado"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["700 g fresh tuna or 2 cans tuna in water (400 g total), drained","600 g cassava (yuca), peeled and cut into 4 cm chunks","1 large red onion (about 200 g), thinly sliced into half-moons","4 medium tomatoes (about 400 g), roughly chopped","4 garlic cloves, roughly chopped","1 tsp ground cumin","1 tsp achiote paste or 1/2 tsp sweet paprika","1.5 litres fish stock or water","3 tbsp fresh lime juice (about 2 limes)","2 tbsp vegetable oil","1 tsp fine sea salt","30 g fresh coriander (cilantro), divided — half to cook, half to garnish","1 jalapeño or aji pepper, deseeded and finely sliced","2 spring onions, thinly sliced (to garnish)"],"ro":["700 g ton proaspăt sau 2 conserve ton în apă (400 g total), scurse","600 g yuca (manioc), curățată și tăiată bucăți de 4 cm","1 ceapă roșie mare (circa 200 g), tăiată în felii subțiri","4 roșii medii (circa 400 g), tăiate grosier","4 căței de usturoi, tăiați grosier","1 linguriță chimen măcinat","1 linguriță pastă de achiote sau 1/2 linguriță paprika dulce","1,5 litri supă de pește sau apă","3 linguri zeamă de lămâie verde (circa 2 lămâi)","2 linguri ulei vegetal","1 linguriță sare fină","30 g coriandru proaspăt, împărțit — jumătate pentru gătit, jumătate pentru servit","1 jalapeno sau ardei iute, fără semințe, feliat subțire","2 fire ceapă verde, tăiate subțire (pentru decor)"]},"howIsMade":{"en":"Heat the oil in a large pot over medium heat, add the onion, garlic, tomatoes, jalapeño, and cumin, and cook for 8-10 minutes, stirring occasionally, until the onion is very soft and the tomatoes have broken down into a thick paste. Stir in the achiote paste and cook for 1 minute until the oil turns a deep orange. Pour in the stock, bring to a boil, then add the cassava and cook for 20-25 minutes until completely tender and just beginning to break apart at the edges. If using fresh tuna, poach the steaks in lightly salted simmering water for 5-6 minutes until just cooked through, cool slightly, and flake into large chunks. Add the flaked tuna (or drained canned tuna), half the coriander, and the lime juice to the pot; simmer for 3-4 minutes to marry the flavours. Season with salt to taste, then ladle the soup into deep bowls. Top with the remaining coriander and spring onions, and serve with tostadas or plantain chips on the side."}},{"id":75,"servings":4,"tipType":"soup","pairingsType":"middle-eastern","origin":{"en":"Morocco","ro":"Maroc"},"name":{"en":"Harira","ro":"Harira"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["400 g lamb shoulder, cut into 3 cm chunks","400 g canned chickpeas (1 x 400 g can), rinsed and drained","150 g green or brown lentils, rinsed","4 medium tomatoes (about 400 g), roughly chopped","1 large onion (about 200 g), finely diced","3 celery stalks with leaves (about 150 g), finely sliced","3 garlic cloves, finely minced","1 tsp ground cumin","1 tsp ground cinnamon + 1 tsp ground ginger","1/2 tsp ground turmeric + 1 tsp fine sea salt","2 tbsp olive oil","1.5 litres water or lamb stock","60 g thin vermicelli, broken into 2 cm pieces","30 g fresh coriander and flat-leaf parsley, roughly chopped"],"ro":["400 g spata de miel, taiata bucati de 3 cm","400 g naut fiert (1 cutie 400 g), scurs si clatit","150 g linte verde sau bruna, clatita","4 rosii medii (circa 400 g), taiate grosier","1 ceapa mare (circa 200 g), tocata marunt","3 tulpini de telina cu frunze (circa 150 g), feliate subtire","3 căței de usturoi, tocati marunt","1 lingurita chimen macinat","1 lingurita scortisoara + 1 lingurita ghimbir macinat","1/2 lingurita turmeric + 1 lingurita sare fina","2 linguri ulei de masline","1,5 litri apa sau supa de miel","60 g vermicelli subtire, rupt in bucati de 2 cm","30 g coriandru proaspat si patrunjel plat, tocat grosier"]},"howIsMade":{"en":"Heat the oil in a large pot over medium-high heat, add the lamb chunks and sear for 4-5 minutes, turning occasionally, until browned on all sides. Add the onion, celery, and garlic and cook for 5 minutes until softened. Stir in the cumin, cinnamon, ginger, turmeric, and salt and cook for 1 minute until fragrant. Add the tomatoes, chickpeas, and lentils, pour in the water or stock, and bring to a boil; skim any foam from the surface. Reduce the heat to low, cover partially, and simmer for 45-50 minutes until the lamb is tender and the lentils have dissolved into the broth, thickening it slightly. Stir in the vermicelli and cook for 5-6 minutes until tender. Remove from the heat, stir in the coriander and parsley, and squeeze in lemon juice to taste. Ladle into bowls and serve immediately with crusty bread and dates."}},{"id":76,"servings":4,"tipType":"veg","pairingsType":"veg","origin":{"en":"Georgia","ro":"Georgia"},"name":{"en":"Lobio","ro":"Lobio"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["500 g dried red kidney beans (or 2 x 400 g cans, rinsed)","1 large onion (about 200 g), finely diced","4 garlic cloves, finely minced","100 g walnut halves, finely ground or very finely chopped","1 tsp ground coriander","1/2 tsp ground fenugreek (utsho suneli)","1/2 tsp ground cinnamon","1/2 tsp dried chilli flakes or 1 small red chilli, deseeded and minced","2 tbsp white wine vinegar or red wine vinegar","3 tbsp vegetable oil","1 tsp fine sea salt","30 g fresh coriander (cilantro), finely chopped","4 tbsp pomegranate seeds (about 1/2 pomegranate)","4 spring onions, thinly sliced"],"ro":["500 g fasole rosie uscata (sau 2 x 400 g conserve, clatite)","1 ceapa mare (circa 200 g), tocata marunt","4 căței de usturoi, tocati marunt","100 g miez de nuca, macinat fin sau tocat marunt","1 lingurita coriandru macinat","1/2 lingurita schinduf macinat (utsho suneli)","1/2 lingurita scortisoara","1/2 lingurita fulgi de ardei iute sau 1 ardei iute mic, fara seminte, tocat","2 linguri otet alb sau de vin rosu","3 linguri ulei vegetal","1 lingurita sare fina","30 g coriandru proaspat, tocat marunt","4 linguri boabe de rodie (circa 1/2 rodie)","4 fire ceapa verde, taiate subtire"]},"howIsMade":{"en":"If using dried beans, soak them overnight in cold water, then drain, cover with fresh cold water in a large pot, bring to a boil, skim any foam, and simmer for 45-60 minutes until completely tender and starting to break apart, with a thick dark-red cooking liquid. Heat the oil in a frying pan over medium heat, add the onion and cook for 10-12 minutes, stirring occasionally, until deep golden and very soft. Add the garlic, ground coriander, fenugreek, cinnamon, and chilli and cook for 2 minutes until fragrant. Stir the onion mixture, ground walnuts, and vinegar into the cooked beans and simmer over low heat for 10 minutes, stirring occasionally, until the flavours meld and the beans are very soft with a thick sauce — mash a few beans against the side of the pot to help thicken. Season with salt and more vinegar to taste. Remove from the heat and stir in half the fresh coriander. Transfer to a shallow dish and top with the spring onions, pomegranate seeds, and remaining coriander. Serve warm with flatbread."}},{"id":77,"servings":4,"tipType":"meat","pairingsType":"middle-eastern","origin":{"en":"Algeria","ro":"Algeria"},"name":{"en":"Chakhchoukha","ro":"Chakhchoukha"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["600 g bone-in lamb shoulder or neck, cut into 4 cm pieces","400 g canned chickpeas (1 x 400 g can), rinsed and drained","4 medium tomatoes (about 400 g), roughly chopped","2 medium onions (about 300 g), finely diced","4 garlic cloves, finely minced","2 tbsp vegetable oil","1 tsp ground cumin","1 tsp ground coriander","1 tsp sweet paprika","1/2 tsp ground cinnamon + 1/2 tsp ground black pepper","1 tsp fine sea salt","600 ml water or lamb stock","4 large sheets of rougag (Algerian flatbread) or large tortillas, torn into 5 cm pieces","30 g fresh coriander and flat-leaf parsley, roughly chopped (to garnish)"],"ro":["600 g spata de miel cu os sau gat, taiata bucati de 4 cm","400 g naut fiert (1 cutie 400 g), scurs si clatit","4 rosii medii (circa 400 g), taiate grosier","2 cepe medii (circa 300 g), tocate marunt","4 căței de usturoi, tocati marunt","2 linguri ulei vegetal","1 lingurita chimen macinat","1 lingurita coriandru macinat","1 lingurita boia dulce","1/2 lingurita scortisoara + 1/2 lingurita piper negru","1 lingurita sare fina","600 ml apa sau supa de miel","4 foi mari de rougag (lipie algeriana) sau 4 tortilla mari, rupte bucati de 5 cm","30 g coriandru proaspat si patrunjel plat, tocat grosier (pentru decor)"]},"howIsMade":{"en":"Heat the oil in a large heavy pot over medium-high heat, add the lamb in batches and sear for 4-5 minutes until browned on all sides. Add the onion and garlic and cook for 5 minutes until softened and golden. Stir in the cumin, coriander, paprika, cinnamon, salt, and pepper and cook for 1 minute until the spices smell toasted. Add the tomatoes and cook for 8-10 minutes, stirring occasionally, until they break down into a thick sauce. Pour in the water or stock, add the chickpeas, and bring to a boil; reduce the heat to low, cover, and simmer for 50-60 minutes until the lamb is completely tender and falling off the bone. Scatter the torn flatbread pieces over the bottom of a large serving dish and ladle the hot meat and sauce generously on top, pressing the bread down gently so it absorbs the liquid and softens — it should be soaked through but not dissolving. Garnish with the fresh coriander and parsley and serve immediately."}},{"id":78,"servings":4,"tipType":"meat","timeMins":{"total":330,"active":60},"pairingsType":"meat","origin":{"en":"Indonesia","ro":"Indonezia"},"name":{"en":"Rendang","ro":"Rendang"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["1 kg beef chuck or brisket, cut into 5 cm cubes","800 ml full-fat coconut milk (2 x 400 ml cans)","5 shallots (about 150 g), roughly chopped","4 garlic cloves, roughly chopped","2 tbsp fresh ginger (about 3 cm piece), roughly chopped","1 tbsp fresh galangal (about 2 cm) or 1 tsp galangal paste","3 lemongrass stalks, pale parts only, roughly sliced","4-6 dried red chillies, soaked in warm water 15 minutes and drained","4 kaffir lime leaves, stems removed, very finely shredded","1 tsp ground turmeric","1 tsp ground coriander","1 tsp ground cumin","1 tsp fine sea salt","1 tbsp vegetable oil"],"ro":["1 kg muschi de vita sau piept, taiat cuburi de 5 cm","800 ml lapte de cocos integral (2 x 400 ml)","5 esalote (circa 150 g), taiate grosier","4 căței de usturoi, tăiați grosier","2 linguri ghimbir proaspat (circa 3 cm), taiat grosier","1 lingura galangal proaspat (circa 2 cm) sau 1 lingurita pasta galangal","3 tulpini de lemongrass, partile palide, feliate grosier","4-6 ardei iuti rosii uscati, înmuiați in apa calda 15 minute, scursi","4 frunze de kafir lime, coada indepartata, maruntite fin","1 lingurita turmeric macinat","1 lingurita coriandru macinat","1 lingurita chimen macinat","1 lingurita sare fina","1 lingura ulei vegetal"]},"howIsMade":{"en":"Blend the shallots, garlic, ginger, galangal, lemongrass, and soaked chillies with 2 tbsp of the coconut milk until completely smooth — about 2 minutes in a food processor. Heat the oil in a large heavy pot over medium heat, add the spice paste and cook for 5-6 minutes, stirring constantly, until deep golden and the raw smell has gone. Add the beef cubes and stir to coat with the paste; cook for 3-4 minutes until lightly coloured. Pour in the remaining coconut milk, add the kaffir lime leaves, turmeric, coriander, cumin, and salt, and stir to combine. Bring to a boil, then reduce to medium-low and simmer uncovered for 1.5 hours, stirring every 15-20 minutes, until the coconut milk thickens significantly and turns light brown. Continue cooking, stirring more frequently (every 5-10 minutes), for another 30-45 minutes as the sauce reduces to almost nothing and the oil splits from the coconut; the beef will begin to fry in its own fat and turn deep mahogany brown — this is when rendang is ready. Serve with steamed white rice."}},{"id":79,"servings":4,"tipType":"fish","timeMins":{"total":4380,"active":45},"pairingsType":"fish","origin":{"en":"Sweden","ro":"Suedia"},"name":{"en":"Gravlax","ro":"Gravlax"},"category":{"en":"Snack","ro":"Gustare"},"ingredients":{"en":["600 g salmon fillet, skin-on and pin-boned","3 tbsp coarse sea salt","2 tbsp caster sugar","1 tsp white peppercorns, coarsely crushed","60 g fresh dill (1 large bunch), roughly chopped","2 tbsp aquavit or vodka (optional)"],"ro":["600 g file de somon cu piele, cu oasele îndepărtate","3 linguri sare grunjoasă de mare","2 linguri zahăr tos","1 linguriță boabe de piper alb, zdrobite grosier","60 g mărar proaspăt (1 legătură mare), tocat grosier","2 linguri aquavit sau vodcă (opțional)"]},"howIsMade":{"en":"Mix the coarse salt, sugar, and crushed peppercorns in a small bowl. Lay the salmon skin-side down on a large piece of cling film; press half the dill evenly over the flesh, spread the cure uniformly over the top, drizzle with aquavit if using, then cover with the remaining dill. Wrap tightly in the cling film and place in a deep dish, setting a heavy plate on top to press the fish. Refrigerate for 48-72 hours, turning the parcel every 12 hours as it cures — brine will pool in the dish. Unwrap, rinse under cold water, and pat dry with paper towels. Slice very thinly on the diagonal with a sharp flexible knife and serve on dark rye bread with a mustard-dill sauce."}},{"id":80,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Belgium","ro":"Belgia"},"name":{"en":"Stoofvlees","ro":"Stoofvlees"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["1 kg beef stew meat (chuck or brisket), cut into 4 cm cubes","330 ml dark Belgian ale (Leffe Brune or similar)","500 g onions (about 3 medium), thinly sliced","2 tbsp Dijon mustard","2 thick slices (about 80 g) stale brown bread, crusts removed","2 tbsp neutral oil","2 bay leaves","3 fresh thyme sprigs","1 tbsp brown sugar","1 tbsp red wine vinegar","1 tsp fine salt","1/2 tsp ground black pepper"],"ro":["1 kg carne de vită pentru tocăniță (capac sau piept), tăiată cuburi de 4 cm","330 ml bere belgiană brună (Leffe Brune sau similară)","500 g ceapă (circa 3 medii), feliată subțire","2 linguri muștar Dijon","2 felii groase (circa 80 g) pâine brună veche, fără coajă","2 linguri ulei neutru","2 foi de dafin","3 crenguțe de cimbru proaspăt","1 lingură zahăr brun","1 lingură oțet de vin roșu","1 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"en":"Season the beef with salt and pepper. Heat the oil in a large heavy casserole over medium-high and brown the beef in batches for 3-4 minutes per side until deeply golden; transfer to a plate. Reduce heat to medium, add the onions to the same pot and cook for 12-15 minutes, stirring occasionally, until soft and golden. Return the beef to the pot, tuck in the bay leaves and thyme, and pour in the beer — it should nearly cover the meat. Spread one side of each bread slice thickly with mustard and lay them mustard-side down on top of the stew; the bread will dissolve and thicken the sauce. Stir in the brown sugar and vinegar, bring to a gentle simmer, cover with the lid slightly ajar, and cook over low heat for 2 hours, stirring every 30 minutes, until the beef is very tender. Remove the lid for the final 20-30 minutes to reduce the sauce to a glossy dark gravy that coats the back of a spoon; discard the bay leaves and thyme and serve with frites or mashed potato."}},{"id":81,"servings":4,"tipType":"soup","pairingsType":"soup","origin":{"en":"Moldova","ro":"Moldova"},"name":{"en":"Zeama","ro":"Zeamă"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["1 kg bone-in chicken pieces (legs and thighs)","2 medium carrots (about 200 g), peeled and halved","1 medium onion, halved","2 celery stalks with leaves","150 g thin egg noodles","200 ml borș (fermented wheat bran liquid) or 4 tbsp fresh lemon juice","1 small bunch fresh lovage (about 15 g), roughly chopped, or flat-leaf parsley","1 tsp fine salt","1/2 tsp white pepper"],"ro":["1 kg bucăți de pui cu os (pulpe și coapse)","2 morcovi medii (circa 200 g), curățați și tăiați în jumătate","1 ceapă medie, tăiată în jumătate","2 tulpini de țelină cu frunze","150 g tăiței subțiri de ou","200 ml borș sau 4 linguri suc proaspăt de lămâie","1 legătură mică leuștean proaspăt (circa 15 g), tocat grosier, sau pătrunjel","1 linguriță sare fină","1/2 linguriță piper alb"]},"howIsMade":{"en":"Place the chicken in a large pot, cover with 2 litres of cold water, and bring to a boil over medium-high heat; skim the foam that rises for the first 5-10 minutes until the broth runs clear. Add the carrots, onion, and celery, reduce heat to medium-low, partially cover, and simmer for 45-50 minutes until the chicken is cooked through and falling from the bone. Lift out the chicken and vegetables; discard the onion, slice the carrots into rounds, and shred the chicken into bite-sized pieces, discarding skin and bones. Return the shredded chicken and carrot rounds to the pot and bring back to a simmer over medium heat. Add the noodles and cook for 5-7 minutes (or per packet) until just tender. Pour in the borș or lemon juice, stir, and taste — the soup should have a pleasant sour edge; add more as needed. Season with salt and white pepper, stir in the lovage or parsley, and serve immediately."}},{"id":82,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Australia","ro":"Australia"},"name":{"en":"Meat Pie","ro":"Meat Pie"},"category":{"en":"Snack","ro":"Gustare"},"ingredients":{"en":["375 g ready-made shortcrust pastry","250 g ready-made puff pastry","500 g lean beef mince","1 medium onion (about 150 g), finely diced","2 garlic cloves, minced","250 ml beef stock","2 tbsp tomato paste","1 tbsp Worcestershire sauce","2 tbsp plain flour","1 egg, lightly beaten, for brushing","1 tsp fine salt","1/2 tsp ground black pepper"],"ro":["375 g aluat fraged gata preparat","250 g aluat foietaj gata preparat","500 g carne de vită tocată (slabă)","1 ceapă medie (circa 150 g), tăiată mărunt","2 căței de usturoi, pisați","250 ml supă de vită","2 linguri pastă de roșii","1 lingură sos Worcestershire","2 linguri făină albă","1 ou, bătut ușor, pentru uns","1 linguriță sare fină","1/2 linguriță piper negru măcinat"]},"howIsMade":{"en":"Preheat the oven to 200°C (180°C fan). Heat a drizzle of oil in a large frying pan over medium-high heat, add the onion and garlic and cook for 3-4 minutes until softened. Add the beef mince and cook, breaking it up with a spoon, for 6-8 minutes until browned all over. Stir in the flour, cook for 1 minute, then add the stock, tomato paste, Worcestershire sauce, salt, and pepper; stir to combine. Simmer over medium heat for 12-15 minutes, stirring occasionally, until the gravy thickens to coat the back of a spoon — the filling should be moist but not runny; remove from heat and cool for 15 minutes. Roll out the shortcrust pastry and cut 4 circles to line 4 individual pie tins (about 12 cm diameter); press into the tins and prick the bases with a fork. Divide the filling evenly between the tins, top with puff pastry lids, press the edges to seal, and brush with beaten egg. Bake for 25-30 minutes until deep golden and the lids are puffed and crisp; rest for 5 minutes then serve with tomato sauce."}},{"id":83,"servings":4,"tipType":"def","pairingsType":"middle-eastern","origin":{"en":"Syria","ro":"Siria"},"name":{"en":"Fatteh","ro":"Fatteh"},"category":{"en":"Breakfast","ro":"Mic dejun"},"ingredients":{"en":["2 large pita breads (about 200 g), torn into bite-sized pieces","400 g canned chickpeas (1 x 400 g can), drained and rinsed","500 g full-fat plain yogurt","3 garlic cloves, minced","2 tbsp tahini","2 tbsp fresh lemon juice","3 tbsp unsalted butter","50 g pine nuts","1 tsp ground cumin","1 tsp sweet paprika","1/2 tsp fine salt","2 tbsp fresh parsley, finely chopped"],"ro":["2 pâini pita mari (circa 200 g), rupte în bucăți","400 g năut din conservă (1 x 400 g), scurs și clătit","500 g iaurt integral simplu","3 căței de usturoi, pisați","2 linguri tahini","2 linguri suc proaspăt de lămâie","3 linguri unt nesărat","50 g semințe de pin","1 linguriță chimion măcinat","1 linguriță boia dulce","1/2 linguriță sare fină","2 linguri pătrunjel proaspăt, tocat fin"]},"howIsMade":{"en":"Preheat the oven to 200°C. Toss the pita pieces with a drizzle of oil, spread on a baking tray and bake for 8-10 minutes until golden and crisp. Drain the chickpeas; heat in a small saucepan with a pinch of salt and cumin over medium heat for 3-4 minutes until warmed through. Whisk the yogurt, garlic, tahini, lemon juice, and salt until smooth; taste and adjust seasoning. Spread the toasted pita pieces in an even layer on a large serving platter. Spoon the warm chickpeas evenly over the pita. Pour the yogurt sauce over the chickpeas, covering everything generously. Melt the butter in a small pan over medium heat; add the pine nuts and cook for 2-3 minutes, stirring, until golden; stir in the paprika and immediately drizzle the hot butter and pine nuts over the yogurt. Scatter the chopped parsley on top and serve immediately before the pita softens."}},{"id":84,"servings":4,"tipType":"def","pairingsType":"def","origin":{"en":"Denmark","ro":"Danemarca"},"name":{"en":"Smørrebrød","ro":"Smørrebrød"},"category":{"en":"Breakfast","ro":"Mic dejun"},"ingredients":{"en":["8 slices dark rye bread (rugbrød), about 400 g","100 g unsalted butter, softened","400 g pickled herring fillets (8 fillets), drained","4 eggs, hard-boiled (10 minutes), peeled and sliced into rounds","1 small red onion (about 80 g), very finely sliced into rings","4 radishes, thinly sliced into rounds","2 tbsp capers, drained","4 tbsp soured cream or crème fraîche","1 tsp Dijon mustard","1 small bunch fresh dill (about 15 g)","1/2 tsp fine salt"],"ro":["8 felii de pâine daneză de secară (rugbrød), circa 400 g","100 g unt nesărat, înmuiat","400 g hering murat (8 fileuri), scurs","4 ouă fierte tari (10 minute), decojite și feliate în rondele","1 ceapă roșie mică (circa 80 g), feliată subțire în inele","4 ridichi, feliate subțire în rondele","2 linguri capere, scurse","4 linguri smântână sau crème fraîche","1 linguriță muștar Dijon","1 legătură mică de mărar proaspăt (circa 15 g)","1/2 linguriță sare fină"]},"howIsMade":{"en":"Hard-boil the eggs: lower into boiling water and cook for 10 minutes, then transfer to cold water for 5 minutes before peeling and slicing into rounds. Mix the soured cream with the Dijon mustard and a pinch of salt in a small bowl. Spread each slice of rye bread generously with softened butter right to the edges — about 1 tablespoon per slice. Lay 1-2 pickled herring fillets on each buttered slice, letting them curve naturally over the surface. Spoon a small dollop of mustard cream onto the herring, then arrange 2-3 egg rounds alongside. Scatter red onion rings, radish slices, and capers over the top. Finish with fresh dill sprigs and serve immediately with a cold beer or aquavit."}},{"id":85,"origin":{"en":"North Korea","ro":"Coreea de Nord"},"name":{"en":"Naengmyeon","ro":"Naengmyeon"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","timeMins":{"total":600,"active":60},"pairingsType":"korean","ingredients":{"en":["400g dried buckwheat noodles (memil-guksu)","300g beef brisket, simmered until tender, chilled, thinly sliced","1.5L beef brisket broth, fully chilled and defatted","1 Korean pear (nashi), peeled, thinly sliced","1 medium cucumber, julienned","4 hard-boiled eggs, halved","2 tbsp rice vinegar","1 tsp Korean mustard (gyeoja) or English mustard","1 tbsp gochugaru (optional, as table condiment)","salt and sugar to taste for the broth","ice cubes as needed"],"ro":["400g tăiței de hrișcă uscați (memil-guksu)","300g piept de vită, fiert și refrigerat, feliat subțire","1.5L supă de piept de vită (răcită complet la frigider, degresată)","1 pară coreeană (nashi), curățată, feliată subțire","1 castravete mediu, feliat julien","4 ouă fierte tari, înjumătățite","2 linguri oțet de orez","1 linguriță muștar coreean (gyeoja) sau muștar englez","1 lingură gochugaru (opțional, pentru condiment la masă)","sare și zahăr după gust pentru supa de bază","cuburi de gheață — câte este necesar"]},"howIsMade":{"en":"Day before: simmer beef brisket in 2L water with 1 tsp salt, a 2 cm piece of ginger, and 3 spring onions over low heat for 1.5–2 hours. Let meat cool in the broth, then refrigerate overnight. Next day, lift off the solidified fat layer. Season the cold broth with rice vinegar, sugar, and salt — it should be lightly tart and subtly sweet. Chill further with ice if needed. Cook noodles per packet (usually 3–4 minutes), drain and immediately rinse under cold running water for 30 seconds, rubbing with hands to remove starch and chill completely. Nest noodles in deep bowls. Ladle cold broth to cover. Top with sliced brisket, pear, julienned cucumber, and halved egg. Serve at once with vinegar and mustard on the side."}},{"id":86,"origin":{"en":"Pakistan","ro":"Pakistan"},"name":{"en":"Nihari","ro":"Nihari"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"indian","ingredients":{"en":["1 kg bone-in beef shanks, cut into 5 cm pieces","2 marrow bones, each about 5 cm long","4 tbsp ghee or clarified butter","2 large onions (~300 g), thinly sliced","2 tbsp ginger-garlic paste","1.5 tsp red chilli powder","1 tsp ground coriander","1/2 tsp ground turmeric","1.5 tsp salt","1 tsp nihari masala or garam masala","3 tbsp plain flour mixed with 100 ml cold water","5 cm piece of fresh ginger, peeled and julienned, to serve","1 lemon cut into wedges and a handful of fresh coriander leaves, to serve"],"ro":["1 kg rasol de vită cu os, tăiat în bucăți de 5 cm","2 oase cu măduvă, fiecare de aproximativ 5 cm","4 linguri unt clarificat (ghee) sau ulei","2 cepe mari (~300 g), feliate subțire","2 linguri pastă de ghimbir și usturoi","1,5 linguriță praf de ardei iute roșu","1 linguriță coriandru măcinat","1/2 linguriță turmeric măcinat","1,5 linguriță sare","1 linguriță masala nihari sau garam masala","3 linguri făină albă amestecate cu 100 ml apă rece","5 cm ghimbir proaspăt, curățat și juliennat, pentru servire","1 lămâie tăiată în felii și un mănunchi de frunze de coriandru, pentru servire"]},"howIsMade":{"en":"Heat 3 tbsp ghee in a large heavy pot over medium-high heat and fry the onions for 12–15 minutes, stirring often, until deep golden brown, then remove with a slotted spoon and set aside. Add the remaining ghee, raise the heat to high, and sear the beef shanks and marrow bones in batches for 3–4 minutes per side until browned, then set aside. Reduce heat to medium, add the ginger-garlic paste and fry for 1–2 minutes until fragrant, then add the chilli powder, coriander, and turmeric and stir for 30 seconds. Return the meat and fried onions to the pot, add the salt and enough water to cover by 5 cm (about 1.2 litres), bring to a boil and skim any foam. Reduce heat to the lowest setting, cover tightly, and simmer for 3–4 hours until the beef is completely tender and falling from the bone. Stir in the nihari masala, pour in the flour slurry in a thin stream while stirring, and simmer uncovered for 10–15 minutes until the broth thickens to a glossy consistency that coats the back of a spoon. Ladle into bowls, top with julienned ginger, coriander leaves, and a squeeze of lemon, and serve with naan or crusty bread."}},{"id":87,"origin":{"en":"Vietnam","ro":"Vietnam"},"name":{"en":"Bún bò Huế","ro":"Bún bò Huế"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","timeMins":{"total":195,"active":75},"pairingsType":"vietnamese","ingredients":{"en":["600 g bone-in pork hock, cut into 4 cm pieces","500 g beef bones, blanched","400 g beef shank, thinly sliced","400 g dried round rice vermicelli (bún)","3 lemongrass stalks, bruised and cut into 5 cm pieces","3 shallots, halved and charred","4 garlic cloves, bruised","2 tbsp fermented shrimp paste (mắm ruốc)","3 tbsp fish sauce","2 tbsp chilli oil or 1 tsp dried chilli flakes","1 tsp sugar","1 tsp salt","to serve: 200 g bean sprouts, fresh herbs (mint, perilla or Vietnamese coriander), 2 limes cut into wedges, and 2 red chillies sliced"],"ro":["600 g picior de porc cu os, tăiat în bucăți de 4 cm","500 g oase de vită, opărite","400 g rasol de vită, feliat subțire","400 g tăiței rotunzi de orez uscați (bún)","3 tulpini de lemongrass, zdrobite și tăiate în bucăți de 5 cm","3 șalote, tăiate pe jumătate și pârlite","4 căței de usturoi, zdrobiți","2 linguri pastă de creveți fermentați (mắm ruốc)","3 linguri sos de pește","2 linguri ulei de ardei iute sau 1 linguriță fulgi de ardei iute","1 linguriță zahăr","1 linguriță sare","pentru servit: 200 g muguri de fasole, ierburi proaspete (mentă sau coriandru vietnamez), 2 lămâi verzi în sferturi și 2 ardei iuți roșii felieți"]},"howIsMade":{"en":"Blanch the pork hock and beef bones in boiling water for 5 minutes, drain and rinse under cold water. Char the shallots and garlic cut-side down in a dry pan over high heat for 3–4 minutes until lightly blackened. Place the pork hock, bones, lemongrass, charred shallots, and garlic in a large pot, add 2.5 litres of cold water, bring to a boil, skim well, then simmer over low heat for 1 hour. Dissolve the shrimp paste in 100 ml of hot broth, stir into the pot, then add fish sauce, sugar, salt, and chilli oil, adjusting until the broth is savoury, lightly spicy, and fragrant. Add the beef shank slices and poach over gentle heat for 15–20 minutes until just cooked through and tender, then remove and slice thinly. Cook the rice vermicelli according to packet instructions (usually 3–5 minutes), drain, and divide among 4 deep bowls. Ladle the hot broth over the noodles, top with slices of pork hock and beef shank, and serve immediately with bean sprouts, fresh herbs, lime wedges, and sliced chilli on the side."}},{"id":88,"origin":{"en":"Brazil","ro":"Brazilia"},"name":{"en":"Moqueca","ro":"Moqueca"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"fish","pairingsType":"latin","ingredients":{"en":["800 g firm white fish fillets (sea bass, cod, or monkfish), cut into 5 cm chunks","2 limes, juice only","1 tsp salt","1 large onion (~180 g), thinly sliced","4 garlic cloves, finely minced","1 red bell pepper (~150 g), deseeded and sliced","1 green bell pepper (~150 g), deseeded and sliced","2 large ripe tomatoes (~300 g), diced","400 ml full-fat coconut milk","2 tbsp dendê (red palm oil)","20 g fresh coriander, roughly chopped, plus extra to serve","1/2 tsp ground black pepper"],"ro":["800 g fileuri de pește alb ferm (biban de mare, cod sau merluciu), tăiate în bucăți de 5 cm","2 lămâi verzi (lime), sucul","1 linguriță sare","1 ceapă mare (~180 g), feliată subțire","4 căței de usturoi, tocați mărunt","1 ardei gras roșu (~150 g), curat și feliat","1 ardei gras verde (~150 g), curat și feliat","2 roșii coapte mari (~300 g), tocate cuburi","400 ml lapte de cocos integral","2 linguri ulei de palmier roșu (dendê)","20 g coriandru proaspăt, tocat grosier, plus extra pentru garnit","1/2 linguriță piper negru măcinat"]},"howIsMade":{"en":"Toss the fish chunks with the lime juice, 1/2 tsp salt, and the black pepper and leave to marinate for 15–20 minutes while you prepare the vegetables. Heat 1 tbsp dendê oil in a large wide pan over medium heat, add the onion slices, and cook for 6–8 minutes until softened and lightly golden. Add the garlic, bell peppers, and tomatoes, stir well, and cook for 5 minutes until the tomatoes begin to break down. Lay the marinated fish over the vegetables in a single layer, pour the coconut milk over the top, and gently push the fish down into the liquid without stirring. Bring to a gentle simmer, cover, and cook for 12–15 minutes until the fish is opaque and flakes easily when pressed. Drizzle the remaining 1 tbsp dendê oil over the surface, scatter the coriander on top, and taste for salt. Serve directly from the pan with white rice or crusty bread, with lime wedges on the side."}},{"id":89,"origin":{"en":"Israel","ro":"Israel"},"name":{"en":"Sabich","ro":"Sabich"},"category":{"en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"def","pairingsType":"middle-eastern","ingredients":{"en":["4 large pita breads","1 large aubergine (~400 g), cut into 1 cm rounds","4 tbsp oil for frying","4 eggs","300 g waxy potatoes, boiled until tender and sliced 1 cm thick","4 tbsp tahini paste","1 lemon, juice only","1 garlic clove, crushed","4 tbsp amba sauce (fermented mango pickle sauce)","2 tomatoes (~200 g), finely diced","1 cucumber (~150 g), finely diced","1 tsp salt","4 slices pickled cucumber and fresh parsley, to serve"],"ro":["4 lipii pita mari","1 vânătă mare (~400 g), tăiată în felii de 1 cm","4 linguri ulei pentru prăjit","4 ouă","300 g cartofi galbeni, fierți până sunt moi și feliați la 1 cm grosime","4 linguri pastă de tahini","1 lămâie, sucul","1 cățel de usturoi, zdrobit","4 linguri sos amba (sos din mango murat)","2 roșii (~200 g), tăiate mărunt","1 castravete (~150 g), tăiat mărunt","1 linguriță sare","4 felii castraveți murați și pătrunjel proaspăt, pentru servire"]},"howIsMade":{"en":"Hard-boil the eggs: lower into boiling water, cook for 10 minutes, then transfer to cold water for 5 minutes, peel, and slice into rounds. Sprinkle the aubergine slices on both sides with 1/2 tsp salt and leave for 10 minutes, then pat dry with kitchen paper. Heat the oil in a large non-stick pan over medium-high heat and fry the aubergine in batches for 3–4 minutes per side until deep golden and tender throughout, then drain on kitchen paper. Whisk the tahini with the lemon juice, crushed garlic, and 3–4 tbsp cold water until creamy and pourable. Combine the diced tomatoes and cucumber with the remaining 1/2 tsp salt and a drizzle of olive oil. Warm each pita for 1 minute per side in a dry pan, then carefully open the pocket without tearing. Layer each pita with fried aubergine, sliced potato and egg, the tomato-cucumber salad, a generous drizzle of tahini sauce, a spoonful of amba sauce, pickled cucumber, and fresh parsley, and serve immediately."}},{"id":90,"origin":{"en":"Cuba","ro":"Cuba"},"name":{"en":"Ropa Vieja","ro":"Ropa Vieja"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"en":["700 g beef flank steak or brisket","2 tbsp olive oil","1 large onion (~200 g), thinly sliced","1 red bell pepper and 1 green bell pepper (~150 g each), deseeded and sliced","4 garlic cloves, finely minced","400 g canned crushed tomatoes","2 tbsp tomato paste","100 ml dry white wine","1 tsp ground cumin","1 tsp dried oregano","2 bay leaves","1 tsp salt and 1/2 tsp ground black pepper"],"ro":["700 g antricot sau piept de vită","2 linguri ulei de măsline","1 ceapă mare (~200 g), feliată subțire","1 ardei gras roșu și 1 ardei gras verde (~150 g fiecare), curățați și feliați","4 căței de usturoi, tocați mărunt","400 g roșii zdrobite la conservă","2 linguri pastă de roșii","100 ml vin alb sec","1 linguriță chimion măcinat","1 linguriță oregano uscat","2 foi de dafin","1 linguriță sare și 1/2 linguriță piper negru măcinat"]},"howIsMade":{"en":"Place the beef in a pot, cover with cold salted water, bring to a boil, skim, reduce heat, and simmer covered for 1.5–2 hours until the meat pulls apart easily. Remove the beef, reserve 200 ml of the cooking liquid, and shred the meat into long strips. Heat the oil in a wide heavy pan over medium heat, add the onion and both bell peppers, and cook for 8–10 minutes until softened and beginning to colour. Add the garlic, cumin, and oregano and stir for 1 minute, then pour in the white wine and cook for 2 minutes until reduced by half. Stir in the crushed tomatoes, tomato paste, reserved cooking liquid, and bay leaves, season with salt and pepper, and simmer for 10 minutes until the sauce thickens slightly. Add the shredded beef, stir to combine, and simmer for 10–15 minutes more until the beef absorbs the sauce and the mixture is juicy but not soupy. Remove the bay leaves and serve with white rice and fried plantains."}},{"id":91,"origin":{"en":"Scotland","ro":"Scoția"},"name":{"en":"Cullen Skink","ro":"Cullen Skink"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"en":["600 g undyed smoked haddock fillets","700 ml whole milk","500 g floury potatoes (such as Maris Piper), peeled and cut into 2 cm cubes","1 large onion (~200 g), finely diced","2 tbsp unsalted butter","2 bay leaves","100 ml double cream","10 g fresh parsley, finely chopped","1/2 tsp white pepper","1/2 tsp salt"],"ro":["600 g fileuri de eglefin afumat (de preferință necolorat)","700 ml lapte integral","500 g cartofi făinoși, curățați și tăiați cuburi de 2 cm","1 ceapă mare (~200 g), tăiată mărunt","2 linguri unt fără sare","2 foi de dafin","100 ml frișcă grasă","10 g pătrunjel proaspăt, tocat mărunt","1/2 linguriță piper alb","1/2 linguriță sare"]},"howIsMade":{"en":"Place the smoked haddock skin-side down in a wide pan, pour over the milk, add the bay leaves, and bring to a gentle simmer over medium heat; poach for 8–10 minutes until the fish is just opaque and flakes at the thickest part. Lift the fish out with a slotted spoon, remove the skin and any bones, break the flesh into large flakes, and strain the poaching milk through a sieve into a jug. Melt the butter in the same pan over medium heat, add the diced onion, and cook for 8–10 minutes, stirring occasionally, until completely soft but not coloured. Add the potato cubes and the strained milk, bring to a simmer, cover loosely, and cook for 15–18 minutes until the potatoes are completely tender when pierced with a knife. Lightly mash about one-third of the potatoes against the side of the pan with the back of a spoon to thicken the soup, leaving the rest in chunks. Stir in the double cream, return the flaked haddock to the pan, and simmer gently for 2–3 minutes until just heated through; season with white pepper and salt, tasting carefully as the haddock is already salty. Ladle into warmed bowls, scatter with chopped parsley, and serve with crusty bread."}},{"id":92,"origin":{"en":"Indonesia","ro":"Indonezia"},"name":{"en":"Gado-Gado","ro":"Gado-Gado"},"category":{"en":"Salad","ro":"Salată"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"en":["400 g firm tofu, pressed and cut into 2 cm cubes","150 g tempeh, cut into 2 cm cubes","4 large eggs","300 g waxy potatoes, peeled and quartered","200 g green beans, trimmed","200 g white cabbage, thinly shredded","150 g bean sprouts","1 cucumber (~200 g), sliced into half-moons","3 tbsp vegetable oil","200 g smooth peanut butter","200 ml coconut milk","2 tbsp kecap manis (sweet soy sauce)","2 tbsp tamarind paste dissolved in 4 tbsp warm water","1 tsp palm sugar or soft brown sugar","2 garlic cloves, finely grated","1/2 tsp chilli flakes","1/2 tsp salt","prawn crackers (krupuk) and lime wedges to serve"],"ro":["400 g tofu ferm, presat și tăiat în cuburi de 2 cm","150 g tempeh, tăiat în cuburi de 2 cm","4 ouă mari","300 g cartofi cu coajă crocantă, curățați și tăiați în sferturi","200 g fasole verde, curățată de capete","200 g varză albă, feliată subțire","150 g germeni de soia","1 castravete (~200 g), tăiat în felii semilună","3 linguri ulei vegetal","200 g unt de arahide cremos","200 ml lapte de cocos","2 linguri kecap manis (sos de soia dulce)","2 linguri pastă de tamarind dizolvată în 4 linguri apă caldă","1 linguriță zahăr de palmier sau zahăr brun","2 căței de usturoi, rași fin","1/2 linguriță fulgi de ardei iute","1/2 linguriță sare","chipsuri de creveți (krupuk) și felii de lămâie verde pentru servit"]},"howIsMade":{"en":"Hard-boil the eggs in simmering water for 9 minutes, transfer to a bowl of ice water, then peel and halve when cool. Cook the potatoes in well-salted boiling water for 12–15 minutes until just tender when pierced; lift out with a slotted spoon and drain, then blanch the green beans in the same water for 3 minutes until bright green and still with some bite, and drain. Blanch the shredded cabbage by pouring boiling water over it in a colander, count 30 seconds, then press out excess water. Heat the oil in a non-stick frying pan over medium-high heat and fry the tofu cubes for 3–4 minutes per side until golden and crisp; remove, then fry the tempeh in the same pan for 2–3 minutes per side until deep golden. Combine the peanut butter, coconut milk, kecap manis, tamarind water, palm sugar, grated garlic, and chilli flakes in a small saucepan; cook over low heat, stirring constantly, for 5–7 minutes until smooth and thick enough to coat the back of a spoon — thin with a splash of water if needed. Arrange the cabbage, potatoes, green beans, bean sprouts, and cucumber slices on a large platter or individual plates; place the tofu, tempeh, and egg halves on top. Pour the warm peanut sauce over everything, and serve with prawn crackers and lime wedges on the side."}},{"id":93,"origin":{"en":"Sweden","ro":"Suedia"},"name":{"en":"Cinnamon Bun","ro":"Kanelbulle"},"category":{"en":"Dessert","ro":"Desert"},"servings":12,"tipType":"dessert","pairingsType":"dessert","ingredients":{"en":["500 g plain flour, plus extra for dusting","250 ml whole milk","7 g fast-action dried yeast (1 sachet)","10 g caster sugar (for dough)","1 large egg","100 g unsalted butter, softened","1 tsp ground cardamom","1/2 tsp salt","75 g unsalted butter, softened (filling)","75 g caster sugar (filling)","1 tbsp ground cinnamon","1 tsp ground cardamom (filling)","1 egg, beaten (for egg wash)","2 tbsp pearl sugar"],"ro":["500 g făină albă, plus extra pentru presărat","250 ml lapte integral","7 g drojdie uscată instant (1 plic)","10 g zahăr tos (pentru aluat)","1 ou mare","100 g unt nesărat, la temperatura camerei","1 linguriță cardamom măcinat","1/2 linguriță sare","75 g unt nesărat, la temperatura camerei (umplutură)","75 g zahăr tos (umplutură)","1 lingură scorțișoară măcinată","1 linguriță cardamom măcinat (umplutură)","1 ou bătut (pentru uns)","2 linguri zahăr perle"]},"howIsMade":{"en":"Warm the milk to 37°C, stir in the yeast and the 10 g of caster sugar, and leave for 5–10 minutes until frothy. Combine the flour, cardamom, and salt in a large bowl; make a well, pour in the yeast mixture and beaten egg, then bring together into a rough dough. Add the 100 g of softened butter a piece at a time and knead on a lightly floured surface for 8–10 minutes until the dough is smooth, elastic, and no longer sticks to your hands; cover and leave in a warm place for 60–90 minutes until doubled in size. Beat together the 75 g of butter, 75 g of caster sugar, cinnamon, and the second teaspoon of cardamom until smooth for the filling. Turn the risen dough onto a lightly floured surface and roll into a 40×50 cm rectangle; spread the filling evenly, fold the dough lengthways into thirds, roll again, and cut into 12 strips. Twist each strip and coil into a knot, tucking the end underneath, then space on lined baking trays; cover loosely and prove 30–45 minutes until noticeably puffed, while preheating the oven to 200°C (fan 180°C). Brush with beaten egg, scatter with pearl sugar, and bake for 12–15 minutes until deep golden brown; transfer to a wire rack and cover with a tea towel to keep them soft."}},{"id":94,"origin":{"en":"Mexico","ro":"Mexic"},"name":{"en":"Chiles en nogada","ro":"Chiles en nogada"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mexican","ingredients":{"en":["4 large poblano chiles (~700 g total)","400 g ground pork","2 tbsp olive oil or lard","1 medium onion (~150 g), finely diced","3 garlic cloves, minced","2 ripe tomatoes (~300 g), peeled and diced","50 g raisins","50 g blanched almonds, roughly chopped","1 ripe peach or pear (~150 g), peeled and diced","1 tsp ground cinnamon, 1/2 tsp ground cloves, 1 tsp salt, 1/2 tsp black pepper","150 g walnut halves, soaked in warm milk 30 minutes then drained","150 g cream cheese, softened","100 ml soured cream","seeds of 1 pomegranate (~100 g)","small handful of fresh flat-leaf parsley leaves"],"ro":["4 ardei poblano mari (~700 g total)","400 g carne de porc tocată","2 linguri ulei de măsline sau untură","1 ceapă medie (~150 g), tăiată mărunt","3 căței de usturoi, tocați","2 roșii coapte (~300 g), curățate de coajă și tocate","50 g stafide","50 g migdale decojite, tocate grosier","1 piersică sau pară coaptă (~150 g), curățată și tăiată cubulețe","1 linguriță scorțișoară, 1/2 linguriță cuișoare, 1 linguriță sare, 1/2 linguriță piper negru","150 g miez de nucă, înmuiat 30 minute în lapte cald și scurs","150 g cremă de brânză, la temperatura camerei","100 ml smântână fermentată","semințele unui rodiu (~100 g)","o mână de frunze de pătrunjel plat proaspăt"]},"howIsMade":{"en":"Char the poblano chiles over an open gas flame or under a hot grill for 8–10 minutes, turning with tongs until the skin is completely blackened on all sides; place in a covered bowl for 10 minutes, then rub off the skin, make a single lengthways slit, and remove the seeds and veins with a small spoon while keeping each chile intact. Heat the oil in a wide frying pan over medium heat, add the onion, and cook for 5–6 minutes until completely soft; add the garlic and cook 1 minute more until fragrant. Add the ground pork and cook, breaking it up with a wooden spoon, for 8 minutes until no pink remains; add the diced tomatoes and cook for 5 minutes until they collapse and the liquid reduces. Stir in the raisins, almonds, peach, cinnamon, cloves, salt, and pepper; cook for 5 minutes until the fruit softens and the mixture is fairly dry, then remove from heat and cool to room temperature. Drain the soaked walnuts and blend with the cream cheese and soured cream until completely smooth; season with a pinch of salt — the nogada should be thick enough to coat a spoon. Stuff each poblano firmly with the cooled meat filling, pressing gently to close the slit; arrange on individual plates or a large serving dish. Spoon the walnut sauce generously over each chile, scatter pomegranate seeds and parsley leaves on top, and serve at room temperature."}},{"id":95,"origin":{"en":"Lebanon","ro":"Liban"},"name":{"en":"Lentil Soup","ro":"Supă de linte"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"soup","ingredients":{"en":["300 g red lentils, rinsed until water runs clear","2 tbsp olive oil","1 large onion (~200 g), finely diced","2 medium carrots (~200 g), peeled and diced","3 garlic cloves, minced","2 tsp ground cumin","1 tsp ground coriander","1/2 tsp ground turmeric","1/4 tsp cayenne pepper","1.2 litres vegetable or chicken stock","juice of 1 lemon","2 tbsp unsalted butter (for topping)","1 tsp sweet paprika (for topping)","salt and black pepper to taste","fresh coriander or parsley and lemon wedges to serve"],"ro":["300 g linte roșie, clătită până apa devine limpede","2 linguri ulei de măsline","1 ceapă mare (~200 g), tăiată mărunt","2 morcovi medii (~200 g), curățați și tăiați cubulețe","3 căței de usturoi, tocați","2 lingurițe chimen măcinat","1 linguriță coriandru măcinat","1/2 linguriță turmeric","1/4 linguriță ardei cayenne","1,2 litri supă de legume sau pui","sucul de la 1 lămâie","2 linguri unt nesărat (pentru topping)","1 linguriță paprika dulce (pentru topping)","sare și piper negru după gust","coriandru proaspăt sau pătrunjel, felii de lămâie pentru servit"]},"howIsMade":{"en":"Heat the olive oil in a large saucepan over medium heat, add the onion and carrots, and cook for 8–10 minutes, stirring occasionally, until softened and the onion is translucent. Add the garlic, cumin, coriander, turmeric, and cayenne; stir for 1–2 minutes until the spices are fragrant and toasted. Add the rinsed lentils and stock, bring to a boil, then reduce the heat, partially cover, and simmer for 20–25 minutes until the lentils are completely tender and beginning to dissolve into the liquid. Use an immersion blender to puree about half the soup directly in the pot for a creamy yet textured finish — or blend it all smooth if you prefer; thin with a splash of extra stock or water if needed. Stir in the lemon juice and season generously with salt and black pepper. Melt the butter in a small pan over medium heat, add the sweet paprika, and let it sizzle for 30 seconds until fragrant and deep red. Ladle the hot soup into warmed bowls, drizzle the paprika butter over each portion, scatter fresh coriander on top, and serve with lemon wedges and crusty bread."}},{"id":96,"origin":{"en":"Greece","ro":"Grecia"},"name":{"en":"Spanakopita","ro":"Spanakopita"},"category":{"en":"Snack","ro":"Gustare"},"servings":6,"tipType":"veg","pairingsType":"veg","ingredients":{"en":["500g phyllo pastry, thawed if frozen","1kg fresh spinach, washed (or 600g frozen spinach, thawed and squeezed dry)","300g feta cheese, crumbled","2 medium onions, finely chopped","4 spring onions, finely sliced","3 large eggs, beaten","30g fresh dill, chopped","20g fresh parsley, chopped","150ml extra virgin olive oil","100g grated kefalotyri or pecorino (optional)","1/2 tsp freshly grated nutmeg","salt and freshly ground black pepper to taste"],"ro":["500g foi de plăcintă (phyllo), decongelate dacă sunt din congelator","1kg spanac proaspăt, spălat (sau 600g spanac congelat, decongelat și stors bine)","300g brânză feta, sfărâmată","2 cepe medii, tocate fin","4 cepe verzi, tăiate fin","3 ouă mari, bătute","30g mărar proaspăt, tocat","20g pătrunjel proaspăt, tocat","150ml ulei de măsline extravirgin","100g kefalotyri sau pecorino, ras (opțional)","1/2 linguriță nucșoară proaspăt rasă","sare și piper negru proaspăt măcinat după gust"]},"howIsMade":{"en":"Preheat the oven to 180°C (fan 160°C); wash 1kg of spinach and wilt it in a large pot over medium heat for 4–5 minutes, until just collapsed; tip into a colander and press out as much water as possible, then squeeze handfuls dry between paper towels. Warm 3 tablespoons of olive oil in a pan and cook the chopped onions over medium heat for 8 minutes, until soft and translucent; add the spring onions and cook 2 more minutes. In a large bowl, combine the squeezed spinach, the onion mixture, 300g crumbled feta, the kefalotyri if using, 3 beaten eggs, dill, parsley, nutmeg, salt and pepper; mix gently — do not overwork or the spinach will release more water. Brush a 25×35 cm baking dish with olive oil; lay one sheet of phyllo, brush with olive oil, and top with another sheet; continue until you have 8 layers as the base; keep unused phyllo covered with a slightly damp cloth. Spread the filling evenly over the phyllo base; top with 8 more sheets of phyllo, brushing each layer generously with olive oil. Tuck the edges in; with a sharp knife, score the top into 6–8 portions, cutting only through the top layers — this prevents shattering when serving; sprinkle a few drops of water on top to stop the pastry curling. Bake for 40–45 minutes, until the top is deep golden brown and the pastry sounds crisp when tapped; rest 15 minutes before cutting along the scored lines."},"timeMins":{"total":90,"active":40}},{"id":97,"origin":{"en":"Nigeria","ro":"Nigeria"},"name":{"en":"Jollof Rice","ro":"Jollof Rice"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"def","ingredients":{"en":["400g long-grain parboiled rice (or basmati), rinsed until water runs clear","6 ripe Roma tomatoes, roughly chopped (or 400g canned chopped tomatoes)","2 large red bell peppers, deseeded and roughly chopped","1 scotch bonnet or red chilli, deseeded","2 large onions (1 blended, 1 sliced)","4 garlic cloves, peeled","30g fresh ginger, peeled","3 tbsp tomato paste","120ml vegetable oil (groundnut oil is traditional)","750ml hot chicken or vegetable stock","2 bay leaves","1 tsp curry powder","1 tsp dried thyme","1 tsp smoked paprika","salt and freshly ground black pepper to taste"],"ro":["400g orez cu bob lung parboiled (sau basmati), spălat până apa rămâne limpede","6 roșii Roma coapte, tăiate grosier (sau 400g roșii din conservă)","2 ardei kapia roșii mari, fără semințe și tăiați grosier","1 ardei scotch bonnet sau ardei iute roșu, fără semințe","2 cepe mari (una mixată, una feliată)","4 căței de usturoi, curățați","30g ghimbir proaspăt, curățat","3 linguri pastă de roșii","120ml ulei vegetal (tradițional, ulei de arahide)","750ml supă fierbinte de pui sau legume","2 foi de dafin","1 linguriță pudră de curry","1 linguriță cimbru uscat","1 linguriță boia afumată","sare și piper negru proaspăt măcinat după gust"]},"howIsMade":{"en":"Rinse 400g of rice in cold water until the water runs clear, then drain — this removes excess starch and keeps the grains separate. Blend the tomatoes, red bell peppers, chilli, one onion, garlic and ginger to a smooth paste in a blender. Heat 120ml oil in a heavy-bottomed pot over medium heat; add the sliced onion and fry for 5–6 minutes, until lightly golden. Stir in 3 tablespoons of tomato paste and cook for 3 minutes, until darkened and the raw aroma is gone. Pour in the blended pepper mixture, add the bay leaves, curry powder, thyme and smoked paprika; cook uncovered over medium heat for 18–20 minutes, stirring often, until the sauce reduces, deepens to a dark red and the oil rises to the surface — this is the critical step. Add the rinsed rice and stir until every grain is coated in sauce; pour in 750ml hot stock, season with salt and pepper, and bring back to a boil. Reduce the heat to the lowest setting, cover the pot tightly (seal the rim with foil before placing the lid for an authentic finish), and cook undisturbed for 25–30 minutes, until the rice is tender and the liquid is absorbed. Turn off the heat and leave covered for 10 more minutes; fluff gently with a fork — the bottom layer should have a slight smoky crust; serve with fried plantain, grilled chicken, or a simple salad."}},{"id":98,"origin":{"en":"Samoa","ro":"Samoa"},"name":{"en":"Oka i'a","ro":"Oka i'a"},"category":{"en":"Snack","ro":"Gustare"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"en":["500g sashimi-grade tuna or mahi-mahi, skinned and boned, cut into 1.5 cm cubes","120ml fresh lime juice (about 6 limes)","200ml full-fat coconut milk (freshly opened or canned)","1 medium cucumber, peeled, deseeded, and finely diced","1 small red onion, finely diced","2 ripe tomatoes, deseeded and diced","1 small red chilli, finely chopped (optional)","1 spring onion, finely sliced","1 tsp fine sea salt","freshly ground black pepper","fresh coriander leaves, to garnish"],"ro":["500g ton sau mahi-mahi de calitate sashimi, fără piele și oase, tăiat cuburi de 1,5 cm","120ml suc proaspăt de lime (aproximativ 6 lime)","200ml lapte de cocos integral (proaspăt deschis sau din conservă)","1 castravete mediu, curățat, fără semințe, tăiat cuburi mici","1 ceapă roșie mică, tăiată cuburi mici","2 roșii coapte, fără semințe, tăiate cuburi","1 ardei iute roșu mic, tocat fin (opțional)","1 ceapă verde, tăiată fin","1 linguriță sare fină de mare","piper negru proaspăt măcinat","frunze de coriandru proaspăt, pentru ornat"]},"howIsMade":{"en":"Place the cubed fish in a non-reactive (glass or ceramic) bowl; pour over 120ml fresh lime juice and toss until every piece is coated; refrigerate for 15–20 minutes — the surface should turn opaque while the centre stays translucent. While the fish marinates, soak the diced red onion in cold water for 10 minutes, then drain; this softens its raw bite without losing the crunch. Drain the fish thoroughly through a fine sieve; discard most of the lime juice but reserve 2 tablespoons. Return the fish to a clean bowl; add the cucumber, drained red onion, tomatoes, chilli and spring onion; toss gently so the fish stays intact. Pour in 200ml coconut milk and the reserved 2 tbsp lime juice; add the salt and a few grinds of pepper; fold everything together gently — the coconut milk should coat without breaking the fish. Taste and adjust salt or lime; serve immediately, very cold, in shallow bowls; scatter fresh coriander leaves on top."}},{"id":99,"origin":{"en":"Armenia","ro":"Armenia"},"name":{"en":"Khorovats","ro":"Khorovats"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["800g pork shoulder or beef tenderloin, cut into 4 cm cubes","2 large red onions (1 sliced for the marinade, 1 cut into wedges for skewering)","1 red bell pepper, cut into 4 cm pieces","1 green bell pepper, cut into 4 cm pieces","1 medium aubergine, cut into 3 cm rounds","4 ripe tomatoes (to be grilled whole alongside)","3 tbsp sunflower oil","1 tsp freshly ground black pepper","2 tsp coarse salt","a small handful of fresh basil and parsley, to serve","lavash or another flatbread, to serve"],"ro":["800g pulpă de porc sau mușchi de vită, tăiat cuburi de 4 cm","2 cepe roșii mari (una feliată pentru marinadă, una tăiată felii pentru frigărui)","1 ardei gras roșu, tăiat bucăți de 4 cm","1 ardei gras verde, tăiat bucăți de 4 cm","1 vânătă medie, tăiată rondele de 3 cm","4 roșii coapte (pentru grătar întregi)","3 linguri ulei de floarea-soarelui","1 linguriță piper negru proaspăt măcinat","2 lingurițe sare grunjoasă","un mănunchi de busuioc și pătrunjel proaspăt, pentru servit","lavaș sau alt tip de pâine plată"]},"howIsMade":{"en":"Thinly slice one onion; in a large bowl, combine 800g cubed meat, the sliced onion, 2 tsp salt, 1 tsp black pepper, and 3 tbsp sunflower oil; massage well by hand and refrigerate 4–8 hours, or overnight. Light a charcoal fire and let it burn down to glowing red embers with white edges — about 30–40 minutes; position the grill 15 cm above the coals. Thread the marinated meat onto metal skewers, alternating with wedges of onion and leaving small gaps between pieces so the hot air can circulate. Lay the whole peppers, aubergine slices and tomatoes directly on the grill, away from the meat; char them rotating frequently, until the skins blacken on every side — about 12–15 minutes total. Place the meat skewers over the hottest part of the embers; grill 10–14 minutes, turning every 2 minutes, until the meat is deeply caramelised outside but still pink in the centre — internal temperature 60°C for pork. Transfer the grilled vegetables to a plate, cover with foil for 5 minutes, then strip off the blackened skins; roughly chop and mix with the resting juices, salt, and chopped parsley to make a rustic relish. Serve the skewers hot with the vegetable relish, fresh basil, lemon wedges, and warm lavash for wrapping."}},{"id":100,"origin":{"en":"Estonia","ro":"Estonia"},"name":{"en":"Verivorst","ro":"Verivorst"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["500g pig's blood (fresh or thawed)","200g pork fat or fatty pork belly, finely diced","200g pearl barley, cooked and cooled","2 large onions, finely chopped","1 tsp dried marjoram","1 tsp ground allspice","1 tsp ground black pepper","2 tsp coarse salt","1.5m cleaned natural sausage casing","2 tbsp pork lard, for cooking","lingonberry jam and pickled cucumbers, to serve"],"ro":["500g sânge de porc (proaspăt sau decongelat)","200g slănină sau piept de porc gras, tăiat cuburi mici","200g orz perlat, fiert și răcit","2 cepe mari, tocate fin","1 linguriță maghiran uscat","1 linguriță ienibahar măcinat","1 linguriță piper negru măcinat","2 lingurițe sare grunjoasă","1,5m maț natural curățat","2 linguri untură de porc, pentru gătit","gem de lingonberry și castraveți murați, pentru servit"]},"howIsMade":{"en":"In a large pan, fry the diced pork fat over low heat for 8–10 minutes, until most of its fat has rendered and the cubes are golden; add the chopped onions and cook 6–8 minutes more, until soft and translucent; set aside to cool completely. In a large bowl, combine the cooked pearl barley, the fried onions and pork fat (with all their fat), the marjoram, allspice, salt and pepper; mix well. Whisk the blood briefly to break up any clots, then stir it gradually into the barley mixture; the filling should look glossy and pourable, but not too liquid. Rinse the sausage casing under cold running water for 5 minutes; tie off one end with kitchen twine. Slide the open end of the casing onto a wide funnel or sausage stuffer; pipe the mixture in gradually, leaving the casing two-thirds full to allow expansion during cooking; tie off into 12–15 cm sausages and prick each with a needle in several places. Bring a large pot of water to 80°C — not boiling; slip the sausages in and poach gently for 30–40 minutes, until they feel firm to the touch and the juices run clear when pricked. Lift the sausages out and let them rest 10 minutes; preheat the oven to 200°C. Brush the sausages with melted lard and roast on a tray for 12–15 minutes, turning once, until the skins are crisp and burnished; serve hot with lingonberry jam and pickled cucumbers."}},{"id":102,"origin":{"en":"South Korea","ro":"Coreea de Sud"},"name":{"en":"Tteokbokki","ro":"Tteokbokki"},"category":{"en":"Snack","ro":"Gustare"},"servings":4,"tipType":"def","pairingsType":"korean","ingredients":{"en":["500g cylindrical rice cakes (garae-tteok), fresh or thawed","150g eomuk (Korean fish cake), cut into triangles","3 tbsp gochujang (fermented red chili paste)","1 tbsp gochugaru (Korean red pepper flakes)","1 tbsp sugar","1 tsp soy sauce","500ml anchovy stock (or water with a dashi packet)","2 spring onions, cut into 5 cm pieces","2 hard-boiled eggs, peeled","1 tsp sesame oil","1 tsp toasted sesame seeds"],"ro":["500g tteok cilindric (garae-tteok) proaspăt sau dezghețat","150g eomuk (prăjitură de pește coreeană), tăiat în triunghiuri","3 linguri gochujang (pastă de ardei iute fermentat)","1 lingură gochugaru (fulgi de ardei iute coreean)","1 lingură zahăr","1 linguriță sos de soia","500ml supă de hamsii (sau apă cu dashi)","2 cepe verzi, tăiate în bucăți de 5 cm","2 ouă fierte tari, decojite","1 linguriță ulei de susan","1 linguriță semințe de susan prăjite"]},"howIsMade":{"en":"If the rice cakes are hard or refrigerated, soak them in warm water for 20–30 minutes until pliable; drain. In a wide shallow pan, bring 500ml of anchovy stock to a boil over medium-high heat. Stir in 3 tbsp gochujang, 1 tbsp gochugaru, 1 tbsp sugar and 1 tsp soy sauce; whisk until the paste fully dissolves and the sauce turns glossy red. Add the drained rice cakes; stir gently to coat every piece, then simmer over medium heat for 8–10 minutes, stirring often, until the rice cakes are tender and the sauce has thickened to a syrupy consistency that coats the back of a spoon. Add the eomuk pieces and cook for another 3–4 minutes, until they have absorbed the sauce and turned bright red. Slip in the 2 hard-boiled eggs to warm through; taste and adjust with a pinch of sugar or a splash of soy if needed. Drizzle with sesame oil, sprinkle with the spring onions and sesame seeds; serve immediately, very hot, straight from the pan."}},{"id":103,"origin":{"en":"Ecuador","ro":"Ecuador"},"name":{"en":"Shrimp Ceviche","ro":"Ceviche de camarón"},"category":{"en":"Snack","ro":"Gustare"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"en":["600g medium shrimp, peeled and deveined","180ml fresh lime juice (about 8 limes)","120ml fresh orange juice","1 large red onion, finely diced","3 ripe tomatoes, deseeded and diced","1 red chili (ají), finely chopped (optional)","30g fresh coriander leaves, chopped","3 tbsp olive oil","1 tsp fine sea salt","freshly ground black pepper","chifles (plantain chips) or toasted corn, to serve"],"ro":["600g creveți medii, decojiți și fără vene","180ml suc proaspăt de lime (aproximativ 8 lime)","120ml suc proaspăt de portocale","1 ceapă roșie mare, tăiată cuburi mici","3 roșii coapte, fără semințe și tăiate cuburi","1 ardei iute roșu (ají), tocat fin (opțional)","30g frunze de coriandru proaspăt, tocate","3 linguri ulei de măsline","1 linguriță sare fină de mare","piper negru proaspăt măcinat","chifles (chipsuri de plantain) sau porumb prăjit, pentru servit"]},"howIsMade":{"en":"Bring a large pot of salted water to a boil; add the shrimp and boil for 60–90 seconds, until pink and opaque; drain immediately and shock in a bowl of ice water. Drain the shrimp, halve them or leave them whole as you prefer, and place in a non-reactive (glass or ceramic) bowl. Pour 180ml lime juice and 120ml orange juice over the shrimp; toss, cover, and refrigerate for 15–20 minutes. While the shrimp marinates, soak the diced red onion in salted ice water for 10 minutes, then drain — this softens the harsh bite without losing crunch. Add the drained onion, tomatoes, chili, coriander, 3 tbsp olive oil and 1 tsp salt to the shrimp bowl; toss gently. Taste and adjust salt, lime, or chili; let rest for 5 minutes so the flavours settle. Serve very cold in shallow bowls, with chifles or toasted corn alongside for crisp contrast."}},{"id":104,"origin":{"en":"Dominican Republic","ro":"Republica Dominicană"},"name":{"en":"La Bandera","ro":"La Bandera"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"latin","ingredients":{"en":["400g long-grain white rice","250g dried red kidney beans (or 800g cooked/canned, drained)","600g bone-in chicken thighs or beef chuck, cut into 4 cm cubes","2 large green plantains, peeled and sliced 1 cm thick","1 medium green bell pepper, finely diced","1 small red bell pepper, finely diced","1 large onion, finely chopped","4 garlic cloves, minced","30g fresh coriander, chopped (or culantro if available)","2 ripe tomatoes, diced (or 200g canned chopped tomatoes)","2 tbsp tomato paste","60ml vegetable oil (plus more for frying plantains)","1 tsp dried oregano","juice of 1 lime","salt and freshly ground black pepper"],"ro":["400g orez cu bob lung alb","250g fasole roșie uscată (sau 800g fasole gătită)","600g pulpe de pui cu os sau pulpă de vită, tăiată cuburi de 4 cm","2 banane plantain verzi mari, decojite, tăiate rondele de 1 cm","1 ardei gras verde mediu, tăiat cuburi mici","1 ardei gras roșu mic, tăiat cuburi mici","1 ceapă mare, tocată fin","4 căței de usturoi, tocați","30g coriandru proaspăt, tocat (sau culantro)","2 roșii coapte, tăiate cuburi (sau 200g roșii din conservă)","2 linguri pastă de roșii","60ml ulei vegetal (plus mai mult pentru prăjit)","1 linguriță oregano uscat","zeamă de la 1 lime","sare și piper negru proaspăt măcinat"]},"howIsMade":{"en":"Soak the dried beans overnight if using; drain, cover with 1L fresh water and a pinch of salt, and simmer for 60–75 minutes, until fully tender; reserve 250ml of the cooking liquid. Season the meat with salt, pepper, oregano, and lime juice; rest for 15 minutes while you prepare the sofrito. Heat 2 tbsp oil in a heavy pot; make a sofrito: sauté the onion for 5 minutes, then add the garlic, both peppers, and half the coriander; cook 4 minutes until soft. Push the sofrito to one side; add the meat to the empty space and brown for 3–4 minutes per side; stir in 2 tbsp tomato paste and the diced tomatoes, cook for 3 minutes; pour in 500ml water, cover, and simmer for 35–40 minutes, until the meat is fork-tender and the sauce has thickened. Meanwhile cook the rice: rinse 400g of rice until the water runs clear; in a wide pot, heat 1 tbsp oil and 1 tsp salt, add the rice, cover with 700ml water, bring to a boil, then reduce to the lowest heat and steam, covered, for 18–20 minutes; rest 10 minutes off heat. Finish the beans: in a small pot, heat 1 tbsp oil and a spoonful of the sofrito set aside in step 3; add the drained beans plus 250ml reserved cooking liquid and 1 tsp salt; simmer for 12–15 minutes, mashing a handful against the side of the pot to thicken to a saucy consistency. Heat 5 cm of oil in a frying pan to 175°C; fry the plantain slices for 3–4 minutes until golden; drain on paper, flatten with a press or the back of a cup, and refry for 1–2 minutes until crisp; salt while hot. Plate each portion with rice as the base, a ladle of beans alongside, a generous portion of braised meat with its sauce, and 4–5 plantain rounds; finish with the remaining coriander, lime wedges, and a simple green salad."}},{"id":105,"origin":{"en":"Iran","ro":"Iran"},"name":{"en":"Fesenjan","ro":"Fesenjan"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"en":["800g boneless chicken thighs, or 1 small duck (1.5kg) jointed","300g shelled walnuts, toasted and finely ground","120ml pomegranate molasses","2 large onions, finely chopped","3 tbsp vegetable oil","1 tsp ground turmeric","1 tsp ground cinnamon","1/2 tsp freshly grated nutmeg","1 tbsp brown sugar (or to taste)","1 litre hot chicken stock or water","fresh pomegranate seeds, to garnish","salt and freshly ground black pepper","basmati rice, to serve"],"ro":["800g pulpe de pui dezosate, sau 1 rață mică (1,5kg) tăiată","300g miez de nucă, prăjit și măcinat fin","120ml melasă de rodie","2 cepe mari, tocate fin","3 linguri ulei vegetal","1 linguriță turmeric măcinat","1 linguriță scorțișoară măcinată","1/2 linguriță nucșoară proaspăt rasă","1 lingură zahăr brun (sau după gust)","1 litru supă de pui sau apă fierbinte","semințe de rodie proaspete, pentru ornat","sare și piper negru proaspăt măcinat","orez basmati pentru servit"]},"howIsMade":{"en":"Toast 300g of walnuts in a dry pan over medium heat for 4–5 minutes, tossing constantly, until fragrant and slightly darker; cool, then grind to as fine a paste as possible in a food processor. In a heavy pot, heat 3 tbsp oil over medium heat; add the chopped onions and cook for 12–15 minutes, until deeply golden and sweet; stir in the turmeric, cinnamon, and nutmeg and cook for 1 minute. Season the meat with salt and pepper; add to the pot and brown for 4–5 minutes per side, just for colour; lift onto a plate. Add the walnut paste to the pot and stir with a wooden spoon for 3 minutes, until it starts releasing oil and smells toasted — this is the step that builds the sauce's depth. Pour in 1 litre of hot stock, return the meat with its juices, and simmer uncovered over low heat for 30–40 minutes, stirring often so the nut paste does not scorch. Add the pomegranate molasses and brown sugar; taste: the sauce should be tart-sweet and deeply savoury; continue to simmer over low heat for another 30–40 minutes, until the meat is fully tender, the sauce has darkened to almost black, and walnut oil rises to the surface. Adjust with salt, more molasses (for tartness) or sugar (to round it); serve over warm basmati rice, scattered with fresh pomegranate seeds."}},{"id":106,"origin":{"en":"Philippines","ro":"Filipine"},"name":{"en":"Kare-Kare","ro":"Kare-Kare"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["1.2kg oxtail, cut at the joints (or bone-in beef shank)","200g unsweetened peanut butter (or 250g roasted peanuts, ground)","2 tbsp annatto (achuete) seeds — or 1 tbsp annatto powder","4 tbsp raw rice, toasted in a dry pan and ground","1 large onion, finely chopped","6 garlic cloves, minced","1 large eggplant, cut into quarters","200g long green beans (sitaw), cut into 7 cm lengths","1 large bok choy or 200g pechay, halved lengthwise","1.5L water (or beef stock)","60ml vegetable oil","salt to taste","bagoong (Filipino shrimp paste), to serve","steamed rice, to serve"],"ro":["1,2kg coadă de vită, tăiată în bucăți la articulație (sau pulpă de vită cu os)","200g pastă de arahide neîndulcită (sau 250g arahide prăjite, măcinate)","2 linguri semințe de annatto (achiote) — sau 1 lingură pudră de annatto","4 linguri orez crud, prăjit într-o tigaie uscată și măcinat","1 ceapă mare, tocată fin","6 căței de usturoi, tocați","1 vânătă mare, tăiată sferturi","200g fasole verde lungă, tăiată în bucăți de 7 cm","1 bok choy mare sau 200g pak choi, tăiat pe lungime","1,5L apă (sau supă de vită)","60ml ulei vegetal","sare după gust","bagoong (pastă de creveți filipineză) pentru servit","orez fiert, pentru servit"]},"howIsMade":{"en":"Put the oxtail in a large pot with 1.5L water; bring to a boil, skim the foam, and boil for 5 minutes; drain and rinse the meat for a clear broth. Return the meat to the pot with 1.5L fresh water (or beef stock) and simmer gently for 2.5–3 hours, until the meat falls almost off the bone; lift out the meat and reserve 1L of the broth. Steep the annatto seeds in 3 tbsp hot water for 10 minutes, then strain to a deep red-orange liquid (or dissolve the annatto powder directly). In a clean pot, heat 60ml oil; sauté the onion for 5 minutes, add the garlic and cook 1 minute more. Stir in the peanut butter, annatto liquid, and 1L of the reserved broth; whisk to keep it smooth; simmer 5 minutes, then add the toasted ground rice — the sauce will begin to thicken visibly. Return the meat to the sauce and simmer over low heat for 10–15 minutes, loosening with more broth if it becomes too thick; season with salt (sparingly — the bagoong at the table is very salty). Add the eggplant quarters and long beans, simmer 5 minutes; lay the bok choy on top, cover, and cook for another 3 minutes, until the vegetables are tender but still vibrant. Serve in deep bowls over steamed rice, with bagoong in a small bowl alongside — each diner stirs in as much as they like."}},{"id":107,"origin":{"en":"Portugal","ro":"Portugalia"},"name":{"en":"Francesinha","ro":"Francesinha"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["8 thick slices white bread (sandwich loaf)","400g rib-eye or sirloin steak, cut into 4 thin slices","4 linguiça or smoked sausage links, halved lengthwise","8 slices cooked ham","8 slices spicy salami or chouriço","12 slices Cheddar or Gouda, melting type","4 eggs, for topping","30g butter","oil for frying eggs","For the sauce:","400ml lager beer","200ml beef stock","200g tomato paste","60ml whisky or brandy","1 small onion, finely chopped","2 garlic cloves, minced","1 bay leaf","1/2 tsp chili flakes (or piri-piri)","1 tbsp flour","salt, pepper, sugar to taste","fries, to serve"],"ro":["8 felii groase de pâine albă (tip toast)","400g antricot sau mușchi de vită, în 4 felii subțiri","4 cârnați linguiça (sau cabanos afumat), tăiați pe lungime","8 felii de șuncă (presunto) fiartă","8 felii salami picant (chouriço)","12 felii brânză cheddar sau Gouda topit","4 ouă (pentru deasupra)","30g unt","ulei pentru prăjit ouăle","Pentru sos:","400ml bere blondă","200ml bulion de vită","200g pastă de roșii","60ml whisky sau brandy","1 ceapă mică, tocată","2 căței de usturoi, tocați","1 frunză de dafin","1/2 linguriță fulgi de chili (sau piri-piri)","1 lingură făină","sare, piper, zahăr după gust","cartofi prăjiți, pentru servit"]},"howIsMade":{"en":"Make the sauce first: heat 1 tbsp of the butter in a saucepan, sauté the onion for 5 minutes, add the garlic and 1 tbsp flour, cook for 1 minute; stir in the tomato paste and cook for 2 minutes. Pour in the beer and whisky, simmer 2 minutes to burn off the alcohol; add the beef stock, bay leaf, chili flakes, a pinch each of salt and sugar; simmer over low heat for 25–30 minutes, until the sauce is thick and glossy; strain for a smooth finish. Season the steak slices with salt and pepper; melt the remaining butter in a frying pan and sear the steak for 1.5 minutes per side, until browned; lift out. In the same pan, fry the linguiça halves for 2–3 minutes per side, until coloured. For each sandwich, toast 2 slices of bread in butter or oil on both sides (1 minute per side); layer: 1 slice bread, 2 slices ham, 1 slice steak, 2 slices salami, 2 linguiça halves, top with second slice of bread; press gently. Place the sandwiches in a greased baking dish; cover each with 3 slices of cheese and slide under a grill at 220°C for 3–4 minutes, until the cheese melts, bubbles and browns in spots. Fry 1 egg per sandwich in oil, leaving the yolk runny. Set each sandwich in a deep plate, place a fried egg on top of the cheese, and pour the hot sauce generously around the sandwich — it should pool at the base of the plate; serve immediately with fries on the side."}},{"id":109,"origin":{"en":"Peru","ro":"Peru"},"name":{"en":"Arroz Chaufa","ro":"Arroz Chaufa"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"latin","ingredients":{"en":["500g long-grain rice, cooked and cooled (preferably day-old)","300g chicken breast or pork loin, cut into 1.5 cm cubes","3 large eggs, beaten","1 red bell pepper, finely diced","6 spring onions, white parts finely sliced, green parts reserved","3 garlic cloves, minced","20g fresh ginger, finely minced","60ml soy sauce","1 tbsp oyster sauce","1 tbsp toasted sesame oil","60ml neutral vegetable oil","1 tsp ají amarillo paste (or 1/2 tsp chili powder)","salt and white pepper to taste"],"ro":["500g orez cu bob lung fiert și răcit (preferabil de o zi)","300g piept de pui sau pulpă de porc, tăiat cuburi de 1,5 cm","3 ouă mari, bătute","1 ardei kapia roșu, tăiat cuburi mici","6 cepe verzi, partea albă tăiată fin, verdele păstrat","3 căței de usturoi, tocați","20g ghimbir proaspăt, tocat fin","60ml sos de soia","1 lingură sos de stridii","1 lingură ulei de susan","60ml ulei vegetal neutru","1 linguriță aji amarillo pastă (sau 1/2 linguriță pudră de chili)","sare și piper alb după gust"]},"howIsMade":{"en":"Beat the eggs with a pinch of salt; heat 1 tbsp of vegetable oil in a wok over medium heat, pour in the eggs, and quickly make a thin omelette by stirring; tip onto a plate and cut into small cubes; set aside. With the wok very hot, add another 1 tbsp oil; stir-fry the meat with a pinch of salt for 3–4 minutes, until browned at the edges and cooked through; move to the plate with the eggs. Pour the remaining vegetable oil into the wok and heat until it just begins to smoke; add the garlic, ginger, and bell pepper, and stir-fry for 30 seconds, until fragrant. Add the white parts of the spring onions and the ají amarillo paste; stir-fry for 30 seconds, letting the flavours infuse the oil. Add the cold rice; use a spatula to break it into small pieces, pressing it against the bottom of the wok between tosses for 3–4 minutes, until every grain is separate and you hear a slight sizzle. Pour the soy sauce and oyster sauce over the rice, tossing for 1 minute to distribute evenly and pick up colour; return the meat and egg to the wok. Turn off the heat; drizzle with the sesame oil and add the green parts of the spring onions; season with white pepper; serve immediately, hot, straight from the wok."}},{"id":110,"origin":{"en":"Singapore","ro":"Singapore"},"name":{"en":"Chili Crab","ro":"Chili Crab"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"en":["2 live mud crabs (1.5kg total), cleaned and halved at the joints","4 tbsp tomato paste","3 tbsp sambal oelek (or chili paste)","2 tbsp sweet chili sauce","60ml ketchup","30g fresh ginger, grated","6 garlic cloves, minced","2 large eggs, beaten","3 spring onions, chopped","1 tbsp rice vinegar","2 tsp sugar","1 tsp salt","500ml chicken stock (or water)","60ml vegetable oil","1 tbsp cornstarch mixed with 2 tbsp water","fried mantou (Chinese buns), to serve"],"ro":["2 crabi de noroi vii (1,5kg în total), curățați și tăiați în jumătăți la articulații","4 linguri pastă de roșii","3 linguri sos sambal oelek (sau pastă de chili)","2 linguri sos dulce de chili","60ml ketchup","30g ghimbir proaspăt, ras","6 căței de usturoi, tocați","2 ouă mari, bătute","3 cepe verzi, tocate","1 lingură oțet de orez","2 lingurițe zahăr","1 linguriță sare","500ml supă de pui (sau apă)","60ml ulei vegetal","1 lingură amidon de porumb amestecat cu 2 linguri apă","mantou prăjit (chifle chinezești), pentru servit"]},"howIsMade":{"en":"Place the crabs in the freezer for 30 minutes to humanely stun them; clean them, lift off the top shell, remove the soft inner organs, and chop the crab in half at the joints; crack the claws with the back of a knife so the flavour penetrates. Beat the eggs in a small bowl; in another bowl, stir together the tomato paste, sambal, sweet chili sauce, ketchup, vinegar, sugar and salt — this is the sauce base. Heat 60ml of oil in a large wok or deep pot over high heat; add the crab pieces and stir-fry for 3–4 minutes, turning, until the shells turn red; lift onto a plate. In the same oil, sauté the grated ginger and garlic for 30 seconds, until very fragrant. Pour in the tomato-paste mixture and 500ml chicken stock; bring to a boil, adjust with more sambal for more heat. Return the crab pieces, cover the wok and simmer for 8–10 minutes, turning once halfway, until the meat is fully cooked and tender. Stir the cornstarch slurry into the sauce in a thin stream so the sauce thickens to a glossy coat; pour the beaten eggs around the wok in a spiral without stirring — they will set as silky ribbons; wait 30 seconds, then fold once. Scatter with the chopped spring onions; serve immediately on a large platter with fried mantou alongside to soak up the sauce."}},{"id":111,"origin":{"en":"Mexico","ro":"Mexic"},"name":{"en":"Tamale","ro":"Tamale"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"mexican","ingredients":{"en":["20–24 dried corn husks","500g masa harina (nixtamalized corn flour)","250g pork lard, at room temperature","500ml warm chicken stock","1 tbsp baking powder","2 tsp salt","For the filling:","500g boneless pork shoulder, simmered and shredded","4 dried guajillo chilies, stems and seeds removed","2 dried ancho chilies, stems and seeds removed","1 small onion, quartered","3 garlic cloves","1 tsp ground cumin","1 tsp Mexican oregano","2 tbsp vegetable oil","salt to taste","red or green salsa, to serve"],"ro":["20–24 foi de porumb uscate (chiote)","500g masa harina (făină de porumb nixtamalizată)","250g untură de porc, la temperatura camerei","500ml supă de pui caldă","1 lingură praf de copt","2 lingurițe sare","Pentru umplutură:","500g pulpă de porc dezosată, fiartă și mărunțită","4 ardei iuți guajillo uscați, fără semințe","2 ardei iuți ancho uscați, fără semințe","1 ceapă mică, tăiată sferturi","3 căței de usturoi","1 linguriță chimion măcinat","1 linguriță oregano mexican","2 linguri ulei vegetal","sare după gust","salsă roșie sau verde, pentru servit"]},"howIsMade":{"en":"Soak the corn husks in warm water for 30 minutes, until pliable; weight them down with a plate so they stay submerged. Make the sauce: toast the guajillo and ancho chilies in a dry pan for 1 minute per side, until fragrant; cover with hot water for 15 minutes; blend the rehydrated chilies with the onion, garlic, cumin, oregano and 250ml of the soaking liquid; strain the sauce. Heat 2 tbsp oil in a pan, pour in the chili sauce and simmer for 8–10 minutes, until thickened; add the shredded pork, season with salt and cook another 5 minutes; let it cool. Beat the lard with a mixer for 3 minutes, until fluffy and pale; add the baking powder and salt, mix 30 seconds more. Add the masa harina alternately with warm chicken stock, beating continuously; the dough should be light, fluffy, and cling to the spatula; test by dropping a small ball into cold water — it should float. Drain the corn husks; for each tamale, spread 3 tbsp of dough in a thin layer on a husk, leaving a 2 cm border on the sides and 5 cm at the top; place 2 tbsp filling down the centre. Fold the sides of the husk over the filling, then fold the narrow end up, leaving the top open; stand the tamales vertically in a steamer basket, open ends up. Steam for 60–75 minutes, until the dough peels cleanly away from the husk when you open one; let them rest 10 minutes before serving; serve warm with red or green salsa alongside."}},{"id":112,"origin":{"en":"Thailand","ro":"Thailanda"},"name":{"en":"Tom Yum","ro":"Tom Yum"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"thai","ingredients":{"en":["1L chicken or seafood stock","300g raw prawns, peeled and deveined","2 stalks lemongrass, cut into 3cm pieces and bruised","30g galangal (or ginger), thinly sliced","6 kaffir lime leaves","3–4 Thai red chillies, halved","200g oyster or button mushrooms, sliced","3 tbsp fish sauce","2 tbsp fresh lime juice","1 tbsp palm sugar","2 tbsp tom yum paste (optional)","1 spring onion stalk, to garnish","Fresh coriander to serve"],"ro":["1 L supă de pui sau stoc de fructe de mare","300g creveți cruzi, curățați","2 tulpini lemongrass, secționate în bucăți de 3 cm și zdrobite","30g galangal (sau ghimbir), felii subțiri","6 frunze de kaffir lime","3–4 ardei iuți roșii thailandezi, tăiați pe jumătate","200g ciuperci pleurotus sau champignon, feliate","3 linguri sos de pește","2 linguri suc proaspăt de lime","1 lingură zahăr de palmier","2 linguri pastă tom yum (opțional)","1 tulpină ceapă verde, pentru servire","Coriandru proaspăt, pentru servire"]},"howIsMade":{"en":"Bring 1L of stock to a gentle simmer in a large pot. Add the bruised lemongrass stalks, sliced galangal, and kaffir lime leaves; simmer for 10 minutes to infuse the aromatics and turn the broth deeply fragrant. Stir in the tom yum paste (if using), halved chillies, and sliced mushrooms; cook for 3–4 minutes, until the mushrooms soften slightly. Add the prawns and cook for exactly 2–3 minutes — they should turn pink and curl; do not overcook or they will become rubbery. Take the pot off the heat; stir in 3 tbsp fish sauce, 2 tbsp fresh lime juice, and 1 tbsp palm sugar. Taste and adjust the balance: the soup should be sour, salty, spicy, and lightly sweet all at once; add more lime for sharpness or more fish sauce for salt. Serve immediately in deep bowls, scattered with spring onion and fresh coriander; the lemongrass, galangal, and lime leaves are aromatics and are not meant to be eaten."}},{"id":113,"origin":{"en":"Argentina","ro":"Argentina"},"name":{"en":"Milanesa","ro":"Milanesa"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"en":["4 thin beef steaks (top round or sirloin), about 150g each","2 large eggs","2 garlic cloves, finely minced","20g fresh parsley, finely chopped","150g dried breadcrumbs (panko works for a lighter crust)","100g plain flour","1 tsp salt","1/2 tsp freshly ground black pepper","500ml vegetable oil, for frying","1 lemon, cut into wedges, to serve"],"ro":["4 felii subțiri de vită (vrăbioară sau pulpă), aproximativ 150g fiecare","2 ouă mari","2 căței de usturoi, tocați fin","20g pătrunjel proaspăt, tocat","150g pesmet uscat (eventual panko pentru o crustă mai aerată)","100g făină simplă","1 linguriță sare","1/2 linguriță piper negru proaspăt măcinat","500ml ulei vegetal, pentru prăjit","1 lămâie, tăiată felii, pentru servit"]},"howIsMade":{"en":"Place the beef slices between two sheets of cling film; pound with a meat mallet until 5 mm thick; season with half the salt and pepper on both sides. Beat the eggs in a wide shallow bowl with the minced garlic, parsley, and the remaining salt and pepper. Set up two shallow plates: one with the flour, one with the breadcrumbs; breading line: flour → beaten egg → breadcrumbs. Dip each slice in flour, shaking off the excess, then in the egg mixture (let it drip for 2 seconds), then press into the breadcrumbs on both sides; the crumbs should fully coat the meat. Let the breaded slices rest on a wire rack for 10 minutes — the breading adheres better this way. Heat 1 cm of oil in a large frying pan to 175°C (use a thermometer or test with a bread cube — it should brown in 30 seconds). Fry the slices one or two at a time for 2 minutes per side, until the crust is deep golden and the meat is tender; drain on a rack over a tray (not on paper — it steams the crust). Serve immediately with lemon wedges to squeeze over the crust just before eating."}},{"id":114,"origin":{"en":"Cambodia","ro":"Cambodgia"},"name":{"en":"Lok Lak","ro":"Lok Lak"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"vietnamese","ingredients":{"en":["600g beef tenderloin or sirloin, cut into 2.5 cm cubes","3 tbsp oyster sauce","2 tbsp soy sauce","1 tbsp palm sugar (or brown sugar)","1 tbsp tomato paste","6 garlic cloves, minced","2 tsp freshly ground black pepper (generous)","3 tbsp vegetable oil","1 large onion, thinly sliced","4 eggs (for frying)","1 small head of lettuce (iceberg or romaine), leaves separated","2 tomatoes, sliced","1 cucumber, sliced","For the dipping sauce:","juice of 2 limes","1 tsp coarse salt","1/2 tsp freshly ground black pepper","steamed rice, to serve"],"ro":["600g vrăbioară sau mușchi de vită, tăiată cuburi de 2,5 cm","3 linguri sos de stridii","2 linguri sos de soia","1 lingură zahăr de palmier (sau zahăr brun)","1 lingură pastă de roșii","6 căței de usturoi, tocați","2 lingurițe piper negru proaspăt măcinat (din belșug)","3 linguri ulei vegetal","1 ceapă mare, tăiată felii subțiri","4 ouă (pentru ochiuri)","1 cap mic de salată verde (iceberg sau romană), frunzele separate","2 roșii, feliate","1 castravete, feliat","Pentru sos:","zeama de la 2 lime","1 linguriță sare grunjoasă","1/2 linguriță piper negru proaspăt măcinat","orez fiert, pentru servit"]},"howIsMade":{"en":"In a bowl, combine the beef with oyster sauce, soy sauce, palm sugar, tomato paste, half the garlic, and 1 tsp black pepper; let it marinate at room temperature for 30 minutes. Make the dipping sauce: stir lime juice, coarse salt, and the remaining pepper in a small bowl; set aside. Arrange the serving platter: lettuce leaves, tomato slices, and cucumber slices laid out on a large platter. Fry 4 eggs in a pan with a little oil, leaving the yolks runny; set them aside on a warm plate. Heat 3 tbsp oil in a large wok over very high heat until it just begins to smoke. Add the sliced onion and remaining garlic, stir-fry for 30 seconds, until fragrant. Add the marinated beef in a single layer; leave it untouched for 1 minute to sear, then stir-fry vigorously for 2 more minutes; the beef should be charred outside and pink inside — do not overcook. Spoon the hot beef over the salad platter, place a fried egg on each portion; serve immediately with the lime dipping sauce alongside and steamed rice for each diner."}},{"id":115,"origin":{"en":"Uzbekistan","ro":"Uzbekistan"},"name":{"en":"Manti","ro":"Manti"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["For the dough:","500g all-purpose flour","250ml warm water","1 egg","1 tsp salt","For the filling:","600g coarsely chopped beef or lamb (knife-cut, not ground)","3 large onions, finely chopped (use a 1:1 onion-to-meat ratio by volume — essential)","1 tsp ground cumin","1 tsp freshly ground black pepper","2 tsp salt","100g lamb-tail fat or pork lardons in tiny cubes (optional, traditional)","To serve:","100g butter","200g full-fat yogurt (or sour cream)","1 tbsp sweet paprika","fresh coriander or parsley leaves, chopped"],"ro":["Pentru aluat:","500g făină","250ml apă caldă","1 ou","1 linguriță sare","Pentru umplutură:","600g carne tocată grosier de vită sau miel","3 cepe mari, tăiate fin (foarte importantă proporția 1:1 cu carnea după volum)","1 linguriță chimion măcinat","1 linguriță piper negru proaspăt măcinat","2 lingurițe sare","100g grăsime de coadă de oaie sau slănină tăiată cuburi mici (opțional, dar tradițional)","Pentru servit:","100g unt","200g iaurt gras (sau smântână)","1 lingură boia dulce","frunze de coriandru sau pătrunjel proaspăt, tocate"]},"howIsMade":{"en":"Make the dough: in a large bowl, combine the flour with salt; beat the egg with warm water and pour over the flour; knead for 10 minutes until smooth and elastic; cover with cling film and rest for 30 minutes. Make the filling: combine the knife-cut meat, onions, cumin, salt, pepper, and lamb-tail fat (if using); mix by hand until uniform; the onions will release liquid — keep it in. Divide the dough into 4 pieces; roll each as thin as possible (1–2 mm); cut into 10x10 cm squares. Place a generous tablespoon of filling in the centre of each square; lift the four corners of the dough up over the filling and pinch them together at the top, then pinch the four side edges closed to form a sealed parcel. Brush a steamer basket with oil; arrange the manti in a single layer, not touching (they will swell as they cook). Steam for 35–40 minutes over medium heat with the water at a steady boil; the dough should become translucent and slightly glossy when done. Melt the butter in a small saucepan, stir in the sweet paprika; let it rest 1 minute off the heat. Arrange the manti on a large platter, scatter with chopped parsley, and spoon the paprika butter over the top; serve with yogurt in a small bowl alongside."}},{"id":116,"origin":{"en":"Georgia","ro":"Georgia"},"name":{"en":"Chakhokhbili","ro":"Chakhokhbili"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["1.2kg bone-in chicken thighs and drumsticks","4 large onions (about 600g), thinly sliced — a 1:1 onion-to-chicken ratio by weight is traditional","6 ripe tomatoes (about 700g), peeled and roughly chopped","1 red bell pepper, deseeded and diced","6 garlic cloves, minced","2 tbsp tomato paste","1 tsp khmeli-suneli (Georgian spice blend)","1/2 tsp ground blue fenugreek (utskho suneli)","1 tsp dried savory or marjoram","30g fresh coriander, leaves and stems separated, both chopped","20g fresh parsley, chopped","1 tsp salt","freshly ground black pepper","1 tbsp white wine vinegar (optional, for brightness)","Georgian flatbread or any sturdy bread, to serve"],"ro":["1,2kg pulpe de pui cu os (pulpe superioare și ciocănele)","4 cepe mari (aproximativ 600g), feliate subțire — raportul 1:1 ceapă:pui după greutate este tradițional","6 roșii coapte (aproximativ 700g), decojite și tăiate grosier","1 ardei kapia roșu, fără semințe, tăiat cuburi","6 căței de usturoi, tocați","2 linguri pastă de roșii","1 linguriță khmeli-suneli (amestec de condimente georgian)","1/2 linguriță schinduf albastru măcinat (utskho suneli)","1 linguriță cimbru de iarnă uscat (sau maghiran)","30g coriandru proaspăt, frunze și tulpini separate, ambele tocate","20g pătrunjel proaspăt, tocat","1 linguriță sare","piper negru proaspăt măcinat","1 lingură oțet de vin alb (opțional, pentru prospețime)","pâine georgiană sau alt tip de pâine rustică, pentru servit"]},"howIsMade":{"en":"Heat a heavy dry pot over medium-high heat — no oil; lay the chicken pieces skin-side down and cook for 6–8 minutes per side, until deeply golden; the chicken renders its own fat — this is the dry-brown step that defines chakhokhbili. Lift the chicken onto a plate; the pot should hold 3–4 tbsp of rendered fat — keep it. Add the sliced onions to the rendered fat; cook over medium heat for 12–15 minutes, stirring often, until deeply golden and soft. Stir in the bell pepper, half the garlic, the chopped coriander stems, khmeli-suneli, blue fenugreek, and savory; cook 2 minutes, until fragrant. Add the tomato paste and cook 2 more minutes, until it darkens; add the chopped tomatoes and return the chicken with its juices to the pot. Reduce the heat to low, cover, and braise for 35–45 minutes, turning the chicken once halfway; the chicken should be falling off the bone and the tomatoes broken down into a thick, glossy sauce. Lift the lid and simmer uncovered 5 more minutes to thicken the sauce if needed; stir in the remaining garlic, the vinegar (if using), and most of the chopped coriander leaves and parsley. Taste, adjust salt and pepper; serve hot in shallow bowls with Georgian flatbread (or any sturdy bread) to mop up the sauce; scatter the remaining herbs on top."}},{"id":117,"origin":{"en":"Peru","ro":"Peru"},"name":{"en":"Lomo Saltado","ro":"Lomo Saltado"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"latin","ingredients":{"en":["600g beef sirloin or tenderloin, cut into 1 cm strips","3 large potatoes (about 700g), cut into thick fries","1 large red onion, cut into 1 cm-thick wedges","2 medium Roma tomatoes, cut into wedges (or thick slices)","1 yellow ají amarillo pepper (or 1 red bell pepper + 1 tsp ají amarillo paste)","4 garlic cloves, minced","2 tbsp fresh ginger, grated","3 tbsp soy sauce","2 tbsp red wine vinegar","30g fresh coriander, roughly chopped","3 tbsp vegetable oil (plus 500ml for frying potatoes)","1 tsp salt","1/2 tsp freshly ground black pepper","400g white basmati rice, cooked","1 lime, cut into wedges (optional)"],"ro":["600g vrăbioară sau mușchi de vită, tăiată fâșii de 1 cm grosime","3 cartofi mari (aproximativ 700g), tăiați cartofi prăjiți groși","1 ceapă roșie mare, feliată în pene groase de 1 cm","2 roșii Roma medii, tăiate sferturi (sau felii groase)","1 ardei aji amarillo galben (sau 1 ardei kapia + 1 linguriță pastă aji amarillo)","4 căței de usturoi, tocați","2 linguri ghimbir proaspăt, ras","3 linguri sos de soia","2 linguri oțet de vin roșu","30g coriandru proaspăt, tocat grosier","3 linguri ulei vegetal (plus 500ml pentru cartofi)","1 linguriță sare","1/2 linguriță piper negru proaspăt măcinat","400g orez basmati alb, gătit","1 lime, tăiat felii (opțional)"]},"howIsMade":{"en":"Season the beef strips with salt and pepper; let them rest for 10 minutes at room temperature — they will sear better at high heat. Heat 500ml of oil in a deep pan to 175°C; fry the potatoes for 6–7 minutes until golden and crisp; drain on a rack and salt lightly while hot. Heat a large wok or cast-iron pan over very high heat with 2 tbsp of vegetable oil — the oil should just begin to smoke; this is the critical step: the pan must be very hot for the Peruvian \"wok hei\" effect. Add the beef in a single layer; leave untouched for 30 seconds to sear, then stir-fry vigorously for 90 seconds — the beef should be browned outside but still pink in the centre; lift onto a plate. In the same wok, add 1 tbsp more oil; stir-fry the onion wedges and ají amarillo for 90 seconds — the onion should stay crisp, not soft. Add the garlic and ginger, stir-fry for 30 seconds until fragrant; add the tomatoes and cook for 1 minute — they should soften slightly but not break down. Pour the soy sauce and red wine vinegar around the edge of the pan (they will steam and create aromatic smoke); return the beef with its juices and add the fries; toss vigorously for 30 seconds, until everything is coated. Turn off the heat, scatter the chopped coriander, and toss once; serve immediately over warm basmati rice with lime wedges on the side."}},{"id":118,"origin":{"en":"Morocco","ro":"Maroc"},"name":{"en":"Chicken Tagine","ro":"Chicken Tagine"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"en":["1.2 kg bone-in skin-on chicken thighs (about 8 pieces), trimmed of excess skin","2 large yellow onions (~400 g), one finely grated for the marinade, one thinly sliced for the stew base","6 garlic cloves, minced","4 cm fresh ginger, finely grated","1 tsp ground cumin + 1 tsp ground ginger + 1 tsp ground coriander + 0.5 tsp ground turmeric + 0.5 tsp sweet paprika + 0.5 tsp ground white pepper + a generous pinch of saffron threads (8-10 strands, bloomed in 2 tbsp hot water)","1 small bunch fresh coriander (cilantro), about 25 g, finely chopped (half for the marinade, half for garnish)","1 small bunch flat-leaf parsley, about 25 g, finely chopped (half for the marinade, half for garnish)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","3 tbsp olive oil + 1 tbsp unsalted butter (or smen for the most traditional flavour)","2 preserved lemons, rinsed, flesh discarded, peel cut into thin strips (about 80 g of peel total)","150 g green Moroccan olives (or Castelvetrano), rinsed, pitted if large","400 ml hot water or low-salt chicken stock","Juice of half a fresh lemon (added at the end, to brighten)","To serve: warm khobz flatbread to mop up the sauce, or steamed couscous"],"ro":["1.2 kg pulpe de pui cu os și piele (aproximativ 8 bucăți), curățate de pielea în exces","2 cepe galbene mari (~400 g), una rasă fin pentru marinadă, una tăiată felii subțiri pentru baza tocăniței","6 căței de usturoi, tocați","4 cm ghimbir proaspăt, ras fin","1 linguriță chimion măcinat + 1 linguriță ghimbir măcinat + 1 linguriță coriandru măcinat + 0.5 linguriță turmeric + 0.5 linguriță boia dulce + 0.5 linguriță piper alb măcinat + un vârf generos de șofran (8-10 fire, înflorite în 2 linguri apă fierbinte)","1 legătură mică de coriandru proaspăt (cilantro), ~25 g, tocat fin (jumătate pentru marinadă, jumătate pentru garnitură)","1 legătură mică de pătrunjel cu frunza lată, ~25 g, tocat fin (jumătate pentru marinadă, jumătate pentru garnitură)","1.5 linguriță sare + 0.5 linguriță piper negru proaspăt măcinat","3 linguri ulei de măsline + 1 lingură unt nesărat (sau smen pentru aroma cea mai tradițională)","2 lămâi conservate, clătite, pulpa îndepărtată, coaja tăiată fâșii subțiri (aproximativ 80 g de coajă)","150 g măsline verzi marocane (sau Castelvetrano), clătite, fără sâmburi dacă sunt mari","400 ml apă fierbinte sau supă de pui cu puțină sare","Zeama de la jumătate de lămâie proaspătă (adăugată la final, pentru prospețime)","Pentru servit: pâine plată khobz caldă pentru a culege sosul, sau couscous aburit"]},"howIsMade":{"en":"MARINATE THE CHICKEN: in a large bowl combine the grated onion, garlic, ginger, all the dry spices, the bloomed saffron with its water, half the chopped coriander, half the parsley, 1.5 tsp salt, 0.5 tsp black pepper and 1.5 tbsp olive oil. Add the chicken thighs and massage the marinade thoroughly into and under the skin. Cover and refrigerate at least 1 hour; 4 hours is markedly better, overnight is best.\n\nSEAR AND BUILD THE BASE: heat the remaining 1.5 tbsp olive oil and the butter in a tagine vessel or wide heavy-bottomed pot over medium heat. Add the sliced onion and cook 8 minutes, stirring, until soft and lightly golden. Push the onions to one side, lay the marinated chicken skin-side down and sear 3-4 minutes until the skin is deep golden, then flip.\n\nSIMMER: scrape every drop of marinade from the bowl into the pot. Pour in the 400 ml hot water or stock. Bring to a gentle simmer, then cover and reduce the heat to its lowest setting. Cook 30 minutes — the conical lid traps the steam that defines a tagine.\n\nADD PRESERVED LEMON AND OLIVES: lift the lid, tuck the preserved-lemon strips and green olives around (not on top of) the chicken — both release brine, so resist the urge to stir vigorously. Re-cover and cook 10-15 minutes more, until the chicken reads 75 °C / 170 °F at the thickest part and the sauce has reduced to a glossy, brothy consistency that coats the back of a spoon.\n\nFINISH AND SERVE: uncover, squeeze the half-lemon juice over the dish, and scatter the reserved coriander and parsley on top. Taste before salting — preserved lemons and olives both contribute salt, so the dish often needs nothing more. Serve straight from the tagine with warm khobz flatbread to mop up the sauce, or alongside steamed couscous."}},{"id":120,"origin":{"en":"Venezuela","ro":"Venezuela"},"name":{"en":"Arepa","ro":"Arepa"},"category":{"en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"latin","ingredients":{"en":["For the dough:","400g harina P.A.N. (pre-cooked white corn flour)","500ml warm water","1 tsp salt","2 tbsp vegetable oil","For reina pepiada (classic chicken-avocado filling):","2 chicken breasts (about 500g), poached and shredded","1 ripe avocado, diced","3 tbsp mayonnaise","1 tbsp lime juice","1 spring onion, finely sliced","10g fresh coriander, chopped","salt and pepper","Other popular fillings:","200g fresh white cheese (queso fresco), sliced","100g shredded beef (carne mechada)","vegetable oil for griddle"],"ro":["Pentru aluat:","400g harina P.A.N. (făină de porumb pre-fiartă)","500ml apă caldă","1 linguriță sare","2 linguri ulei vegetal","Pentru reina pepiada (umplutura clasică):","2 piepți de pui (aproximativ 500g), fierți și mărunțiți","1 avocado copt, tăiat cuburi","3 linguri maioneză","1 lingură zeamă de lime","1 ceapă verde, tăiată fin","10g coriandru proaspăt, tocat","sare și piper","Alte umpluturi populare:","200g brânză albă proaspătă (queso fresco), feliată","100g carne de vită mărunțită (carne mechada)","ulei vegetal pentru prăjit pe plită"]},"howIsMade":{"en":"In a large bowl, combine 500ml warm water with salt and oil; gradually add 400g harina P.A.N., mixing with your hand or a spatula. Knead for 3–4 minutes until the dough is smooth and pliable; cover with a cloth and let it rest for 5 minutes — the flour absorbs the water and the dough becomes easier to shape. Test the dough: it should be slightly sticky but not raw; if it cracks while shaping, add a tablespoon more water. Divide into 8 equal balls (about 100g each); flatten each between your palms into a 8 cm wide, 1.5 cm thick disc, smoothing the edges with damp fingers. Heat a heavy pan or griddle over medium heat with a little oil; add the arepas and cook for 4–5 minutes per side, until a golden crust with darker spots forms. Transfer to a baking tray and finish in a preheated 180°C oven for 10–15 minutes, until they sound hollow when tapped lightly; this is the doneness test. While the arepas rest, make the reina pepiada: mix the shredded chicken with avocado, mayonnaise, lime juice, spring onion, coriander, salt, and pepper. Slice each arepa horizontally with a sharp knife (like a pita pocket), without cutting all the way through; stuff with reina pepiada (or your chosen filling); serve immediately while the arepa is warm and crisp on the outside."}},{"id":121,"origin":{"en":"Finland","ro":"Finlanda"},"name":{"en":"Karelian Pie","ro":"Karjalanpiirakka"},"category":{"en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"en":["For the dough:","150g rye flour","100g plain white flour","150ml cold water","1/2 tsp salt","1 tbsp vegetable oil","For the rice porridge filling:","200g short-grain rice (pudding rice)","1 litre whole milk","1/2 tsp salt","20g butter","For muna voi (egg butter, classic topping):","100g soft unsalted butter","2 hard-boiled eggs, peeled and finely chopped","1/4 tsp salt","1/4 tsp white pepper"],"ro":["Pentru aluat:","150g făină de secară","100g făină albă","150ml apă rece","1/2 linguriță sare","1 lingură ulei vegetal","Pentru umplutura de orez:","200g orez cu bob rotund (orez pudding)","1 litru lapte integral","1/2 linguriță sare","20g unt","Pentru muna voi (untul de ouă pentru servire):","100g unt moale","2 ouă fierte tari, decojite și tocate fin","1/4 linguriță sare","1/4 linguriță piper alb"]},"howIsMade":{"en":"Make the rice porridge (can be made a day ahead): combine 200g rice with 250ml hot water in a pot; cook 8 minutes over medium heat, until the water is absorbed. Add 1 litre milk and 1/2 tsp salt; simmer over low heat, stirring often, for 35–45 minutes, until the porridge is very creamy and thick; stir in 20g butter and cool completely. For the dough: combine rye flour, white flour, and salt in a bowl; add cold water and oil, knead for 5 minutes until firm but elastic. Divide the dough into 16 equal pieces and roll into balls; on a rye-floured surface, roll each ball into a very thin oval (1 mm thick, 12 cm long). Spoon 1–2 tbsp cold rice porridge into the centre of each oval, leaving a 2 cm border. Lift the dough over the filling on both long sides, leaving the centre exposed; pinch the dough with your fingers to create the characteristic zigzag pleats — this is the traditional Karelian seal. Arrange the pies on a lined baking tray; bake in a preheated 250°C oven for 15–20 minutes, until the edges are golden brown. While the pies bake, make muna voi: mash the soft butter with the chopped eggs, salt, and white pepper; serve the pies warm, generously spread with muna voi over the exposed rice surface."}},{"id":123,"origin":{"en":"Italy","ro":"Italia"},"name":{"en":"Pasta e fagioli","ro":"Pasta e fagioli"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"pasta","pairingsType":"italian","ingredients":{"en":["200g short pasta (ditalini, tubetti, or orecchiette)","400g canned borlotti or cannellini beans, drained (or 200g dried, soaked overnight and cooked)","1 large onion, finely chopped","2 carrots, finely diced","2 celery stalks, finely diced","3 garlic cloves, minced","100g pancetta or bacon, diced (optional)","400g canned chopped tomatoes","2 tbsp tomato paste","1 bay leaf","1 sprig fresh rosemary","1 sprig fresh thyme","1.2L hot chicken or vegetable stock","4 tbsp extra-virgin olive oil","1 piece Parmigiano rind (optional, for flavour)","salt and freshly ground black pepper","grated Parmigiano and extra-virgin olive oil, to serve"],"ro":["200g paste scurte (ditalini, tubetti sau orecchiette)","400g fasole borlotti sau cannellini din conservă, scurse (sau 200g fasole uscată înmuiată peste noapte și fiartă)","1 ceapă mare, tocată fin","2 morcovi, tăiați cuburi mici","2 tulpini de țelină, tăiate cuburi mici","3 căței de usturoi, tocați","100g pancetta sau bacon, tăiat cuburi (opțional)","400g roșii sfărâmate din conservă","2 linguri pastă de roșii","1 frunză de dafin","1 crenguță de rozmarin proaspăt","1 crenguță de cimbru proaspăt","1,2 litri supă de pui sau legume fierbinte","4 linguri ulei de măsline extravirgin","1 bucată coajă de Parmigiano (opțional, pentru aromă)","sare și piper negru proaspăt măcinat","Parmigiano ras și ulei de măsline extravirgin, pentru servit"]},"howIsMade":{"en":"In a large heavy-bottomed pot, heat 3 tbsp olive oil over medium heat; add the diced pancetta (if using) and cook for 5 minutes, until browned and the fat has rendered. Add the onion, carrots, celery and a pinch of salt; sauté for 10–12 minutes, until soft and lightly caramelised — this is the soffritto, the aromatic foundation. Stir in the garlic, tomato paste, rosemary, and thyme; cook for 2 minutes, until the paste darkens. Add the chopped tomatoes, bay leaf, and Parmigiano rind (if using); simmer for 5 minutes over medium heat. Add half the beans whole and the other half mashed with a fork or hand whisk (the traditional texture calls for both); pour in 1.2L hot stock; bring to a boil. Add the pasta and cook for 8–10 minutes over medium heat, stirring often, until al dente; the liquid will thicken as the pasta releases starch. Taste and adjust salt; remove the Parmigiano rind, rosemary, and thyme stems; let the soup rest 5 minutes — it will thicken further into a dense, creamy stew. Serve hot in deep bowls; crown with generous fresh black pepper, a heavy drift of grated Parmigiano, and a final drizzle of extra-virgin olive oil."}},{"id":124,"origin":{"en":"Sri Lanka","ro":"Sri Lanka"},"name":{"en":"Kottu","ro":"Kottu"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"indian","ingredients":{"en":["8 godhamba roti or paratha (about 640 g total), thinly sliced into 1 cm-wide strips","600 g boneless, skinless chicken thigh, cut into 1.5 cm pieces","5 large eggs, lightly beaten with a pinch of salt","2 medium red onions (about 240 g), thinly sliced","1 large leek (about 200 g), trimmed, thinly sliced, and washed","2 small carrots (about 140 g), julienned","3 fresh green chillies, finely sliced (seeded for a milder finish)","2 tbsp finely grated fresh ginger","5 garlic cloves, finely chopped","2 tsp Sri Lankan curry powder","1 tsp ground turmeric","2 tsp Kashmiri chilli powder or sweet paprika","15 fresh curry leaves","400 ml warm chicken or coconut curry sauce","3 tbsp soy sauce","4 tbsp coconut or vegetable oil","1.5 tsp salt, plus more to taste","2 tbsp lime juice, to finish"],"ro":["8 lipii godhamba sau paratha (aproximativ 640 g în total), tăiate în fâșii subțiri de 1 cm lățime","600 g pulpă de pui dezosată, fără piele, tăiată în bucăți de 1,5 cm","5 ouă mari, bătute ușor cu un praf de sare","2 cepe roșii medii (aproximativ 240 g), feliate subțire","1 praz mare (aproximativ 200 g), curățat, feliat subțire și spălat","2 morcovi mici (aproximativ 140 g), tăiați julienne","3 ardei iuți verzi proaspeți, feliați subțire (fără semințe pentru un gust mai blând)","2 linguri ghimbir proaspăt, ras fin","5 căței de usturoi, tocați fin","2 lingurițe pudră de curry srilankez","1 linguriță turmeric măcinat","2 lingurițe pudră de ardei iute Kashmiri sau boia dulce","15 frunze de curry proaspete","400 ml sos de curry de pui sau de cocos, cald","3 linguri sos de soia","4 linguri ulei de cocos sau vegetal","1,5 lingurițe sare, plus după gust","2 linguri suc de lime, pentru finisare"]},"howIsMade":{"en":"Heat 1 tbsp of the oil in a large skillet or wok over medium-high heat; season the chicken with 0.5 tsp of the salt and a pinch of the curry powder; cook for 7–8 minutes, stirring occasionally, until lightly golden and just cooked through (no pink in the centre); transfer to a plate. Add the remaining 3 tbsp of oil to the same pan; when shimmering, add the curry leaves — they will crackle for 5–10 seconds; add the sliced red onions and cook for 3–4 minutes until softened and translucent at the edges but still firm. Add the leek, carrots, and green chillies and stir-fry for 2–3 minutes — the vegetables should remain crisp-tender, not soft. Push the vegetables to one side of the pan; add the ginger and garlic to the open space and cook for 30 seconds, until fragrant but not browned; stir in the remaining curry powder, the turmeric, and the Kashmiri chilli powder; toast for 20–30 seconds until aromatic. Pour the beaten eggs into the centre of the pan and gently scramble for 60–90 seconds until set but still glossy — break the curd into small pieces with the spatula. Return the chicken to the pan along with the sliced roti; toss everything together for 1–2 minutes so the roti picks up colour from the spices and chicken juices. Pour the soy sauce and warm curry sauce around the edge of the pan; use two metal spatulas (or the back of a heavy wooden spoon) and chop-and-toss the mixture vigorously for 3–4 minutes — keep cutting through the pile so the roti strips break down into small irregular pieces and soak up the sauce; the mixture should look glossy and unified, not soupy. Taste and add more salt if needed; squeeze over the lime juice, toss once more, and serve immediately while the kottu still steams, with an extra ladle of curry sauce on the side."}},{"id":125,"origin":{"en":"Latvia","ro":"Letonia"},"name":{"en":"Piragi","ro":"Piragi"},"category":{"en":"Snack","ro":"Gustare"},"servings":8,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["500 g strong white bread flour, plus extra for dusting","250 ml whole milk, gently warmed to 38°C","7 g sachet (2 tsp) instant dry yeast","50 g caster sugar","1 tsp fine sea salt","70 g unsalted butter, melted and slightly cooled","1 large egg, lightly beaten","350 g smoked streaky bacon (or smoked speck), in small 5 mm dice","1 large onion (about 180 g), very finely diced","1 tbsp neutral oil (only if the bacon is very lean)","0.5 tsp freshly ground black pepper","Pinch of caraway seeds, lightly crushed (optional)","1 large egg yolk beaten with 1 tbsp milk, for glazing","Flaky sea salt, for sprinkling (optional)"],"ro":["500 g făină albă de pâine, plus pentru tăvălit","250 ml lapte integral, încălzit ușor la 38°C","1 plic de 7 g (2 lingurițe) drojdie instant uscată","50 g zahăr tos","1 linguriță sare fină de mare","70 g unt nesărat, topit și ușor răcit","1 ou mare, bătut ușor","350 g bacon afumat (sau speck afumat), tăiat cuburi mici de 5 mm","1 ceapă mare (aproximativ 180 g), tocată foarte fin","1 lingură ulei neutru (doar dacă baconul este foarte slab)","0,5 linguriță piper negru proaspăt măcinat","Un vârf de semințe de chimen, ușor zdrobite (opțional)","1 gălbenuș mare bătut cu 1 lingură de lapte, pentru glazură","Fulgi de sare de mare, pentru presărat (opțional)"]},"howIsMade":{"en":"Pour the warm milk into a large bowl, scatter the yeast and sugar over it, and stir lightly; let stand 5–10 minutes until foamy on the surface — this confirms the yeast is alive. Add the melted butter, beaten egg, and salt to the milk; pour in the flour and stir with a wooden spoon until a shaggy dough forms; tip onto a lightly floured surface and knead for 8–10 minutes, until smooth, elastic, and only slightly tacky to the touch. Shape the dough into a ball, place it in a lightly oiled bowl, cover with a damp cloth, and leave to rise in a warm spot for 1 hour to 1 hour 15 minutes, until doubled. Meanwhile, prepare the filling; cook the diced bacon in a dry frying pan over medium heat for 5–6 minutes, stirring often, until the fat has rendered and the edges just begin to colour but the bacon is not crisp; add the onion (and the oil if needed) and cook for another 4–5 minutes, until the onion is translucent but not browned; season with the pepper and caraway; cool completely. Knock back the risen dough and divide it into 24 equal pieces (about 35 g each); roll each piece into a smooth ball, then flatten with a rolling pin into an 8 cm oval, about 4 mm thick. Spoon 1 tsp of cold filling onto one half of each oval, fold the dough over to enclose, and pinch the edges firmly to seal; pull the sealed ends gently toward each other to form the classic crescent shape, with the seam facing down on the tray. Arrange the piragi on two parchment-lined trays, leaving 3 cm between them; cover lightly and let rise for another 20–25 minutes, until visibly puffy; meanwhile heat the oven to 220°C (425°F / fan 200°C). Brush the tops with the egg-yolk glaze, sprinkle with flaky salt if using, and bake for 12–15 minutes — they are ready when the tops are deep golden brown, the seams hold tight, and the bottoms sound hollow when tapped; cool on a rack for 5 minutes and serve warm."}},{"id":126,"origin":{"en":"Vietnam","ro":"Vietnam"},"name":{"en":"Banh Xeo","ro":"Bánh xèo"},"category":{"en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"fish","pairingsType":"vietnamese","ingredients":{"en":["250 g rice flour","30 g cornflour (cornstarch)","1 tsp ground turmeric","0.5 tsp fine sea salt, plus more for the pork","1 tsp caster sugar","400 ml full-fat coconut milk","350 ml cold sparkling water (or cold still water)","4 spring onions, green tops finely sliced (about 30 g)","300 g pork belly or shoulder, cut into 5 mm-thick strips","300 g raw peeled prawns (about 24 medium), deveined","200 g fresh mung bean sprouts","1 medium onion (about 120 g), thinly sliced","60 ml neutral oil (peanut or vegetable), for frying","1 tbsp fish sauce, plus 3 tbsp for the nuoc cham","3 tbsp fresh lime juice","2 tbsp caster sugar (for the nuoc cham)","1 garlic clove, finely minced, and 1 small red chilli, finely sliced (for the nuoc cham)","1 head butter lettuce or romaine, leaves separated, plus a large bunch of fresh herbs (mint, perilla, coriander, Thai basil) and 1 cucumber, julienned, to serve"],"ro":["250 g făină de orez","30 g amidon de porumb","1 linguriță turmeric măcinat","0,5 linguriță sare fină de mare, plus în plus pentru carnea de porc","1 linguriță zahăr tos","400 ml lapte de cocos integral","350 ml apă minerală rece (sau apă plată rece)","4 cepe verzi, părțile verzi feliate subțire (aproximativ 30 g)","300 g piept sau pulpă de porc, tăiat fâșii de 5 mm grosime","300 g creveți cruzi decojiți (aproximativ 24 medii), curățați de venă","200 g germeni proaspeți de fasole mung","1 ceapă medie (aproximativ 120 g), feliată subțire","60 ml ulei neutru (de arahide sau vegetal), pentru prăjit","1 lingură sos de pește, plus 3 linguri pentru nuoc cham","3 linguri suc de lime proaspăt","2 linguri zahăr tos (pentru nuoc cham)","1 cățel de usturoi tocat fin și 1 ardei iute roșu mic feliat subțire (pentru nuoc cham)","1 căpățână de salată verde de unt sau romană, frunze separate, plus o legătură mare de ierburi proaspete (mentă, perilla, coriandru, busuioc thailandez) și 1 castravete tăiat julienne, pentru servit"]},"howIsMade":{"en":"Make the batter at least 30 minutes ahead; whisk together the rice flour, cornflour, turmeric, 0.5 tsp salt, and 1 tsp sugar in a large bowl; pour in the coconut milk and sparkling water and whisk until smooth; stir in the sliced spring-onion greens; cover and rest in the fridge for at least 30 minutes (up to 4 hours) — the resting hydrates the flour for a crisper crepe. While the batter rests, mix the nuoc cham; stir 3 tbsp fish sauce, 3 tbsp lime juice, 2 tbsp sugar, and 4 tbsp warm water in a bowl until the sugar dissolves; add the minced garlic and sliced chilli; set aside. Toss the pork strips with 1 tbsp fish sauce and 0.5 tsp pepper; rinse and pat dry the prawns; wash the bean sprouts and shake dry; arrange the lettuce, herbs, and cucumber on a serving platter. Heat a 24 cm non-stick pan over medium-high heat; add 1 tsp oil, swirl to coat, then add 2–3 prawns and a handful of pork strips; stir-fry for 60–90 seconds until the prawns curl pink and the pork edges are golden but not fully cooked through. Stir the batter, then ladle about 100 ml into the pan, immediately swirling so the batter coats the base in a thin layer and reaches halfway up the sides; drop a small handful of sliced onion over one half of the crepe. Cover with a lid for 60 seconds — the steam helps cook the top; then uncover, drizzle 1 tsp oil around the edge, and cook for a further 2–3 minutes, until the edges turn deep golden and lift cleanly from the pan with a thin spatula. Pile a handful of bean sprouts onto the half topped with pork and prawns; fold the empty half over to form a half-moon, then slide onto a warmed plate; repeat with the remaining batter, prawns, pork, and bean sprouts; you should get 4–5 crepes. Serve immediately, while the crepes are still loud-crispy; to eat: tear a piece, wrap it in lettuce with herbs and cucumber, and dip into the nuoc cham; the crepe should crackle audibly as it bends — if it goes soft, the next one needs a hotter pan and a slightly thinner pour."}},{"id":127,"origin":{"en":"Peru","ro":"Peru"},"name":{"en":"Causa Limeña","ro":"Causa Limeña"},"category":{"en":"Appetizer","ro":"Aperitiv"},"servings":4,"tipType":"fish","pairingsType":"latin","ingredients":{"en":["1 kg yellow Peruvian potatoes (or Yukon Gold or other waxy yellow potatoes), peeled and cut into chunks","60 ml fresh lime juice (about 2 limes)","60 ml neutral oil (sunflower or olive)","2 tbsp ají amarillo paste (or 1 tbsp ají amarillo + 1 tsp Korean gochujang as substitute)","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground white pepper","2 × 160 g tins of high-quality tuna in olive oil, drained (or 320 g cooked shredded chicken breast)","120 g good mayonnaise","2 spring onions, very finely sliced (about 20 g)","1 small celery stalk, finely diced (about 30 g, optional)","0.5 tsp fine sea salt","1 large ripe avocado (about 200 g), sliced 5 mm thick and tossed with 1 tsp lime juice","12 black olives (botija or kalamata), halved and pitted","2 hard-boiled eggs, halved or quartered","Sprigs of fresh coriander or parsley"],"ro":["1 kg cartofi galbeni peruvieni (sau Yukon Gold ori alți cartofi galbeni cu pastă fermă), curățați și tăiați în bucăți","60 ml suc proaspăt de lime (aproximativ 2 lime)","60 ml ulei neutru (de floarea-soarelui sau de măsline)","2 linguri pastă de ají amarillo (sau 1 lingură ají amarillo + 1 linguriță gochujang ca substitut)","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper alb proaspăt măcinat","2 conserve de 160 g de ton de calitate în ulei de măsline, scurse (sau 320 g piept de pui fiert și mărunțit)","120 g maioneză bună","2 cepe verzi, feliate foarte fin (aproximativ 20 g)","1 tulpină mică de țelină, tocată fin (aproximativ 30 g, opțional)","0,5 linguriță sare fină de mare","1 avocado mare copt (aproximativ 200 g), feliat la 5 mm și amestecat cu 1 linguriță suc de lime","12 măsline negre (botija sau Kalamata), tăiate în două și fără sâmburi","2 ouă fierte tare, tăiate în jumătăți sau sferturi","Crenguțe de coriandru sau pătrunjel proaspăt"]},"howIsMade":{"en":"Boil the potatoes in well-salted water (about 1 tbsp salt per litre) for 18–20 minutes, until a knife slides in with no resistance but the potatoes are not falling apart; drain and leave to steam-dry on a rack for 5 minutes. While still warm, pass the potatoes through a ricer or fine sieve into a wide bowl; add the ají amarillo paste, lime juice, oil, 1.5 tsp salt, and white pepper; knead gently with your hands for 2–3 minutes — the mash should be smooth, silky, and slightly elastic, holding its shape when pinched. Taste and adjust with more salt or lime; cover and let cool to room temperature, then chill for 20 minutes to firm slightly. Make the filling; flake the drained tuna (or shred the chicken) into a bowl; add the mayonnaise, spring onions, celery (if using), and 0.5 tsp salt; fold gently — keep visible flakes of fish rather than a smooth purée; chill until needed. Line a 22 × 12 cm loaf tin (or a round 18 cm cake ring) with cling film, leaving a generous overhang; press one-third of the potato mash into the base in an even 1.5 cm layer, using the back of a damp spoon to smooth. Spread half the tuna or chicken filling over the potato in a 1 cm layer, leaving a 5 mm border; arrange the avocado slices on top in a tight overlapping single layer; press a second third of potato over the avocado, then top with the remaining filling and a final layer of potato. Fold the cling film over the top and press firmly with the flat of your hand or a small board to compact the terrine; refrigerate for at least 1 hour (or up to 6 hours) to set the layers. Lift the terrine out using the cling film, peel back, and slice into 8 generous portions with a hot wet knife (rinse the blade between cuts); top each slice with an olive half, a wedge of hard-boiled egg, and a sprig of coriander; serve cold, within 2 hours of slicing."}},{"id":129,"origin":{"en":"Kyrgyzstan","ro":"Kârgâzstan"},"name":{"en":"Beshbarmak","ro":"Beshbarmak"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["1.2 kg bone-in lamb shoulder or beef brisket (or a mix), cut into 4 large pieces","3 litres cold water","1 tbsp fine sea salt, plus more to taste","1 onion, halved (for the broth)","1 carrot, halved (for the broth)","2 bay leaves","10 whole black peppercorns","400 g plain (all-purpose) flour, plus extra for dusting","2 large eggs","150 ml warm water","1 tsp fine sea salt","2 large onions (about 350 g), halved and thinly sliced into half-moons","0.5 tsp freshly ground black pepper","Pinch of sugar","Fresh dill or parsley, roughly chopped"],"ro":["1,2 kg umăr de miel sau piept de vită cu os (sau un amestec), tăiat în 4 bucăți mari","3 litri apă rece","1 lingură sare fină de mare, plus după gust","1 ceapă, tăiată în două (pentru bulion)","1 morcov, tăiat în două (pentru bulion)","2 frunze de dafin","10 boabe de piper negru întregi","400 g făină albă obișnuită, plus pentru tăvălit","2 ouă mari","150 ml apă caldă","1 linguriță sare fină de mare","2 cepe mari (aproximativ 350 g), tăiate în două și feliate subțire în semilune","0,5 linguriță piper negru proaspăt măcinat","Un vârf de zahăr","Mărar sau pătrunjel proaspăt, tocat grosier"]},"howIsMade":{"en":"Place the meat in a large stockpot, cover with the cold water, and bring slowly to the boil over medium heat — slow heating draws maximum flavour into the broth; skim the grey foam carefully for the first 10 minutes until the surface runs clear. Add the 1 tbsp salt, halved onion, carrot, bay leaves, and peppercorns; reduce the heat to a bare simmer (the surface should barely move) and cook uncovered for 2–2.5 hours, until the meat is fork-tender and falling from the bone. While the meat simmers, make the dough; whisk the flour and 1 tsp salt in a wide bowl, make a well, and add the eggs and warm water; stir with a fork, then knead on a floured surface for 8–10 minutes until firm, smooth, and elastic; cover with cling film and rest at room temperature for 30 minutes. Divide the rested dough into 4 pieces; working with one piece at a time and keeping the rest covered, roll out as thinly as possible on a floured surface — about 1 mm thick; cut into rough 8 × 8 cm squares (or 10 × 5 cm diamonds); dust generously with flour and lay flat on a tray so they do not stick. Lift the meat out of the broth onto a board, cover loosely with foil, and rest; strain the broth into a clean pot through a fine sieve and discard the boiling vegetables; keep the broth at a gentle simmer. Ladle 500 ml of the hot broth into a separate small pot; add the thinly sliced onions and a pinch of sugar and simmer for 5–6 minutes — the onions should stay translucent and just tender, not collapsed; stir in 0.5 tsp black pepper. Bring the strained broth back to a vigorous boil; drop the dough squares in batches, stir gently to prevent sticking, and cook 3–4 minutes per batch until they float and are al dente; lift out with a slotted spoon onto a warmed serving platter. Slice the meat thickly against the grain and arrange over the noodles; spoon the onions and their broth liberally over the meat; scatter with chopped dill, then ladle a cup of the hot clear broth on the side for each diner to sip between bites; serve immediately while everything is steaming hot."}},{"id":130,"origin":{"en":"Thailand","ro":"Thailanda"},"name":{"en":"Coconut Rice","ro":"Orez cu lapte de cocos"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"en":["400 g long-grain rice (Thai jasmine or basmati)","400 ml full-fat coconut milk (1 standard tin)","250 ml cold water","1 tsp fine sea salt","1 tsp caster sugar","2 fresh pandan leaves, tied into a knot (or 1 tsp pandan extract — optional but traditional)","1 small shallot (about 30 g), finely sliced","1 stalk lemongrass, lightly bruised (optional, for Southeast Asian aroma)","3 cm strip lime zest (optional, for brightness)","1 tbsp coconut oil or neutral oil","30 g unsweetened desiccated coconut, lightly toasted (for garnish)","Small handful fresh coriander leaves (for garnish)"],"ro":["400 g orez cu bob lung (jasmine thailandez sau basmati)","400 ml lapte de cocos integral (1 conservă standard)","250 ml apă rece","1 linguriță sare fină de mare","1 linguriță zahăr tos","2 frunze de pandan proaspete, legate în nod (sau 1 linguriță extract de pandan — opțional, dar tradițional)","1 eșalotă mică (aproximativ 30 g), feliată fin","1 tulpină de lemongrass, ușor zdrobită (opțional, pentru aroma sud-est asiatică)","Coajă de lime de 3 cm, fâșie subțire (opțional, pentru prospețime)","1 lingură ulei de cocos sau ulei neutru","30 g cocos rasă neîndulcită, ușor prăjită (pentru garnitură)","Un pumn mic de frunze de coriandru proaspete (pentru garnitură)"]},"howIsMade":{"en":"Rinse the rice thoroughly in a sieve under cold running water for about 1 minute, swirling with your hand, until the water runs almost clear; drain well; this removes surface starch and keeps the grains separate at the end. Heat the coconut oil in a heavy-based 2-litre pan over medium heat; add the sliced shallot and stir-fry for 90 seconds–2 minutes, until softened and lightly golden at the edges but not browned. Add the drained rice to the pan and stir for 30 seconds to coat each grain in oil; pour in the coconut milk and water, then add the salt, sugar, knotted pandan leaves, bruised lemongrass, and lime zest. Stir once to dissolve the salt and bring to a gentle boil over medium-high heat — keep stirring gently for about 2 minutes so the coconut milk does not catch on the base. Lower the heat to the lowest possible setting, cover with a tight-fitting lid, and cook undisturbed for 12 minutes; do not lift the lid — the trapped steam is what cooks the rice evenly. Turn off the heat (leave the pan covered) and rest the rice for 10 minutes — this finishing steam dries the grains and stops them clumping. Lift the lid, remove and discard the pandan, lemongrass, and lime zest; fluff the rice gently with a fork, scatter the toasted desiccated coconut and coriander leaves over the top, and serve immediately alongside curry, sambols, or grilled fish."}},{"id":131,"origin":{"en":"Malaysia","ro":"Malaezia"},"name":{"en":"Nasi lemak","ro":"Nasi lemak"},"category":{"en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"fish","pairingsType":"fish","ingredients":{"en":["400 g long-grain jasmine rice","400 ml full-fat coconut milk","200 ml cold water","1 tsp fine sea salt","2 fresh pandan leaves tied into a knot, plus 1 bruised stalk of lemongrass and 3 thin slices of fresh ginger (for the rice)","60 g raw skinless peanuts","60 g ikan bilis (dried Malaysian anchovies)","4 large eggs","1 medium cucumber (about 200 g), sliced into 5 mm rounds","10 dried red chillies, soaked in hot water for 15 minutes and drained","4 fresh red chillies (mild)","2 large shallots (about 120 g), peeled, plus 3 garlic cloves and 1 thumb-sized piece of fresh ginger (15 g)","1 tbsp belacan (toasted shrimp paste), or 1.5 tsp fish sauce as a substitute","2 tbsp tamarind paste mixed with 4 tbsp warm water (or 3 tbsp lime juice)","2 tbsp palm sugar or dark brown sugar","1 medium red onion (about 120 g), sliced into thin rings","60 ml plus 250 ml neutral oil (split: 60 ml for the sambal, the rest for frying anchovies and peanuts)","0.5 tsp fine sea salt for the sambal"],"ro":["400 g orez jasmine cu bob lung","400 ml lapte de cocos integral","200 ml apă rece","1 linguriță sare fină de mare","2 frunze de pandan proaspete, legate în nod, plus 1 tulpină de lemongrass zdrobită și 3 felii subțiri de ghimbir proaspăt (pentru orez)","60 g arahide crude fără pieliță","60 g ikan bilis (anșoa malaezieni uscați)","4 ouă mari","1 castravete mediu (aproximativ 200 g), tăiat rondele de 5 mm","10 ardei iuți roșii uscați, înmuiați în apă fierbinte 15 minute și scurși","4 ardei iuți roșii proaspeți (blânzi)","2 eșalote mari (aproximativ 120 g), decojite, plus 3 căței de usturoi și o bucată de ghimbir cât degetul mare (15 g)","1 lingură belacan (pastă de creveți prăjită) sau 1,5 linguriță sos de pește ca substitut","2 linguri pastă de tamarin amestecată cu 4 linguri apă caldă (sau 3 linguri suc de lime)","2 linguri zahăr de palmier sau zahăr brun închis","1 ceapă roșie medie (aproximativ 120 g), feliată inele subțiri","60 ml plus 250 ml ulei neutru (împărțit: 60 ml pentru sambal, restul pentru prăjit anșoa și arahide)","0,5 linguriță sare fină de mare pentru sambal"]},"howIsMade":{"en":"Rinse the rice in a sieve under cold running water for 1 minute, until the water runs almost clear, then drain well; put it in a heavy 2-litre pan with the coconut milk, water, 1 tsp salt, pandan, lemongrass, and ginger; bring to a gentle boil over medium-high heat, stirring once; lower the heat to the lowest setting, cover with a tight lid, and cook undisturbed for 12 minutes; turn off the heat and rest, covered, for another 10 minutes — the trapped steam finishes cooking and dries the grains; discard the aromatics before serving. While the rice cooks, fry the peanuts; heat the 250 ml oil in a small pan to 160°C; fry the peanuts for 3–4 minutes until pale gold (they will darken as they cool), then lift onto paper towels with a slotted spoon; salt lightly. Pat the ikan bilis dry; in the same oil, fry them in two batches for 60–90 seconds per batch, stirring once, until crisp and deep gold; lift onto a separate sheet of paper; reserve the oil. Hard-boil the eggs: lower them into gently simmering water and cook for exactly 8 minutes for set yolks (or 7 minutes for slightly jammy); transfer immediately to iced water for 3 minutes, then peel and halve. Make the sambal paste; combine the drained dried chillies, fresh chillies, shallots, garlic, the 15 g ginger piece, and belacan in a blender or mortar with 2 tbsp of the reserved oil and process to a coarse paste. Heat 60 ml fresh oil in a wok or wide pan over medium heat; add the sambal paste and fry, stirring continuously, for 12–15 minutes, until the oil splits out around the edges and the paste turns deep brick-red; this long fry is what kills the raw bite of the aromatics. Stir in the red onion rings, tamarind water, palm sugar, and 0.5 tsp salt; simmer for 6–8 minutes more, until the onions are softened and the sambal has a glossy, jammy texture that holds a clean line when you drag a spoon across the pan; taste and balance — it should be hot, sweet, sour, and savoury in roughly equal measure. To serve: mound a portion of rice on each plate; surround with a hard-boiled egg half, a generous spoonful of sambal, a small heap of peanuts, a small heap of crispy anchovies, and a fan of cucumber slices; eat by mixing small amounts from each pile into each bite."}},{"id":132,"origin":{"en":"Switzerland","ro":"Elveția"},"name":{"en":"Rösti","ro":"Rösti"},"category":{"en":"Breakfast","ro":"Mic dejun"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"en":["1 kg waxy potatoes (Yukon Gold, Charlotte, or similar), unpeeled","60 g unsalted butter, in two 30 g portions","2 tbsp neutral oil (sunflower or grapeseed), in two 1 tbsp portions","1 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper","Pinch of grated nutmeg (optional, traditional in Bernese versions)","1 small onion (about 80 g), very finely diced (optional, common variation)","60 g aged gruyère, coarsely grated (optional, for a richer finish)","1 tbsp finely chopped fresh chives, to garnish"],"ro":["1 kg cartofi cu pastă fermă (Yukon Gold, Charlotte sau similari), necurățați","60 g unt nesărat, împărțit în două porții de 30 g","2 linguri ulei neutru (de floarea-soarelui sau de struguri), împărțit în două porții de 1 lingură","1 linguriță sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat","Un vârf de nucșoară rasă (opțional, tradițional în versiunea berneză)","1 ceapă mică (aproximativ 80 g), tăiată foarte fin (opțional, variantă obișnuită)","60 g gruyère maturat, ras grosier (opțional, pentru finisare mai bogată)","1 lingură arpagic proaspăt tocat fin, pentru garnitură"]},"howIsMade":{"en":"The day before, parboil the potatoes whole and unpeeled in well-salted water (1 tbsp salt per litre) for 8–10 minutes — a knife should meet some resistance, the centre should still be raw; drain and cool completely; refrigerate uncovered overnight so the surface dries and the starches firm up. The next day, peel the cold potatoes — the skins should slip off easily; grate them on the large holes of a box grater into long, even shreds, working briskly so they do not warm. In a bowl, season the grated potatoes with the salt, pepper, and nutmeg, and toss gently to distribute — use your fingertips, not a heavy hand, so the strands stay long. Heat 1 tbsp oil and 30 g of the butter in a 24 cm non-stick or well-seasoned cast-iron pan over medium heat until the butter foams and just turns nut-brown; add the diced onion (if using) and cook for 90 seconds–2 minutes, until soft and lightly golden. Add the seasoned potato to the pan in one even layer, lightly pressing with the back of a spatula to form a 1.5 cm cake about 22 cm across — do not pack it down hard, the air gaps are what crisp the inside; cook undisturbed for 8–10 minutes, until the underside is deep golden brown and pulls cleanly from the pan when you slide a spatula under it. Hold a flat plate over the pan, invert the rösti onto it, then slide it back into the pan with the cooked side up; add the remaining 30 g butter and 1 tbsp oil around the edges so they run under the cake; cook for a further 7–9 minutes, until the second side is equally deep golden and the centre is hot and tender (a paring knife pushed into the middle should meet no resistance). Slide the rösti onto a board, scatter with the grated gruyère if using (the residual heat will melt it lightly), top with chopped chives, and cut into 4 wedges; serve immediately with a fried egg on top, smoked ham, or Bratwurst."}},{"id":133,"origin":{"en":"Romania","ro":"România"},"name":{"en":"Beans with Sausages","ro":"Fasole cu cârnați"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["500 g dried white beans (cannellini, navy, or Greek elephant), soaked overnight in cold water","4 smoked pork sausages (about 500 g; e.g. cârnați Pleșcoi or smoked Polish sausage)","150 g smoked bacon (kaiser) or smoked pork ribs, cut into 2 cm pieces (optional, for extra depth)","2 large onions (about 350 g), finely diced","2 medium carrots (about 200 g), finely diced","1 medium red bell pepper, finely diced","4 garlic cloves, finely chopped","3 tbsp tomato paste","200 g canned crushed tomatoes (or 2 fresh tomatoes, grated)","3 bay leaves","1 tsp sweet paprika","0.5 tsp dried thyme (or 1 sprig fresh)","0.5 tsp freshly ground black pepper","1.5 tsp fine sea salt, plus more to taste","60 ml sunflower oil (or 30 g lard)","1.5–2 litres water (or unsalted chicken stock for richer flavour)","2 tbsp finely chopped fresh dill or parsley, to finish","1 tbsp white wine vinegar (optional, to balance at the end)"],"ro":["500 g fasole albă uscată (cannellini, navy sau fasole gigant grecească), înmuiată peste noapte în apă rece","4 cârnați afumați de porc (aproximativ 500 g, ex. cârnați Pleșcoi sau cârnați polonezi afumați)","150 g kaiser afumat sau coaste de porc afumate, tăiate bucăți de 2 cm (opțional, pentru profunzime)","2 cepe mari (aproximativ 350 g), tocate fin","2 morcovi medii (aproximativ 200 g), tocați mărunt","1 ardei kapia roșu mediu, tocat fin","4 căței de usturoi, tocați fin","3 linguri bulion (pastă de roșii)","200 g roșii sfărâmate din conservă (sau 2 roșii proaspete, date pe răzătoare)","3 foi de dafin","1 linguriță boia dulce","0,5 linguriță cimbru uscat (sau 1 crenguță proaspătă)","0,5 linguriță piper negru proaspăt măcinat","1,5 lingurițe sare fină de mare, plus după gust","60 ml ulei de floarea-soarelui (sau 30 g untură)","1,5–2 litri apă (sau supă neagră de pui pentru o aromă mai bogată)","2 linguri mărar sau pătrunjel proaspăt tocat fin, pentru finisare","1 lingură oțet de vin alb (opțional, pentru echilibru la final)"]},"howIsMade":{"en":"The night before, place the dried beans in a large bowl, cover with at least 2 litres of cold water, and leave to soak for 8–12 hours; they will roughly double in size and lose much of the gas-producing sugars. The next day, drain and rinse the beans; put them in a heavy pot with fresh water to cover by 5 cm, bring to a boil, and cook uncovered for 10 minutes; drain again — this first quick boil mellows the beans and shortens the final cooking time. Return the beans to the pot with 1.5 litres of fresh water (or stock), the smoked bacon (if using), and 2 of the bay leaves; bring to a gentle simmer and cook partially covered for 50–60 minutes — the beans should be just tender but not falling apart; do not salt yet (salt at this stage toughens the skins). While the beans simmer, heat the oil in a wide deep pan over medium heat; add the diced onions and a generous pinch of salt and cook for 8–10 minutes, stirring often, until soft and golden brown at the edges; add the carrots and red bell pepper and cook for another 5–6 minutes, until softened. Push the vegetables to one side, add the garlic to the empty space and cook for 30 seconds, then stir in the paprika and thyme — toast for 20–30 seconds until fragrant; add the tomato paste and crushed tomatoes and cook, stirring, for 3–4 minutes, until the tomato is deeper red and the oil splits out around the edges. Slice 2 of the smoked sausages into 2 cm rounds; keep the other 2 whole for the top; add the sliced sausage to the tomato base and cook for 2–3 minutes to render some fat. Tip the bean pot and its liquid into the tomato base, add the remaining bay leaf, the 1.5 tsp salt, and the black pepper; bury the whole sausages in the stew; simmer uncovered for 35–45 minutes, stirring occasionally, until the beans are soft and the liquid has thickened to a thin gravy that coats the back of a spoon; add a splash of water if it tightens too much. Taste, adjust with salt, and add the white wine vinegar if using (a touch of acid brightens the smoke); lift out the whole sausages and slice on the diagonal; ladle the beans into deep bowls, top each with a fan of sausage slices, scatter with chopped dill, and serve with pickles and crusty bread or polenta."}},{"id":134,"origin":{"en":"Hungary","ro":"Ungaria"},"name":{"en":"Chicken Paprikash","ro":"Chicken Paprikash"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["1.5 kg bone-in, skin-on chicken thighs and drumsticks (about 8 pieces)","2 large onions (about 400 g), finely diced","3 tbsp sweet Hungarian paprika (Édesnemes, preferably from Kalocsa or Szeged), plus 0.5 tsp hot Hungarian paprika (optional)","3 garlic cloves, finely chopped","1 medium red bell pepper, finely diced","1 medium tomato (about 100 g), peeled and finely diced (or 2 tbsp tomato paste)","60 g lard (or 4 tbsp neutral oil)","500 ml hot unsalted chicken stock or water","200 g full-fat sour cream (at least 20% fat — do NOT use light sour cream, it will split)","1 tbsp plain (all-purpose) flour","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper","1 tsp caraway seeds (optional, traditional in some regions)","Fresh dill or parsley, chopped, to garnish"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți)","2 cepe mari (aproximativ 400 g), tocate fin","3 linguri paprika dulce maghiară (Édesnemes, de preferință din Kalocsa sau Szeged), plus 0,5 linguriță paprika iute maghiară (opțional)","3 căței de usturoi, tocați fin","1 ardei gras roșu mediu, tăiat cuburi mici","1 roșie medie (aproximativ 100 g), curățată și tăiată cuburi mici (sau 2 linguri pastă de roșii)","60 g untură (sau 4 linguri ulei neutru)","500 ml supă de pui fierbinte nesărată sau apă","200 g smântână grasă (cel puțin 20% grăsime — NU smântână ușoară, se taie)","1 lingură făină albă","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat","1 linguriță semințe de chimen (opțional, tradițional în unele regiuni)","Mărar sau pătrunjel proaspăt tocat, pentru garnitură"]},"howIsMade":{"en":"Pat the chicken dry with paper towels and season both sides with 1 tsp of the salt and the black pepper; rest at room temperature for 15 minutes. Melt the lard in a heavy 28 cm Dutch oven or wide deep pan over medium-high heat; working in two batches, sear the chicken skin-side down for 4–5 minutes, then 3 minutes on the other side, until the skin is deep golden — do not crowd the pan; lift onto a plate. Reduce the heat to medium and pour off all but about 3 tbsp of the rendered fat; add the onions and a pinch of salt and cook for 12–15 minutes, stirring often, until soft, glossy, and fully golden — this slow sweat is the foundation of paprikash flavour. Add the garlic, red bell pepper, and caraway seeds (if using) and cook for another 2–3 minutes, until the pepper is just softened. Take the pan off the heat completely; stir in the sweet paprika (and hot paprika if using) — paprika scorches and turns bitter on direct heat, so the pan must be off when it goes in; stir for 30 seconds until the onions are stained a deep brick red and the spice smells warm and sweet. Return the pan to medium heat; add the diced tomato (or tomato paste) and stir for 1 minute; pour in the hot stock and the remaining 0.5 tsp salt, then nestle the chicken back into the sauce, skin-side up; bring to a gentle simmer. Cover and braise on the lowest heat for 35–45 minutes, until the chicken pulls easily from the bone and the internal temperature reads 75°C; lift the chicken onto a warm plate and tent with foil while you finish the sauce. Whisk the flour into the sour cream until smooth, then whisk in a ladle of the hot pan sauce to temper; off the heat, pour the tempered cream back into the pan and stir until silky; return the chicken to the sauce just to warm through, taste and adjust salt, then serve over nokedli, fresh pasta, or buttered noodles with chopped dill on top."}},{"id":135,"origin":{"en":"Italy","ro":"Italia"},"name":{"en":"Pasta alla Norma","ro":"Pasta alla Norma"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"pasta","pairingsType":"italian","ingredients":{"en":["2 medium aubergines (about 700 g total), unpeeled, cut into 2 cm cubes","1.5 tsp fine sea salt for salting the aubergine, plus more for the pasta water","300 ml extra-virgin olive oil for shallow-frying the aubergine","400 g rigatoni, penne rigate, or maccheroni","3 tbsp extra-virgin olive oil for the sauce","3 garlic cloves, sliced thin","0.5 tsp dried chilli flakes (optional)","800 g whole peeled tomatoes (San Marzano if available), crushed by hand, or 700 g passata","1 tsp caster sugar (only if the tomatoes are sharp)","0.5 tsp freshly ground black pepper","1 large bunch fresh basil (about 30 g), leaves picked and torn","120 g ricotta salata, finely grated, plus more to serve","1 tbsp coarse sea salt for the pasta water"],"ro":["2 vinete medii (aproximativ 700 g în total), necurățate, tăiate cuburi de 2 cm","1,5 lingurițe sare fină de mare pentru asezonarea vinetelor, plus mai multă pentru apa pastelor","300 ml ulei de măsline extravirgin pentru prăjit vinetele","400 g rigatoni, penne rigate sau maccheroni","3 linguri ulei de măsline extravirgin pentru sos","3 căței de usturoi, feliați subțire","0,5 linguriță fulgi de ardei iute uscat (opțional)","800 g roșii întregi, decojite (San Marzano dacă e posibil), zdrobite cu mâna, sau 700 g pasată","1 linguriță zahăr tos (doar dacă roșiile sunt acrișoare)","0,5 linguriță piper negru proaspăt măcinat","1 legătură mare de busuioc proaspăt (aproximativ 30 g), frunzele rupte","120 g ricotta salata, rasă fin, plus în plus pentru servit","1 lingură sare grunjoasă de mare pentru apa pastelor"]},"howIsMade":{"en":"Toss the aubergine cubes with the 1.5 tsp fine salt in a colander and leave to drain over a bowl for 30 minutes — this draws out bitter water and stops the aubergine from drinking too much oil during frying; press lightly with a paper towel and pat dry. Heat the 300 ml olive oil in a wide deep frying pan to 170°C; test with a single aubergine cube — it should sizzle briskly; fry the aubergine in three batches for 3–4 minutes per batch, turning often, until deeply golden on all sides and tender inside (a knife should pass through easily); lift onto paper towels with a slotted spoon to drain; reserve. While the aubergine fries, bring a large pot with 4 litres of water and 1 tbsp coarse salt to a rolling boil. In a wide sauté pan, heat the 3 tbsp olive oil over medium heat; add the sliced garlic and chilli flakes (if using) and cook for 60–90 seconds — the garlic should just turn pale gold around the edges, never brown. Add the crushed tomatoes, the sugar (if using), 0.5 tsp salt, and the black pepper; stir and bring to a simmer; cook for 12–15 minutes, stirring occasionally, until the sauce has thickened slightly and the oil rises to the surface; tear in half of the basil for the last minute. Drop the pasta into the boiling water and cook 1 minute less than the package says for al dente; reserve 250 ml of starchy pasta water, then drain. Fold the fried aubergine into the tomato sauce, then add the drained pasta; toss vigorously over medium heat for 1–2 minutes, adding splashes of pasta water as needed, until the sauce clings glossy to every piece — it should be loose enough to flow when you tilt the pan but not watery. Off the heat, scatter half the grated ricotta salata and most of the remaining basil and toss once; divide between four warmed bowls, finish each with more ricotta salata, the last basil leaves, and a drizzle of raw olive oil; serve immediately."}},{"id":137,"origin":{"en":"Turkmenistan","ro":"Turkmenistan"},"name":{"en":"Ichlekli","ro":"Ichlekli"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["500 g plain (all-purpose) flour, plus extra for rolling","1 tsp fine sea salt","240 ml warm water","1 tbsp neutral oil (sunflower or grapeseed)","500 g lamb shoulder or beef chuck, finely minced (or coarsely diced and pulsed in a processor)","100 g lamb-tail fat or beef suet, finely diced (or 30 g unsalted butter as substitute)","2 large onions (about 350 g), finely diced","200 g waxy potatoes, peeled and diced into 5 mm cubes (optional but traditional)","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp ground cumin","0.5 tsp ground coriander","0.5 tsp dried red pepper flakes (optional)","1 large egg yolk, beaten with 1 tbsp milk, for brushing"],"ro":["500 g făină albă obișnuită, plus pentru întins","1 linguriță sare fină de mare","240 ml apă caldă","1 lingură ulei neutru (de floarea-soarelui sau de struguri)","500 g umăr de miel sau pulpă de vită, tocate fin (sau cuburi mărunte pulsate într-un robot)","100 g grăsime de coadă de miel sau seu de vită, tăiate fin (sau 30 g unt nesărat ca substitut)","2 cepe mari (aproximativ 350 g), tocate fin","200 g cartofi cu pastă fermă, curățați și tăiați cuburi de 5 mm (opțional, dar tradițional)","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță chimion măcinat","0,5 linguriță coriandru măcinat","0,5 linguriță fulgi de ardei iute uscat (opțional)","1 gălbenuș mare bătut cu 1 lingură de lapte, pentru uns"]},"howIsMade":{"en":"Make the dough; whisk the flour and salt in a wide bowl; make a well, pour in the warm water and oil, and stir with a wooden spoon until a shaggy dough forms; knead on a lightly floured surface for 6–8 minutes until smooth, firm, and elastic — slightly stiffer than bread dough; wrap in cling film and rest at room temperature for 30 minutes while you prepare the filling. In a large bowl, combine the minced lamb, fat, onions, potato cubes (if using), salt, pepper, cumin, coriander, and pepper flakes; mix with your hands for 1 minute until the mixture is sticky and well bound; do not pre-cook — the filling cooks inside the dough. Heat the oven to 220°C (425°F / fan 200°C) and place an upturned heavy baking tray or pizza stone on the middle rack to heat through for at least 20 minutes; the hot surface is what crisps the bottom. Divide the rested dough into two equal pieces; on a lightly floured surface, roll one piece into a 32 cm round, about 2 mm thick — work the edges thinner than the centre so the seal will not be too thick. Slide the round onto a sheet of baking parchment; spread the filling evenly over the disc, leaving a 2 cm border, and press it down lightly into a 1.5 cm layer. Roll out the second piece of dough to the same 32 cm round and lay it on top; press the two layers together firmly around the edge, then roll and pinch the rim inward into a tight rope-like border so no juice can escape. Brush the top with the egg-yolk glaze and prick the centre in 6–8 places with a fork to let steam vent; slide the pie, on its parchment, onto the hot tray in the oven; bake for 30–35 minutes, until the top is deep golden brown and the bottom sounds hollow when you tap it. Rest the pie on a board for 5 minutes (the steam settles and the filling firms up), then cut into 8 wedges with a sharp knife; serve hot with green tea, plain yoghurt, or soured milk."}},{"id":138,"origin":{"en":"Ukraine","ro":"Ucraina"},"name":{"en":"Chicken Kiev","ro":"Pui Kiev"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["100 g unsalted butter, softened to room temperature","3 garlic cloves, very finely minced (or 1 tbsp garlic paste)","30 g flat-leaf parsley, very finely chopped","1 tbsp lemon juice","0.5 tsp fine sea salt","0.25 tsp freshly ground black pepper","4 large skinless chicken breasts (about 200 g each)","1 tsp fine sea salt for the breasts","0.5 tsp freshly ground black pepper for the breasts","80 g plain (all-purpose) flour","2 large eggs, beaten with 1 tbsp cold water","150 g panko or fine dry breadcrumbs","750 ml neutral oil (sunflower or rapeseed), for deep-frying","1 tbsp unsalted butter, for finishing the oil (optional, for a nuttier crust)","Lemon wedges and a small bunch of parsley, to serve"],"ro":["100 g unt nesărat, înmuiat la temperatura camerei","3 căței de usturoi, tocați foarte fin (sau 1 lingură pastă de usturoi)","30 g pătrunjel cu frunze plate, tocat foarte fin","1 lingură suc de lămâie","0,5 linguriță sare fină de mare","0,25 linguriță piper negru proaspăt măcinat","4 piepți mari de pui dezosați și fără piele (aproximativ 200 g fiecare)","1 linguriță sare fină de mare pentru piepți","0,5 linguriță piper negru proaspăt măcinat pentru piepți","80 g făină albă obișnuită","2 ouă mari, bătute cu 1 lingură apă rece","150 g panko sau pesmet fin uscat","750 ml ulei neutru (de floarea-soarelui sau de rapiță), pentru prăjire adâncă","1 lingură unt nesărat, pentru aromatizarea uleiului (opțional, pentru o crustă cu unt prăjit)","Felii de lămâie și o legătură mică de pătrunjel, pentru servit"]},"howIsMade":{"en":"Make the herb butter; beat the softened butter in a bowl with the minced garlic, chopped parsley, lemon juice, 0.5 tsp salt, and 0.25 tsp pepper until evenly combined; scrape onto cling film, shape into a 12 cm long, 2 cm thick log, wrap tightly, and freeze for at least 1 hour, until firm enough to slice. Slice the chilled butter log into 4 equal cylinders; return them to the freezer while you prepare the chicken — the butter must be very cold or it will leak out during frying. With a sharp knife, cut a deep horizontal pocket into the thick side of each chicken breast, stopping about 1 cm before the opposite edge — do not cut through; open the breast like a book, lay it between two sheets of cling film, and pound gently with a meat mallet to an even 5 mm thickness, working from the centre outwards; season the inside with 1 tsp salt and 0.5 tsp pepper. Place one cold butter cylinder along the centre of each pounded breast; fold the two long sides over the butter, then roll the breast tightly into a sealed cylinder, pressing to expel air; tuck any loose flaps underneath; wrap each parcel in cling film and refrigerate for 30 minutes. Set up three shallow bowls: one with the flour, one with the beaten eggs and water, one with the breadcrumbs; take a parcel, dip in flour and pat off excess, then egg, draining well, then breadcrumbs — press firmly on all sides; dip the egg and breadcrumbs again for a second coat: this double coat is what stops the butter from blowing out during frying; repeat with the other three. Heat the oil in a deep pan to 170°C; test with a breadcrumb — it should sizzle and turn pale gold in 20 seconds; lower two Kievs in carefully and fry for 6–7 minutes, turning once, until the crust is deeply golden brown all over; lift onto a wire rack set over a tray; repeat with the other two. Finish in the oven if needed; place the fried Kievs on a rack over a baking tray and bake at 180°C (350°F) for 8–10 minutes, until a temperature probe pushed into the chicken (not the butter) reads 70°C; this ensures the chicken is cooked through without overcooking the crust. Rest for 2 minutes on the rack, then plate; pierce the top of each Kiev at the table — the molten herb butter will spill out in a golden stream; serve immediately with lemon wedges and parsley, alongside mashed potatoes or buttered rice."}},{"id":139,"origin":{"en":"Lithuania","ro":"Lituania"},"name":{"en":"Cepelinai","ro":"Cepelinai"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["1.5 kg raw waxy potatoes (Yukon Gold or similar), peeled and weighed","500 g floury potatoes (Russet or King Edward), peeled and weighed","1 tbsp lemon juice or 1 tsp citric acid (to prevent the raw grated potato from greying)","1 tsp fine sea salt for the dough","2 tbsp cornflour (cornstarch) — only if the raw potato is very wet","500 g coarsely minced pork shoulder (or 50% pork + 50% beef)","1 medium onion (about 150 g), very finely diced","1 tsp fine sea salt for the filling","0.5 tsp freshly ground black pepper","1 tsp dried marjoram or dried savory","60 ml cold water for the filling","200 g smoked streaky bacon, cubed","1 large onion (about 200 g), finely sliced","200 g full-fat sour cream","Dill or parsley, finely chopped, to garnish","1 tbsp coarse sea salt for the cooking water"],"ro":["1,5 kg cartofi cu pastă fermă (Yukon Gold sau similari), curățați și cântăriți după curățare","500 g cartofi făinoși (Russet sau King Edward), curățați și cântăriți după curățare","1 lingură suc de lămâie sau 1 linguriță acid citric (pentru a împiedica înnegrirea cartofului ras crud)","1 linguriță sare fină de mare pentru aluat","2 linguri amidon de porumb — doar dacă aluatul rămâne prea umed","500 g carne de porc tocată grosier (sau 50% porc + 50% vită)","1 ceapă medie (aproximativ 150 g), tocată foarte fin","1 linguriță sare fină de mare pentru umplutură","0,5 linguriță piper negru proaspăt măcinat","1 linguriță maghiran uscat sau cimbru de munte uscat","60 ml apă rece pentru umplutură","200 g bacon afumat striat, tăiat cuburi","1 ceapă mare (aproximativ 200 g), feliată fin","200 g smântână grasă","Mărar sau pătrunjel, tocat fin, pentru garnitură","1 lingură sare grunjoasă de mare pentru apa de fierbere"]},"howIsMade":{"en":"Make the filling first so the flavours marry; mix the minced pork, finely diced onion, 1 tsp salt, pepper, marjoram, and 60 ml cold water in a bowl with your hand for 1–2 minutes, until the mixture is sticky and well bound; cover and chill while you prepare the potato dough. Boil the 500 g floury potatoes whole and unpeeled in salted water for 25–30 minutes, until very tender; drain, peel while hot, and pass through a ricer or mash smoothly; spread out on a tray to cool to room temperature — hot mash would cook the raw potato in the next step. Grate the 1.5 kg waxy potatoes on the fine side of a box grater into a large bowl lined with a clean kitchen towel; gather the towel and squeeze hard over a second bowl to extract as much liquid as possible; you should end up with about 250 ml of liquid; leave it to settle for 5 minutes. Carefully pour off the clear water from the bowl of squeezed liquid, leaving the white starch settled at the bottom; scrape this starch back into the squeezed grated potato — it is the natural binder that holds the dumplings together; add the cooled mashed potato, the lemon juice, and 1 tsp salt; mix vigorously by hand for 2–3 minutes, until you have a sticky, elastic dough; add the cornflour only if the dough still feels wet. With wet hands, divide the dough into 8 equal pieces (about 220 g each); flatten one piece on a wet palm into a 12 × 8 cm oval, place about 60 g of the chilled filling in the centre, then wrap the dough up and around the filling, pinching to seal completely; smooth into a 12 cm zeppelin shape, with no cracks where steam or water could enter. Bring a wide deep pan with 4 litres of water and 1 tbsp coarse salt to a gentle simmer (not a rolling boil — vigorous water can break the dumplings); lower the cepelinai in 2 batches, stir gently once to keep them off the base, and cook for 25–30 minutes at the gentlest simmer, until the surface goes from matte to translucent and the dumplings float high. While they cook, make the sauce; cook the cubed bacon in a dry frying pan over medium heat for 6–8 minutes until the fat renders and the cubes are crisp; add the sliced onion and cook for another 5–6 minutes until soft and lightly golden; stir off the heat and keep warm. Lift the cooked cepelinai out with a slotted spoon onto warmed plates — 2 per person; scatter generously with the bacon-onion mixture and its fat, top with a heap of cold sour cream, and finish with chopped dill; serve immediately while everything is hot and the centres are juicy."}},{"id":140,"origin":{"en":"France","ro":"Franța"},"name":{"en":"Chicken Fricassée","ro":"Fricassée de Poulet"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"french","ingredients":{"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (about 8 pieces), or a 1.5 kg whole chicken jointed into 8","1 tsp fine sea salt + 0.5 tsp freshly ground white pepper (black pepper works but speckles the sauce)","60 g unsalted butter, divided into 30 g + 30 g","2 tbsp neutral oil","250 g pearl onions or small shallots, peeled (or 1 medium onion finely diced)","200 g chestnut or button mushrooms, halved or quartered if large","2 medium carrots (about 200 g), peeled and cut into 5 cm batons","2 garlic cloves, finely minced","30 g plain (all-purpose) flour","150 ml dry white wine (Riesling or Sauvignon Blanc)","500 ml hot unsalted chicken stock","1 small bouquet garni (1 bay leaf + 4 thyme sprigs + 4 parsley stalks tied with string)","200 ml double cream (heavy cream, 35% fat or higher), plus 2 optional egg yolks for a richer liaison","1 tbsp fresh lemon juice","2 tbsp finely chopped fresh flat-leaf parsley, to garnish"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți) sau 1,5 kg pui întreg dezasamblat în 8 bucăți","1 linguriță sare fină de mare + 0,5 linguriță piper alb proaspăt măcinat (piperul negru funcționează dar pătează sosul)","60 g unt nesărat, împărțit în două porții de 30 g","2 linguri ulei neutru","250 g cepe de primăvară sau eșalote mici, decojite (sau 1 ceapă medie tocată fin)","200 g ciuperci champignon (albe sau brune), tăiate în jumătăți sau sferturi dacă sunt mari","2 morcovi medii (aproximativ 200 g), curățați și tăiați bastonașe de 5 cm","2 căței de usturoi, tocați fin","30 g făină albă obișnuită","150 ml vin alb sec (Riesling sau Sauvignon Blanc)","500 ml supă de pui fierbinte nesărată","1 bouquet garni mic (1 foaie de dafin + 4 crenguțe de cimbru + 4 cozi de pătrunjel legate cu sfoară)","200 ml smântână grasă (cel puțin 35% grăsime), plus 2 gălbenușuri opționale pentru o legătură mai bogată","1 lingură suc de lămâie proaspăt","2 linguri pătrunjel proaspăt cu frunze plate, tocat fin, pentru garnitură"]},"howIsMade":{"en":"Pat the chicken pieces dry with paper towels and season both sides with 1 tsp salt and the white pepper; rest at room temperature for 15 minutes. Heat 30 g of the butter and 2 tbsp oil in a wide 28 cm heavy-based sauté pan or Dutch oven over medium heat; when the butter foams, add the chicken skin-side down in one layer (work in batches if needed) and cook 5–6 minutes per side — the surface should turn pale gold and gilded, NOT brown; a brown crust would muddy the sauce; lift onto a plate. Reduce the heat to medium-low; add the pearl onions to the same pan and cook for 5–6 minutes, stirring, until lightly gilded but still pale; lift onto the plate with the chicken. Add the carrots and mushrooms to the pan and cook for 4–5 minutes — the mushrooms will release their water and reabsorb it; add the garlic and stir for 30 seconds. Sprinkle the flour over the vegetables and stir constantly for 2 minutes to cook out the raw taste — a pale roux will form around the vegetables; pour in the wine and bring to a brisk simmer, scraping up any sediment from the pan base, until reduced by half (1–2 minutes). Return the chicken and pearl onions to the pan in a single layer; pour in the hot stock to nearly cover, tuck in the bouquet garni, and bring to the gentlest simmer; cover and cook for 30–35 minutes for thighs (or 25 minutes for breasts removed earlier), until the meat pulls easily from the bone and the internal temperature reads 75°C. Lift the chicken and vegetables to a warmed dish and cover with foil; discard the bouquet garni; bring the sauce to a brisk simmer over medium heat and reduce for 3–5 minutes, until it coats the back of a spoon (about 350 ml). Make the liaison; whisk the cream and egg yolks together in a small bowl; whisk in a ladle of hot sauce to temper, then pour the tempered mixture back into the pan off the heat; stir gently — DO NOT BOIL, or the yolks will scramble; add the lemon juice, taste and adjust the salt; pour over the chicken, scatter with chopped parsley, and serve immediately with rice, buttered noodles, or steamed potatoes."}},{"id":141,"origin":{"en":"Kuwait","ro":"Kuweit"},"name":{"en":"Machboos","ro":"Machboos"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"middle-eastern","ingredients":{"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (or 1.2 kg bone-in lamb shoulder cut into 6 cm chunks)","400 g basmati rice, rinsed and soaked in cold water for 30 minutes, then drained","60 ml neutral oil (or 30 g ghee + 2 tbsp oil for a richer flavour)","3 large onions (about 600 g), finely sliced — reserve a small handful raw for serving","6 garlic cloves, finely chopped","1 thumb-sized piece of fresh ginger (about 30 g), finely grated","3 medium tomatoes (about 300 g), grated (or 200 g canned chopped tomatoes)","2 tbsp tomato paste","2 dried limes (loomi), pierced with a knife in 3 places (or 2 tbsp fresh lime juice as a less-traditional substitute)","1 tbsp baharat (or 1 tsp ground cinnamon + 1 tsp ground cumin + 1 tsp ground coriander + 0.5 tsp ground cardamom + 0.5 tsp ground black pepper)","0.5 tsp ground turmeric","4 whole green cardamom pods, lightly cracked + 1 cinnamon stick (5 cm) + 4 whole cloves + 2 bay leaves","1 small bunch fresh coriander (about 30 g), stems chopped fine for the pot, leaves reserved for garnish","2 fresh green chillies, slit lengthwise","1.2 litres hot water (or unsalted chicken stock for more depth)","1.5 tsp fine sea salt, plus more to taste","60 g flaked almonds and 40 g sultanas, lightly toasted in 1 tsp ghee (to scatter on top)","0.5 tsp saffron threads soaked in 2 tbsp warm water (optional, for finishing the rice)"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (sau 1,2 kg umăr de miel cu os tăiat bucăți de 6 cm)","400 g orez basmati, clătit și înmuiat în apă rece 30 de minute, apoi scurs","60 ml ulei neutru (sau 30 g ghee + 2 linguri ulei pentru aromă mai bogată)","3 cepe mari (aproximativ 600 g), feliate fin — păstrează o mică parte crudă pentru servit","6 căței de usturoi, tocați fin","O bucată de ghimbir proaspăt cât degetul mare (aproximativ 30 g), ras fin","3 roșii medii (aproximativ 300 g), date pe răzătoare (sau 200 g roșii sfărâmate din conservă)","2 linguri pastă de roșii","2 lămâi uscate (loomi), înțepate cu cuțitul în 3 locuri (sau 2 linguri suc proaspăt de lime ca substitut mai puțin tradițional)","1 lingură baharat (sau 1 linguriță scorțișoară măcinată + 1 linguriță chimion măcinat + 1 linguriță coriandru măcinat + 0,5 linguriță cardamom măcinat + 0,5 linguriță piper negru măcinat)","0,5 linguriță turmeric măcinat","4 capsule întregi de cardamom verde, ușor crăpate + 1 baton de scorțișoară (5 cm) + 4 cuișoare + 2 foi de dafin","1 legătură mică de coriandru proaspăt (aproximativ 30 g), tijele tocate fin pentru oală, frunzele păstrate pentru garnitură","2 ardei iuți verzi proaspeți, crestați pe lungime","1,2 litri apă fierbinte (sau supă de pui nesărată pentru profunzime)","1,5 lingurițe sare fină de mare, plus după gust","60 g migdale feliate și 40 g stafide blonde, ușor prăjite în 1 linguriță ghee (pentru deasupra)","0,5 linguriță fire de șofran înmuiate în 2 linguri apă caldă (opțional, pentru finisarea orezului)"]},"howIsMade":{"en":"Rinse the basmati rice under cold running water until the water runs almost clear, then soak in fresh cold water for 30 minutes; this removes excess starch and shortens the final cooking step; drain just before use. Pat the chicken pieces dry and season with 0.5 tsp of the salt; heat the oil (or ghee + oil) in a heavy 28 cm pot over medium-high heat; when shimmering, add the chicken skin-side down and sear for 4–5 minutes per side until deep golden; lift onto a plate. Reduce the heat to medium; add the sliced onions and a pinch of salt to the same pot and cook for 12–15 minutes, stirring often, until deeply golden and very soft; add the garlic and ginger and cook for 1 minute until fragrant. Stir in the cardamom pods, cinnamon stick, cloves, bay leaves, baharat, and turmeric; toast for 30 seconds — the spices should turn aromatic and deepen in colour; add the tomato paste and grated tomatoes and cook, stirring, for 4–5 minutes, until the mixture darkens to a rich red and the oil splits out around the edges. Return the chicken to the pot in a single layer; pour in the hot water (or stock), add the dried limes, slit chillies, chopped coriander stems, and remaining salt; bring to a gentle boil, then cover, reduce to the lowest simmer, and cook for 35–40 minutes (chicken) or 1 h 30 min (lamb), until the meat is fork-tender and the broth is deeply flavoured. Lift the chicken onto a plate and cover loosely with foil to keep warm; skim any excess fat from the broth. Add the drained rice to the pot, gently pushing it down so it is just covered by the broth (top up with hot water if needed — you want about 2.5 cm of liquid above the rice); bring back to a gentle boil, then cover with a tight lid, reduce to the lowest possible heat, and cook undisturbed for 18 minutes. Turn off the heat; drizzle the saffron water (if using) over the rice, place the chicken pieces on top, replace the lid, and rest for 10 minutes — the steam finishes cooking the chicken and the rice grains separate; fluff the rice with a fork, transfer to a wide platter with the chicken on top, and scatter with toasted almonds, sultanas, raw onion slices, and fresh coriander leaves; serve with deeba (tamarind sauce) or yoghurt on the side."}},{"id":142,"origin":{"en":"Republic of the Congo","ro":"Republica Congo"},"name":{"en":"Moambe chicken","ro":"Pui Moambe"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["1.5 kg bone-in skin-on chicken thighs and drumsticks (about 8 pieces)","1 tsp fine sea salt + 0.5 tsp freshly ground black pepper for the chicken","60 ml red palm oil (or 30 ml palm + 2 tbsp neutral oil if the flavour is too strong)","2 large onions (about 400 g), finely diced","6 garlic cloves, finely chopped","1 thumb-sized piece of fresh ginger (about 20 g), finely grated","400 g ripe tomatoes, grated, or 1 × 400 g can chopped tomatoes","2 tbsp tomato paste","100 g unsweetened smooth peanut butter (or 200 g canned moambe palm paste when available)","2 fresh scotch bonnet or habanero chillies, slit lengthwise (or 1 tsp dried chilli flakes; adjust to taste — moambe is hot)","2 bay leaves","500 ml hot unsalted chicken stock or water","1.5 tsp fine sea salt, plus more to taste","2 tbsp finely chopped flat-leaf parsley (or 2 tbsp lemon basil), to garnish","Steamed white rice, fufu, or boiled plantains, to serve"],"ro":["1,5 kg pulpe și copane de pui cu os și piele (aproximativ 8 bucăți)","1 linguriță sare fină de mare + 0,5 linguriță piper negru proaspăt măcinat pentru pui","60 ml ulei de palmier roșu (sau 30 ml palmier + 2 linguri ulei neutru dacă aroma e prea puternică)","2 cepe mari (aproximativ 400 g), tocate fin","6 căței de usturoi, tocați fin","O bucată de ghimbir proaspăt cât degetul mare (aproximativ 20 g), ras fin","400 g roșii coapte, date pe răzătoare (sau 1 × 400 g conservă de roșii tocate)","2 linguri pastă de roșii","100 g unt de arahide neîndulcit, fin (sau 200 g pastă de moambe la conservă, când e disponibilă)","2 ardei iuți proaspeți scotch bonnet sau habanero, crestați pe lungime (sau 1 linguriță fulgi de ardei iute; ajustează după gust — muambe este picant)","2 foi de dafin","500 ml supă de pui fierbinte nesărată sau apă","1,5 lingurițe sare fină de mare, plus după gust","2 linguri pătrunjel cu frunze plate tocat fin (sau 2 linguri busuioc de lămâie), pentru garnitură","Orez alb fiert, fufu sau banane plantain fierte, pentru servit"]},"howIsMade":{"en":"Pat the chicken pieces dry and season both sides with 1 tsp salt and 0.5 tsp pepper; rest at room temperature for 15 minutes. Heat the palm oil in a heavy 28 cm pot over medium-high heat — palm oil melts into a deep orange-red liquid; when shimmering, add the chicken pieces skin-side down in one layer (work in two batches if needed) and sear for 4–5 minutes per side until the skin is deep golden; lift onto a plate. Reduce the heat to medium; add the diced onions and a pinch of salt to the same pot and cook for 8–10 minutes, stirring often, until soft, glossy, and lightly golden but not browned. Add the garlic and ginger and cook for 1 minute until fragrant; stir in the tomato paste and grated tomatoes and cook for 5–6 minutes, stirring, until the mixture darkens to a rich brick-red and the palm oil starts to separate around the edges — this oil split is the signature look of moambe. Whisk the peanut butter with 200 ml of the hot stock in a small bowl until smooth, then pour into the pot and stir to combine; add the remaining 300 ml stock, the bay leaves, slit chillies, and the remaining 0.5 tsp salt. Return the chicken to the pot in a single layer, nestling the pieces into the sauce skin-side up so the skin stays above the liquid; bring to a gentle simmer. Cover with a lid set slightly ajar and cook on the lowest heat for 35–40 minutes, stirring once at the halfway mark, until the chicken pulls easily from the bone and the internal temperature reads 75°C; the sauce should be coral-orange and thick enough to coat the back of a spoon — if it tightens too much, loosen with a splash of hot water. Taste and adjust with salt or extra chilli; lift the chicken into a warmed serving dish, spoon the sauce generously over the top, scatter with chopped parsley, and serve immediately with steamed rice, fufu, or boiled plantain to soak up the sauce."}},{"id":143,"origin":{"en":"France","ro":"Franța"},"name":{"en":"Cassoulet","ro":"Cassoulet"},"category":{"en":"Dinner","ro":"Cină"},"servings":6,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["500 g dried white beans (haricot tarbais or cannellini), soaked in cold water overnight","4 confit duck legs (cuisses de canard confites), at room temperature, fat reserved","400 g pork shoulder, cut into 4 cm pieces","300 g pork belly with rind, cut into 3 cm pieces","4 Toulouse sausages (about 500 g) — or smoked pork sausages as a substitute","1 large carrot (about 150 g), peeled and cut into 2 cm chunks","1 large onion (about 200 g), peeled and studded with 4 whole cloves","1 head of garlic (about 60 g), halved horizontally","1 bouquet garni (1 bay leaf + 4 thyme sprigs + 4 parsley stalks + a piece of dried orange peel, tied)","1 pork knuckle bone or ham hock (about 400 g, optional but traditional)","200 g canned chopped tomatoes (or 2 ripe tomatoes, peeled and chopped)","2 tbsp tomato paste","1.5 litres unsalted chicken or pork stock (or water)","60 g coarse white breadcrumbs","1.5 tsp fine sea salt, plus more to taste","1 tsp freshly ground black pepper","2 tbsp finely chopped fresh flat-leaf parsley, to garnish","2 tbsp duck fat (from the confit), for browning the meats"],"ro":["500 g fasole albă uscată (haricot tarbais sau cannellini), înmuiată în apă rece peste noapte","4 pulpe de rață confit (cuisses de canard confites), la temperatura camerei, grăsimea păstrată","400 g umăr de porc, tăiat bucăți de 4 cm","300 g piept de porc cu șorici, tăiat bucăți de 3 cm","4 cârnați de Toulouse (aproximativ 500 g) — sau cârnați afumați de porc ca substitut","1 morcov mare (aproximativ 150 g), curățat și tăiat bucăți de 2 cm","1 ceapă mare (aproximativ 200 g), curățată și înfiptă cu 4 cuișoare întregi","1 căpățână de usturoi (aproximativ 60 g), tăiată orizontal","1 bouquet garni (1 foaie de dafin + 4 crenguțe de cimbru + 4 cozi de pătrunjel + o bucată de coajă uscată de portocală, legate)","1 os de jambon afumat sau o ciolan de porc (aproximativ 400 g, opțional dar tradițional)","200 g roșii sfărâmate din conservă (sau 2 roșii coapte, decojite și tocate)","2 linguri pastă de roșii","1,5 litri supă de pui sau de porc nesărată (sau apă)","60 g pesmet alb grosier","1,5 lingurițe sare fină de mare, plus după gust","1 linguriță piper negru proaspăt măcinat","2 linguri pătrunjel proaspăt cu frunze plate, tocat fin, pentru garnitură","2 linguri grăsime de rață (din confit), pentru rumenirea cărnurilor"]},"howIsMade":{"en":"The night before, place the beans in a large bowl, cover with at least 2 litres of cold water, and soak for 10–12 hours; they will roughly double in size; drain and rinse the next day. Make the bean stock; put the drained beans in a heavy 5-litre pot with the pork knuckle (if using), the studded onion, the halved garlic head, the carrot chunks, the bouquet garni, and 1.5 litres of cold stock; bring to a gentle simmer and cook uncovered for 50–60 minutes, until the beans are just tender but not falling apart; do not salt yet. Meanwhile, brown the meats; heat 2 tbsp duck fat in a wide skillet over medium-high heat; pat the pork shoulder and pork belly dry and brown in batches for 4–5 minutes per side until deep golden; lift onto a plate; in the same fat, brown the Toulouse sausages for 2–3 minutes per side just to colour the casings; add to the plate. Heat the oven to 160°C (320°F / fan 140°C); lift the cooked knuckle, onion, garlic, carrot, and bouquet garni out of the bean pot and discard the aromatics; pull any meat from the knuckle bone, shred coarsely, and reserve; stir the tomato paste and chopped tomatoes into the bean liquid, then taste and add 1.5 tsp salt and the pepper. Assemble the cassoulet in a wide 26 cm cassole (or any wide oven-safe pot); spread one-third of the beans on the bottom, then arrange the browned pork shoulder, pork belly, knuckle meat, and the cold confit duck legs on top; cover with another third of the beans, lay the browned sausages on top, then finish with the remaining beans; pour over enough bean liquid to just cover the top layer of beans — keep the rest warm for topping up. Sprinkle the breadcrumbs evenly over the top; place the cassole in the oven, uncovered, and cook for 1 hour; the breadcrumbs will gild and form a brown crust. After 1 hour, break the crust by pressing it down into the cassoulet with the back of a wooden spoon — do not stir; top up with a ladle of reserved bean liquid if it looks dry; return to the oven and cook for another hour, breaking the crust again after 30 minutes, until a fresh crust has formed and the cassoulet is bubbling deeply around the edges. Repeat once more: break the crust, top up the liquid, and bake a final 30–40 minutes; the total oven time is about 2 h 30 m — three crusts in all; rest the cassoulet for 10 minutes out of the oven so the beans drink back the liquid; scatter with chopped parsley and serve straight from the pot, with crusty bread and a green salad."},"timeMins":{"total":240,"active":45}},{"id":144,"origin":{"en":"Croatia","ro":"Croația"},"name":{"en":"Pasticada","ro":"Pašticada"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["1.2 kg beef rump or topside, in one piece","100 g pork fat back or pancetta, cut into 5 mm × 5 cm strips for larding","2 medium carrots (about 200 g): 1 cut into matchsticks for larding, 1 finely diced for the sauce","10 whole cloves (5 for larding, 5 for the marinade) + 0.5 tsp ground cloves for the sauce","6 garlic cloves, peeled — 3 crushed for the marinade, 3 finely chopped for the sauce","200 ml white wine vinegar + 200 ml cold water + 3 bay leaves + 1 tsp black peppercorns + 4 juniper berries (for the marinade)","2 large onions (about 400 g), finely diced","200 g pitted prunes (dried plums)","100 ml prošek dessert wine (or sweet Marsala or 1 tbsp brown sugar + 80 ml port)","500 ml dry red wine (Plavac Mali, Merlot, or any robust dry red)","300 ml unsalted beef stock","2 tbsp tomato paste + 200 g canned chopped tomatoes","1 tsp ground cinnamon + 0.5 tsp freshly grated nutmeg","50 g lard (or 3 tbsp olive oil), for browning","1.5 tsp fine sea salt, plus more to taste","0.5 tsp freshly ground black pepper, for finishing","Fresh parsley, finely chopped, to garnish","Gnocchi or fresh pasta (about 500 g), to serve"],"ro":["1,2 kg vrăbioară sau pulpă de vită, într-o singură bucată","100 g slană de porc sau pancetta, tăiată fâșii de 5 mm × 5 cm pentru împănat","2 morcovi medii (aproximativ 200 g): 1 tăiat fâșii subțiri pentru împănat, 1 tăiat cuburi mici pentru sos","10 cuișoare întregi (5 pentru împănat, 5 pentru marinadă) + 0,5 linguriță cuișoare măcinate pentru sos","6 căței de usturoi decojiți — 3 zdrobiți pentru marinadă, 3 tocați fin pentru sos","200 ml oțet de vin alb + 200 ml apă rece + 3 foi de dafin + 1 linguriță boabe de piper negru + 4 boabe de ienupăr (pentru marinadă)","2 cepe mari (aproximativ 400 g), tocate fin","200 g prune uscate fără sâmburi","100 ml vin dulce prošek (sau Marsala dulce, sau 1 lingură zahăr brun + 80 ml porto)","500 ml vin roșu sec (Plavac Mali, Merlot sau orice vin sec robust)","300 ml supă de vită nesărată","2 linguri pastă de roșii + 200 g roșii sfărâmate din conservă","1 linguriță scorțișoară măcinată + 0,5 linguriță nucșoară proaspăt rasă","50 g untură (sau 3 linguri ulei de măsline), pentru rumenire","1,5 lingurițe sare fină de mare, plus după gust","0,5 linguriță piper negru proaspăt măcinat, pentru finisare","Pătrunjel proaspăt tocat fin, pentru garnitură","Gnocchi sau paste proaspete (aproximativ 500 g), pentru servit"]},"howIsMade":{"en":"Day 1, lard the beef; using a sharp paring knife, make 16 deep slits across the surface of the beef joint; slide a strip of pork fat, a carrot matchstick, and (in alternate slits) half of a whole clove into each slit; the fat will baste the meat from the inside, the carrot will sweeten the sauce, and the cloves perfume the meat. Make the marinade; in a non-reactive bowl just large enough to hold the beef, combine 200 ml wine vinegar, 200 ml cold water, the 3 crushed marinade garlic cloves, 3 bay leaves, peppercorns, juniper berries, and the remaining 5 whole cloves; submerge the beef, cover, and refrigerate 24 hours (up to 48 hours), turning twice. Day 2, lift the beef out, scrape off any clinging spices, and pat thoroughly dry — wet meat will not brown; discard the marinade; season the meat with 1 tsp salt and 0.5 tsp pepper. Heat the lard in a heavy Dutch oven or braiser (28 cm) over medium-high heat; sear the beef on all sides for 3–4 minutes per side, about 12–15 minutes total, until evenly mahogany brown all over; lift onto a plate. Reduce the heat to medium; add the diced onion and a pinch of salt to the rendered fat and cook for 10–12 minutes, stirring often, until deeply golden brown — this slow caramelisation builds the sauce; add the diced carrot and chopped garlic and cook for another 3–4 minutes; stir in the tomato paste, ground cloves, cinnamon, and nutmeg and toast for 1 minute. Pour in the prošek and stir for 1 minute, scraping the base; add the red wine, raise the heat, and reduce by half (about 6–8 minutes); add the chopped tomatoes, beef stock, prunes, and the remaining 0.5 tsp salt; return the beef to the pot, settling it into the liquid — the sauce should come about three-quarters of the way up the meat. Cover with a tight lid and braise on the lowest hob heat (or in a 150°C oven) for 2 h 30 m – 3 h, turning the beef every 45 minutes, until a knife slides into the centre with no resistance; lift the beef onto a board and rest, tented with foil, for 15 minutes. Finish the sauce; lift out the prunes and reserve a handful for garnish; blend the rest with the sauce using a stick blender to a thick, glossy gravy (or push through a sieve for a finer finish); reduce uncovered for 5–8 minutes if it needs thickening — it should coat the back of a spoon and taste deeply sweet-sour-spiced; slice the rested beef across the grain into 1 cm slices, fan over warm gnocchi or fresh pasta, spoon the sauce generously, scatter with reserved prunes and chopped parsley, and serve immediately."}},{"id":145,"origin":{"en":"Cyprus","ro":"Cipru"},"name":{"en":"Sheftalia","ro":"Sheftalia"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mediterranean","ingredients":{"en":["400 g coarsely minced pork shoulder (15–20% fat)","300 g coarsely minced lamb shoulder (or 700 g all pork if lamb is unavailable)","300 g caul fat (lamb or pork), soaked in cold lightly-salted water for 30 minutes then drained — about a 30 × 30 cm sheet","1 large onion (about 200 g), grated and squeezed of excess liquid","30 g flat-leaf parsley, finely chopped","20 g fresh mint (Cypriot dyosmos), finely chopped (optional but traditional)","4 garlic cloves, finely minced","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp ground cumin","0.5 tsp ground cinnamon","60 ml dry white wine or 2 tbsp red wine vinegar (to bind and tenderise)","1 tbsp olive oil for the meat mixture","1 tbsp olive oil for brushing the grill","Lemon wedges, sliced red onion, sliced tomato, and warm pitta or Cypriot lemoni-bread, to serve","Tzatziki or hummus, to serve"],"ro":["400 g umăr de porc tocat grosier (15–20% grăsime)","300 g umăr de miel tocat grosier (sau 700 g doar porc, dacă mielul nu este disponibil)","300 g prapure (de porc sau miel), înmuiat în apă rece ușor sărată 30 de minute, apoi scurs — o foaie de aproximativ 30 × 30 cm","1 ceapă mare (aproximativ 200 g), dată pe răzătoare și stoarsă de lichidul în exces","30 g pătrunjel cu frunze plate, tocat fin","20 g mentă proaspătă (dyosmos cipriot), tocată fin (opțional, dar tradițional)","4 căței de usturoi, tocați fin","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță chimion măcinat","0,5 linguriță scorțișoară măcinată","60 ml vin alb sec sau 2 linguri oțet de vin roșu (pentru a lega și a frăgezi)","1 lingură ulei de măsline pentru compoziție","1 lingură ulei de măsline pentru uns grătarul","Felii de lămâie, ceapă roșie feliată, roșii feliate și pita caldă sau pâine cipriotă de lămâie (lemoni), pentru servit","Tzatziki sau hummus, pentru servit"]},"howIsMade":{"en":"Make the meat mixture; in a wide bowl combine the minced pork, minced lamb, grated onion, parsley, mint (if using), garlic, salt, pepper, cumin, cinnamon, wine (or vinegar), and 1 tbsp olive oil; knead with your hand for 2–3 minutes until sticky and homogeneous; cover and chill in the fridge for at least 1 hour (up to 12 hours) so the seasoning matures. Prepare the caul fat; spread the soaked and drained caul fat carefully on a clean board — it tears very easily; use scissors to cut it into 12 squares of about 12 × 12 cm; patch holes by overlapping pieces. Shape the sheftalia; take a tablespoon-sized portion of meat (about 50–60 g) and shape into a slightly tapered cylinder 7–8 cm long; place at the edge of one caul-fat square; fold the sides over the meat, then roll up tightly into a sausage shape, finishing with the seam underneath; pierce onto a metal skewer if you have one — otherwise the wrapped seam will hold; repeat with the remaining meat and caul fat: you should get 12 sheftalia, 3 per person. Rest the wrapped sausages on a tray and chill for at least 15 minutes (up to 4 hours) so the caul fat firms — they hold together better on the grill. Heat a charcoal grill or a heavy ridged griddle pan to medium-high (about 200°C / 390°F surface); brush lightly with 1 tbsp olive oil; the sheftalia should hiss when they touch the grill but not flare aggressively — too high and the caul fat will burn before the meat cooks through. Grill the sheftalia for 12–15 minutes total, turning every 3–4 minutes onto each of their four sides, until the caul fat has rendered down into a thin lacy crust and the meat reaches 70°C in the centre; they should be deep golden brown and feel firm but not hard. Lift the sheftalia onto a board and rest, loosely tented with foil, for 5 minutes; the juices settle and the meat finishes cooking from residual heat. Warm the pitta or Cypriot lemoni-bread on the grill for 30 seconds per side; pile 3 sheftalia per person on each plate with the warm bread, lemon wedges, sliced red onion, and tomato; spoon tzatziki or hummus to the side; eat by tearing pieces of sheftalia into the pitta with the salad and dip."}},{"id":146,"origin":{"en":"Bosnia and Herzegovina","ro":"Bosnia și Herțegovina"},"name":{"en":"Cevapi","ro":"Cevapi"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["500 g coarsely minced beef chuck (about 15% fat)","300 g coarsely minced lamb shoulder (or 800 g all beef if lamb is unavailable)","4 garlic cloves, crushed with 0.5 tsp salt to a fine paste","60 ml chilled sparkling water","1 tsp baking soda (sodium bicarbonate) — the key to the springy texture","1.5 tsp fine sea salt","1 tsp freshly ground black pepper","1 tsp sweet Hungarian paprika","0.5 tsp dried marjoram or oregano (optional but traditional)","1 tbsp neutral oil for brushing","4 somun flatbreads (or 4 pittas), about 18 cm across each, to serve","1 large red onion (about 200 g), very finely diced","200 g ajvar (roasted red-pepper relish)","100 g kajmak (Balkan clotted cream) or thick crème fraîche, as a substitute","1 small bunch flat-leaf parsley, leaves picked, to scatter"],"ro":["500 g pulpă de vită tocată grosier (15% grăsime)","300 g umăr de miel tocat grosier (sau 800 g doar vită, dacă nu există miel)","4 căței de usturoi, zdrobiți cu 0,5 linguriță sare într-o pastă fină","60 ml apă minerală rece (carbogazoasă)","1 linguriță bicarbonat de sodiu — cheia texturii elastice","1,5 lingurițe sare fină de mare","1 linguriță piper negru proaspăt măcinat","1 linguriță boia dulce maghiară","0,5 linguriță maghiran sau oregano uscat (opțional, dar tradițional)","1 lingură ulei neutru pentru uns","4 lipii somun (sau 4 pita) de aproximativ 18 cm fiecare, pentru servit","1 ceapă roșie mare (aproximativ 200 g), tocată foarte fin","200 g ajvar (pastă de ardei copți)","100 g kajmak (smântână groasă balcanică) sau crème fraîche groasă ca substitut","1 legătură mică de pătrunjel cu frunze plate, frunzele păstrate, pentru servit"]},"howIsMade":{"en":"Make the meat mixture; in a wide bowl combine the minced beef, minced lamb, garlic-salt paste, chilled sparkling water, baking soda, salt, pepper, paprika, and marjoram; knead vigorously with your hand for 4–5 minutes — the mixture should become noticeably sticky and start to pull together; this long knead and the bicarbonate are what give cevapi their characteristic springy bounce. Cover the bowl with cling film and rest the mixture in the fridge for at least 4 hours, ideally 12–24 hours; the flavour matures and the proteins relax. Wet your hands with cold water; take a tablespoon-sized portion of meat (about 35–40 g) and roll it between your palms into a finger-shaped cylinder about 7–8 cm long and 2 cm thick; repeat with the remaining meat to make about 24 cevapi (6 per person); arrange on a tray as you go. Chill the shaped cevapi for at least 20 minutes (up to 4 hours) to firm — they hold their shape better on the grill. Heat a charcoal grill or a heavy ridged griddle pan to medium-high (about 220°C surface); brush the cevapi very lightly with oil — barely a glaze; the grill should hiss but not smoke aggressively. Grill the cevapi for 8–10 minutes total, turning every 2 minutes onto all four sides, until the surface is mahogany brown with crisp edges and the centre reaches 65°C (they continue cooking on the plate); do not press them down; the goal is juicy, springy interiors. While the cevapi rest for 2 minutes, warm the somun (or pittas) on the grill 30 seconds per side until just puffed and lightly charred; split each one open along the seam to make a pocket. Pile 6 cevapi inside each warm flatbread (or arrange 6 on each plate beside the bread); spoon 1–2 tablespoons of ajvar to one side, add a generous knob of kajmak (or crème fraîche), and a small mound of diced raw red onion; scatter parsley leaves and serve immediately — the cevapi juices should soak into the somun."}},{"id":147,"origin":{"en":"Ghana","ro":"Ghana"},"name":{"en":"Fufu","ro":"Fufu"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"veg","pairingsType":"veg","ingredients":{"en":["700 g fresh cassava root, peeled and cut into 5 cm chunks (or 500 g pre-peeled frozen cassava chunks, thawed)","500 g semi-ripe plantains, about 3 large, peeled and cut into 5 cm chunks (yellow skin streaked with black gives the right balance of sweet and starchy)","1 tbsp fine sea salt for the cooking water","2 litres cold water for boiling","About 150 ml hot cooking water reserved from the pot, kept warm in a jug","1 tbsp neutral oil (palm or sunflower), for oiling hands and the serving bowl","1 large pot of hot West African soup (600 ml–1 L of light soup, palmnut, groundnut, or egusi), for serving","Sliced fresh scotch bonnet chilli, for those who want extra heat","Roasted peanuts or crushed groundnuts, to scatter over the soup (optional)"],"ro":["700 g manioc proaspăt, curățat și tăiat bucăți de 5 cm (sau 500 g cassava decongelată, deja curățată)","500 g banane plantain semi-coapte, aproximativ 3 mari, decojite și tăiate bucăți de 5 cm (coaja galbenă cu pete negre dă echilibrul potrivit între dulce și amidonos)","1 lingură sare fină de mare pentru apa de fierbere","2 litri apă rece pentru fierbere","Aproximativ 150 ml apă fierbinte de fierbere păstrată separat, ținută caldă într-un vas","1 lingură ulei neutru (palmier sau floarea-soarelui), pentru a unge mâinile și bolul de servit","O cratiță mare cu supă vest-africană caldă (600 ml–1 L de light soup, palmnut, groundnut sau egusi), pentru servit","Ardei iute scotch bonnet feliat, pentru cei care vor mai mult picant","Arahide prăjite sau pisate, pentru presărat peste supă (opțional)"]},"howIsMade":{"en":"Prepare the cassava; wash the cassava chunks under cold water to remove any clinging grit; with a paring knife slit the thick brown skin lengthwise, then peel it away (along with the pink underlayer) to expose the white core; cut out the fibrous central string from each piece and discard. In a heavy 5-litre pot, combine the peeled cassava chunks, the plantain chunks, the 1 tbsp salt, and the 2 litres cold water; bring to a gentle boil over medium-high heat, then reduce to medium-low and cook for 30–40 minutes, until both cassava and plantain are fork-tender — the cassava should feel like a cooked potato when pierced. Drain into a colander but reserve at least 250 ml of the hot cooking liquid in a jug for later; pick out and discard any visible fibres or strings. Pound the fufu; traditional method: transfer the hot cassava-plantain mixture in batches to a heavy wooden mortar lubricated with a few drops of oil; with a long wooden pestle, pound rhythmically while a second person (lightly oiled hands) turns and gathers the mass between strokes; work for 8–10 minutes per batch until the paste is dense, perfectly smooth, and noticeably elastic — no lumps remain. Mortar-free method: place the hot cassava and plantain together in a sturdy stand mixer with the dough-hook attachment; run at low speed for 1 minute to break down the chunks, then increase to medium and beat for 6–8 minutes, scraping the bowl every 2 minutes, until the mass forms a single elastic dough around the hook; add a tablespoon of reserved hot cooking water at a time if it is too dry — the goal is glossy and elastic without being wet. Test the texture; pinch off a small piece (about 50 g) and roll it in lightly oiled palms into a smooth ball; the surface should be glossy and seamless, and the ball should hold its shape on a plate without sagging or cracking; if it cracks, work in another spoonful of hot water; if it slumps, knead for another 2 minutes. Shape the serving portions with lightly oiled hands: form 4 large balls of about 250 g each (or 8 smaller balls for traditional individual servings); place each ball in a slightly oiled wide bowl so it does not stick; cover with a damp cloth until ready to serve — fufu hardens quickly when exposed to air. Serve immediately; ladle hot West African soup (light soup, palmnut, groundnut, or egusi) into a wide soup bowl around each fufu ball; eat by pinching off a small piece of fufu with the right hand, pressing a depression into it with the thumb to form a cup, and using it to scoop up the soup — do not chew the fufu, swallow it whole so the flavour of the soup carries it down; scatter chopped scotch bonnet and roasted peanuts to taste."}},{"id":148,"origin":{"en":"Georgia","ro":"Georgia"},"name":{"en":"Khinkali","ro":"Khinkali"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["500 g plain (all-purpose) flour, plus extra for rolling","250 ml cold water","1 large egg, lightly beaten (optional — some Georgian families use an egg for a softer dough)","1 tsp fine sea salt for the dough","1 tbsp neutral oil for the dough","500 g coarsely minced beef (around 15% fat)","200 g coarsely minced pork shoulder (or 700 g all beef for a leaner result)","1 large onion (about 200 g), very finely diced — do NOT grate, the texture matters","3 garlic cloves, finely minced","20 g fresh coriander, finely chopped — stems and leaves","1 tsp ground cumin + 1 tsp freshly ground black pepper + 0.5 tsp khmeli suneli (or 0.25 tsp caraway + 0.25 tsp ground fenugreek as substitute)","1.5 tsp fine sea salt for the filling","200 ml ice-cold beef stock or cold water (releases steam slowly during boiling — this is what creates the famous broth pocket)","1 tbsp coarse sea salt for the cooking water","Plenty of freshly cracked black pepper, to scatter at the table"],"ro":["500 g făină albă obișnuită, plus pentru întins","250 ml apă rece","1 ou mare, bătut ușor (opțional — unele familii georgiene folosesc un ou pentru un aluat mai moale)","1 linguriță sare fină de mare pentru aluat","1 lingură ulei neutru pentru aluat","500 g vită tocată grosier (în jur de 15% grăsime)","200 g umăr de porc tocat grosier (sau 700 g doar vită pentru un rezultat mai slab)","1 ceapă mare (aproximativ 200 g), tocată foarte fin — NU rasă, textura contează","3 căței de usturoi, tocați fin","20 g coriandru proaspăt, tocat fin — tulpini și frunze","1 linguriță chimion măcinat + 1 linguriță piper negru proaspăt măcinat + 0,5 linguriță khmeli suneli (sau 0,25 linguriță chimion negru + 0,25 linguriță schinduf măcinat ca substitut)","1,5 lingurițe sare fină de mare pentru umplutură","200 ml supă de vită rece ca gheața sau apă rece (eliberează aburi încet în timpul fierberii — acesta este secretul pungii de bulion)","1 lingură sare grunjoasă de mare pentru apa de fierbere","Mult piper negru proaspăt măcinat, pentru presărat la masă"]},"howIsMade":{"en":"DOUGH: mix 500 g flour with 1 tsp salt in a large bowl; gradually pour in 250 ml cold water (and optionally 1 beaten egg + 1 tbsp oil), stirring with a fork, then knead on the bench 8–10 minutes until the dough is smooth, firm and elastic — it needs to be tough enough to roll thin without tearing; cover with film and rest 30 minutes at room temperature. FILLING: in a bowl, mix by hand 500 g beef + 200 g pork coarse-mince with 200 g very finely diced onion, 3 garlic cloves, 20 g chopped coriander, 1 tsp cumin, 1 tsp black pepper, 0.5 tsp khmeli suneli and 1.5 tsp salt; slowly pour in 200 ml ice-cold stock, 50 ml at a time, mixing after each addition — the filling should be loose and wet but not soupy; cover and chill 30 minutes. ROLLING: divide the dough into 4 pieces; work one piece at a time (keep the rest covered); roll out to a 2 mm thin sheet on a lightly floured surface; cut 12–14 cm diameter circles with a saucer or large glass; gather scraps, knead briefly and roll again. SHAPING: place a circle in your palm, put about 30 ml (2 tbsp) of filling in the centre; with the other hand, form 18–20 pleats around the filling, pinching each pleat between thumb and forefinger and twisting it gently toward the centre; at the end, gather all pleats at the top and twist the tip — the tail — to seal; set the khinkali on a floured surface. COOKING WATER: bring 4 litres of water to a vigorous rolling boil in a large pot and add 1 tbsp coarse salt. BOILING: drop 5–6 khinkali at a time into the boiling water (do not crowd); the moment they float to the surface (after 2–3 minutes), start your timer: boil another 8–10 minutes; total 12–14 minutes; they are done when the pleats turn translucent and you can see the broth moving inside. REMOVING: lift them out with a slotted spoon, let drain briefly and arrange on a warm plate; immediately scatter plenty of freshly cracked black pepper over the top; no sauce — khinkali are eaten plain. HOW TO EAT: hold the khinkali by the tail with your fingers, tilt slightly and bite a small hole near the seam, then sip the hot broth from inside first before it spills; then eat the rest of the dumpling, leaving the twisted tail on the plate; the number of tails left = how many you ate."}},{"id":149,"origin":{"en":"Mexico","ro":"Mexic"},"name":{"en":"Pozole","ro":"Pozole"},"category":{"en":"Lunch","ro":"Prânz"},"servings":6,"tipType":"meat","pairingsType":"mexican","ingredients":{"en":["1.2 kg boneless pork shoulder, cut into 4 cm cubes","500 g pork neck bones or pork tail (for a richer broth)","1 large white onion halved, skin on (for color) + 1 small onion finely diced for serving","8 garlic cloves (6 for the broth, 2 for the chili sauce)","3 bay leaves","1 tbsp coarse salt for the broth + salt to taste","4 litres cold water for the broth","800 g canned hominy, drained and rinsed (or 250 g dried hominy soaked overnight and boiled separately)","6 dried guajillo chilies, stemmed and deseeded","4 dried ancho chilies, stemmed and deseeded","2 dried árbol chilies (optional, for heat)","1 tsp ground cumin","1 tsp dried Mexican oregano","200 g green cabbage, finely shredded for serving","150 g red radishes, thinly sliced","4–6 limes cut into wedges","12 tostadas (crisp corn tortillas)","Fresh or dried oregano to scatter at the table"],"ro":["1,2 kg umăr de porc dezosat, tăiat în cuburi de 4 cm","500 g oase de porc cu carne (gât sau coadă) pentru un bulion mai bogat","1 ceapă albă mare tăiată în jumătăți (cu coajă, pentru culoare) + 1 ceapă mică tocată fin pentru servire","8 căței de usturoi (6 pentru bulion, 2 pentru sosul de ardei)","3 frunze de dafin","1 lingură sare grunjoasă pentru bulion + sare după gust","4 litri apă rece pentru bulion","800 g hominy din conservă, scurs și clătit (sau 250 g hominy uscat înmuiat peste noapte și fiert separat)","6 ardei guajillo uscați, decotorați și fără semințe","4 ardei ancho uscați, decotorați și fără semințe","2 ardei de árbol uscați (opțional, pentru iuțeală)","1 linguriță chimion măcinat","1 linguriță oregano mexican uscat","200 g varză verde tocată mărunt, pentru servire","150 g ridichi roșii feliate subțire","4–6 lime tăiate în sferturi","12 tostadas (lipii de porumb crocante)","Oregano proaspăt sau uscat de presărat la masă"]},"howIsMade":{"en":"BROTH BASE: place 1.2 kg cubed pork shoulder + 500 g pork bones, 1 halved onion (skin on), 6 garlic cloves, 3 bay leaves and 1 tbsp salt in a large stockpot; cover with 4 litres of cold water; bring to a boil, skim the foam for the first 5 minutes, then reduce to a gentle simmer. SIMMER THE PORK: simmer uncovered 1.5–2 hours until the pork is fork-tender; lift out meat and bones, shred the meat coarsely with two forks, set aside; strain the broth (~3.5 L) and discard the solids. TOAST THE CHILIES: heat a dry skillet over medium heat; toast 6 guajillo + 4 ancho + 2 árbol chilies (optional), pressing them down with a spatula, 30 seconds per side until fragrant and lightly blistered — do not burn or the broth will turn bitter; transfer to a bowl, cover with boiling water, and soak 15 minutes until softened. CHILI SAUCE: transfer the soaked chilies to a blender with 2 garlic cloves, 1 tsp cumin, 1 tsp oregano and 500 ml of the warm broth; blend on high 2–3 minutes until completely smooth; strain the puree through a fine sieve into a bowl, pressing the pulp through — discard the skin bits left behind. COMBINE: pour the strained chili sauce back into the broth pot; add the shredded pork and 800 g drained hominy; bring to a simmer and cook uncovered 30–40 minutes, stirring occasionally, until the broth thickens slightly and the flavours meld; taste and adjust salt — it should be deeply savoury. PREP THE GARNISHES: while the pozole simmers, finely shred 200 g cabbage, thinly slice 150 g radishes, finely dice 1 onion, cut 4–6 limes into wedges, prepare oregano; arrange each in small bowls on the table. TOSTADAS: warm 12 tostadas in a dry skillet 30 seconds per side until crisp and lightly toasted; place in a basket for the table. SERVE: ladle the pozole into deep bowls; each guest customises their bowl: a handful of cabbage, scattering of radish, pinch of onion and oregano, squeeze of lime; tostadas eaten alongside — broken into the broth or used to scoop; eaten immediately while piping hot."}},{"id":150,"origin":{"en":"Guatemala","ro":"Guatemala"},"name":{"en":"Pepian","ro":"Pepian"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"meat","pairingsType":"mexican","ingredients":{"en":["1.2 kg bone-in chicken thighs and drumsticks (about 8 pieces)","1.5 L cold water + 1 tsp salt for poaching","100 g raw hulled pumpkin seeds (pepitas)","50 g sesame seeds","4 dried guajillo chilies, stemmed and deseeded","2 dried ancho or pasilla chilies, stemmed and deseeded","1 dried chipotle chili (optional, for smokiness)","4 medium tomatoes (~500 g), halved","4 tomatillos (~200 g), husked and halved","1 medium onion (~150 g), quartered","5 unpeeled garlic cloves","1 Ceylon cinnamon stick (~5 cm)","2 whole cloves","1 tsp ground black pepper + 0.5 tsp ground allspice","1 corn tortilla, torn into pieces (for thickening)","200 g güisquil (chayote squash) or zucchini, peeled and cubed 2 cm","300 g potatoes, peeled and cubed 2 cm","2 tbsp vegetable oil for cooking the paste","2 tbsp fresh cilantro, finely chopped, to garnish","Salt to taste","500 g cooked white rice + warm tortillas to serve"],"ro":["1,2 kg pulpe și pulpe inferioare de pui cu os (aproximativ 8 bucăți)","1,5 L apă rece + 1 linguriță sare pentru fierberea puiului","100 g semințe crude de dovleac decojite (pepitas)","50 g semințe de susan","4 ardei guajillo uscați, decotorați și fără semințe","2 ardei ancho sau pasilla uscați, decotorați și fără semințe","1 ardei chipotle (opțional, pentru afumare)","4 roșii medii (~500 g), tăiate în jumătăți","4 tomatillos (~200 g), curățați de coajă și tăiați în jumătăți","1 ceapă medie (~150 g), tăiată în sferturi","5 căței de usturoi, necurățați","1 batjoc de scorțișoară Ceylon (~5 cm)","2 cuișoare întregi","1 linguriță piper negru măcinat + 0,5 linguriță ienibahar măcinat","1 tortilla de porumb, ruptă în bucăți (pentru îngroșare)","200 g chayote (sau dovlecel ca substitut), curățat și tăiat cuburi de 2 cm","300 g cartofi, curățați și tăiați cuburi de 2 cm","2 linguri ulei vegetal pentru sotare","2 linguri coriandru proaspăt, tocat fin, pentru ornare","Sare după gust","500 g orez alb gătit + tortillas calde pentru servire"]},"howIsMade":{"en":"POACH THE CHICKEN: place 1.2 kg chicken pieces in 1.5 L cold water with 1 tsp salt in a large pot; bring to a boil, skim the foam, then reduce to a gentle simmer; cook 25–30 minutes until the chicken is just cooked through (juices run clear); remove the chicken to a plate and reserve the broth (~1.2 L). TOAST THE SEEDS: in a dry skillet over medium heat, toast 100 g pumpkin seeds, stirring constantly, 3–4 minutes until they puff up and turn golden brown — do not burn; transfer to a bowl; in the same skillet, toast 50 g sesame seeds 1–2 minutes until golden and fragrant, stirring constantly; add to the same bowl. CHAR THE VEGETABLES: in a dry skillet or comal over medium-high heat, char 4 halved tomatoes (cut side down first), 4 halved tomatillos, 1 quartered onion, and 5 unpeeled garlic cloves; turn occasionally for 8–10 minutes until the skins are blackened in spots and the vegetables soften; peel the garlic after they cool. TOAST THE CHILIES AND SPICES: in the same skillet, briefly toast 4 guajillo + 2 ancho + 1 chipotle (optional) chilies, pressing them flat with a spatula, 20–30 seconds per side until fragrant — do not burn; transfer to a bowl and cover with boiling water; soak 15 minutes; in the same skillet, briefly toast 1 cinnamon stick, 2 cloves, 1 tsp pepper, and 0.5 tsp allspice for 30 seconds; toast the torn tortilla pieces 30 seconds per side until crisp. BLEND THE PASTE: in a blender, combine the drained chilies, the charred vegetables, peeled garlic, toasted seeds, toasted tortilla pieces, and 500 ml of the chicken broth; blend on high 3–4 minutes until the paste is completely smooth — strain through a fine sieve if you want it silky. COOK THE SAUCE: heat 2 tablespoons of oil in the pot over medium heat; pour in the blended paste — be careful, it will splutter; simmer 10 minutes, stirring frequently with a wooden spoon, until the sauce darkens and the rawness cooks off; the sauce should coat the back of the spoon. STEW THE CHICKEN: return the chicken pieces to the pot, then pour in the remaining 700 ml broth + 200 g chayote + 300 g potato cubes; simmer gently, partially covered, 25–30 minutes until the potatoes and chayote are fork-tender and the chicken is fully infused with the sauce; stir occasionally to prevent sticking; adjust salt to taste — the sauce should taste deeply spiced and slightly sweet. SERVE: spoon the pepian into deep plates over a bed of steamed white rice; top each serving with a sprinkle of fresh cilantro and a squeeze of lime (optional); serve with warm corn tortillas on the side for scooping up the sauce."}},{"id":151,"origin":{"en":"Russia","ro":"Rusia"},"name":{"en":"Okroshka","ro":"Okroshka"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"soup","ingredients":{"en":["1 L plain kefir (3.2% fat), well chilled","500 ml cold still mineral water (or cold boiled water), chilled","500 g medium starchy potatoes (4 pieces), boiled in skins then peeled and diced 1 cm","4 large hard-boiled eggs, peeled and diced 1 cm","400 g cucumbers (3 medium), peeled, large seeds scooped out, diced 0.5 cm","300 g cooked doktorskaya sausage or boiled ham, diced 0.5 cm","150 g red radishes, trimmed and diced 0.5 cm","6 spring onions (whites and greens kept separate), thinly sliced","30 g fresh dill, finely chopped (plus 1 tbsp to garnish)","1 tbsp Dijon-style mustard (optional but traditional)","1.5 tsp fine salt + 0.5 tsp freshly ground black pepper","1 tsp sugar (balances the kefir tang)","1 tsp lemon juice or white-wine vinegar","Sour cream (smetana) to drizzle when serving","Ice cubes and fresh dark rye bread for serving"],"ro":["1 L chefir simplu 3,2% grăsime, bine răcit","500 ml apă minerală plată rece sau apă fiartă rece, răcită","500 g cartofi medii (4 bucăți) fierți în coajă, decojiți și tăiați cuburi de 1 cm","4 ouă mari fierte tari, decojite și tăiate cuburi de 1 cm","400 g castraveți (3 bucăți medii), decojiți, fără sâmburi mari și tăiați cuburi de 0,5 cm","300 g cârnați doktorskaya sau șuncă fiartă, tăiată cuburi de 0,5 cm","150 g ridichi roșii, tăiate cuburi de 0,5 cm","6 cepe verzi (cu părți albe și verzi separate), feliate subțire","30 g mărar proaspăt, tocat fin (plus 1 lingură pentru ornare)","1 lingură muștar Dijon (opțional, dar tradițional)","1,5 lingurițe sare fină + 0,5 linguriță piper negru proaspăt măcinat","1 linguriță zahăr (echilibrează aciditatea chefirului)","1 linguriță suc de lămâie sau oțet de vin alb","Smântână (smetana) pentru servire","Cuburi de gheață și pâine neagră proaspătă pentru servire"]},"howIsMade":{"en":"BOIL THE POTATOES AND EGGS: in a pot of cold salted water, boil 500 g whole potatoes (skins on, scrubbed) 20–25 min until fork-tender; in a second pot, place 4 eggs in cold water, bring to a boil, then simmer 9 min for hard-boiled; drain both, cover potatoes with cold water to peel easily, plunge eggs into ice water 5 min; peel and dice both 1 cm; spread on a tray and chill 30 min in the fridge — everything must be cold before mixing. DICE THE CUCUMBERS: peel 400 g cucumbers, halve lengthwise, scoop out any large watery seeds with a spoon, then dice 0.5 cm — the small even cube is essential, larger pieces sink and ruin the soup; pat with paper towel to remove excess water. DICE THE PROTEIN: dice 300 g cooked sausage or boiled ham into 0.5 cm cubes — the same size as the cucumbers so each spoonful balances. DICE RADISH AND ONIONS: trim and dice 150 g radishes 0.5 cm; slice 6 spring onions (whites and greens kept separate); finely chop 30 g dill, reserve 1 tbsp for garnish; in a small bowl, mash 2 tbsp of the spring-onion whites with a pinch of salt using the back of a spoon — this releases their aroma into the soup. THE DRESSING: in a large mixing bowl, whisk together 1 L cold kefir + 500 ml cold water + 1 tbsp mustard + 1 tsp lemon juice + 1.5 tsp salt + 0.5 tsp pepper + 1 tsp sugar; whisk 30 seconds until smooth, then taste — the base should be tangy and slightly sweet, generously seasoned because the diced ingredients will dilute it. ASSEMBLE: add all diced ingredients (potatoes, eggs, cucumbers, sausage, radish, spring-onion greens and mashed whites, dill) to the kefir base; stir gently with a ladle to distribute evenly without crushing anything. CHILL: cover and refrigerate the okroshka 30 minutes minimum (ideally 1 hour) so the flavours mingle and the soup becomes ice-cold; do not chill longer than 3 hours — the cucumbers will start to release water and the soup turns thin. SERVE: stir gently before serving; ladle into deep, well-chilled bowls; top each bowl with 1 tablespoon sour cream, a few extra dill fronds, and 2 ice cubes per bowl in summer heat; serve immediately with fresh dark rye bread on the side; mustard on the table for those who like it sharper."}},{"id":152,"origin":{"en":"Uzbekistan","ro":"Uzbekistan"},"name":{"en":"Plov","ro":"Plov"},"category":{"en":"Dinner","ro":"Cină"},"servings":6,"tipType":"meat","pairingsType":"meat","ingredients":{"en":["600 g lamb shoulder or beef chuck with some fat, cut into 3 cm cubes","100 g lamb-tail fat (kurdyuk) for authentic flavour — OR 150 ml neutral sunflower oil as a substitute","500 g devzira or long-grain basmati rice","500 g yellow carrots (or 600 g orange carrots), cut into julienne matchsticks 0.5 × 0.5 × 5 cm — do NOT grate","2 large yellow onions (~300 g), thinly sliced","2 whole heads of garlic (papery outer skins removed but heads intact)","1 tbsp whole cumin seeds (not ground)","1 tbsp dried barberries (zira/barbaris) — optional but traditional","0.5 tsp ground turmeric (for colour)","1 dried whole hot red chili (optional)","1 tsp ground black pepper","1.5 tbsp fine salt + extra to season","1.2 L boiling water (reserve)","100 g chickpeas, soaked overnight (optional, traditional Tashkent style)","To serve: thinly sliced red onion with vinegar, achichuk tomato-cucumber salad, flatbread (non)"],"ro":["600 g umăr de miel sau gulaș de vită cu puțină grăsime, tăiat cuburi de 3 cm","100 g grăsime de coadă de oaie (kurdyuk) — opțional pentru aromă autentică — SAU 150 ml ulei neutru de floarea-soarelui ca substitut","500 g orez devzira sau basmati cu bob lung","500 g morcovi galbeni (sau 600 g morcovi portocalii), tăiați julien în bețișoare de 0,5 × 0,5 × 5 cm — NU dați prin răzătoare","2 cepe galbene mari (~300 g), feliate subțire","2 căpățâni de usturoi întregi (cu coaja exterioară curățată, dar capul păstrat întreg)","1 lingură semințe de chimion întregi (nu măcinate)","1 lingură fructe uscate de cătină (zira/barbaris) — opțional, tradițional","0,5 linguriță turmeric măcinat (pentru culoare)","1 ardei roșu iute uscat întreg (opțional)","1 linguriță piper negru măcinat","1,5 linguri sare fină + sare după gust","1,2 L apă clocotită (rezerve)","100 g năut, înmuiat peste noapte (opțional, tradițional Tashkent)","Pentru servire: ceapă roșie feliată subțire cu oțet, salată de roșii cu castraveți (achichuk), pâine plată non"]},"howIsMade":{"en":"SOAK THE RICE: wash 500 g rice in cold water 4–5 times until the water runs clear, then soak it in warm salted water (1 tsp salt per litre) for 1 hour; this step is non-negotiable for plov — the grains stay separate and absorb the broth evenly; drain just before adding to the pot. RENDER THE FAT: in a heavy cast-iron kazan or Dutch oven over medium heat, melt 100 g lamb-tail fat until the cracklings are golden brown (about 8 minutes), then remove them with a slotted spoon; if using oil: heat 150 ml oil until it shimmers and faintly smokes (about 3 minutes at high heat) — essential to neutralize the raw taste. SEAR THE MEAT: raise heat to high and add 600 g cubed meat in a single layer to the hot fat; sear undisturbed 2–3 minutes per side, total 8–10 minutes, until deeply browned on all sides; lift the meat out to a plate. ONION + CARROT: in the remaining fat, add 300 g sliced onion and fry, stirring, 5–6 minutes until golden brown; return the meat and add 500 g julienned carrots in a single layer on top — do NOT stir for the first 5 minutes (this lets the carrots steam); then stir gently and cook another 8–10 minutes until the carrots are wilted, golden, and just starting to caramelize. ZIRVAK (BROTH BASE): pour in 1.2 L boiling water (it should cover the meat and carrots by 1 cm); add 1 tbsp cumin seeds (first rubbed briefly between your palms to release the oils), 1 tbsp barberries, 0.5 tsp turmeric, 1 dried chili, 1 tsp black pepper, 100 g chickpeas, 1.5 tbsp salt, and the 2 whole garlic heads pushed into the centre; bring to a boil, reduce heat to low and simmer uncovered 30 minutes — this is the zirvak; the broth must taste slightly over-seasoned; the rice will tame it. ADD THE RICE: drain the soaked rice carefully and spread it evenly over the zirvak (do not stir it in); the rice should just be submerged — if not, add boiling water carefully; raise heat to high and cook uncovered 10–12 minutes until the visible water has reduced to the surface of the rice (poke with a chopstick to check); tap the rice flat with a slotted spoon but never mix it with the meat layer below. COVER + STEAM: once the surface water has evaporated and small steam holes appear on the rice surface, mound the rice into a dome, poke 4–5 deep holes through to the bottom with the handle of a wooden spoon (for steam to escape), reduce heat to the lowest setting, cover the pot with a tight lid (place a clean kitchen towel under the lid to absorb condensation), and cook 25 minutes; then remove from heat and let rest, covered, 15 minutes — do not lift the lid. SERVE: uncover and lift out the garlic heads and chili; gently dig down with a spoon, lifting the rice and bringing the meat and carrots from the bottom to the top, mixing as you transfer to a large communal platter; arrange the meat and garlic on top in the centre, surrounded by rice; serve immediately with sliced red onion sprinkled with vinegar, fresh tomato salad, and flatbread on the side."}},{"id":153,"servings":8,"tipType":"dessert","pairingsType":"dessert","origin":{"en":"Slovenia","ro":"Slovenia"},"name":{"en":"Potica","ro":"Potica"},"category":{"en":"Dessert","ro":"Desert"},"ingredients":{"en":["For the dough: 500 g bread flour (or strong all-purpose), plus extra for kneading","7 g instant dry yeast OR 21 g fresh yeast","50 g caster sugar (1 tsp to feed the yeast, the rest in the dough)","5 g fine salt","250 ml warm whole milk (38 °C)","100 g unsalted butter, melted and cooled to lukewarm","2 large egg yolks + 1 whole egg for the dough","1 tbsp dark rum (optional, traditional)","Finely grated zest of 1 unwaxed lemon","For the walnut filling: 400 g finely ground shelled walnuts (freshly ground — pre-ground will not work)","200 ml hot whole milk","150 g acacia honey (or mild floral honey)","100 g unsalted butter, melted, for the filling","100 g caster sugar for the filling","2 large egg yolks + 2 egg whites (whipped to stiff peaks separately)","1 tbsp dark rum, 1 tsp ground cinnamon, 0.5 tsp ground cloves, 1 tbsp fresh breadcrumbs","For finishing: 1 egg beaten with 1 tbsp milk (egg wash), icing sugar to dust after baking"],"ro":["Pentru aluat: 500 g făină pentru pâine (T550), plus pentru frământare","7 g drojdie uscată instant SAU 21 g drojdie proaspătă","50 g zahăr fin (1 linguriță pentru a hrăni drojdia, restul în aluat)","5 g sare fină","250 ml lapte integral cald (38 °C)","100 g unt nesărat topit și răcit la călduț","2 gălbenușuri mari + 1 ou întreg pentru aluat","1 lingură rom întunecat (opțional, tradițional)","Coaja rasă fin de la 1 lămâie netratată","Pentru umplutură: 400 g miez de nucă măcinat fin (proaspăt măcinat, nu pre-măcinat — esențial)","200 ml lapte integral fierbinte","150 g miere de salcâm (sau miere florală blândă)","100 g unt nesărat topit pentru umplutură","100 g zahăr fin pentru umplutură","2 gălbenușuri + 2 albușuri (bătute spumă tare separat)","1 lingură rom întunecat, 1 linguriță scorțișoară măcinată, 0,5 linguriță cuișoare măcinate, 1 lingură pesmet proaspăt","Pentru finisare: 1 ou bătut cu 1 lingură lapte (spălătură), zahăr pudră pentru presărat după coacere"]},"howIsMade":{"en":"ACTIVATE THE YEAST: in a small bowl, dissolve 7 g instant dry yeast (or 21 g fresh yeast) into 250 ml warm milk (~38 °C) with 1 tsp sugar; let stand 10 minutes until a creamy foam appears on top — if it doesn't foam, the yeast is dead, start over. THE DOUGH: in a stand mixer with dough hook (or by hand), combine 500 g flour with the remaining 47 g sugar, 5 g salt, and lemon zest; pour in the foamed yeast-milk, 2 egg yolks + 1 whole egg, 100 g melted-and-cooled butter, and 1 tbsp rum; knead on medium speed 10 minutes (or 15 by hand) until the dough is smooth, elastic, and pulls cleanly from the bowl — it should be soft but not sticky; cover with film and proof in a warm place 1.5–2 hours until doubled. THE WALNUT FILLING: place 400 g freshly ground walnuts in a large bowl; pour over 200 ml hot milk, 100 g melted butter, 150 g honey, and 100 g sugar; stir well to scald the walnuts and dissolve the sugars; cool 10 minutes, then mix in 2 egg yolks, 1 tbsp rum, 1 tsp cinnamon, 0.5 tsp cloves, 1 tbsp breadcrumbs, and a pinch of salt; in a separate bowl, whip 2 egg whites to stiff peaks, then fold them gently into the walnut mixture in 3 additions — the filling should be airy and spreadable. ROLL THE DOUGH: lightly flour a clean tea towel and turn the proofed dough out onto it; punch down gently, then roll out into a thin rectangle 60 × 40 cm and 4–5 mm thick — work from the centre outward, lifting and rotating to prevent sticking; the dough must be thin enough that the spiral is visible after baking, but thick enough to hold the filling. SPREAD THE FILLING: spread the walnut filling evenly over the rolled dough, leaving a 2 cm border along the long edges; pat it gently with a spatula — do not overload, the filling should be 5–6 mm thick; sprinkle a few extra ground walnuts if any spot oozes thin. ROLL UP: using the tea towel to help, roll up the dough tightly from the long side, forming a long log; roll snug but not so tight you compress the filling; pinch the seam closed and tuck in the ends; the log should be about 60 cm long. SHAPE IN MOLD + SECOND PROOF: grease a tubular potica mold (or a 24 cm Bundt pan or a kugelhopf form) thoroughly with butter and dust with flour; lay the log in the mold, seam side down, joining the ends to form a closed ring (pinch them together); cover loosely and proof again in a warm place 45–60 minutes until the dough has risen visibly to almost fill the mold; meanwhile, preheat the oven to 175 °C. BAKE: brush the top with the egg wash; bake on the middle rack of the 175 °C oven 45–55 minutes — cover loosely with foil after 30 min if the top is browning too fast; the potica is done when a skewer comes out clean and the internal temperature reaches 92–95 °C; let it rest 15 minutes in the mold, then carefully invert onto a wire rack to cool completely; dust generously with icing sugar before slicing; serve at room temperature with strong coffee or tea."}},{"id":154,"servings":4,"tipType":"def","pairingsType":"soup","origin":{"en":"Nigeria","ro":"Nigeria"},"name":{"en":"Egusi soup","ro":"Egusi soup"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["250 g raw egusi seeds, finely ground (or 200 g pre-ground egusi)","600 g goat meat or beef chuck on the bone, cut into 4 cm pieces","200 g smoked fish (mackerel or catfish) — cleaned, boned, broken into chunks (optional, traditional)","100 g dried prawns or stockfish (panla), soaked 30 min and torn small (optional)","1 medium onion (~150 g), roughly chopped","2 Scotch bonnet peppers (or 3 habaneros) — adjust to heat tolerance","2 red bell peppers (~300 g), seeded","100 ml red palm oil","3 large fresh tomatoes (~400 g) OR 200 g tomato paste blended with 200 ml water","4 garlic cloves, finely minced","5 cm fresh ginger, peeled and grated","2 stock cubes (Maggi or similar, 10 g)","1 tbsp ground crayfish (essential for authentic flavour) — substitute: 1 tbsp ground dried shrimp","1 bay leaf (or 1 tsp ground bay)","200 g fresh spinach or ugu pumpkin leaves, washed and roughly chopped","1.5 tsp salt + more to taste","1 tbsp locust beans (iru/dawadawa) — optional, traditional Yoruba addition","To serve: pounded yam, fufu, eba (gari), or boiled white rice"],"ro":["250 g semințe egusi brute, măcinate fin (sau 200 g egusi pre-măcinat)","600 g carne de capră sau gulaș de vită cu os, tăiată în bucăți de 4 cm","200 g pește afumat (macrou sau somn) — curățat, dezosat, rupt în bucăți (opțional, tradițional)","100 g creveți uscați sau stockfish, înmuiat 30 minute și rupt mic (opțional)","1 ceapă medie (~150 g), tocată grosier","2 ardei iuți Scotch bonnet (sau 3 habanero) — ajustează după toleranța la iuțeală","2 ardei roșii grași (~300 g), fără semințe","100 ml ulei roșu de palmier","3 roșii mari proaspete (~400 g) sau 200 g pastă de roșii amestecată cu 200 ml apă","4 căței de usturoi, tocați fin","5 cm rădăcină de ghimbir proaspăt, curățată și rasă","2 cuburi Maggi sau pentru condimentare (10 g)","1 lingură crayfish măcinat (esențial pentru aroma autentică) — substitut: 1 lingură creveți uscați măcinați","1 frunză de dafin (sau 1 linguriță dafin măcinat)","200 g spanac proaspăt sau frunze de ugu (pumpkin leaves), spălate și tocate","1,5 lingurițe sare + sare după gust","1 lingură semințe de locust (iru/dawadawa) — opțional, tradițional Yoruba","Pentru servire: igname pisată, fufu, eba (gari) sau orez fiert"]},"howIsMade":{"en":"EGUSI PASTE: pulse 250 g egusi seeds in a spice grinder or food processor 30 seconds until finely ground but not yet pasty; in a small bowl, mix with 200 ml warm water into a thick, hummus-like paste; let it sit 10 minutes to hydrate fully — this is the secret to the signature lumpy-creamy texture. COOK THE MEAT: in a heavy pot, combine 600 g cut meat with 1 chopped onion, 4 minced garlic, grated ginger, 2 stock cubes, 1 tsp salt and 1 L water; bring to boil, then simmer covered 40–50 minutes (longer if using goat) until the meat is tender enough to bite easily but not falling apart; strain and reserve 800 ml of the broth; set the meat aside. BLEND THE PEPPER BASE: in a blender, combine 2 red bell peppers, 2 Scotch bonnet peppers, and 3 fresh tomatoes (or paste-and-water mix); blend 1–2 minutes until completely smooth; pour into a wide pan and simmer over medium heat 15 minutes — the mix should reduce by half and the colour deepen to a rich brick-red; this concentration is essential or the soup will be watery. FRY THE PALM-OIL BASE: in your soup pot over medium heat, warm 100 ml palm oil 2 minutes until it just shimmers (do NOT smoke it — over-smoking destroys the flavour); add the reduced pepper-tomato base and fry, stirring, 8–10 minutes until the oil floats to the surface and the mixture darkens slightly; this is called \"frying the base\". ADD THE EGUSI: take the hydrated egusi paste by tablespoons and drop dumpling-style into the simmering pepper base — do NOT stir; let the dumplings cook undisturbed 5 minutes, then gently fold them in; some will hold their shape (the lumps) while others break apart and thicken the sauce — this is the desired texture. ADD STOCK + MEAT + FISH: pour in 800 ml reserved meat broth; add the cooked meat, 200 g smoked fish (broken into chunks), 100 g soaked dried prawns/stockfish (optional), 1 tbsp ground crayfish, 1 tbsp locust beans (optional), and 1 bay leaf; stir gently, bring to a simmer and cook uncovered 15–20 minutes until the soup has reduced and thickened to a pudding-like consistency — it should mound on a spoon, not pour like broth. ADD GREENS: stir in 200 g chopped spinach (or ugu/pumpkin leaves) into the simmering soup; cook 5–7 minutes uncovered until the greens are wilted but still bright green; taste and adjust salt and heat; the soup should taste deeply savoury, slightly nutty (from the egusi), with a clean palm-oil finish and a building chili heat. REST AND SERVE: turn off the heat and let the soup rest 5 minutes — the flavours meld dramatically in this short rest; serve in deep bowls with the swallow of choice (pounded yam, fufu, eba, or amala) on the side; eat with the right hand: take a small lump of swallow, dip into the soup, and swallow without chewing; boiled white rice is a milder option."}},{"id":155,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Poland","ro":"Polonia"},"name":{"en":"Kotlet schabowy","ro":"Kotlet schabowy"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["4 boneless pork loin chops (~180–200 g each, ~1.5–2 cm thick) — about 800 g total","1 tsp fine salt for the pork","0.5 tsp freshly ground white pepper","200 ml whole milk for the tenderizing soak (the Polish trick)","80 g all-purpose flour for breading","3 large eggs beaten with 1 tbsp milk and a pinch of salt","200 g fine fresh breadcrumbs (homemade from day-old bread is best) or panko","80 g lard (traditional) OR 100 ml neutral sunflower oil for frying","30 g unsalted butter for the finishing baste","1 lemon, cut into wedges (modern garnish)","For dill potatoes: 800 g floury potatoes peeled + 30 g butter + 1 small bunch chopped dill + salt for the cooking water","For sautéed sauerkraut: 400 g drained sauerkraut + 1 small onion finely chopped + 1 tbsp lard + 100 ml water"],"ro":["4 cotlete de porc din mușchi (~180–200 g fiecare, ~1,5–2 cm grosime) — aproximativ 800 g total","1 linguriță sare fină pentru carne","0,5 linguriță piper alb proaspăt măcinat","200 ml lapte integral pentru marinada de tendierare","80 g făină pentru panare","3 ouă mari bătute cu 1 lingură lapte și un vârf de sare","200 g pesmet fin proaspăt (de casă, din pâine de o zi) sau panko","80 g untură (tradițional) SAU 100 ml ulei neutru de floarea-soarelui pentru prăjit","30 g unt nesărat pentru finisare","1 lămâie tăiată în sferturi (garnitură modernă)","Pentru cartofi cu mărar: 800 g cartofi făinoși decojiți + 30 g unt + 1 bunch mic de mărar tocat + sare pentru apa de fierbere","Pentru varza murată: 400 g varză murată scursă + 1 ceapă mică tocată + 1 lingură untură + 100 ml apă"]},"howIsMade":{"en":"POUND THE PORK: place each pork chop between two sheets of cling film and pound with a flat meat mallet from the centre outward, 30 seconds per side, until the chops are 6–7 mm thick and almost doubled in size — they must be even thickness for uniform cooking; score the fatty rim 3–4 times to prevent curling. MILK SOAK: pat the pounded chops dry and rub each side with salt and white pepper; place in a shallow dish, pour over 200 ml milk so the chops are mostly submerged, cover and refrigerate 30 minutes (up to 2 hours) — the lactic acid tenderizes the meat without altering the flavour. SET UP THE BREADING STATION: three shallow plates in a row: plate 1 with 80 g flour; plate 2 with 3 beaten eggs + 1 tbsp milk + a pinch of salt; plate 3 with 200 g fine breadcrumbs; the line-up matters: every chop must travel flour → egg → breadcrumbs without skipping. BREAD THE CHOPS: lift one chop from the milk, let the excess drip off, and dredge in flour, shaking off the excess — the flour must coat thinly and evenly or the egg won't stick; then dip into the egg, letting it drip 2 seconds, then press firmly into the breadcrumbs on both sides, patting them on so they adhere; set on a plate; repeat for all 4 chops; let them rest 5 minutes — the breading hydrates and binds. BOIL THE POTATOES: meanwhile, peel 800 g potatoes and cut into 4 cm chunks; place in cold salted water, bring to boil, and simmer 15–18 minutes until fork-tender; drain, return to the pot off heat for 2 minutes to dry, then toss with 30 g butter and chopped dill. SAUTÉ THE SAUERKRAUT: in a separate pan, melt 1 tbsp lard over medium heat; add 1 finely chopped onion, fry 5 minutes until golden; add 400 g drained sauerkraut and 100 ml water; simmer covered 15 minutes, then uncover and cook 5 minutes more until most of the liquid has evaporated and the kraut is tender; season with a twist of pepper. FRY THE SCHNITZELS: heat 80 g lard (or 100 ml oil) in a large heavy skillet over medium-high heat until shimmering (175 °C, or a breadcrumb sizzles immediately on contact); fry the chops 2 at a time so the pan isn't crowded, 3–4 minutes per side undisturbed until deeply golden brown and crisp; the internal temperature should reach 70 °C; in the last 30 seconds, add 15 g butter to the pan and tilt to baste the schnitzels — the butter foams brown and gives the breading its iconic Polish-Sunday aroma; transfer to a rack lined with paper towels to drain (NOT a plate, which would steam the bottom soggy). SERVE IMMEDIATELY: plate each schnitzel alongside a mound of dill potatoes and a heap of sauerkraut; garnish with a lemon wedge if you like (the squeeze brightens the fat); eat with a knife and fork — never just a fork, this is a respect-the-classics dish; the schnitzel should be eaten within 5 minutes of frying for maximum crunch."}},{"id":156,"origin":{"en":"South Korea","ro":"Coreea de Sud"},"name":{"en":"Kimbap","ro":"Kimbap"},"category":{"en":"Lunch","ro":"Prânz"},"servings":4,"tipType":"def","pairingsType":"korean","ingredients":{"en":["360 g (2 cups) short-grain white rice, uncooked — makes ~4 rolls","540 ml (2¼ cups) cold water for cooking the rice","4 sheets toasted nori (gim, 20 × 18 cm)","4 strips danmuji (yellow pickled radish), cut to nori length, ~1 cm thick","100 g baby spinach (or 1 small bunch regular spinach)","2 medium carrots (~150 g), julienned 0.5 × 0.5 × 8 cm matchsticks","3 large eggs","200 g imitation crab sticks (or cooked ham, or tuna mixed with mayo)","100 g cucumber (1 small Korean cucumber or 1/3 English cucumber), seeded and cut into long batons","3 tbsp toasted sesame oil (1.5 tbsp for the rice, 0.5 tsp for spinach, the rest for the outer rub)","1.5 tsp fine salt (1 tsp for the rice, pinches for veg and eggs)","2 tsp toasted sesame seeds","1 tbsp neutral oil for cooking the eggs and carrots","0.5 tsp ground white pepper","Bamboo rolling mat (gimbal) + plastic wrap"],"ro":["360 g (2 căni) orez cu bob scurt necopt, pentru ~4 rulouri","540 ml (2¼ căni) apă rece pentru fierberea orezului","4 foi de nori prăjit (gim, 20 × 18 cm)","4 fâșii de danmuji (ridiche galbenă murată), tăiate la lungimea norii, grosime ~1 cm","100 g spanac baby (sau 1 mănunchi mic de spanac obișnuit)","2 morcovi medii (~150 g), tăiați julien 0,5 × 0,5 × 8 cm","3 ouă mari, bătute","200 g bețe de crab imitație (sau șuncă fiartă sau ton conservat amestecat cu maioneză)","100 g castraveți (1 mic castravete coreean sau 1/3 castravete englezesc), fără sâmburi, tăiat fâșii lungi","3 linguri ulei de susan prăjit (1,5 lingură pentru orez, 0,5 linguriță pentru spanac, restul pentru exterior)","1,5 linguriță sare fină (1 linguriță pentru orez, restul pentru legume)","2 lingurițe semințe de susan prăjite","1 lingură ulei neutru pentru gătit ouăle și sotat morcovii","0,5 linguriță piper alb măcinat","Covoraș de bambus (kimbal) + folie alimentară"]},"howIsMade":{"en":"Rinse 360 g rice in cold water 3–4 times until the water runs clear, drain well, then put in a heavy pot with 540 ml fresh cold water, bring to a boil uncovered over medium-high heat (3–4 min), cover, reduce to the lowest possible heat and cook 12 minutes without lifting the lid, then remove from heat and rest covered 10 minutes until the rice is tender, slightly sticky, with separate grains. While the rice is still hot, transfer it to a wide bowl, drizzle 1.5 tbsp sesame oil, 1 tsp salt and 2 tsp toasted sesame seeds over the top and fold gently with a rice paddle in cutting motions — never stir aggressively or the grains break and turn mushy — then cover with a damp cloth and let cool to lukewarm (10–15 min). Bring a small pot of salted water to a boil and blanch 100 g spinach for 30 seconds until just wilted, then drain and rinse under cold water immediately to stop the cooking and preserve the bright green colour, squeeze in your fist as hard as possible to remove all water (wet spinach ruins the roll) and season with 0.5 tsp sesame oil and a pinch of salt. Heat 1 tsp neutral oil in a small pan over medium heat, add 150 g julienned carrot and a pinch of salt and stir-fry 2 minutes until just softened but still crisp, then tip onto a plate to cool — limp, oily carrots will break the roll. Beat 3 eggs with a pinch of salt and 0.5 tsp white pepper, heat 1 tsp neutral oil in a non-stick pan over medium-low heat, pour in the eggs and tilt the pan to form a thin even sheet 25 × 20 cm, cook 2 minutes until set on top without flipping, then slide onto a board, let cool 2 minutes and cut into 4 long strips the width of the nori. Cut 100 g cucumber lengthwise into 8 long batons and scrape the seedy core out with a teaspoon, split 200 g crab sticks in half lengthwise and cut 4 strips of danmuji to nori length, then arrange everything on a tray in the order you'll lay them: spinach, carrot, cucumber, crab, egg, danmuji. Place the bamboo mat with the slats running horizontally and lay a sheet of nori shiny-side down, then with wet fingers spread ~150 g rice in a thin even layer over the bottom 3/4 of the nori while leaving a clean 4 cm strip at the far edge, and about 3 cm in from the near edge line up one strip each of spinach, carrot, cucumber, crab, egg and danmuji in a tight bundle, then lift the near edge of the mat and roll firmly forward, tucking the fillings under the rice with the first roll and continuing to roll tightly to the far edge, then press along the seam to seal. Brush the outside of each roll lightly with 0.5 tsp sesame oil to make the nori glossy and prevent it from sticking to the knife, wipe a sharp knife with a damp cloth between cuts, then slice each roll into 8 even rounds with one decisive push (no sawing) for 32 pieces total, arrange on a plate and sprinkle with sesame seeds — eat within 4 hours of rolling and never refrigerate kimbap."},"timeMins":{"total":60,"active":50}},{"id":157,"servings":6,"tipType":"meat","pairingsType":"latin","origin":{"en":"Chile","ro":"Chile"},"name":{"en":"Pastel de Choclo","ro":"Pastel de Choclo"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["For the pino (meat filling): 600 g ground beef (chuck or sirloin, 20% fat)","2 large onions (~400 g), finely diced","4 garlic cloves, finely minced","2 tbsp neutral oil for sautéing","1.5 tsp salt + 1 tsp freshly ground black pepper for the pino","1 tsp ground cumin + 1 tsp sweet paprika + 1 tsp dried oregano + 1 tsp aji color (or pimentón as substitute)","60 ml beef stock or water","80 g dark raisins, soaked 15 min in 100 ml warm water, then drained","4 bone-in skin-on chicken thighs (~600 g) — poached and pulled (traditional addition)","1 bay leaf + 800 ml water to poach the chicken","6 hard-boiled eggs, peeled and halved (1 per portion)","18–24 pitted black olives (kalamata-style)","For the corn paste (choclo): 1.2 kg fresh white corn kernels (~6–8 ears) OR 1 kg thawed frozen corn","80 ml whole milk","60 g unsalted butter","1 tbsp fresh basil leaves, finely chopped (the Chilean signature)","1 tsp fine salt + 1 tbsp granulated sugar for the corn paste","2 tbsp granulated sugar to sprinkle over the top before baking (for the iconic caramelized crust)"],"ro":["Pentru pino: 600 g vită tocată (gulaș sau pulpă, 20% grăsime)","2 cepe mari (~400 g), tăiate fin","4 căței de usturoi, tocați fin","2 linguri ulei neutru pentru sotat","1,5 lingurițe sare + 1 linguriță piper negru proaspăt măcinat (pentru pino)","1 linguriță chimion măcinat + 1 linguriță boia dulce + 1 linguriță oregano uscat + 1 linguriță aji color (sau pimentón pentru substitut)","60 ml supă de vită sau apă","80 g stafide negre, înmuiate 15 minute în 100 ml apă caldă, apoi scurse","4 pulpe de pui cu os și piele (~600 g) — fierte și destrămate (tradițional)","1 frunză de dafin + 800 ml apă pentru fiertul puiului","6 ouă tari, decojite și tăiate în jumătăți (1 per porție)","18–24 măsline negre cu sâmbure scos (stil kalamata)","Pentru pasta de porumb: 1,2 kg boabe proaspete de porumb alb (~6–8 știuleți) SAU 1 kg porumb congelat dezghețat","80 ml lapte integral","60 g unt nesărat","1 lingură busuioc proaspăt, tocat fin (semnătura chiliană)","1 linguriță sare fină + 1 lingură zahăr granulat pentru pasta de porumb","2 linguri zahăr granulat pentru presărat pe suprafață înainte de coacere (crusta caramelizată iconică)"]},"howIsMade":{"en":"CARAMELIZE THE ONIONS: in a heavy skillet over medium heat, warm 2 tbsp oil and add 400 g finely diced onion with 0.5 tsp salt; sauté 12–15 minutes, stirring often, until deeply golden and translucent — DO NOT rush this step, the caramelized onion is the foundation of pino flavour; add 4 minced garlic cloves and cook 1 minute more until fragrant. BROWN THE BEEF: raise the heat to medium-high; add 600 g ground beef to the onions, breaking it apart with a wooden spoon; cook 6–8 minutes until the meat is no longer pink and any liquid has evaporated; add 1 tsp cumin, 1 tsp paprika, 1 tsp oregano, 1 tsp aji color (if using), the remaining 1 tsp salt and 1 tsp pepper; stir 1 minute to bloom the spices. FINISH THE PINO: pour in 60 ml beef stock and the drained raisins; simmer 3–4 minutes until the mixture is moist but not soupy — the pino should be glossy and able to hold its shape on a spoon; remove from heat and let cool 15 minutes — letting it rest deepens the flavour and prevents the corn topping from sliding off. POACH THE CHICKEN: while the pino rests, simmer 4 chicken thighs in 800 ml lightly salted water with 1 bay leaf for 25 minutes until cooked through; drain, cool slightly, then pull the meat from the bones in large chunks (skin discarded); reserve the stock for serving alongside the pastel. CORN PASTE: in a food processor or blender, pulse 1.2 kg fresh corn kernels with 80 ml milk and 1 tsp salt 30 seconds until coarsely pureed — keep some texture, do not blend to a smooth cream; transfer to a heavy saucepan with 60 g butter over medium heat; cook 10–15 minutes, stirring constantly with a wooden spoon, until the puree thickens to a polenta-like consistency that pulls away from the sides of the pan; stir in 1 tbsp chopped basil and remove from heat. ASSEMBLE: preheat oven to 200 °C with a rack in the upper third; divide the pino between 6 individual earthenware pailas (or one 28 cm baking dish); top each portion with chunks of poached chicken, 1 hard-boiled egg half, 3–4 olives, and a small pile of raisins arranged decoratively; spoon the warm corn paste over the top in an even 2 cm layer, smoothing with the back of a spoon to seal all the way to the edges. SUGAR CRUST: sprinkle 2 tbsp granulated sugar evenly over the corn topping; this is non-negotiable — the sugar caramelizes during baking into the iconic dark, almost-burnt golden crust that distinguishes pastel de choclo from any other shepherd's pie. BAKE: place the pastels on the upper rack of the 200 °C oven and bake 25–30 minutes until the corn topping is golden brown and the sugar has caramelized into dark spots across the surface; the corners may bubble — that's correct; let rest 10 minutes before serving (the filling needs to set); serve straight from the paila with a side of pebre salsa and a glass of Chilean Carmenère."}},{"id":158,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Serbia","ro":"Serbia"},"name":{"en":"Pljeskavica","ro":"Pljeskavica"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["500 g coarsely ground beef chuck (~20% fat)","300 g coarsely ground lamb shoulder (or pork shoulder for a milder version)","1 large onion (~200 g), finely grated and water squeezed out (the secret to juicy patties)","4 garlic cloves, crushed with 0.5 tsp salt into a paste","1 tbsp sweet Hungarian paprika","1 tsp hot paprika (smoked or Kashmiri, optional)","1.5 tsp fine salt","1 tsp freshly ground black pepper","1 tsp baking soda (the Balkan trick — helps keep them juicy and tender)","100 ml ice-cold sparkling water (for the fluffy springy texture)","0.5 tsp dried marjoram or oregano","1 tbsp vegetable oil for the grill or pan","To serve: 4 somun or pita breads (~18 cm rounds), 1 medium red onion (~150 g) thinly sliced, 200 g ajvar red-pepper relish, 100 g kajmak or sour cream, fresh parsley, lemon wedges (optional)"],"ro":["500 g vită tocată grosier (ceafă, ~20% grăsime)","300 g umăr de miel tocat grosier (sau umăr de porc pentru o versiune mai blândă)","1 ceapă mare (~200 g), rasă fin și stoarsă bine (secretul cărnurilor suculente)","4 căței de usturoi, zdrobiți cu 0,5 linguriță sare într-o pastă","1 lingură boia ungurească dulce","1 linguriță boia iute (afumată sau Kashmir, opțional)","1,5 lingurițe sare fină","1 linguriță piper negru proaspăt măcinat","1 linguriță bicarbonat de sodiu (trucul balcanic — păstrează carnea suculentă și frageda)","100 ml apă minerală carbogazoasă rece ca gheața (pentru textura pufoasă)","0,5 linguriță maghiran uscat sau oregano","1 lingură ulei vegetal pentru grătar sau tigaie","Pentru servire: 4 chifle somun sau pita (~18 cm), 1 ceapă roșie medie (~150 g) tăiată subțire, 200 g ajvar, 100 g kajmak sau smântână, pătrunjel proaspăt, lămâie (opțional)"]},"howIsMade":{"en":"ONION PREP: grate 200 g onion on the fine side of a box grater; transfer to a clean tea towel and squeeze HARD over the sink to remove as much liquid as possible — at least 80 ml of juice should come out; wet onion makes the patties fall apart on the grill; reserve 2 tbsp of the squeezed pulp for the meat. MIX THE MEAT: in a large bowl, combine 500 g beef + 300 g lamb (or pork); add 2 tbsp squeezed onion pulp, 4 garlic cloves crushed with 0.5 tsp salt, 1 tbsp sweet paprika, 1 tsp hot paprika (if using), 1 tsp salt, 1 tsp pepper, 0.5 tsp marjoram and 1 tsp baking soda; knead vigorously by hand 4–5 minutes — the mixture should become sticky and noticeably tightened, which gives pljeskavica its signature springy bounce. ADD SPARKLING WATER: slowly drizzle in 100 ml ice-cold sparkling water while continuing to knead, in 4 additions of 25 ml each; the water aerates the mince and combines with the baking soda to keep the patties juicy and tender; cover with film and refrigerate at least 4 hours, ideally overnight — the rest is non-negotiable for flavour development and binding. SHAPE THE PATTIES: divide the rested meat into 4 equal portions of ~225 g each; with wet hands (to prevent sticking), roll each portion into a ball, then flatten into a flat disc 18–20 cm in diameter and 8 mm thick; the disc must be the same diameter as the bread it will be served in; press the centre slightly with your thumb to create a dimple — this prevents the patty from doming up on the grill. SECOND CHILL: place the shaped patties on a parchment-lined tray; cover loosely and refrigerate 20 minutes to firm up; meanwhile, fire up a charcoal grill to medium-high (200 °C) or heat a heavy ridged griddle pan with 1 tbsp oil until just smoking. GRILL: brush the patties lightly with oil; grill 4–5 minutes per side without moving — turn ONCE only; the patties are done when the internal temperature reaches 65 °C (medium) and a deep mahogany crust has formed on both sides with visible grill marks; resist pressing them — you'll lose all the juice and undo the work you did in step 3. WARM THE BREAD: during the last minute of grilling, place 4 somun or pita on the grill for 30 seconds per side until warmed and lightly toasted; split each pita open at one edge to make a pocket large enough for the patty. SERVE: slip one patty into each warm pita pocket; top with 1 tbsp ajvar, a knob of kajmak, a generous mound of sliced raw red onion, a sprinkle of parsley, and a squeeze of lemon if you like; eat immediately with your hands while the bread is warm — the contrast of hot juicy meat, cool kajmak, and smoky ajvar is the soul of Balkan street food."}},{"id":159,"servings":4,"tipType":"dessert","pairingsType":"dessert","origin":{"en":"Netherlands","ro":"Olanda"},"name":{"en":"Poffertjes","ro":"Poffertjes"},"category":{"en":"Dessert","ro":"Desert"},"ingredients":{"en":["250 g buckwheat flour (traditional, gives the signature flavour) — OR 100 g buckwheat + 150 g all-purpose flour as a milder substitute","7 g instant dry yeast (or 21 g fresh yeast)","1 tbsp granulated sugar (1 tsp to feed the yeast, the rest in the batter)","0.5 tsp fine salt","350 ml warm whole milk (38 °C)","2 large eggs","30 g unsalted butter, melted and cooled to lukewarm for the batter","50 g additional unsalted butter for the pan + finishing","1 tbsp dark rum or vanilla extract (optional, traditional)","To serve: 30 g cold unsalted butter cubes for topping, 60 g icing sugar to dust, stroopwafel syrup or maple syrup (optional), fresh berries (optional)","Equipment: poffertjespan cast-iron pan with 24–30 dimples (or aebleskiver pan); small wooden skewer or chopstick for flipping"],"ro":["250 g făină de hrișcă (tradițional, dă aroma signature) — SAU 100 g hrișcă + 150 g făină albă ca substitut mai blând","7 g drojdie uscată instant (sau 21 g drojdie proaspătă)","1 lingură zahăr (1 linguriță pentru drojdie, restul în aluat)","0,5 linguriță sare fină","350 ml lapte integral cald (38 °C)","2 ouă mari","30 g unt nesărat topit și răcit la călduț pentru aluat","50 g unt nesărat suplimentar pentru tigaie și finisare","1 lingură rom întunecat sau extract de vanilie (opțional, tradițional)","Pentru servire: 30 g unt rece în cuburi pentru a pune deasupra, 60 g zahăr pudră pentru presărat, sirop stroopwafel sau de arțar (opțional), fructe de pădure proaspete (opțional)","Echipament: tigaie poffertjespan din fontă cu 24–30 adâncituri (sau tigaie aebleskiver); bețișoară de lemn pentru întors"]},"howIsMade":{"en":"ACTIVATE THE YEAST: warm 350 ml milk in a saucepan to about 38 °C (lukewarm — comfortable on your wrist); pour into a large bowl, sprinkle 7 g instant dry yeast and 1 tsp sugar over the surface, and let stand 10 minutes until a creamy foam appears on top; if no foam, the yeast is dead — start over with fresh yeast. MAKE THE BATTER: whisk 2 eggs into the foamed yeast-milk until smooth; in a separate bowl, sift together 250 g buckwheat flour (or the buckwheat+all-purpose mix), the remaining 2 tsp sugar and 0.5 tsp salt; add the dry to the wet in two additions, whisking each time until smooth — no lumps; whisk in 30 g melted cooled butter and 1 tbsp rum (if using); the batter should be the consistency of thin cream that ribbons off the whisk. FIRST PROOF: cover the bowl with a clean cloth and let rise in a warm spot for 60 minutes, until the surface is covered with bubbles and the batter has risen noticeably (about 1.5× volume); the yeast develops the signature airy, slightly sour flavour of true poffertjes. STIR DOWN AND REST: gently stir the risen batter to deflate large bubbles; transfer to a squeeze bottle, jug or piping bag — the easiest way to portion accurately into the small dimples; let rest 10 minutes while the pan heats. HEAT THE POFFERTJESPAN: place a 24- or 30-dimple cast-iron poffertjespan over medium-low heat for 3 minutes until evenly hot (test with a drop of water — it should sizzle and evaporate in 2 seconds); use a folded paper towel dipped in melted butter to grease each dimple generously — every dimple must be coated or the poffertjes will stick. FILL THE DIMPLES: working fast, squeeze or pour batter into each dimple until 3/4 full (about 1 tbsp per dimple); wait 60–90 seconds until the edges are set and a golden ring forms around each one, with bubbles forming on the surface. FLIP EACH ONE: using a wooden skewer, pull each half-set poffertje up the side of its dimple and flip it upside down — the uncooked top batter will flow into the dimple, filling out a round ball; cook another 60–90 seconds until the second side is deep golden brown; each poffertje should be a fluffy round ball, golden on both sides, about 3 cm wide. SERVE IMMEDIATELY: slide 8–10 poffertjes onto each warm plate; top with a small knob of cold butter (it will melt and soak in) and a generous dust of icing sugar through a fine sieve; serve immediately — poffertjes turn rubbery within 5 minutes of being made; optional: drizzle stroopwafel syrup or scatter fresh berries."}},{"id":160,"origin":{"en":"Japan","ro":"Japonia"},"name":{"en":"Japanese Curry Rice","ro":"Curry japonez"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","ingredients":{"en":["2 cups short-grain rice (uncooked)","400g boneless skinless chicken thighs (or beef chuck), cut into 3 cm pieces","2 large onions, cut into medium dice","2 medium potatoes, cut into 3 cm cubes","2 medium carrots, cut into 1.5 cm rounds","1 tbsp vegetable oil","800ml water","1 pack Japanese curry roux blocks (e.g. S&B Golden Curry, medium, approx. 100g)","1 tsp Worcestershire sauce","1 tsp ketchup (optional, for depth)","salt and black pepper to taste"],"ro":["2 căni orez cu bob scurt (nepreparare)","400g pulpe de pui dezosate fără piele (sau vită pentru friptură), tăiate cuburi de 3 cm","2 cepe mari, tăiate cuburi medii","2 cartofi medii, tăiați cuburi de 3 cm","2 morcovi medii, tăiați rondele de 1,5 cm","1 lingură ulei vegetal","800ml apă","1 pachet blocuri de roux curry japonez (ex. S&B Golden Curry, mediu picant, aprox. 100g)","1 linguriță sos Worcestershire","1 linguriță ketchup (opțional, pentru rotunjimea gustului)","sare și piper negru după gust"]},"howIsMade":{"en":"THE RICE: rinse 360 g (2 cups) short-grain rice in cold water 3–4 times until the water runs clear; place in a pot with 540 ml (2½ cups) cold water; bring to a boil uncovered, cover, reduce to lowest heat and cook 13 minutes; remove from heat and rest covered 10 minutes; do not lift the lid. CARAMELIZE THE ONIONS: in a large pot, heat 1 tbsp oil over medium heat; add 2 medium-diced onions and cook, stirring often, for 15–20 minutes until soft and golden — DO NOT skip this step; the caramelized onions are the backbone of flavour. BROWN THE MEAT: add 400 g boneless chicken thighs or beef chuck cut in 3 cm pieces, season with salt and pepper, sear on all sides 3–4 minutes; the meat must have a deep golden crust — extra flavour. VEGETABLES: add 2 carrots cut in 1.5 cm rounds and 2 potatoes cut in 3 cm cubes; stir 1 minute to coat the vegetables in the oil. SIMMER THE BASE: pour in 800 ml water, bring to a boil, reduce to a gentle simmer uncovered for 15 minutes, or until the potato is just tender (check with a skewer). ADD THE ROUX: remove the pot from the heat; break 100 g Japanese curry roux blocks into small pieces and stir into the pot until fully dissolved — adding off heat prevents lumps. THICKEN THE SAUCE: return the pot to low heat and simmer, stirring frequently, for 10 minutes until the sauce is thick and glossy — it should coat the back of a spoon; stir in 1 tsp Worcestershire sauce and 1 tsp ketchup for depth, taste and adjust salt. SERVE: spoon a generous portion of curry over hot rice in deep plates; traditional accompaniments: katsu schnitzel, shredded cabbage, pickled red radishes (fukujinzuke); a single plate holds both rice and curry without mixing them — you spoon them together at the table."}},{"id":161,"servings":4,"tipType":"def","pairingsType":"mediterranean","origin":{"en":"Greece","ro":"Grecia"},"name":{"en":"Fasolada","ro":"Fasolada"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["400 g dried white beans (cannellini, navy, or large Greek gigantes), soaked overnight in cold water","2 medium carrots (~200 g), peeled and diced 1 cm","2 celery stalks (~150 g), diced 1 cm + 30 g celery leaves chopped (optional, traditional)","1 large onion (~200 g), finely diced","4 garlic cloves, finely minced","400 g ripe tomatoes (4 medium) — peeled and grated OR 1 × 400 g can crushed tomatoes","1 tbsp tomato paste","100 ml extra-virgin olive oil for the soffritto + 60 ml more for finishing","2 bay leaves","1 tsp dried oregano","1.5 tsp salt + more to taste","0.5 tsp freshly ground black pepper","1 tbsp red wine vinegar (optional, brightens at the end)","1.5 L water (or vegetable stock)","To serve: crusty country bread, Kalamata olives, crumbled feta cheese, fresh parsley"],"ro":["400 g fasole albă uscată (cannellini, navy sau gigantes grecești), înmuiate peste noapte în apă rece","2 morcovi medii (~200 g), curățați și tăiați cuburi de 1 cm","2 tulpini de țelină (~150 g), tăiate cuburi de 1 cm + 30 g frunze de țelină tocate (opțional, tradițional)","1 ceapă mare (~200 g), tăiată fin","4 căței de usturoi, tocați fin","400 g roșii coapte (4 medii) — decojite și rase SAU 1 conservă × 400 g de roșii zdrobite","1 lingură pastă de roșii","100 ml ulei de măsline extravirgin pentru sotat + 60 ml suplimentar pentru finisare","2 frunze de dafin","1 linguriță oregano uscat","1,5 lingurițe sare + sare după gust","0,5 linguriță piper negru proaspăt măcinat","1 lingură oțet de vin roșu (opțional, dă luminozitate la final)","1,5 L apă (sau supă de legume)","Pentru servire: pâine de țară crocantă, măsline Kalamata, brânză feta sfărâmată, pătrunjel proaspăt"]},"howIsMade":{"en":"SOAK THE BEANS: place 400 g dried white beans in a large bowl, cover with cold water by 5 cm, and soak 8 hours or overnight; drain and rinse — the soak shortens the cooking time and helps even, intact beans. PARBOIL THE BEANS: place the drained beans in a large pot, cover with cold water by 3 cm, and bring to a boil; boil hard 10 minutes, then drain — this removes the indigestible compounds that cause gas and gives a cleaner-tasting broth. SOFFRITTO: in a heavy 5 L pot, heat 100 ml olive oil over medium heat; add 200 g diced onion + 200 g diced carrot + 150 g diced celery and cook, stirring often, 12–15 minutes until very soft and starting to gold — this slow vegetable base is the foundation of fasolada's depth; add 4 minced garlic cloves and cook 1 more minute until fragrant. BLOOM THE TOMATO: add 1 tbsp tomato paste and cook stirring 2 minutes until darkened; add 400 g grated tomato (or canned crushed) and simmer 5 minutes until the raw acidity cooks off and the mixture turns deep red. ADD BEANS AND WATER: return the parboiled beans to the pot; add 1.5 L water (or vegetable stock), 2 bay leaves, 1 tsp oregano, 1.5 tsp salt and 0.5 tsp pepper; bring to a boil, reduce to a gentle simmer. SLOW SIMMER: cook uncovered 60–90 minutes, stirring occasionally, until the beans are completely tender and creamy at the centre but still hold their shape — taste a bean every 15 minutes after the 1 hour mark; the broth should reduce by about half and thicken to a soupy consistency; add more water if it dries out too fast. FINISH: discard the bay leaves; stir in 30 g chopped celery leaves (if using) and 1 tbsp red wine vinegar for brightness; taste and adjust salt; off the heat, drizzle 60 ml fresh extra-virgin olive oil over the surface — this is the finishing oil that makes the soup glossy and aromatic; let rest 10 minutes for flavours to settle. SERVE: ladle into deep bowls, drizzle each portion with another teaspoon of olive oil, and grind fresh black pepper over the top; serve with crusty country bread, a small bowl of Kalamata olives, crumbled feta, and chopped fresh parsley on the table; even better the next day."}},{"id":162,"servings":4,"tipType":"meat","pairingsType":"mexican","origin":{"en":"Mexico","ro":"Mexic"},"name":{"en":"Tlayudas","ro":"Tlayudas"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["4 tlayuda tortillas (~30 cm, semi-dried) or 4 large flour tortillas as substitute","250 g dried black beans soaked overnight (or 1 × 400 g can)","100 g lard or 100 ml vegetable oil for frying beans + cooking","1 large onion (~200 g): half quartered for the beans, the other half finely diced for serving","4 garlic cloves (2 for beans, 2 for meat)","1 tsp ground cumin + 1 tsp dried oregano + 1 tsp salt for the beans","500 g flank or skirt steak, sliced very thinly across the grain (tasajo-style)","200 g fresh Mexican chorizo (or Spanish), removed from casing","300 g quesillo (Oaxaca string cheese) or low-moisture mozzarella, shredded","200 g shredded iceberg lettuce","2 ripe avocados (~300 g), sliced","4 ripe tomatoes (~400 g), sliced","200 g salsa roja or salsa verde (homemade or store-bought)","1 lime cut into wedges + fresh cilantro for serving"],"ro":["4 tortillas tlayuda (~30 cm, semi-uscate) sau 4 tortillas mari de făină","250 g fasole neagră uscată înmuiată peste noapte (sau 1 conservă × 400 g)","100 g untură sau 100 ml ulei vegetal pentru prăjit fasolea + sotat","1 ceapă mare (~200 g): jumătate tăiată sferturi pentru fasole, cealaltă jumătate tocată fin pentru servire","4 căței de usturoi (2 pentru fasole, 2 pentru carne)","1 linguriță chimion măcinat + 1 linguriță oregano uscat + 1 linguriță sare pentru fasole","500 g flank steak sau skirt steak, feliat foarte subțire în diagonală (stil tasajo)","200 g chorizo proaspăt mexican (sau spaniol), scos din maț","300 g quesillo (brânză Oaxaca) sau mozzarella low-moisture, rasă","200 g salată iceberg, tocată","2 avocado coapte (~300 g), feliate","4 roșii coapte (~400 g), feliate","200 g salsa roja sau verde (de casă sau de la magazin)","1 lime tăiată sferturi + coriandru proaspăt pentru servire"]},"howIsMade":{"en":"THE BEANS: drain 250 g soaked black beans; boil in 1.5 L water with half an onion in quarters, 2 whole garlic cloves, 1 tsp cumin, 1 tsp oregano and 1 tsp salt for 60–90 minutes until very tender; drain, reserving 200 ml of the cooking liquid. REFRY THE BEANS (frijoles refritos): in a skillet, heat 50 g lard over medium heat; add the cooked beans and mash with a potato masher or spatula, adding the reserved liquid gradually until you have a thick creamy paste; cook 5–7 minutes, stirring, until slightly blackened and smoky. SEAR THE STEAK: heat 1 tbsp oil in a large skillet over medium-high; season 500 g beef with salt and pepper, sear 2 minutes per side in a single layer (do not crowd the pan, work in batches); rest the meat on a foil-tented plate. FRY THE CHORIZO: in the same skillet, add 200 g chorizo from its casing, break it up with a wooden spoon, and fry 5–7 minutes over medium heat until the red oil is released and the meat is fully cooked; leave it in the pan with its oil. PREP THE TOPPINGS: slice 2 avocados, 4 tomatoes and the remaining onion half (finely diced); shred 200 g lettuce; place each in a separate bowl for fast assembly. ASSEMBLE THE TLAYUDA: preheat a plancha or large griddle over medium-high heat; place a tlayuda tortilla on the dry surface and spread it with a generous layer of refried beans to within 1 cm of the edges; scatter 75 g shredded cheese over the beans; add a portion of seared steak and chorizo. CRISP IT UP: cook on the plancha over medium heat 5–7 minutes without flipping — the bottom of the tortilla must turn golden brown, crunchy, and show light scorch marks; the cheese must melt completely; cover with a lid for the last 2 minutes to speed melting. SERVE: slide the tlayuda onto a plate with a wide spatula; top with lettuce, tomato slices, avocado, diced onion, salsa; squeeze lime and scatter cilantro; fold in half or eat open with your hands; repeat for the remaining 3 tlayudas; serve immediately — it gets chewy if it sits."}},{"id":163,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"en":"Colombia","ro":"Columbia"},"name":{"en":"Bandeja Paisa","ro":"Bandeja Paisa"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["For frijoles antioqueños: 400 g dried red kidney or cargamanto beans, soaked overnight","1 medium carrot (~100 g) grated + 2 medium tomatoes (~250 g) grated + 1 onion (~150 g) finely diced + 4 garlic cloves for the hogao","2 tbsp oil + 1 tbsp tomato paste + 1 tsp ground cumin + 1 tsp salt for the beans","1 ripe plantain (~150 g) diced for the beans","For arroz blanco: 360 g (2 cups) medium-grain white rice + 540 ml water + 0.5 tsp salt","For carne molida: 500 g ground beef + 1 onion finely diced + 4 garlic cloves + 2 grated tomatoes + 2 tbsp oil + 1 tsp cumin + 1 tsp salt + 0.5 tsp pepper + 50 ml beef stock","For chicharrón: 800 g pork belly skin-on cut into 8 strips of ~10 cm + 1 tsp salt","4 raw Colombian chorizos (~80 g each)","4 morcillas (blood sausages, ~80 g each)","For 4 small arepas: 200 g precooked white corn flour (Harina P.A.N.) + 240 ml warm water + 0.5 tsp salt + 1 tbsp oil for the griddle","For maduro: 2 very ripe plantains (deep black skin) + 2 tbsp oil","4 large eggs for sunny-side up + 1 tbsp oil + salt and pepper","2 ripe avocados, halved and pitted","4 slices of crusty white bread + 4 lime wedges + salt to serve"],"ro":["Pentru frijoles antioqueños: 400 g fasole roșie uscată (cargamanto sau kidney) înmuiată peste noapte","1 morcov mediu (~100 g) ras + 2 roșii medii (~250 g) rase + 1 ceapă (~150 g) tocată fin + 4 căței usturoi pentru hogao","2 linguri ulei + 1 lingură pastă de roșii + 1 linguriță chimion + 1 linguriță sare pentru fasole","1 banană plantain coaptă (~150 g) tocată în cuburi pentru fasole","Pentru arroz blanco: 360 g (2 căni) orez cu bob mediu + 540 ml apă + 0,5 linguriță sare","Pentru carne molida: 500 g vită tocată + 1 ceapă tocată + 4 căței usturoi + 2 roșii rase + 2 linguri ulei + 1 linguriță chimion + 1 linguriță sare + 0,5 linguriță piper + 50 ml supă de vită","Pentru chicharrón: 800 g costiță de porc cu coajă tăiată în 8 fâșii lungi de 10 cm + 1 linguriță sare","4 chorizos columbieni cruzi (~80 g fiecare)","4 morcillas (cârnați de sânge, ~80 g fiecare)","Pentru arepas (4 mici): 200 g făină de porumb precoaptă (Harina P.A.N.) + 240 ml apă caldă + 0,5 linguriță sare + 1 lingură ulei pentru tigaie","Pentru maduro: 2 banane plantain foarte coapte (coaja neagră) + 2 linguri ulei","4 ouă mari pentru ochiuri + 1 lingură ulei + sare și piper","2 avocado coapte, jumătățite și fără sâmbure","4 felii pâine albă crocantă + 4 felii de lime + sare pentru servire"]},"howIsMade":{"en":"SOAK & PLAN: soak 400 g red beans overnight; bandeja paisa runs 6 parallel components — gather all ingredients and tools before starting, plus 3 pots and 2 skillets. THE BEANS: drain the beans, simmer in 1.5 L water with grated carrot + 1 grated tomato + onion + 2 garlic cloves + 1 tsp cumin + 1 tsp salt 60–90 minutes until tender; in the final 15 minutes make the hogao: sauté in 2 tbsp oil the remaining onion + 2 garlic + 1 grated tomato + 1 tbsp tomato paste 5 minutes; stir into the beans with the diced plantain and cook 10 more minutes. THE RICE: rinse 360 g rice in cold water 3 times; place with 540 ml water and 0.5 tsp salt; bring to a boil, cover, reduce to lowest heat 12 minutes, rest covered 10 minutes. CARNE MOLIDA: heat 2 tbsp oil in a skillet over medium-high; sauté onion and garlic 5 minutes until soft; add 500 g ground beef, break up with the spoon and brown 8 minutes; add 2 grated tomatoes, 1 tsp cumin, 1 tsp salt and 0.5 tsp pepper, cook 5 minutes; deglaze with 50 ml stock. CHICHARRÓN: place 8 strips of pork belly skin-on in a pot with 200 ml cold water and 1 tsp salt; bring to a boil, cover and simmer 30 minutes; drain completely; in the same pot, fry the pork in its own fat over medium-high heat 8–10 minutes turning often until the skin is golden and crackling; (Alternative: 200 °C oven 40 minutes on a rack.). AREPAS: mix 200 g corn flour with 240 ml warm water and 0.5 tsp salt in a bowl until a damp dough forms; rest 5 minutes; shape into 4 patties of 10 cm diameter and 1 cm thick; griddle in a hot pan with 1 tbsp oil over medium heat 4–5 minutes per side until golden with dark spots. MADURO + EGGS + SAUSAGES: slice 2 black plantains into 1 cm rounds; fry in 2 tbsp oil over medium heat 2 minutes per side until caramelized; in another skillet, fry 4 raw chorizos 5 minutes per side and 4 morcillas 3 minutes per side; then fry 4 eggs in 1 tsp oil 2 minutes until whites set but yolks runny. ASSEMBLY: on 4 large platters arrange in this order: a mound of rice, a generous ladle of beans, a portion of carne molida, 2 chicharrón pieces, 1 chorizo, 1 morcilla, 1 fried egg on top of the meat, 2 maduro slices, 1/2 avocado, 1 arepa, 1 bread slice, 1 lime wedge; serve immediately — bandeja paisa is eaten with knife and fork, each bite in combination with others."}},{"id":164,"servings":4,"tipType":"def","pairingsType":"def","origin":{"en":"Hungary","ro":"Ungaria"},"name":{"en":"Lángos","ro":"Lángos"},"category":{"en":"Snack","ro":"Gustare"},"ingredients":{"en":["500 g all-purpose or T550 bread flour","7 g instant dry yeast (or 21 g fresh yeast)","1 tsp granulated sugar (to feed yeast)","1.5 tsp fine salt for the dough","300 ml warm whole milk (or water, traditional) at 38 °C","100 g boiled mashed potato (the secret to the fluffy texture)","2 tbsp neutral oil for the dough","1 L sunflower or neutral oil for deep-frying","For garlic rub: 4 garlic cloves crushed with 1 tsp salt + 1 tbsp water into a paste","200 g Hungarian sour cream (tejföl)","200 g sharp grated cheese (cheddar/gouda/edam-style)","1 small bunch fresh chives, finely chopped (optional)","Salt for finishing","Equipment: wide heavy pot for frying + slotted spoon + wire rack"],"ro":["500 g făină universală sau de pâine T550","7 g drojdie uscată instant (sau 21 g drojdie proaspătă)","1 linguriță zahăr granulat (pentru hrănirea drojdiei)","1,5 lingurițe sare fină pentru aluat","300 ml lapte integral cald (sau apă, tradițional) la 38 °C","100 g cartof fiert și pasat (secretul texturii pufoase)","2 linguri ulei neutru pentru aluat","1 L ulei de floarea-soarelui sau neutru pentru prăjit","Pentru ungerea cu usturoi: 4 căței de usturoi zdrobiți cu 1 linguriță sare + 1 lingură apă în pastă","200 g smântână ungurească (tejföl)","200 g brânză tare rasă (cheddar/gouda/edam)","1 legăturică mică de ceapă verde proaspătă (arpagic), tocată fin (opțional)","Sare pentru finisare","Echipament: oală grea și lată pentru prăjit + lingură cu fante + grătar de sârmă"]},"howIsMade":{"en":"PROOF THE YEAST: warm 100 ml of the milk to 38 °C, add 7 g yeast and 1 tsp sugar, stir and let stand 10 minutes until foamy; no foam = dead yeast, start over. MAKE THE DOUGH: in a large bowl combine 500 g flour with 1.5 tsp salt; make a well, add the foamed yeast-milk, the remaining 200 ml warm milk, 100 g smooth mashed potato (no lumps), and 2 tbsp oil; knead by hand or stand mixer 10 minutes until smooth, soft and slightly sticky — softer than bread dough. FIRST PROOF: cover with a clean towel and rise in a warm place 1.5–2 hours until doubled. SHAPE: lightly oil hands and work surface; divide into 4 equal portions (~225 g each); roll into balls, rest 10 minutes covered; with oiled hands stretch each ball into a 25 cm disc about 1 cm thick, slightly thinner at the edges. SECOND PROOF: place shaped discs on an oiled tray, cover loosely and let rise 20 minutes until puffy. HEAT THE OIL: pour 1 L oil into a wide heavy pot to a 5 cm depth; heat to 175 °C (medium-high) — a small piece of dough should sizzle and rise within 5 seconds. FRY THE LÁNGOS: carefully slide one lángos into the hot oil; after 30 seconds, gently push under with a slotted spoon — it puffs dramatically; fry 60–90 seconds per side until deeply golden brown; drain on a wire rack (NOT paper towels which steam the base soft). TOPPING & SERVE: brush the still-hot top with garlic paste (4 garlic crushed with 1 tsp salt + 1 tbsp water); smear with 50 g sour cream, scatter 50 g grated cheese, sprinkle chopped chives and a pinch of salt; serve in hand or on a plate, eaten within 5 minutes while bread is crisp outside and pillowy inside."}},{"id":165,"servings":4,"tipType":"veg","pairingsType":"indian","origin":{"en":"India","ro":"India"},"name":{"en":"Rajma","ro":"Rajma"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["350 g dried red kidney beans (rajma) soaked 8–12 h in cold water (OR 2 × 400 g cans drained as a shortcut)","1.2 L cooking water for the beans + 1 tsp salt + 2 bay leaves + 4 black cardamom pods (for pressure-cooking the beans)","3 tbsp ghee or neutral oil for the masala","1 tsp whole cumin seeds (jeera)","2 medium yellow onions (~300 g) very finely diced","6 garlic cloves + 4 cm fresh ginger — grated into a paste with 1 tbsp water","1 green chili (or to taste), finely chopped","4 medium ripe tomatoes (~400 g), pureed in a blender to a smooth pulp","1 tbsp tomato paste (for body)","1 tsp ground coriander (dhania) + 1 tsp ground cumin (jeera) + 0.5 tsp turmeric (haldi) + 1 tsp Kashmiri red chili powder + 1 tsp salt for the masala","1 tsp garam masala (added at end, not boiled)","1 tsp kasuri methi (dried fenugreek leaves), crushed in palm (added at end)","30 g butter cubed (the restaurant-style finish)","1 tbsp single cream or 2 tbsp full-fat yogurt (optional, for creaminess)","Fresh coriander (cilantro) leaves to garnish + 1 lime in wedges; to serve: 360 g (2 cups) basmati rice cooked in 540 ml water with 0.5 tsp salt, and naan or jeera rice if preferred"],"ro":["350 g fasole roșie uscată (rajma) înmuiată 8–12 h în apă rece (SAU 2 × 400 g cutii de fasole roșie scursă ca scurtătură)","1,2 L apă de fierbere pentru fasole + 1 linguriță sare + 2 foi de dafin + 4 păstăi de cardamom negru (pentru fierberea sub presiune)","3 linguri ghee sau ulei neutru pentru masala","1 linguriță semințe întregi de chimion (jeera)","2 cepe galbene medii (~300 g) tocate foarte fin","6 căței de usturoi + 4 cm de ghimbir proaspăt — răzuite în pastă cu 1 lingură de apă","1 ardei iute verde (sau după gust), tocat fin","4 roșii medii coapte (~400 g), pasate la blender până la o pulpă fină","1 lingură pastă de roșii (pentru corp)","1 linguriță coriandru măcinat (dhania) + 1 linguriță chimion măcinat (jeera) + 0,5 linguriță turmeric (haldi) + 1 linguriță Kashmiri chili pudră + 1 linguriță sare pentru masala","1 linguriță garam masala (adăugat la final, nu fiert)","1 linguriță kasuri methi (frunze uscate de schinduf), zdrobite în palmă (adăugat la final)","30 g unt cubulețe (finisajul în stil restaurant)","1 lingură smântână dulce single sau 2 linguri iaurt gras (opțional, pentru cremozitate)","Frunze proaspete de coriandru (cilantro) pentru garnitură + 1 lămâie verde feliată; pentru servire: 360 g (2 căni) orez basmati fiert în 540 ml apă cu 0,5 linguriță sare, plus naan sau jeera rice dacă preferi"]},"howIsMade":{"en":"SOAK THE BEANS: rinse 350 g rajma in cold water 2–3 times; cover with cold water by 5 cm and soak 8–12 hours (or overnight); drain and rinse; skipping the soak gives undercooked centers and gassy texture. PRESSURE-COOK THE BEANS: place soaked rajma in a pressure cooker with 1.2 L water + 1 tsp salt + 2 bay leaves + 4 black cardamom pods; pressure-cook on high heat 4–5 whistles, then reduce to low and cook 25 minutes; let the pressure release naturally; beans should be completely tender — press one between thumb and forefinger; it should mash with light pressure; (Alternative: open pot 1.5–2 h simmer.) Drain reserving 500 ml bean cooking liquid. BHUNAO — TEMPER: in a heavy kadhai or deep pan over medium heat, melt 3 tbsp ghee; when shimmering, add 1 tsp cumin seeds — they will sizzle and pop within 5 seconds; do not let them blacken. ONIONS: add 300 g very finely diced onion; cook stirring often 12–15 minutes until deeply golden brown — almost caramelized; this long, slow onion bhunao is what separates restaurant rajma from amateur attempts; do not rush. GINGER-GARLIC-CHILI: add the ginger-garlic paste and green chili; stir 1–2 minutes until the raw smell disappears. TOMATO BASE: add the pureed tomato pulp + 1 tbsp tomato paste + 1 tsp ground coriander + 1 tsp ground cumin + 0.5 tsp turmeric + 1 tsp Kashmiri chili powder + 1 tsp salt; cook stirring frequently 8–10 minutes until the oil separates from the masala on the edges of the pan — this is the visual sign the bhunao is complete and the raw tomato has cooked off. SIMMER WITH BEANS: tip in the drained rajma and 500 ml of reserved bean liquid; stir gently; bring to a simmer and cook uncovered 20–25 minutes, partially mashing some beans against the side of the pan with a spoon to thicken the gravy; the gravy should reduce and coat the beans — neither soupy nor dry, like a thick stew that holds on a spoon. FINISH AND SERVE: stir in 1 tsp garam masala + 1 tsp crushed kasuri methi + 30 g butter cubed + 1 tbsp cream (optional); stir until butter melts; cover and let rest off heat 5 minutes for flavors to settle; serve hot over steamed basmati rice (or jeera rice or naan), topped with chopped fresh coriander and a squeeze of lime; better the next day."}},{"id":166,"servings":4,"tipType":"meat","pairingsType":"latin","origin":{"en":"Cuba","ro":"Cuba"},"name":{"en":"Picadillo","ro":"Picadillo"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["600 g ground beef (chuck, ~20% fat)","2 tbsp olive oil for the sofrito","1 large yellow onion (~200 g), finely diced","1 large green bell pepper (~200 g), finely diced","6 garlic cloves, minced","1 tsp ground cumin (comino) + 1 tsp dried oregano + 0.5 tsp sweet smoked paprika (pimentón) + 1 bay leaf","400 g can crushed tomatoes (or 4 fresh tomatoes peeled and grated) + 2 tbsp tomato paste","100 ml dry white wine OR 50 ml dry sherry (Cuban traditional — burns off raw-meat smell)","100 g pitted green olives (manzanilla), halved","60 g golden or dark raisins, soaked 10 min in 100 ml hot water then drained","100 g frozen green peas, thawed","1 tbsp capers, drained (optional, traditional)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","Fresh flat-leaf parsley to garnish","To serve: 360 g (2 cups) white rice cooked in 540 ml water with 0.5 tsp salt + 240 g cooked black beans + 2 ripe plantains sliced and fried + lime wedges"],"ro":["600 g carne tocată de vită (gât/cap de piept, ~20% grăsime)","2 linguri ulei de măsline pentru sofrito","1 ceapă galbenă mare (~200 g), tăiată cubulețe fine","1 ardei gras verde mare (~200 g), tăiat cubulețe fine","6 căței de usturoi, tocați mărunt","1 linguriță chimion măcinat (comino) + 1 linguriță oregano uscat + 0,5 linguriță boia dulce afumată (pimentón) + 1 foaie de dafin","400 g roșii zdrobite la conservă (sau 4 roșii proaspete decojite și răzuite) + 2 linguri pastă de roșii","100 ml vin alb sec SAU 50 ml sherry sec (tradițional cubanez — arde mirosul de carne crudă)","100 g măsline verzi fără sâmburi (manzanilla), tăiate în jumătăți","60 g stafide aurii sau negre, înmuiate 10 minute în 100 ml apă caldă, apoi scurse","100 g mazăre verde congelată, dezghețată","1 lingură capere, scurse (opțional, tradițional)","1,5 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat","Pătrunjel verde proaspăt cu frunza lată pentru garnitură","Pentru servire: 360 g (2 căni) orez alb fiert în 540 ml apă cu 0,5 linguriță sare + 240 g fasole neagră fiartă + 2 banane plantain coapte feliate și prăjite + felii de lămâie verde"]},"howIsMade":{"en":"SOFRITO BASE: in a heavy 5 L pot, heat 2 tbsp olive oil over medium heat; add 200 g diced onion + 200 g diced green pepper with a pinch of salt; cook stirring often 8–10 minutes until soft and beginning to gold — the sofrito is the soul of Cuban cooking; add 6 minced garlic cloves and cook 1 minute more until fragrant. BLOOM THE SPICES: add 1 tsp cumin, 1 tsp oregano, 0.5 tsp smoked paprika and 1 bay leaf to the hot oil-and-vegetable base; stir 30 seconds until the spices release their aroma — do not burn. BROWN THE BEEF: raise heat to medium-high; add 600 g ground beef in a single layer and let it sit undisturbed 2–3 minutes to develop a crust; then break it up with a wooden spoon and brown another 6–8 minutes until no pink remains and any released liquid has evaporated. DEGLAZE: pour in 100 ml dry white wine (or 50 ml sherry) and scrape any browned bits stuck to the bottom of the pot; simmer 2–3 minutes until the alcohol smell disappears. TOMATO + BUILD: stir in the can of crushed tomatoes + 2 tbsp tomato paste; cook 5 minutes until the mixture darkens and oil starts to appear on the surface — tomato fully cooked, no raw acidity. ADD OLIVES, RAISINS & SEASON: stir in 100 g halved green olives + 60 g drained raisins + 1 tbsp capers (if using) + 1.5 tsp salt + 0.5 tsp pepper; the sweet-salty contrast is the unique Cuban signature. SIMMER: reduce heat to low, cover partially, and simmer 20–25 minutes, stirring every few minutes; the mixture should thicken into a saucy hash — neither dry nor soupy, holding together on a spoon; add 60 ml water if it gets too dry. PEAS & SERVE: in the last 3 minutes, stir in 100 g thawed peas — just to warm through, keeping them bright green; remove the bay leaf; off the heat, scatter chopped parsley; serve over steamed white rice with black beans on the side, fried plantains, and lime wedges — the classic Cuban comida criolla plate."}},{"id":167,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Morocco","ro":"Maroc"},"name":{"en":"Lamb Tagine","ro":"Tagine cu miel"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["1 kg boneless lamb shoulder, cut into 4 cm cubes (with some fat on for richness)","2 large yellow onions (~400 g), one finely diced for the base and one cut into thick wedges for the stew","6 garlic cloves, minced","4 cm fresh ginger, grated","3 tbsp olive oil (or 2 tbsp oil + 1 tbsp butter for traditional richness)","1 tsp ground cumin + 1 tsp ground coriander + 1 tsp ground cinnamon + 0.5 tsp ground turmeric + 0.5 tsp sweet paprika + 0.5 tsp ground ginger + a pinch of saffron threads (5–6 strands, bloomed in 2 tbsp hot water)","1.5 tsp ras el hanout (Moroccan spice blend)","1.5 tsp salt + 0.5 tsp freshly ground black pepper","2 tbsp tomato paste","400 g ripe tomatoes (4 medium), peeled and grated, or 1 × 400 g can","200 g dried apricots, halved (use Turkish or California — not too sweet)","60 g pitted dried prunes or raisins (optional, for depth)","600 ml hot water or low-salt chicken stock","1 cinnamon stick + 1 bay leaf","80 g whole blanched almonds (or skin-on, toasted)","1 tbsp honey (added at the end to balance sweetness)","Fresh coriander + flat-leaf parsley + 1 tbsp lightly toasted sesame seeds to garnish","To serve: 400 g couscous steamed with 400 ml water + 1 tbsp butter + 0.5 tsp salt, OR warm khobz flatbread"],"ro":["1 kg pulpă de miel dezosată (spată), tăiată cuburi de 4 cm (cu puțină grăsime pentru bogăție)","2 cepe galbene mari (~400 g), una tăiată cubulețe fine pentru bază și una tăiată în felii groase pentru tocăniță","6 căței de usturoi, tocați mărunt","4 cm ghimbir proaspăt, ras","3 linguri ulei de măsline (sau 2 linguri ulei + 1 lingură unt pentru bogăție tradițională)","1 linguriță chimion măcinat + 1 linguriță coriandru măcinat + 1 linguriță scorțișoară măcinată + 0,5 linguriță turmeric măcinat + 0,5 linguriță boia dulce + 0,5 linguriță ghimbir măcinat + un vârf de șofran (5–6 fire, înflorit în 2 linguri apă caldă)","1,5 linguriță ras el hanout (amestec marocan de condimente)","1,5 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat","2 linguri pastă de roșii","400 g roșii coapte (4 medii), decojite și răzuite, sau 1 cutie × 400 g","200 g caise uscate, tăiate în jumătăți (turcești sau californiene — nu prea dulci)","60 g prune uscate fără sâmburi sau stafide (opțional, pentru profunzime)","600 ml apă fierbinte sau supă de pui cu puțină sare","1 baton de scorțișoară + 1 foaie de dafin","80 g migdale întregi blanșate (sau cu coajă, prăjite)","1 lingură miere (adăugată la final pentru a echilibra dulceața)","Coriandru proaspăt + pătrunjel cu frunza lată + 1 lingură semințe de susan ușor prăjite pentru garnitură","Pentru servire: 400 g couscous aburit cu 400 ml apă + 1 lingură unt + 0,5 linguriță sare, SAU pâine plată khobz caldă"]},"howIsMade":{"en":"MARINATE THE LAMB: in a large bowl combine 1 kg lamb cubes with 1 tsp cumin + 1 tsp coriander + 1 tsp cinnamon + 0.5 tsp turmeric + 0.5 tsp paprika + 0.5 tsp ginger + 1.5 tsp ras el hanout + 1.5 tsp salt + 0.5 tsp pepper + 3 of the minced garlic cloves and 1 tbsp olive oil; rub the spices into the meat with your hands; cover and rest 30 minutes at room temperature (or up to 24 h in the fridge) so the spices penetrate. BLOOM SAFFRON: place 5–6 saffron threads in 2 tbsp hot water and let steep 10 minutes — this releases the flavour and colour; set aside. BUILD THE BASE: heat the remaining 2 tbsp oil (and 1 tbsp butter if using) in a heavy-bottomed tagine or Dutch oven over medium heat; add 200 g finely diced onion and cook stirring often 8–10 minutes until soft and translucent; add the remaining 3 minced garlic + grated ginger and stir 1 minute. SEAR THE LAMB: raise heat to medium-high; push the onions to the sides of the pot and add the marinated lamb in a single layer (work in 2 batches if needed); sear 3–4 minutes per side without moving until deeply browned on all sides — the crust is essential for the rich stew flavour; stir everything together once the lamb is browned. TOMATO + LIQUID: stir in 2 tbsp tomato paste and cook 1 minute until darkened; add the 400 g grated tomatoes, the saffron-water, 1 cinnamon stick and 1 bay leaf; pour in 600 ml hot water (or stock) — the liquid should come about halfway up the meat, not cover it; bring to a gentle simmer. SLOW COOK: reduce heat to low, cover with the tagine lid (or a tight Dutch-oven lid), and simmer 1.5–2 hours, checking every 30 minutes and stirring gently; the lamb is ready when a fork sinks in easily; add a splash of hot water if the sauce reduces too quickly. ADD APRICOTS + ONIONS: stir in 200 g halved dried apricots + 60 g prunes (if using) + the 200 g onion wedges; cover and simmer 25–30 minutes more until the fruit is plump and the onion wedges are tender but still holding shape; the sauce should be glossy, coating the back of a spoon; finish with 1 tbsp honey, taste, adjust salt. FINISH AND SERVE: while the tagine rests off the heat for 5 minutes, toast 80 g whole almonds in a dry pan over medium heat 3–4 minutes until golden — watch carefully, they burn fast; spoon the lamb tagine over warm couscous (or serve with khobz), top with toasted almonds, sesame seeds, and a scatter of fresh coriander and parsley; eat with bread to mop up the sauce."}},{"id":168,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"United Kingdom","ro":"Marea Britanie"},"name":{"en":"Shepherd's Pie","ro":"Plăcintă a ciobanului"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["600 g minced lamb (~15% fat — leaner than usual ground beef but with enough fat for moisture)","1 large onion (~200 g), finely diced","2 medium carrots (~200 g), finely diced 0.5 cm (small dice — they should disappear into the filling)","4 garlic cloves, minced","1 tbsp tomato paste","1 tbsp Worcestershire sauce (the secret depth — non-negotiable)","1 tsp dried thyme (or 2 sprigs fresh)","1 tsp dried rosemary, finely chopped","2 tbsp plain flour (to thicken the gravy)","300 ml hot lamb or beef stock (homemade or low-salt)","150 g frozen peas","1 tbsp neutral oil","1 tsp salt + 0.5 tsp freshly ground black pepper for the filling","For the mash topping: 1 kg floury potatoes (Maris Piper, King Edward, or Yukon Gold), peeled and cut into 4 cm chunks","60 g unsalted butter + 100 ml warm whole milk + 2 large egg yolks (the yolks give the iconic golden crisp top) + 30 g grated mature cheddar (optional but traditional)","0.5 tsp white pepper + 0.5 tsp salt for the mash"],"ro":["600 g carne tocată de miel (~15% grăsime — mai slabă decât vita tocată obișnuită, dar cu suficientă grăsime pentru umiditate)","1 ceapă mare (~200 g), tăiată cubulețe fine","2 morcovi medii (~200 g), tăiați cubulețe fine de 0,5 cm (cubulețe mici — trebuie să dispară în umplutură)","4 căței de usturoi, tocați","1 lingură pastă de roșii","1 lingură sos Worcestershire (profunzimea secretă — nenegociabil)","1 linguriță cimbru uscat (sau 2 crenguțe proaspete)","1 linguriță rozmarin uscat, tocat fin","2 linguri făină albă (pentru a îngroșa sosul)","300 ml supă fierbinte de miel sau vită (de casă sau cu sare redusă)","150 g mazăre congelată","1 lingură ulei neutru","1 linguriță sare + 0,5 linguriță piper negru proaspăt măcinat pentru umplutură","Pentru piureul de deasupra: 1 kg cartofi făinoși (Maris Piper, King Edward sau Yukon Gold), curățați și tăiați bucăți de 4 cm","60 g unt nesărat + 100 ml lapte integral cald + 2 gălbenușuri mari (gălbenușurile dau crusta aurie iconică) + 30 g cheddar maturat ras (opțional dar tradițional)","0,5 linguriță piper alb + 0,5 linguriță sare pentru piure"]},"howIsMade":{"en":"1. BOIL THE POTATOES: place 1 kg peeled and cubed potatoes in a large pot of cold salted water (1 tbsp salt per 2 L), bring to a boil, then reduce to a steady simmer and cook 15–18 minutes until a knife slides through with no resistance; drain and return to the pot off the heat for 2 minutes to steam off, since wet potatoes make wet mash. 2. MAKE THE MASH: pass the dry potatoes through a ricer (best for fluffy mash) or mash with a hand masher, then beat in 60 g butter while still hot followed by 100 ml warm milk added in 3 stages, beating between each, and off the heat beat in 2 yolks, 0.5 tsp white pepper and 0.5 tsp salt until the mash is glossy, smooth and stiff enough to hold ridges (if it's too loose the topping will sink); cover with foil to keep warm. 3. SWEAT THE VEGETABLES: heat 1 tbsp oil in a large heavy skillet over medium heat, add 200 g diced onion and 200 g diced carrot with a pinch of salt, and cook, stirring often, 8–10 minutes until very soft and the carrots have lost their crunch (they will not soften further once mixed with meat), then stir in 4 minced garlic cloves, thyme and rosemary and cook 1 minute more. 4. BROWN THE LAMB: raise the heat to medium-high, add 600 g minced lamb and break it apart with a wooden spoon, then cook 8–10 minutes until the lamb is no longer pink and the released fat has begun to crisp small bits at the bottom of the pan (this Maillard browning is the foundation of the gravy), and spoon off any pooled fat over 1 tbsp, since lamb sheds a lot and too much makes the pie greasy. 5. BUILD THE GRAVY: stir 1 tbsp tomato paste into the lamb and cook 1 minute until darkened, sprinkle 2 tbsp flour over and stir 1–2 minutes to cook the raw taste out, then pour in 300 ml hot stock, 1 tbsp Worcestershire sauce, 1 tsp salt and 0.5 tsp pepper, scraping the bottom of the pan to lift the browned bits. 6. SIMMER + PEAS: reduce heat to low and simmer uncovered 15 minutes, stirring occasionally, until the gravy has thickened to a thick, glossy consistency that coats the meat (it should not be runny, or the mash will sink), then stir in 150 g frozen peas (they will warm through in the oven) and taste and adjust seasoning. 7. ASSEMBLE: preheat the oven to 200 °C and transfer the lamb filling to a 23 × 30 cm baking dish (about 2 L capacity), spoon the mash on top in dollops and spread carefully with a spatula sealing all the way to the edges, then drag the tines of a fork in long lines across the surface (these ridges crisp up beautifully in the oven) and scatter 30 g grated cheddar over the top if using. 8. BAKE & REST: place the dish on a baking sheet to catch any bubbling drips and bake on the middle rack 25–30 minutes until the top is deeply golden, the ridges are crisp, and the gravy is visibly bubbling around the edges, then rest 10 minutes before serving so the filling sets and slicing is cleaner, and serve straight from the dish with a green salad or buttered cabbage on the side (even better the next day, reheated until piping hot)."}},{"id":169,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"China","ro":"China"},"name":{"en":"Mapo Tofu","ro":"Mapo Tofu"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["600 g soft (silken or medium-soft) tofu, cut into 2 cm cubes — the texture is part of the dish, do not use firm tofu","200 g ground pork (~20% fat — the small amount adds umami without dominating)","3 tbsp neutral oil (rapeseed or peanut)","3 tbsp Pixian doubanjiang (Sichuan broad-bean chili paste) — the SOUL of the dish, do not skip or substitute","1 tbsp douchi (fermented black beans), rinsed and roughly chopped","2 tsp Sichuan chili bean paste (la doubanjiang) OR 1 tsp Korean gochujang as substitute","4 garlic cloves, finely minced","4 cm fresh ginger, peeled and grated","6 spring onions: the white parts finely chopped for cooking + the green tops cut diagonally for garnish (keep separate)","1.5 tbsp dark soy sauce (laochou)","1 tsp granulated sugar","300 ml hot unsalted chicken stock or water","2 tsp Sichuan peppercorns (huajiao), toasted in a dry pan 60 sec and crushed in a mortar","1.5 tbsp cornstarch (cornflour) mixed with 3 tbsp cold water for the final slurry","2 tsp chili oil (la yu) for finishing","1 tsp toasted sesame oil for the last drizzle","To serve: 320 g (1.6 cups dry) cooked jasmine rice or short-grain rice"],"ro":["600 g tofu moale (mătăsos sau mediu-moale), tăiat în cuburi de 2 cm — textura face parte din preparat, nu folosi tofu ferm","200 g carne tocată de porc (~20% grăsime — cantitatea mică adaugă umami fără a domina)","3 linguri ulei neutru (rapiță sau arahide)","3 linguri doubanjiang Pixian (pastă de fasole-chili din Sichuan) — SUFLETUL preparatului, nu omite și nu substitui","1 lingură douchi (fasole neagră fermentată), clătită și tocată grosier","2 lingurițe pastă de fasole-chili Sichuan (la doubanjiang) SAU 1 linguriță gochujang coreean ca substitut","4 căței de usturoi, tocați fin","4 cm ghimbir proaspăt, curățat și ras","6 cepe verzi: părțile albe tocate fin pentru gătit + vârfurile verzi tăiate oblic pentru ornament (păstrează separat)","1,5 linguri sos de soia închis (laochou)","1 linguriță zahăr granulat","300 ml supă fierbinte de pui nesărată sau apă","2 lingurițe boabe de piper sichuan (huajiao), prăjite într-o tigaie uscată 60 sec și zdrobite în mojar","1,5 linguri amidon de porumb (cornflour) amestecat cu 3 linguri apă rece pentru slurry-ul final","2 lingurițe ulei de chili (la yu) pentru finisare","1 linguriță ulei de susan prăjit pentru ultima stropire","Pentru servire: 320 g (1,6 căni uscat) orez jasmine fiert sau orez cu bob scurt"]},"howIsMade":{"en":"PREP THE TOFU: bring a small pot of water with 1 tsp salt to a gentle simmer (not boil); slip the 2 cm tofu cubes in carefully and let them warm 2 minutes — this firms the surface so they hold their shape in the sauce; drain gently and set aside in the warm pot off the heat. TOAST SICHUAN PEPPERCORNS: in a dry pan over medium heat, toast 2 tsp Sichuan peppercorns 60 seconds until intensely fragrant; tip into a mortar and crush coarsely; set aside. RENDER THE PORK: heat 2 tbsp neutral oil in a wok or heavy skillet over medium-high heat; add 200 g ground pork and break it apart with a spatula; stir-fry 4–5 minutes until the pork is no longer pink and the small bits are crispy and golden brown — the texture difference between crisp pork and soft tofu is essential. BLOOM THE DOUBANJIANG: push the pork to the side of the pan and add 1 tbsp more oil to the empty space; add 3 tbsp doubanjiang to the oil and stir 60–90 seconds until the oil turns deep red — this oil-frying releases the colour and umami of the paste; stir into the pork; add chopped douchi + minced garlic + grated ginger + 2 tsp la doubanjiang (or gochujang) and stir-fry 60 seconds until intensely aromatic. LIQUID: pour in 300 ml hot stock + 1.5 tbsp dark soy sauce + 1 tsp sugar; bring to a simmer. ADD THE TOFU: slide the warm tofu cubes gently into the simmering sauce; do NOT stir — use the back of a ladle to push them under, then shake the pan gently to settle; simmer 4–5 minutes, basting the tops of the tofu with sauce occasionally, so the cubes absorb flavour without breaking. THICKEN: stir the cornstarch slurry one more time and pour HALF into the sauce, then shake the pan and let it simmer 30 seconds; the sauce will turn glossy and start to coat the tofu; if still thin, add the rest of the slurry; the finished sauce should cling lightly to the tofu, not be soupy. FINISH AND SERVE: off the heat, drizzle 2 tsp chili oil + 1 tsp toasted sesame oil over the surface and scatter the green spring-onion tops + crushed Sichuan peppercorns; do NOT stir — the peppercorns must hit your tongue undiluted for the ma (numbing) sensation; serve immediately with hot jasmine rice; each bite: rice + tofu + sauce + peppercorn = the full ma-la experience."}},{"id":170,"servings":2,"tipType":"veg","pairingsType":"veg","origin":{"en":"Turkey","ro":"Turcia"},"name":{"en":"Menemen","ro":"Menemen"},"category":{"en":"Breakfast","ro":"Mic dejun"},"ingredients":{"en":["6 large eggs, at room temperature","3 tbsp Turkish or extra-virgin olive oil","2 sivri biber (long green Turkish peppers, mildly hot) OR 1 green bell pepper + 1 jalapeño as substitute (~150 g total), seeds removed and finely diced","4 ripe tomatoes (~500 g), peeled and roughly grated on a box grater (the skin holds back, only the pulp grates through — this is the Turkish technique)","1 tbsp tomato paste (salça) — optional, deepens the red","1 tsp pul biber (Turkish red pepper flakes, Aleppo or Maraş-style) — adds warmth without harsh heat","0.5 tsp dried oregano","0.5 tsp salt + freshly ground black pepper","30 g feta-style beyaz peynir, crumbled (optional, regional Aegean addition)","1 small handful flat-leaf parsley, finely chopped, to finish","1 small bunch chives or spring onion green, finely chopped (optional)","To serve: 4 thick slices of fresh ekmek country bread OR 2 simit (Turkish sesame bagels), Turkish black tea (çay) brewed strong","Note on regional debate: this version is WITHOUT onion (Istanbul-style); if making the Aegean-style, add 1 small onion finely diced and cook 4 min before the peppers"],"ro":["6 ouă mari, la temperatura camerei","3 linguri ulei de măsline turcesc sau extravirgin","2 sivri biber (ardei lungi verzi turcești, ușor iuți) SAU 1 ardei gras verde + 1 jalapeño ca substitut (~150 g total), fără semințe și tocați fin","4 roșii coapte (~500 g), opărite și răzuite grosier pe răzătoarea cu găuri mari (coaja rămâne în mână, doar pulpa trece prin răzătoare — aceasta este tehnica turcească)","1 lingură pastă de roșii (salça) — opțional, adâncește roșul","1 linguriță pul biber (fulgi de ardei roșu turcesc, stil Aleppo sau Maraș) — adaugă căldură fără iuțeală agresivă","0,5 linguriță oregano uscat","0,5 linguriță sare + piper negru proaspăt măcinat","30 g beyaz peynir tip feta, fărâmițat (opțional, adaos regional egeean)","1 mână mică de pătrunjel cu frunza lată, tocat fin, pentru finisare","1 legătură mică de arpagic sau partea verde a cepei verzi, tocată fin (opțional)","Pentru servire: 4 felii groase de ekmek proaspăt (pâine de țară) SAU 2 simit (covrigi turcești cu susan), ceai negru turcesc (çay) preparat tare","Notă despre dezbaterea regională: această versiune este FĂRĂ ceapă (stil Istanbul); dacă faci versiunea egeeană, adaugă 1 ceapă mică tocată fin și gătește 4 minute înainte de ardei"]},"howIsMade":{"en":"PEEL AND GRATE THE TOMATOES: cut a shallow cross in the bottom of each of 4 ripe tomatoes; drop into boiling water 30 seconds, then transfer to ice water; the skins peel off easily; halve each tomato horizontally and rub the cut sides against the coarse side of a box grater placed over a bowl — the flesh grates through and the empty skin remains in your hand; this Turkish technique gives a pulpy, juicy tomato base with no skin pieces. COOK THE PEPPERS: heat 3 tbsp olive oil in a heavy 24 cm skillet (cast iron or earthenware sahan is traditional) over medium heat; add 150 g finely diced green peppers and cook stirring often 5–6 minutes until softened and slightly blistered at the edges but still bright green — do not let them brown. ADD TOMATO PASTE: stir 1 tbsp tomato paste into the peppers and cook 30 seconds — the salça deepens the colour and umami; (Skip this step if not using paste.). ADD GRATED TOMATOES: pour in the grated tomato pulp + 1 tsp pul biber + 0.5 tsp oregano + 0.5 tsp salt and a generous twist of black pepper; bring to a simmer and cook 6–8 minutes, stirring occasionally, until the tomato has reduced by half and looks jammy — the bottom of the spatula should drag a clear line through the sauce that does not fill in immediately. PREP THE EGGS: while the tomatoes cook, crack 6 eggs into a bowl one at a time — DO NOT beat them; the eggs go into the pan whole or barely broken, with yolks intact at first. ADD THE EGGS: when the tomato is jammy, lower the heat to medium-low; slip the eggs gently into the pan, spaced around the surface; let them sit 30 seconds undisturbed to set on the bottom. SCRAMBLE LIGHTLY: with a wooden spoon, push the eggs gently through the tomato in slow figure-eight motions — DO NOT vigorously stir; the whites should set into ribbons and the yolks should break and streak through the sauce in golden swirls; cook 90 seconds–2 minutes only — the menemen should remain glossy and barely-set, NOT scrambled-egg-dry; take off the heat while still slightly wet — it continues cooking in the hot pan. SERVE FROM THE PAN: scatter 30 g crumbled feta + chopped parsley (and chives if using); bring the pan straight to the table — menemen is always eaten from the pan with bread torn and dipped into the sauce; serve with strong Turkish black tea; best eaten within 5 minutes of cooking, while warm and glossy."}},{"id":171,"servings":4,"tipType":"meat","pairingsType":"soup","origin":{"en":"Russia","ro":"Rusia"},"name":{"en":"Solyanka","ro":"Solyanka"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["500 g beef brisket or shin on the bone (for the broth)","2 L cold water for the broth + 1 onion + 1 carrot + 2 bay leaves + 5 black peppercorns + 1 tsp salt for the stock","200 g smoked kielbasa or krakovskaya, sliced 5 mm thick","150 g cooked ham, cut into 1 cm cubes (or boiled tongue, traditional)","100 g salami or hunting sausage, sliced thin","2 large pickled cucumbers (~250 g, half-sour or fully sour), cut into thin matchsticks; reserve 100 ml of the pickle brine","1 large onion (~200 g), finely diced","1 tbsp tomato paste","200 g grated tomatoes (or 1 × 200 g canned, drained)","2 tbsp butter or 30 g rendered beef fat for the soffritto","80 g pitted black olives (kalamata-style) + 80 g pitted green olives","2 tbsp capers, drained","1 lemon, sliced into thin half-moons","1 bay leaf + 0.5 tsp ground black pepper + 1 tsp paprika (optional, for color)","A small bunch fresh dill, finely chopped","200 g smetana (sour cream) for serving","To serve: 4 thick slices of fresh dark rye bread, optional 1 tbsp horseradish (khren)"],"ro":["500 g piept de vită sau rasol cu os (pentru supă)","2 L apă rece pentru supă + 1 ceapă + 1 morcov + 2 foi de dafin + 5 boabe de piper negru + 1 linguriță sare pentru bulion","200 g kielbasa afumată sau cracovskaya, tăiată felii de 5 mm","150 g șuncă fiartă, tăiată cuburi de 1 cm (sau limbă fiartă, tradițional)","100 g salam sau cârnați de vânătoare, tăiat felii subțiri","2 castraveți murați mari (~250 g, semi-acri sau acri complet), tăiați fâșii subțiri; păstrează 100 ml din zeama de murături","1 ceapă mare (~200 g), tocată fin","1 lingură pastă de roșii","200 g roșii răzuite (sau 1 × 200 g din conservă, scurse)","2 linguri unt sau 30 g grăsime de vită topită pentru sotă","80 g măsline negre fără sâmburi (gen kalamata) + 80 g măsline verzi fără sâmburi","2 linguri capere, scurse","1 lămâie, tăiată felii subțiri în formă de semilună","1 foaie de dafin + 0,5 linguriță piper negru măcinat + 1 linguriță boia (opțional, pentru culoare)","O legăturică mică de mărar proaspăt, tocat fin","200 g smetana (smântână) pentru servire","Pentru servire: 4 felii groase de pâine de secară neagră proaspătă, opțional 1 lingură hrean (khren)"]},"howIsMade":{"en":"THE BROTH: place 500 g beef brisket in a large pot with 2 L cold water; bring to a boil and skim the foam thoroughly for the first 5 minutes — this gives a clear broth; add 1 whole quartered onion + 1 whole carrot + 2 bay leaves + 5 peppercorns + 1 tsp salt; reduce to a gentle simmer and cook covered 1.5 hours until the meat is fully tender. STRAIN AND SHRED: lift the beef out and let it cool slightly; strain the broth through a fine sieve back into a clean pot — you should have about 1.5 L of clear, savoury broth; cut the beef across the grain into bite-sized strips, discarding any tough sinew. SOFFRITTO: in a wide skillet, melt 2 tbsp butter over medium heat; add 200 g finely diced onion and sauté 6–8 minutes until soft and translucent; stir in 1 tbsp tomato paste and cook 1 minute until darkened; add the 200 g grated tomatoes and cook 4–5 minutes until the mixture has reduced and the oil starts to appear on the surface. ADD PICKLES: stir the cucumber matchsticks into the soffritto and cook 3–4 minutes; the pickles should be warmed through, not over-softened — they need to keep some crunch for texture contrast. FRY THE SAUSAGES: in a separate dry pan over medium heat, fry the smoked kielbasa slices, ham cubes, and salami slices 4–5 minutes until lightly browned at the edges and the fat has rendered; this step is non-negotiable — searing the meats before adding them to the broth is what gives solyanka its deep, smoky character. ASSEMBLE THE SOUP: pour the soffritto into the strained broth and stir in the seared sausages, ham, salami, and shredded beef; add the reserved 100 ml pickle brine + 1 bay leaf + 0.5 tsp ground pepper + 1 tsp paprika; bring to a gentle simmer. SIMMER: cook over low heat 15–20 minutes, partially covered, for the flavours to marry; add the olives + capers in the last 5 minutes only — they should warm through but keep their shape; taste and adjust salt — most of the saltiness comes from the pickles, capers, olives, and brine, so go cautiously. SERVE: ladle the hot solyanka into deep bowls; to each bowl add 1 thin lemon slice (whole, peel on), a generous spoonful of smetana, and a scatter of chopped dill; black pepper to taste; serve immediately with thick slices of fresh dark rye bread on the side — solyanka is a main course, not a starter; in Russian tradition, this is the classic post-celebration restorative."}},{"id":172,"servings":4,"tipType":"fish","pairingsType":"fish","origin":{"en":"USA","ro":"SUA"},"name":{"en":"Clam Chowder","ro":"Clam Chowder"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["1.5 kg fresh littleneck or quahog clams in shells (or 2 × 200 g cans whole baby clams in juice as substitute for landlocked cooks)","500 ml fresh clam juice or fish stock (reserve all the steaming liquid if using fresh clams)","150 g thick-cut smoked bacon, diced 0.5 cm","1 large yellow onion (~250 g), finely diced","2 medium celery stalks (~120 g), finely diced","4 garlic cloves, minced (optional — Boston purists frown but most modern recipes include)","30 g unsalted butter","30 g all-purpose flour (for the roux)","750 g floury potatoes (Yukon Gold or russet), peeled and cut into 1.5 cm cubes","250 ml whole milk","250 ml heavy cream (or half-and-half for a lighter version)","2 bay leaves + 1 tsp dried thyme + 0.5 tsp freshly ground black pepper","0.5 tsp salt (taste first — clam juice is salty)","A pinch of cayenne or 1 dash hot sauce (optional)","1 small bunch fresh chives, finely chopped, and 2 tbsp fresh flat-leaf parsley to garnish","To serve: 4 small hollowed-out sourdough rolls as edible bread bowls OR oyster crackers (a traditional New England side); 1 lemon, sliced into wedges"],"ro":["1,5 kg scoici proaspete (littleneck sau quahog) în cochilii (sau 2 × 200 g conserve de scoici mici întregi în suc, ca substitut pentru cei departe de mare)","500 ml suc de scoici proaspăt sau fond de pește (rezervă tot lichidul de aburire dacă folosești scoici proaspete)","150 g bacon afumat tăiat gros, cuburi de 0,5 cm","1 ceapă galbenă mare (~250 g), tăiată mărunt","2 tulpini medii de țelină (~120 g), tăiate mărunt","4 căței de usturoi, tocați (opțional — puriștii din Boston dezaprobă, dar majoritatea rețetelor moderne îi includ)","30 g unt nesărat","30 g făină universală (pentru roux)","750 g cartofi făinoși (Yukon Gold sau russet), curățați și tăiați cuburi de 1,5 cm","250 ml lapte integral","250 ml smântână grasă (sau jumătate-jumătate pentru o versiune mai ușoară)","2 foi de dafin + 1 linguriță cimbru uscat + 0,5 linguriță piper negru proaspăt măcinat","0,5 linguriță sare (gustă întâi — sucul de scoici este sărat)","Un vârf de cayenne sau 1 strop de sos iute (opțional)","O legăturică mică de arpagic proaspăt, tocat fin, și 2 linguri de pătrunjel proaspăt cu frunze plate pentru garnitură","Pentru servire: 4 chifle mici de sourdough scobite ca boluri comestibile SAU biscuiți pentru stridii (un acompaniament tradițional al Noii Anglii); 1 lămâie, tăiată felii pentru garnitură"]},"howIsMade":{"en":"Rinse 1.5 kg fresh clams in cold water 2-3 times to remove sand and discard any that are open and do not close when tapped, then place them in a wide pot with 250 ml water, cover and steam over high heat for 4-5 minutes until the shells just open, discarding any that stayed shut. Lift the clams out and strain the steaming liquid through a fine sieve lined with damp cheesecloth into a measuring cup, aiming for ~400-500 ml of clean clam broth, then pick the clam meat from the shells, roughly chop it, and set aside (if using canned clams, drain them reserving the juice and use the 500 ml fish stock plus the canned juice). In a heavy 5 L pot or Dutch oven over medium heat, add 150 g diced bacon and cook stirring often for 6-8 minutes until the bacon is deeply browned and most of the fat has rendered, then lift the crispy bacon onto a paper towel and set aside for garnish, leaving 3 tbsp of bacon fat in the pot. Add 250 g diced onion and 120 g diced celery to the bacon fat with a pinch of salt and cook stirring often for 8-10 minutes until soft and translucent but not browned (chowder is white, so you do not want colour here), then add 4 minced garlic cloves and cook 1 minute more. Add 30 g butter and let it melt, then sprinkle 30 g flour over the vegetables and stir constantly with a wooden spoon for 2 minutes, cooking out the raw flour taste without letting it darken to keep a white roux. Pour in the strained clam broth in a slow steady stream while whisking constantly to prevent lumps, add 750 g potato cubes, 2 bay leaves, 1 tsp thyme, and 0.5 tsp black pepper, bring to a gentle simmer, then cook uncovered for 15-18 minutes stirring occasionally until the potatoes are tender but still hold their shape and a knife slides in with no resistance. Lower the heat to its lowest setting and stir in 250 ml whole milk and 250 ml heavy cream, taking care not to let it boil after adding dairy or the cream will curdle, then warm through for 3 minutes before stirring in the chopped clam meat and most of the bacon (saving 2 tbsp of bacon and all the chives for garnish), and simmer 3 more minutes until the clams are just heated through (overcooking turns them tough and rubbery), then remove the bay leaves and taste, adjusting seasoning with salt and a pinch of cayenne if you like. Hollow out 4 small sourdough rolls (or use oyster crackers as a traditional simpler option), ladle the hot chowder into the bread bowls or deep soup plates, top each with the reserved crispy bacon, a generous scatter of chives and parsley, and a fresh twist of black pepper, and serve immediately with lemon wedges on the side, just as a New England restaurant typically brings a small dish of oyster crackers and a side of hot sauce to the table."}},{"id":173,"servings":2,"tipType":"meat","pairingsType":"meat","origin":{"en":"Germany","ro":"Germania"},"name":{"en":"Currywurst","ro":"Currywurst"},"category":{"en":"Snack","ro":"Gustare"},"ingredients":{"en":["4 Berliner-style Bratwurst pork sausages (~120 g each, total ~480 g) — fresh, not pre-grilled; or substitute fine Bockwurst or Frankfurter if Bratwurst unavailable","2 tbsp neutral oil (sunflower) for frying the sausages","For the curry sauce: 200 g good-quality tomato ketchup (Heinz or German Hela)","100 ml passata or 1 tbsp tomato paste + 80 ml water as substitute","2 tbsp medium-hot curry powder (a yellow Madras-style blend) — Herta Heuwer's original used a similar British colonial curry powder","1 tsp sweet Hungarian paprika","0.5 tsp smoked paprika (optional, adds depth)","1 tbsp Worcestershire sauce (the secret of Heuwer's original — not negotiable)","1 tbsp apple cider vinegar OR white wine vinegar","1 tbsp white sugar (helps balance the vinegar and brings out the tomato)","0.5 tsp ground allspice + 0.5 tsp ground ginger (the 'secret' warm-spice mix Heuwer added)","0.5 tsp salt + a pinch of cayenne or hot chili powder","To serve: extra curry powder for dusting on top + 2 portions of Pommes Frites (about 400 g hot crispy fries from the oven or fryer), or 2 small Brötchen rolls; 2 small wooden forks (Pommespieker) for the authentic Berlin experience"],"ro":["4 cârnați Bratwurst de Berlin din porc (~120 g fiecare, total ~480 g) — proaspeți, nu pre-grătar; sau substituție cu Bockwurst fin sau Frankfurter dacă Bratwurst nu este disponibil","2 linguri ulei neutru (floarea-soarelui) pentru prăjirea cârnaților","Pentru sosul de curry: 200 g ketchup de tomate de bună calitate (Heinz sau german Hela)","100 ml passata sau 1 lingură pastă de tomate + 80 ml apă ca substitut","2 linguri pudră de curry medie-iute (un amestec galben stil Madras) — originalul Herta Heuwer folosea o pudră de curry similară colonială britanică","1 linguriță paprika dulce maghiară","0,5 linguriță paprika afumată (opțional, adaugă profunzime)","1 lingură sos Worcestershire (secretul originalului Heuwer — nu este negociabil)","1 lingură oțet de cidru de mere SAU oțet de vin alb","1 lingură zahăr alb (ajută la echilibrarea oțetului și scoate în evidență tomatele)","0,5 linguriță piment ienibahar + 0,5 linguriță ghimbir măcinat (amestecul 'secret' de mirodenii calde pe care Heuwer le-a adăugat)","0,5 linguriță sare + un vârf de cayenne sau chili iute","Pentru servire: pudră de curry suplimentară pentru presărare deasupra + 2 porții de Pommes Frites (aproximativ 400 g cartofi prăjiți fierbinți și crocanți din cuptor sau friteuză), sau 2 Brötchen mici; 2 furculițe mici de lemn (Pommespieker) pentru experiența autentică berlineză"]},"howIsMade":{"en":"PRICK THE SAUSAGES: take 4 Bratwurst out of the fridge 15 minutes before cooking to come closer to room temperature; prick each sausage 4–5 times with a fork — this prevents the skin from bursting open in the pan and lets some fat render out. MAKE THE CURRY SAUCE: in a small saucepan, combine 200 g ketchup + 100 ml passata + 2 tbsp curry powder + 1 tsp sweet paprika + 0.5 tsp smoked paprika + 1 tbsp Worcestershire + 1 tbsp vinegar + 1 tbsp sugar + 0.5 tsp allspice + 0.5 tsp ground ginger + 0.5 tsp salt + a pinch of cayenne; whisk to combine. SIMMER THE SAUCE: bring the curry sauce to a gentle simmer over medium-low heat; cook 8–10 minutes, stirring often with a wooden spoon, until the sauce is glossy and slightly reduced — it should coat the back of a spoon; taste and adjust: if too sharp, add a pinch more sugar; if too sweet, a splash more vinegar; keep warm on the lowest heat. FRY THE SAUSAGES: heat 2 tbsp oil in a heavy skillet over medium heat; add the pricked sausages and fry 8–10 minutes, turning every 2 minutes with tongs, until deeply golden brown on all sides and the skin is crisp; the internal temperature should reach 70 °C — sausages must be fully cooked through. REST 2 MINUTES: transfer the sausages onto a board lined with paper towel; let them rest 2 minutes — this finishes cooking and lets the juices redistribute, so they don't gush out when sliced. SLICE: with a sharp knife, slice each sausage diagonally into 8 pieces of 1.5 cm; the diagonal cut gives more surface for the sauce to cling to and is the iconic Berlin presentation. ASSEMBLE: divide the sliced sausages between 2 deep paper-tray plates or shallow bowls (the Berlin Imbiss style); ladle the hot curry sauce generously over the top so it pools around the slices; dust the whole plate with an extra generous pinch of curry powder — the dusty top is what makes it a currywurst, not just a sausage in sauce. SERVE WITH POMMES: stab a wooden Pommespieker (small fork) into the slices, set on the side of the tray a heap of golden Pommes Frites and a small dollop of mayonnaise + ketchup (the German Pommes rot-weiß); eat standing up, ideally on a Berlin street corner; pair with a cold Pilsner; best eaten within 5 minutes — the joy is in the contrast of crisp skin, hot sauce, dusty curry, and salty fries."}},{"id":174,"servings":4,"tipType":"meat","pairingsType":"thai","origin":{"en":"Thailand","ro":"Thailanda"},"name":{"en":"Tom Kha Gai","ro":"Tom Kha Gai"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["500 g boneless skinless chicken thighs (more flavour than breast in this delicate broth), thinly sliced across the grain into 5 mm strips","400 ml unsweetened full-fat coconut milk (the cream layer separated, see step 2)","600 ml unsalted chicken stock (low-sodium homemade or store-bought)","1 hand of fresh galangal (kha) — ~50 g, peeled and cut into 5 mm coin slices; do NOT substitute ginger, the flavour is completely different","3 stalks fresh lemongrass (takrai) — outer leaves removed, lower 10 cm bruised with the back of a knife and cut into 5 cm sections","6 fresh kaffir lime leaves (bai makrut), de-veined and torn (NOT chopped — they release oils when torn)","4 small Thai bird's eye chilies (prik kee noo) — lightly bruised whole, not sliced if you want gentle heat (sliced for hot)","4 garlic cloves, lightly bruised","2 small shallots (~80 g), thinly sliced","200 g straw mushrooms (canned, drained), halved — or fresh oyster/shiitake/button mushrooms as substitute","4 tbsp Thai fish sauce (nam pla) — Squid or Tiparos brand for best flavour","1 tbsp palm sugar (or light brown sugar)","60 ml fresh lime juice (from 2 limes) — added at the END, never boiled","2 tbsp Thai chili paste in soybean oil (nam prik pao) — adds the signature smoky depth (optional but traditional)","1 small bunch fresh cilantro (coriander) leaves, roughly chopped, to garnish","4 spring onions, thinly sliced on the diagonal, to garnish","To serve: 320 g cooked jasmine rice (80 g dry per serving) + 1 lime cut into wedges"],"ro":["500 g pulpe de pui dezosate și fără piele (mai aromate decât pieptul în acest bulion delicat), feliate subțire în benzi de 5 mm contra fibrei","400 ml lapte de cocos integral neîndulcit (cu stratul de smântână separat, vezi pasul 2)","600 ml supă de pui nesărată (de casă sau cumpărată cu conținut scăzut de sodiu)","1 mână de galangal proaspăt (kha) — ~50 g, curățat și tăiat în felii de 5 mm; NU înlocui cu ghimbir, aroma este complet diferită","3 tulpini de lemongrass proaspăt (takrai) — frunzele exterioare îndepărtate, partea inferioară de 10 cm zdrobită cu dosul cuțitului și tăiată în secțiuni de 5 cm","6 frunze de kaffir lime proaspete (bai makrut), cu vinele îndepărtate și rupte (NU tăiate — eliberează uleiurile când sunt rupte)","4 ardei iuți thailandezi mici (prik kee noo) — zdrobiți ușor întregi, nu feliați dacă vrei iuțeală blândă (feliați pentru iute)","4 căței de usturoi, zdrobiți ușor","2 șalote mici (~80 g), feliate subțire","200 g ciuperci de paie (la conservă, scurse), tăiate în jumătăți — sau ciuperci proaspete oyster/shiitake/champignon ca substitut","4 linguri sos de pește thailandez (nam pla) — marca Squid sau Tiparos pentru cea mai bună aromă","1 lingură zahăr de palmier (sau zahăr brun deschis)","60 ml suc de lime proaspăt (din 2 limete) — adăugat la SFÂRȘIT, niciodată fiert","2 linguri pastă thailandeză de ardei iute în ulei de soia (nam prik pao) — adaugă profunzimea afumată caracteristică (opțional dar tradițional)","1 mănunchi mic de coriandru proaspăt (frunze de cilantro), tocat grosier, pentru garnitură","4 cepe verzi, feliate subțire pe diagonală, pentru garnitură","Pentru servire: 320 g orez jasmin fiert (80 g uscat pe porție) + 1 lime tăiat în felii"]},"howIsMade":{"en":"PREP THE AROMATICS: peel and slice 50 g galangal into 5 mm coins; remove the tough outer leaves from 3 lemongrass stalks and bruise the lower 10 cm with the back of a heavy knife to release the oils — then cut into 5 cm pieces; tear (don't chop) 6 kaffir lime leaves to release their oils; lightly bruise 4 chilies + 4 garlic cloves with the side of the knife; these aromatics are the soul of the broth — never use ground substitutes. SEPARATE THE COCONUT MILK: open a 400 ml can of coconut milk without shaking; the thick cream usually sits on top — spoon off about 100 ml of the thick cream and set aside (this is your hua kati, the cream); the rest is the thinner milk (hang kati). BLOOM THE CREAM: in a medium pot over medium heat, simmer the 100 ml coconut cream 3–4 minutes until it splits and the oil starts to separate visibly — this concentrates the coconut flavor and is the traditional Thai opening move; (If your coconut milk doesn't separate cleanly, skip this step and just start with everything in the pot.). INFUSE THE AROMATICS: add the galangal slices, lemongrass pieces, torn lime leaves, bruised chilies, garlic, and 80 g sliced shallots to the hot coconut cream; stir 1 minute until intensely aromatic; the kitchen should smell distinctly of Thai — bright citrus, peppery galangal, and sweet coconut. BUILD THE BROTH: pour in the remaining 300 ml coconut milk + 600 ml chicken stock + 2 tbsp nam prik pao (if using); bring to a gentle simmer (NEVER a hard boil — coconut milk separates ugly if boiled hard); simmer 8 minutes uncovered, so the aromatics infuse fully and the broth tastes deep and rounded. ADD THE CHICKEN: drop the 500 g sliced chicken into the simmering broth, stirring gently to separate the pieces; simmer 4–5 minutes until the chicken is just cooked through and white — overcooking turns it tough; add 200 g halved straw mushrooms and simmer 2 minutes more. SEASON: turn off the heat; stir in 4 tbsp fish sauce + 1 tbsp palm sugar; taste — the broth should be savoury, slightly sweet, mildly hot, and full of citrus aroma; add a splash more fish sauce or sugar if needed; off heat is critical here. LIME AT THE LAST MOMENT: stir in 60 ml fresh lime juice ONLY just before serving — boiling the lime juice turns it bitter and dull; ladle into deep bowls; top with fresh cilantro + sliced spring onions + a few extra slices of bruised chili for those who like more heat; serve hot with steamed jasmine rice on the side and lime wedges; tell guests: the galangal, lemongrass, and lime leaves are aromatics, not edible — fish them to the side of the bowl."}},{"id":175,"servings":6,"tipType":"meat","pairingsType":"latin","origin":{"en":"Cape Verde","ro":"Capul Verde"},"name":{"en":"Cachupa","ro":"Cachupa"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["400 g milho cachupa (white hominy corn, the cracked dried Cape Verdean variety) — soaked overnight in plenty of cold water (mandatory)","200 g dried red kidney beans — soaked overnight","200 g dried butter beans (lima beans) or chickpeas — soaked overnight (the mixture of legumes is the Cape Verdean signature)","500 g pork shoulder (cabidela), cut into 3 cm cubes","300 g salted pork ribs or pork belly (toucinho), cut into chunks — soak 1 hour in cold water to remove excess salt","200 g linguiça or chouriço portuguesa (Portuguese smoked sausage), cut into 1.5 cm slices","200 g morcela (Portuguese blood sausage) — optional, traditional","2 large yellow onions (~350 g), one finely diced for the refogado and one cut into wedges","6 garlic cloves, minced","2 medium ripe tomatoes (~250 g), peeled and grated, or 1 × 200 g can crushed tomatoes","1 tbsp tomato paste","2 bay leaves + 1 tsp ground cumin + 1 tsp sweet paprika + 0.5 tsp dried oregano + 1 tsp salt + 0.5 tsp black pepper","3 tbsp red palm oil OR olive oil (palm oil is more traditional in some islands)","500 g pumpkin or butternut squash, peeled and cut into 4 cm cubes","300 g sweet potato or yam, peeled and cut into 4 cm cubes","200 g savoy cabbage, cut into 4 cm wedges (added in the final stage)","2 L water (or pork stock) + 1 piri-piri or scotch bonnet chili (optional, for the islands' light heat)","To serve: chunks of fresh white bread, a few extra slices of grilled linguiça, hot piri-piri sauce, and the next-day pan-fried 'cachupa guisada' with eggs option mentioned"],"ro":["400 g milho cachupa (porumb hominy alb, varietatea crăpată uscată specifică Capului Verde) — înmuiat peste noapte în multă apă rece (obligatoriu)","200 g fasole roșie uscată — înmuiată peste noapte","200 g fasole untoasă uscată (lima) sau năut — înmuiată peste noapte (amestecul de leguminoase este semnătura capverdiană)","500 g spată de porc (cabidela), tăiată în cuburi de 3 cm","300 g coaste de porc sărate sau burtă de porc (toucinho), tăiate în bucăți — înmuiate 1 oră în apă rece pentru a îndepărta excesul de sare","200 g linguiça sau chouriço portuguesa (cârnat afumat portughez), tăiat în felii de 1.5 cm","200 g morcela (cârnat de sânge portughez) — opțional, tradițional","2 cepe galbene mari (~350 g), una tăiată mărunt pentru refogado și una tăiată în felii mari","6 căței de usturoi, tocați mărunt","2 roșii medii coapte (~250 g), decojite și răzuite, sau 1 cutie de 200 g de roșii zdrobite","1 lingură pastă de roșii","2 foi de dafin + 1 linguriță chimion măcinat + 1 linguriță boia dulce + 0.5 linguriță oregano uscat + 1 linguriță sare + 0.5 linguriță piper negru","3 linguri ulei roșu de palmier SAU ulei de măsline (uleiul de palmier este mai tradițional în unele insule)","500 g dovleac sau dovleac plăcintar, curățat și tăiat în cuburi de 4 cm","300 g cartof dulce sau ignamă, curățat și tăiat în cuburi de 4 cm","200 g varză de Milano, tăiată în felii mari de 4 cm (adăugată în etapa finală)","2 L apă (sau supă de porc) + 1 ardei iute piri-piri sau scotch bonnet (opțional, pentru iuțeala ușoară a insulelor)","Pentru servire: bucăți de pâine albă proaspătă, câteva felii suplimentare de linguiça la grătar, sos iute piri-piri și opțiunea 'cachupa guisada' a doua zi (prăjită în tigaie cu ouă)"]},"howIsMade":{"en":"SOAK OVERNIGHT: this is non-negotiable; the night before cooking, place 400 g hominy corn + 200 g kidney beans + 200 g butter beans/chickpeas each in separate bowls covered by 5 cm of cold water; soak 12 hours minimum; the next morning, drain and rinse; skipping the soak gives a corn that stays gritty after hours of cooking. PRE-COOK THE HOMINY: place the drained hominy in a large pot with 1.5 L fresh cold water + 1 bay leaf + 1 tsp salt; bring to a boil, then simmer covered 1 hour; the corn should be partially tender but still firm at the centre — it will continue cooking in the stew; drain, reserving 500 ml of the cooking liquid. PRE-COOK THE BEANS: in a second pot, place the drained kidney beans and butter beans together with fresh cold water to cover by 3 cm; bring to a boil, skim foam for 5 min, then simmer 45 min until al dente — they will finish in the stew; drain. THE REFOGADO: in a large heavy 8 L pot, heat 3 tbsp palm or olive oil over medium heat; add 200 g finely diced onion + 6 minced garlic and cook 8–10 minutes until soft and golden; stir in 1 tbsp tomato paste and cook 1 min until darkened; add 250 g grated tomato + 1 tsp paprika + 1 tsp cumin + 0.5 tsp oregano and cook 4–5 min until the mixture reduces and the oil separates on the surface. SEAR THE PORK: push the refogado to the side; raise the heat to medium-high and add the 500 g pork shoulder cubes in a single layer; sear 3 minutes per side until golden brown, then stir into the refogado; add the drained salted pork ribs/belly + 1 tsp salt + 0.5 tsp pepper + 1 remaining bay leaf + the optional piri-piri chili. BUILD THE STEW: add the partially-cooked hominy + the drained beans + 2 L water (or pork stock) + the 500 ml reserved corn-cooking liquid; bring to a gentle simmer. SLOW SIMMER: simmer uncovered, stirring every 20–30 minutes, for 2 hours; after 1 hour, add the 500 g pumpkin cubes + 300 g sweet potato cubes + the linguiça slices; after 1.5 hours, add the 200 g cabbage wedges + the onion wedges + the morcela slices (if using); the stew should reduce to a thick, porridge-like consistency where the corn, beans, vegetables, and meats are all tender; taste and adjust salt — the saltpork and sausages add a lot. REST AND SERVE: turn off the heat and let the cachupa rest 10 minutes — this is when it thickens to the perfect consistency; ladle generously into deep bowls with all the colors visible: yellow corn, red beans, orange pumpkin, green cabbage, golden sausage, and rich pork; serve with chunks of fresh white bread, hot piri-piri sauce on the table, and a glass of Cape Verdean grogue or beer; the leftovers next day are pan-fried with a fried egg on top as 'cachupa guisada' — considered even better than the first day."}},{"id":176,"servings":4,"tipType":"veg","pairingsType":"indian","origin":{"en":"India","ro":"India"},"name":{"en":"Pav Bhaji","ro":"Pav Bhaji"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["500 g floury potatoes, peeled and cut into 3 cm cubes","250 g cauliflower florets (about 1/2 small head)","100 g green peas (fresh or frozen)","100 g French beans, cut into 1 cm pieces","1 medium carrot (~100 g), diced","100 g unsalted butter (yes — that much, this is street-vendor butter quantities) — divided","2 large red onions (~300 g) — one finely diced for the bhaji, one finely diced raw for the garnish","1 large green bell pepper or capsicum (~150 g), finely diced","4 ripe tomatoes (~500 g), pureed in a blender","1 tbsp ginger-garlic paste (or 3 cm ginger + 4 garlic cloves, grated together)","2 tbsp pav bhaji masala (Everest or MDH brand) — the specific spice blend, do not substitute with garam masala","1 tsp Kashmiri red chili powder (for the iconic red color, mild heat)","0.5 tsp turmeric + 1.5 tsp salt + 0.5 tsp ground black pepper","1 lemon, cut into 4 wedges + chopped fresh coriander (cilantro), generously","8 small soft pav buns (Mumbai-style ladi pav, or substitute with brioche slider buns)","50 g unsalted butter for toasting the pav + extra red chili powder for sprinkling","To serve: extra raw red onion, fresh coriander, lemon wedges, 1 small green chili finely chopped (optional)"],"ro":["500 g cartofi făinoși, curățați și tăiați în cuburi de 3 cm","250 g buchețele de conopidă (aproximativ 1/2 căpățână mică)","100 g mazăre verde (proaspătă sau congelată)","100 g fasole verde franceză, tăiată în bucăți de 1 cm","1 morcov mediu (~100 g), tăiat cubulețe","100 g unt nesărat (da — atât de mult, acestea sunt cantitățile de unt ale vânzătorilor de stradă) — împărțit","2 cepe roșii mari (~300 g) — una tăiată mărunt pentru bhaji, una tăiată mărunt crudă pentru garnitură","1 ardei capia verde mare sau capsicum (~150 g), tăiat mărunt","4 roșii coapte (~500 g), pasate în blender","1 lingură pastă de ghimbir-usturoi (sau 3 cm ghimbir + 4 căței usturoi, răzuiți împreună)","2 linguri pav bhaji masala (marca Everest sau MDH) — amestecul specific de condimente, nu înlocuiți cu garam masala","1 linguriță pudră de chili roșu Kashmiri (pentru culoarea roșie iconică, iuțeală blândă)","0.5 linguriță turmeric + 1.5 linguriță sare + 0.5 linguriță piper negru măcinat","1 lămâie, tăiată în 4 sferturi + coriandru proaspăt (cilantro) tocat, generos","8 chifle pav mici și moi (ladi pav stil Mumbai, sau înlocuiți cu chifle brioche slider)","50 g unt nesărat pentru prăjirea pavului + suplimentar pudră de chili roșu pentru presărat","Pentru servire: ceapă roșie crudă suplimentară, coriandru proaspăt, sferturi de lămâie, 1 ardei iute verde mic tocat mărunt (opțional)"]},"howIsMade":{"en":"PRESSURE-COOK THE VEGETABLES: in a pressure cooker (or large pot) combine 500 g potato cubes + 250 g cauliflower + 100 g peas + 100 g French beans + 100 g diced carrot + 500 ml water + 1 tsp salt; pressure cook 3 whistles on high, then turn off and let the pressure release naturally (about 15 min); if using a regular pot, cover and simmer 25–30 minutes until everything is fork-tender; drain, RESERVING 250 ml of the cooking water. MASH THE VEGETABLES: with a potato masher, vigorously mash the boiled vegetables right in the pot until you have a coarse purée — some texture should remain, this is NOT a smooth soup; set aside. BLOOM THE AROMATICS: heat 50 g butter in a large heavy skillet or kadhai over medium heat until melted and foaming; add 150 g finely diced red onion and cook stirring often 5–6 minutes until soft and just turning golden at the edges. GINGER-GARLIC + BELL PEPPER: add 1 tbsp ginger-garlic paste and stir 1 minute until the raw smell disappears; add 150 g diced green bell pepper and cook 3–4 minutes until just softened but still bright green. SPICES BLOOM: add 2 tbsp pav bhaji masala + 1 tsp Kashmiri chili powder + 0.5 tsp turmeric; stir 30 seconds until the spices are intensely fragrant — do not burn, lower the heat slightly if needed. BUILD THE BHAJI: pour in the pureed tomatoes + 0.5 tsp ground pepper + 0.5 tsp salt; cook stirring often 6–8 minutes until the tomato has reduced and the butter starts to separate around the edges of the pan — this is the visual sign that the masala is ready; add the reserved 250 ml vegetable water + the mashed vegetables; stir vigorously to combine. SIMMER + MASH MORE: simmer the bhaji 10–12 minutes, stirring frequently and mashing more with a potato masher right in the pan; the bhaji should become thick, dark red, glossy, and intensely fragrant; adjust seasoning — Mumbai street vendors love it salty and spicy; stir in another 30 g butter and 1 tbsp chopped coriander; squeeze in juice of half a lemon. TOAST THE PAV AND SERVE: slice 8 pav buns horizontally without cutting all the way through (book-style); heat a wide skillet over medium heat; add 30 g butter + a pinch of pav bhaji masala + a pinch of Kashmiri chili powder, swirl; press the open pav buns into the hot butter and toast 30–60 seconds per side until golden and fragrant; plate immediately: a generous mound of hot bhaji topped with a knob of butter, chopped raw red onion, chopped coriander, a lemon wedge, and optional chopped green chili; serve with 2 toasted pav per person on the side; tear the pav, dip into the bhaji, squeeze the lemon over each bite — Mumbai street food at home."}},{"id":177,"servings":4,"tipType":"meat","pairingsType":"meat","origin":{"en":"Finland","ro":"Finlanda"},"name":{"en":"Karelian stew","ro":"Karjalanpaisti"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["400 g beef chuck, cubed 3 cm","400 g pork shoulder, cubed 3 cm","400 g lamb shoulder, cubed 3 cm (or reindeer in Lapland)","2 large yellow onions (~400 g), thickly sliced","4 medium carrots (~400 g), cut into 3 cm chunks","1 tsp whole black peppercorns","4 bay leaves","6 whole juniper berries (the Finnish signature, slightly piny — non-negotiable)","6 whole allspice berries","2 tsp salt","1 L cold water (or weak beef stock — traditional is water)","1 tbsp neutral oil OR 50 g butter for the optional searing step","To serve: 800 g boiled new potatoes with butter and dill, pickled cucumber, lingonberry jam (puolukkahillo), dark rye bread, and a glass of cold milk or beer"],"ro":["400 g pulpă de vită (chuck), tăiată în cuburi de 3 cm","400 g spată de porc, tăiată în cuburi de 3 cm","400 g spată de miel, tăiată în cuburi de 3 cm (sau ren în Laponia)","2 cepe galbene mari (~400 g), tăiate în felii groase","4 morcovi medii (~400 g), tăiați în bucăți de 3 cm","1 linguriță boabe întregi de piper negru","4 foi de dafin","6 boabe întregi de ienupăr (semnătura finlandeză, ușor rășinos — non-negociabil)","6 boabe întregi de ienibahar","2 lingurițe sare","1 L apă rece (sau supă slabă de vită — tradițional este apa)","1 lingură ulei neutru SAU 50 g unt pentru pasul opțional de rumenire","Pentru servire: 800 g cartofi noi fierți cu unt și mărar, castravete murat, gem de merișoare lingonberry (puolukkahillo), pâine neagră de secară și un pahar de lapte rece sau bere"]},"howIsMade":{"en":"PREHEAT THE OVEN to 125 °C — the very low slow oven is the SIGNATURE of Karjalanpaisti, the dish that defines its melting texture. TRIM AND CUBE: trim 400 g beef + 400 g pork + 400 g lamb of any sinew; cut into uniform 3 cm cubes — DO NOT cut smaller; this is a 5 h cook and larger cubes hold up; smaller pieces dissolve into shreds. CHOOSE YOUR STYLE — TRADITIONAL: skip browning; layer everything raw and let the oven do the work, as Karelian grandmothers have done for centuries; mODERN: heat 1 tbsp oil in a Dutch oven over high heat, brown the meat in 3 batches 2 min per side for added Maillard flavour, then lift out; both methods produce excellent results. LAYER THE POT: in a large Dutch oven or cast-iron casserole, build alternating layers in this order: beef on the bottom, sliced onion, pork, carrot chunks, lamb on top; distribute 4 bay leaves + 6 juniper berries + 6 allspice + 1 tsp peppercorns + 2 tsp salt between the layers — never just on top. ADD LIQUID: pour in 1 L cold water (or weak beef stock) so it comes halfway up the meat — NOT covering; the meats release their own juices during the long cook and the sauce concentrates naturally. SEAL AND SLOW-COOK: cover with a tight-fitting lid; transfer to the 125 °C oven for 4–5 hours — yes, five hours, that is the point; do NOT open the lid except once every 1.5 hours to check the liquid; if reducing too fast, add a splash of hot water; the meat is ready when a fork sinks in effortlessly. REST IN THE OVEN: turn off the oven and let the karjalanpaisti rest in the closed warm oven another 30 minutes — the flavours deepen and the meat relaxes into the sauce. SERVE: lift the tender meat into warm deep plates; spoon over the brothy concentrated juices; the juniper berries and allspice can stay in for the brave, or be fished out; serve with boiled new potatoes tossed in butter and dill, pickled cucumber on the side, a generous dollop of lingonberry jam (the sweet-tart counterpoint), slices of dark rye bread, and a glass of cold milk or beer — the traditional Finnish dinner accompaniment."}},{"id":178,"servings":6,"tipType":"meat","pairingsType":"french","origin":{"en":"France","ro":"Franța"},"name":{"en":"Boeuf Bourguignon","ro":"Boeuf Bourguignon"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["1.5 kg beef chuck or shin, cubed 4 cm (some marbling for richness)","200 g lardons (smoked pork belly cut 1 cm × 3 cm) OR 200 g thick-cut bacon diced","750 ml full-bodied Burgundy red wine (Pinot Noir) — DO NOT use cheap wine","200 ml beef stock","2 tbsp tomato paste","1 large onion (~250 g), finely diced for the marinade and braise","2 medium carrots (~250 g), cut into 2 cm chunks","4 garlic cloves, minced","30 g unsalted butter + 2 tbsp olive oil for searing","3 tbsp all-purpose flour","1 bouquet garni: 3 thyme sprigs + 2 bay leaves + 6 parsley stems tied with kitchen string","250 g pearl onions (silverskin), peeled","250 g cremini or button mushrooms, halved or quartered","30 g extra butter for the mushroom-and-pearl-onion garnish","1.5 tsp salt + 1 tsp freshly ground black pepper","2 tbsp Cognac OR brandy for optional flambé","Fresh flat-leaf parsley + baguette + boiled new potatoes or buttered egg noodles to serve"],"ro":["1.5 kg pulpă de vită (chuck) sau gambă, tăiată în cuburi de 4 cm (cu ceva marmurare pentru bogăție)","200 g lardoni (piept de porc afumat tăiat 1 cm × 3 cm) SAU 200 g bacon gros tăiat cubulețe","750 ml vin roșu Burgundia robust (Pinot Noir) — NU folosi vin ieftin","200 ml supă de vită","2 linguri pastă de roșii","1 ceapă mare (~250 g), tăiată mărunt pentru marinadă și pentru tocană","2 morcovi medii (~250 g), tăiați în bucăți de 2 cm","4 căței de usturoi, tocați mărunt","30 g unt nesărat + 2 linguri ulei de măsline pentru rumenire","3 linguri făină universală","1 buchet garni: 3 crenguțe cimbru + 2 foi de dafin + 6 cozi de pătrunjel legate cu sfoară de bucătărie","250 g ceapă perlată (silverskin), curățată","250 g ciuperci cremini sau champignon, tăiate în jumătăți sau sferturi","30 g unt suplimentar pentru garnitura de ciuperci și ceapă perlată","1.5 linguriță sare + 1 linguriță piper negru proaspăt măcinat","2 linguri Cognac SAU brandy pentru flambare opțională","Pătrunjel proaspăt cu frunza plată + baghetă + cartofi noi fierți sau tăiței cu unt pentru servire"]},"howIsMade":{"en":"Place 1.5 kg cubed beef in a non-reactive bowl with the 750 ml red Burgundy, 1 chopped onion, 1 chopped carrot, 4 garlic cloves, the bouquet garni and 1 tsp pepper, then cover and refrigerate for 12-24 hours; drain through a sieve while reserving the wine, and pat the beef very dry with paper towel so it sears rather than steams. In a heavy Dutch oven over medium heat, cook 200 g lardons for 6-8 minutes until crisp and golden and the fat is fully rendered, then lift them out with a slotted spoon and leave 2 tbsp of rendered fat behind in the pot. Raise the heat to high and add 1 tbsp olive oil plus 15 g butter, then sear the dried beef cubes in 3-4 uncrowded batches for 2-3 minutes per side (about 8 minutes per batch) until deeply browned on all sides; transfer each batch to a tray and leave the dark fond stuck to the pot as your flavour base. Reduce the heat to medium, add 250 g diced onion and 250 g carrot chunks and cook 5 minutes until starting to soften, then stir in 4 minced garlic cloves and 2 tbsp tomato paste and cook 1 minute; pour in 2 tbsp Cognac and ignite carefully (the flames die in 30 seconds), or skip the flambe and simply use the Cognac to deglaze. Sprinkle 3 tbsp flour over the vegetables and stir for 1 minute to cook out the raw taste, then pour in the reserved wine slowly while scraping the bottom to lift the fond, add 200 ml beef stock, the bouquet garni, 1.5 tsp salt and 1 tsp pepper, and return the beef and lardons to the pot so the liquid barely covers everything. Bring to a gentle simmer, cover with the lid slightly ajar and transfer to a 160 °C oven (or simmer on the lowest stovetop heat) for 2.5-3 hours, stirring every 45 minutes until the beef is fall-apart tender and the sauce has thickened to a glossy coats-the-spoon consistency; discard the bouquet garni. In a separate skillet, melt 15 g butter over medium heat, add 250 g peeled pearl onions with 1 tbsp water, 1 tsp sugar and a pinch of salt, cover and cook 15 minutes, then uncover and brown 5 minutes until glossy and golden; in the same skillet add another 15 g butter and 250 g mushrooms and saute 6-8 minutes in 2 batches until deeply golden brown, never crowding the pan. Fold the pearl onions and mushrooms into the braise and warm together 5 minutes, then taste and adjust the salt and let the braise rest 10 minutes off the heat so the flavours deepen; serve generous portions in deep plates over boiled new potatoes (or buttered egg noodles), scatter with chopped fresh flat-leaf parsley and offer crusty baguette to mop up the sauce -- it is always better the next day, and pairs perfectly with a bottle of the same Burgundy you cooked with."}},{"id":179,"servings":2,"tipType":"veg","pairingsType":"middle-eastern","origin":{"en":"Tunisia","ro":"Tunisia"},"name":{"en":"Chakchouka","ro":"Chakchouka"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["4 large eggs at room temperature","4 tbsp extra-virgin olive oil (Tunisian or Mediterranean)","1 medium yellow onion (~150 g), finely diced","2 mild red bell peppers (~300 g), seeded and cut into 1 cm dice","1 small red chili finely chopped OR 1 tsp Tunisian harissa paste (the more traditional choice)","4 garlic cloves, minced","1 tsp ground cumin (kamoun) — the warm spice base","1 tsp ground caraway (karwiya) — Tunisia's DEFINING warm spice, NOT the same as cumin despite looking similar; substitute fennel seed if unavailable","1 tsp sweet paprika","0.5 tsp ground coriander","400 g can crushed tomatoes (or 4 ripe tomatoes peeled and grated)","1 tbsp tomato paste for body","1 tsp salt + 0.5 tsp freshly ground black pepper + a pinch of sugar to balance acidity","60 g feta-style cheese (Tunisian or Bulgarian-style, crumbled, optional) + fresh flat-leaf parsley + cilantro + lemon wedges + fresh baguette or Tunisian khobz tabouna to serve"],"ro":["4 ouă mari la temperatura camerei","4 linguri ulei de măsline extravirgin (tunisian sau mediteranean)","1 ceapă galbenă medie (~150 g), tăiată mărunt","2 ardei graşi roşii blânzi (~300 g), curăţaţi de seminţe şi tăiaţi în cuburi de 1 cm","1 ardei iute roşu mic tocat mărunt SAU 1 linguriţă pastă de harissa tunisiană (alegerea mai tradiţională)","4 căţei de usturoi, tocaţi mărunt","1 linguriţă chimion măcinat (kamoun) — baza de mirodenii calde","1 linguriţă chimen măcinat (karwiya) — mirodenia caldă DEFINITORIE a Tunisiei, NU acelaşi lucru cu chimionul deşi arată asemănător; înlocuieşte cu sămânţă de fenicul dacă nu este disponibil","1 linguriţă boia dulce","0.5 linguriţă coriandru măcinat","400 g roşii zdrobite la cutie (sau 4 roşii coapte decojite şi rase)","1 lingură pastă de roşii pentru corp","1 linguriţă sare + 0.5 linguriţă piper negru proaspăt măcinat + un vârf de zahăr pentru echilibrul acidităţii","60 g brânză tip feta (tunisiană sau bulgărească, sfărâmată, opţional) + pătrunjel proaspăt cu frunza lată + coriandru + felii de lămâie + baghetă proaspătă sau khobz tabouna tunisian pentru servire"]},"howIsMade":{"en":"PREP THE AROMATICS: chakchouka cooks fast — mise-en-place is non-negotiable; dice 150 g onion + 300 g red bell peppers + 1 red chili; mince 4 garlic; measure the spice quartet — cumin + caraway + paprika + coriander — into a small bowl; the caraway is what makes this Tunisian and not Israeli or Levantine shakshuka. WARM THE OIL: heat 4 tbsp olive oil in a heavy 24 cm skillet (cast iron is ideal — earthenware tagine is the most traditional Tunisian) over medium heat until shimmering. SOFFRITTO: add 150 g diced onion with a pinch of salt and cook 6–8 min until very soft and translucent — NOT browned; tunisian chakchouka wants the sweetness of slowly-sweated onions, not caramelization. PEPPERS + CHILI + GARLIC: add 300 g diced red bell peppers + 1 chopped red chili (or 1 tsp harissa); cook 6–8 min until peppers are softened but still bright red; add 4 minced garlic and cook 1 min until fragrant. BLOOM THE SPICES: add the spice mix (1 tsp cumin + 1 tsp caraway + 1 tsp paprika + 0.5 tsp coriander) directly into the hot oil-and-vegetable base; stir 30 seconds until intensely aromatic — do not burn, or the dish turns bitter. BUILD THE SAUCE: stir in 1 tbsp tomato paste and cook 1 min; pour in 400 g crushed tomatoes + 1 tsp salt + 0.5 tsp pepper + a pinch of sugar; simmer 8–10 min, stirring occasionally, until the sauce has thickened — a spoon dragged through the surface should leave a clear trail that does not immediately fill back in. ADD EGGS: with the back of a spoon, make 4 wells in the simmering sauce; crack 1 egg into each well — keep yolks intact; sprinkle a pinch of salt over the whites and a twist of pepper over the yolks; cover the skillet with a lid and cook over medium-low heat 4–6 min, until the whites are just set but the yolks remain runny — peek through the lid; the whites should be opaque and the yolks still bright orange and trembling. FINISH AND SERVE: scatter 60 g crumbled feta + a generous handful of chopped parsley and cilantro over the top; bring the pan straight to the table — chakchouka is always communal, eaten from the skillet; each diner tears off a piece of fresh baguette or khobz tabouna and uses it to mop up the sauce and break into a yolk; squeeze a lemon wedge over your own portion; best within 10 minutes of cooking, while the yolks are still molten."}},{"id":180,"origin":{"en":"Japan","ro":"Japonia"},"name":{"en":"Okonomiyaki","ro":"Okonomiyaki"},"category":{"en":"Dinner","ro":"Cină"},"servings":4,"tipType":"def","pairingsType":"japanese","ingredients":{"en":["200g plain flour (or cake flour)","240ml cold dashi stock (or water + 1 tsp dashi powder)","2 large eggs","400g white cabbage, finely shredded","200g thinly sliced pork belly (buta bara), cut into 5 cm pieces","2 tbsp tenkasu (tempura scraps, optional)","½ tsp baking powder","4 tbsp Japanese mayonnaise (Kewpie)","4 tbsp okonomiyaki sauce (e.g. Otafuku brand)","1 tsp Worcestershire sauce","katsuobushi (dried bonito flakes) to serve","aonori (powdered seaweed) to serve"],"ro":["200g făină albă simplă (sau făină pentru prăjituri)","240ml supă dashi (rece; sau apă + 1 linguriță pudră dashi)","2 ouă mari","400g varză albă, tăiată fin","200g burta de porc feliată subțire (buta bara), tăiată în bucăți de 5 cm","2 linguri tenkasu (firimituri de tempura, opțional)","½ linguriță praf de copt","4 linguri maioneză Kewpie (japoneză)","4 linguri sos okonomiyaki (ex. Otafuku)","1 linguriță sos Worcestershire","katsuobushi (fulgi de ton uscat), pentru servire","aonori (alge marine pudră), pentru servire"]},"howIsMade":{"en":"In a large bowl whisk together flour, baking powder, eggs, and cold dashi until just combined — do not overmix. Fold in shredded cabbage and tenkasu with a spatula; the batter should be thick and mounded with cabbage. Heat a non-stick pan over medium heat, brush with a thin layer of oil. Pour batter into the pan and shape into a disc about 2 cm thick. Lay pork belly slices over the entire top surface. Cook 5–6 minutes on medium-low until the edges look set and the underside is golden-brown. Flip carefully using two spatulas, pressing lightly; cook another 5–6 minutes until pork is crisp and batter is cooked through. Brush the pork side with okonomiyaki sauce, drizzle Kewpie in a zigzag, scatter katsuobushi and aonori. Serve immediately from the pan."}},{"id":181,"servings":2,"tipType":"meat","timeMins":{"total":780,"active":120},"pairingsType":"japanese","origin":{"en":"Japan","ro":"Japonia"},"name":{"en":"Tonkotsu Ramen","ro":"Ramen Tonkotsu"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["1.2kg pork marrow bones, blanched","300g fresh thin ramen noodles","3 tbsp dark soy sauce (for tare)","2 tbsp mirin","200g chashu pork belly, sliced 1cm thick","2 soft-boiled ramen eggs, halved","80g bamboo shoots (menma), drained","2 sheets nori, halved","2 spring onions, thinly sliced","4 cloves garlic, crushed","30g fresh ginger, peeled and sliced","1 tsp toasted sesame oil"],"ro":["1,2 kg oase de porc (măduvă), opărite","300g tăiței ramen proaspeți subțiri","3 linguri sos de soia închis (pentru tare)","2 linguri mirin","200g burtă de porc chashu, feliată la 1 cm grosime","2 ouă ramen fierte moale, tăiate în jumătate","80g lăstari de bambus (menma), scurși","2 foi alge nori, tăiate în jumătate","2 cepe verzi, feliate subțire","4 căței usturoi, zdrobiți","30g ghimbir proaspăt, curățat și feliat","1 linguriță ulei de susan prăjit"]},"howIsMade":{"en":"Blanch pork bones in boiling water for 10 minutes, drain and rinse under cold water. Transfer to a large pot with 3L cold water, bring to a rolling boil and hold it there — not a simmer — for 10 to 12 hours, topping up with water as needed; the hard boil breaks down collagen and turns the broth white. Roll pork belly tightly, tie with kitchen string, sear all sides in a dry pan, then braise in 3 tbsp soy sauce, 2 tbsp mirin, 1 tbsp sake and 100ml water on the lowest heat for 90 minutes; rest 20 minutes, slice 1cm thick. Make tare: 4 tbsp soy sauce + 2 tbsp mirin, simmer 3 minutes, cool. Cook noodles per packet, drain. Spoon 2 tbsp tare into each bowl, ladle 400ml hot broth, then top with chashu slices, halved egg, bamboo shoots, nori and spring onion. Finish with sesame oil."}},{"id":182,"servings":2,"tipType":"meat","timeMins":{"total":360,"active":90},"pairingsType":"japanese","origin":{"en":"Japan","ro":"Japonia"},"name":{"en":"Shoyu Ramen","ro":"Ramen Shoyu"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["1.5L chicken bone stock","2 tbsp soy sauce","1 tbsp mirin","1 tbsp sake","400g pork belly, rolled and tied with kitchen string","4 large eggs","300g fresh ramen noodles","100g bamboo shoots (menma), rinsed","4 sheets nori","3 spring onions, thinly sliced","4 slices narutomaki fish cake","1 tsp sesame oil"],"ro":["1,5 L supă de oase de pui","2 linguri sos de soia","1 lingură mirin","1 lingură sake","300g burtă de porc, rulată și legată","4 ouă mari","300g tăiței ramen proaspeți","100g lăstari de bambus (menma), clătiți","4 foi alge nori","3 cepe verzi, feliate subțire","4 felii pastă de pește narutomaki","1 linguriță ulei de susan"]},"howIsMade":{"en":"Simmer chicken bone stock with a 5cm piece of ginger, 3 garlic cloves and 2 spring onions for 3–4 hours, strain and discard solids. Mix soy sauce, mirin and sake in a small pan, simmer 5 minutes to cook off the alcohol — this is the shoyu tare. Roll pork belly tightly, tie with kitchen string, sear on all sides in a hot pan, then braise in 3 tbsp soy sauce, 2 tbsp mirin, 1 tbsp sake and 100ml water on low heat for 1.5 hours; rest 15 minutes before slicing into 1cm rounds. Soft-boil eggs exactly 6.5 minutes, cool in cold water, peel and submerge in the remaining chashu braising liquid for at least 4 hours. Cook noodles per packet, drain; ladle hot broth into bowls (2 tbsp shoyu tare per bowl), add noodles and top with sliced chashu, halved egg, bamboo shoots, nori, spring onions, narutomaki and a drizzle of sesame oil."}},{"id":183,"servings":2,"tipType":"def","pairingsType":"japanese","origin":{"en":"Japan","ro":"Japonia"},"name":{"en":"Miso Ramen","ro":"Ramen Miso"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["1.5L chicken or pork bone broth","3 tbsp red or white miso paste","300g fresh ramen noodles","150g ground pork","80g canned corn kernels, drained","1 tbsp unsalted butter","60g bamboo shoots, drained and sliced","2 soft-boiled ramen eggs, halved","2 sheets nori, halved","2 spring onions, sliced","1 tsp toasted sesame seeds","80g fresh bean sprouts, blanched"],"ro":["1,5L supă de oase de pui sau porc","3 linguri pastă miso roșu sau alb","300g tăiței ramen proaspeți","150g carne tocată de porc","80g porumb din conservă, scurs","1 lingură unt nesărat","60g lăstari de bambus, scurși și feliați","2 ouă fierte moale, marinate, tăiate în jumătate","2 foi alge nori, tăiate în jumătate","2 cepe verzi, feliate","1 linguriță semințe de susan prăjit","80g muguri de fasole proaspeți, opăriți"]},"howIsMade":{"en":"Sauté garlic and ground pork in a wok over high heat, breaking up the meat as it cooks, until no pink remains. Add miso paste and stir-fry 60 seconds until it darkens slightly. Pour in hot broth and bring to a low simmer — do not boil hard once miso is in or it loses its fermented edge. Add butter and stir until melted. Cook noodles per packet, drain. Divide noodles between two bowls, ladle miso broth over. Top with corn, bean sprouts, halved ramen egg, bamboo shoots, nori and spring onion. Scatter sesame seeds last."}},{"id":184,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":480,"prot":22,"carb":38,"fat":26,"fib":3},"origin":{"en":"Japan","ro":"Japonia"},"name":{"en":"Tempura","ro":"Tempura"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["400 g large prawns (8–12 head-on, peeled but tails on), deveined and patted bone-dry","1 small Japanese sweet potato (~200 g), peeled and cut into 5 mm rounds","200 g kabocha squash, cut into 5 mm half-moons (skin left on)","1 Japanese eggplant, cut on the bias into 1 cm slices","6 fresh shiitake mushrooms, stems trimmed, caps scored with an X","100 g shishito or thin green peppers, each pricked with a fork so they don't burst","For the batter (mix LAST, just before frying): 1 large egg, 250 ml ice-cold sparkling water, 150 g plain (cake) flour, sifted","30 g extra plain flour for dusting the pieces before dipping","1.5 L neutral oil for deep-frying (rice bran or vegetable)","For the tentsuyu dipping sauce: 200 ml dashi, 60 ml soy sauce, 60 ml mirin","30 g daikon, finely grated and lightly squeezed","10 g fresh ginger, finely grated","Fine sea salt and lemon wedges, to serve"],"ro":["400 g creveți mari (8–12 bucăți cu cap, decojiți dar cu coadă), curățați de vinișor și șterși bine de umiditate","1 cartof dulce japonez mic (~200 g), curățat și tăiat rondele de 5 mm","200 g dovleac kabocha, tăiat semilune de 5 mm (cu coajă)","1 vânătă japoneză, tăiată oblic în felii de 1 cm","6 ciuperci shiitake proaspete, fără picioare, capul crestat în X","100 g ardei shishito sau ardei verzi subțiri, fiecare înțepat cu furculița ca să nu plesnească","Pentru aluat (se amestecă LA FINAL, chiar înainte de prăjit): 1 ou mare, 250 ml apă minerală foarte rece, 150 g făină simplă cernută","30 g făină simplă suplimentară pentru pudrat bucățile înainte de înmuierea în aluat","1.5 L ulei neutru pentru prăjit (de orez sau vegetal)","Pentru sosul tentsuyu: 200 ml dashi, 60 ml sos de soia, 60 ml mirin","30 g daikon, ras fin și stors ușor","10 g ghimbir proaspăt, ras fin","Sare fină de mare și felii de lămâie, pentru servit"]},"howIsMade":{"en":"Pat the prawns and vegetables completely dry, then make three shallow cuts on the underside of each prawn and press gently along the spine so they fry straight rather than curling.\n\nFor the tentsuyu, bring the dashi, soy sauce and mirin briefly to a simmer to cook off the alcohol, then divide between small dipping bowls and set the grated daikon and ginger alongside.\n\nHeat the oil in a heavy pot to 175°C, measured with a probe thermometer.\n\nJust before frying, beat the egg into the ice-cold sparkling water in a chilled bowl, tip in the sifted flour all at once and stir only five to eight strokes — the batter should still show streaks of dry flour.\n\nDust each piece lightly with the extra flour, dip into the batter, and slip into the oil four or five at a time; prawns and shiitake take about 90 seconds, eggplant and kabocha 2 minutes, sweet potato 3 minutes, shishito a minute, and the crust should stay pale ivory.\n\nLift onto a wire rack set over paper and serve straight away, with the tentsuyu, daikon and ginger to stir in, or the vegetables with a pinch of fine salt and a squeeze of lemon."}},{"id":185,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":280,"prot":7,"carb":52,"fat":4,"fib":2},"origin":{"en":"Japan","ro":"Japonia"},"name":{"en":"Onigiri","ro":"Onigiri"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["500 g Japanese short-grain rice (Koshihikari or sushi rice)","600 ml fresh cold water for cooking (rice to water ratio ~1:1.1)","For the tezu (finger water): 200 ml warm water + 1.5 tsp fine sea salt","4 sheets toasted nori, cut into strips about 3 cm wide × the length of the sheet","Filling option 1 — tuna mayo: 80 g canned tuna (drained), 1.5 tbsp Japanese mayonnaise, ½ tsp soy sauce","Filling option 2 — umeboshi: 60 g pitted salted plums, lightly mashed with a fork","Filling option 3 — shiozake (grilled salted salmon): 100 g salmon fillet grilled and flaked, with the skin removed","Filling option 4 — okaka: 8 g bonito flakes mixed with 1 tsp soy sauce","For plain onigiri: 2 tbsp furikake (rice seasoning), to coat the outside","Optional: a few sesame seeds for the surface of plain ones"],"ro":["500 g orez japonez cu bobul scurt (Koshihikari sau orez pentru sushi)","600 ml apă rece proaspătă pentru fiert (raport orez:apă ~1:1.1)","Pentru tezu (apa de mâini): 200 ml apă caldă + 1.5 linguriță sare fină de mare","4 foi de nori prăjit, tăiate fâșii de ~3 cm lățime × lungimea foii","Umplutură opțiunea 1 — ton cu maioneză: 80 g ton la conservă (scurs), 1.5 lingură maioneză japoneză, ½ linguriță sos de soia","Umplutură opțiunea 2 — umeboshi: 60 g prune sărate fără sâmburi, ușor strivite cu furculița","Umplutură opțiunea 3 — shiozake (somon sărat la grătar): 100 g file de somon făcut la grătar, fără piele, fărâmițat","Umplutură opțiunea 4 — okaka: 8 g fulgi de bonito amestecați cu 1 linguriță sos de soia","Pentru onigiri simplu: 2 linguri furikake (condiment pentru orez), pentru exterior","Opțional: câteva semințe de susan pentru exterior"]},"howIsMade":{"en":"Rinse the rice in cold water four or five times until the water runs almost clear, drain in a strainer for 20 minutes, then cook with the 600 ml of fresh water in a heavy pot or rice cooker; once cooked, rest off the heat with the lid on for 10 minutes.\n\nWhile the rice rests, mash the umeboshi with a fork, mix the tuna with the Japanese mayonnaise into a creamy paste, and flake the grilled salmon — each onigiri needs only about a tablespoon of filling.\n\nDissolve the salt in the warm water to make the tezu; this is the finger water that keeps the rice from sticking to your palms and lightly salts the outside.\n\nTip the hot rice onto a wide tray, fluff gently with a wooden paddle and let it cool until just warm enough to handle.\n\nWet your palms in the tezu, take about 100 g of rice in your palm, press a hollow in the centre, drop in a tablespoon of filling and gather the rice around it; cup your hand and press into a triangle with three flat faces, firm but not crushed.\n\nWrap a strip of nori around the base of each triangle just before eating so the seaweed stays crisp; for plain onigiri, roll the outside in furikake instead. Eat at room temperature within 4 hours."}},{"id":186,"servings":4,"tipType":"def","pairingsType":"japanese","nutrition":{"cal":360,"prot":36,"carb":8,"fat":18,"fib":1},"origin":{"en":"Japan","ro":"Japonia"},"name":{"en":"Yakitori","ro":"Yakitori"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["600 g boneless, skin-on chicken thighs, cut into 2.5 cm cubes","6 fat spring onions (or 2 negi), white and pale green parts cut into 3 cm pieces (~150 g total)","16 short bamboo skewers (15 cm), soaked in cold water for 30 minutes","For the tare: 120 ml dark soy sauce, 120 ml mirin, 60 ml sake, 30 g light brown sugar","Fine sea salt for the shio skewers","1 tsp neutral oil for the grate","Shichimi togarashi, to serve","Lemon wedges, to serve"],"ro":["600 g pulpe de pui dezosate cu piele, tăiate cuburi de 2.5 cm","6 cepe verzi mari (sau 2 negi), partea albă și verde-deschis tăiată bucățele de 3 cm (~150 g)","16 frigărui scurte de bambus (15 cm), înmuiate în apă rece 30 de minute","Pentru tare: 120 ml sos de soia închis, 120 ml mirin, 60 ml sake, 30 g zahăr brun deschis","Sare fină de mare pentru frigăruile shio","1 linguriță ulei neutru pentru grătar","Shichimi togarashi, pentru servit","Felii de lămâie, pentru servit"]},"howIsMade":{"en":"Cut the chicken thigh into 2.5 cm cubes and the white parts of the spring onions into 3 cm pieces, then soak the bamboo skewers in cold water for 30 minutes so they don't burn on the grill.\n\nFor the tare, simmer the soy sauce, mirin, sake and brown sugar in a small pan for about 10 minutes until lightly syrupy, then let it cool to room temperature.\n\nThread the skewers in two styles: negima alternates chicken, scallion, chicken, scallion, chicken; momo is just chicken cubes packed close together but not squashed.\n\nHeat a charcoal grill or a heavy grill pan over high heat and lightly oil the grate.\n\nLay the skewers down with the skin or fattiest side first and grill for 3–4 minutes until deep golden, then flip and cook another 2–3 minutes.\n\nFor tare skewers, dip in the cooled sauce, return to the grill for 30 seconds to glaze, then dip and glaze once more; season the shio skewers with a pinch of salt straight off the heat. Serve at once with shichimi togarashi and lemon."}},{"id":187,"servings":4,"tipType":"def","pairingsType":"mexican","nutrition":{"cal":520,"prot":38,"carb":22,"fat":28,"fib":6},"origin":{"en":"Mexico","ro":"Mexic"},"name":{"en":"Mole Poblano","ro":"Mole Poblano"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["80 g mixed dried chiles — 3 ancho + 3 mulato + 2 pasilla — stemmed and seeded","1 chipotle chile in adobo, plus 1 tbsp of its sauce","100 g blanched almonds and 80 g raw peanuts","30 g raw sesame seeds (plus extra to garnish) and 60 g raisins","2 large ripe tomatoes, halved; 1 small white onion, quartered; 3 garlic cloves, unpeeled","1 cinnamon stick, 2 cloves, 1 star anise and 6 black peppercorns","2 corn tortillas, torn into pieces — the traditional thickener","60 g Mexican chocolate, broken up (or 50 g dark chocolate + 1 tsp cinnamon + 1 tbsp light brown sugar)","1.2 L unsalted chicken stock, kept warm","3 tbsp lard (manteca) or neutral oil","4 bone-in chicken thighs, poached in salted water for 25 minutes and patted dry","1 tsp fine sea salt and a small pinch of sugar","To serve: cooked white rice, warm corn tortillas, fresh coriander leaves"],"ro":["80 g de ardei iuți uscați amestecați — 3 ancho + 3 mulato + 2 pasilla — fără codiță și seminţe","1 ardei chipotle în sos adobo, plus 1 lingură din sosul lui","100 g de migdale blanşate și 80 g de arahide crude","30 g de seminţe de susan crude (plus în plus pentru garnitură) și 60 g de stafide","2 roșii mari coapte, tăiate jumătăți; 1 ceapă albă mică, tăiată sferturi; 3 căţei de usturoi, necurăţaţi","1 baton de scorţișoară, 2 cuișoare, 1 stea de anason și 6 boabe de piper negru","2 tortilla de porumb, rupte în bucăţi — îngroșătorul tradiţional","60 g de ciocolată mexicană, fărâmiţată (sau 50 g de ciocolată neagră + 1 linguriţă de scorţișoară + 1 lingură de zahăr brun deschis)","1.2 L de supă de pui nesărată, ţinută caldă","3 linguri de untură (manteca) sau ulei neutru","4 pulpe de pui cu os, fierte în apă sărată 25 de minute și șterse","1 linguriţă de sare fină de mare și un vârf mic de zahăr","Pentru servit: orez alb fiert, tortilla de porumb calde, frunze de coriandru proaspăt"]},"howIsMade":{"en":"Toast the dried chiles in a dry heavy pan over medium heat for about 30 seconds per side until fragrant, then transfer to a bowl, cover with hot water and soak for 20 minutes.\n\nIn the same pan, toast the almonds, peanuts, sesame seeds, raisins and whole spices in small batches until just golden — about 2 minutes each — and set aside.\n\nChar the tomato halves, onion quarters and unpeeled garlic directly over a flame or under a hot broiler until blackened in patches, then peel the garlic once cool enough to handle.\n\nDrain the chiles (keeping the soaking water) and blend them with the charred vegetables, chipotle and its sauce, toasted nuts and seeds, raisins, spices and torn tortillas, adding about 500 ml of warm chicken stock to make a smooth dark paste.\n\nHeat the lard in a heavy pot over medium-high heat, pour in the paste and stir constantly for 10–15 minutes; the mole will darken, thicken and turn glossy as the flavours fry together.\n\nStir in the remaining 700 ml of chicken stock and the broken chocolate, then simmer gently for 30–40 minutes, stirring often, until the sauce coats the back of a spoon; season with the salt and a small pinch of sugar.\n\nSlide the poached chicken thighs into the mole and simmer 10 minutes more so they take on the sauce.\n\nServe the chicken in shallow bowls, ladle generous mole over the top, and finish with the reserved sesame seeds, coriander leaves, white rice and warm corn tortillas on the side."}},{"id":188,"servings":4,"tipType":"def","pairingsType":"mexican","nutrition":{"cal":480,"prot":18,"carb":38,"fat":28,"fib":6},"origin":{"en":"Mexico","ro":"Mexic"},"name":{"en":"Chilaquiles","ro":"Chilaquiles"},"category":{"en":"Breakfast","ro":"Mic dejun"},"ingredients":{"en":["200 g day-old corn tortillas, cut into eighths (or store-bought totopos)","500 ml neutral oil for frying (or 4 tbsp for shallow-frying)","For the salsa roja: 6 ripe tomatoes (~600 g), 2 guajillo chiles + 1 chile de árbol (stemmed and seeded), 1 garlic clove, ½ small white onion","1 tsp fine sea salt and 1 tbsp neutral oil for the salsa","4 large eggs, fried sunny-side-up (optional but classic)","100 ml Mexican crema (or sour cream thinned with milk)","80 g queso fresco, crumbled (or mild feta)","½ small red onion, very thinly sliced","A small handful of fresh coriander, leaves picked","1 ripe avocado, sliced just before serving","Pickled jalapeños, to taste"],"ro":["200 g tortilla de porumb de o zi, tăiate în opt (sau totopos cumpărate)","500 ml ulei neutru pentru prăjit (sau 4 linguri pentru prăjit superficial)","Pentru salsa roja: 6 roșii coapte (~600 g), 2 ardei guajillo + 1 ardei de árbol (fără codiță și semințe), 1 cățel de usturoi, ½ ceapă albă mică","1 linguriță sare fină de mare și 1 lingură ulei neutru pentru salsa","4 ouă mari, ochiuri (opțional dar tradițional)","100 ml crema mexicană (sau smântână subțiată cu lapte)","80 g queso fresco, sfărâmat (sau feta blândă)","½ ceapă roșie mică, tăiată felii foarte subțiri","Un mic mănunchi de coriandru proaspăt, doar frunzele","1 avocado copt, feliat chiar înainte de servit","Jalapeños murați, după gust"]},"howIsMade":{"en":"Cut the day-old tortillas into eighths and either deep-fry them at 175°C until golden and crisp, about 90 seconds per batch, or shallow-fry in 4 tablespoons of oil; drain on a rack and salt lightly while still warm.\n\nFor the salsa, toast the guajillo and árbol chiles in a dry pan for 20 seconds per side until fragrant, then soak in hot water for 10 minutes; meanwhile, char the tomatoes, garlic and onion under a hot broiler or directly over a flame until blackened in patches.\n\nDrain the chiles and blend with the charred vegetables, 1 teaspoon of salt and a splash of the chile-soaking water until smooth.\n\nHeat 1 tablespoon of oil in a wide pan, pour in the salsa and simmer for about 5 minutes, stirring, until it deepens in colour and looks glossy.\n\nTip in the crisp tortillas and gently fold them through the salsa over medium heat for a minute or two — they should soak up sauce while keeping some bite.\n\nPlate at once, top with the fried eggs if using, drizzle with crema, and scatter queso fresco, sliced red onion, coriander, avocado and pickled jalapeños over the top."}},{"id":189,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":530,"prot":9,"carb":70,"fat":24,"fib":1},"origin":{"en":"Mexico","ro":"Mexic"},"name":{"en":"Tres Leches Cake","ro":"Tort Tres Leches"},"category":{"en":"Dessert","ro":"Desert"},"ingredients":{"en":["5 large eggs, separated, at room temperature","200 g caster sugar, plus 30 g for the whipped cream","200 g plain flour and 1 tsp baking powder, sifted together","1 tsp vanilla extract for the sponge, plus ½ tsp for the cream","1 can (397 g) sweetened condensed milk","1 can (340 g) evaporated milk","200 ml whole milk and 50 ml heavy cream (the three-milk soak)","250 ml cold heavy cream for whipping, plus ground cinnamon for dusting"],"ro":["5 ouă mari, separate, la temperatura camerei","200 g zahăr tos, plus 30 g pentru frișcă","200 g făină albă și 1 linguriță praf de copt, cernute împreună","1 linguriță esență de vanilie pentru blat, plus ½ linguriță pentru frișcă","1 cutie (397 g) lapte condensat îndulcit","1 cutie (340 g) lapte evaporat","200 ml lapte integral și 50 ml smântână pentru frișcă (amestec pentru îmbibare)","250 ml smântână rece pentru frișcă (35% grăsime), plus scorțișoară măcinată pentru pudrat"]},"howIsMade":{"en":"Heat the oven to 175°C and butter and flour a 23×33 cm baking dish, then whisk the whites with a pinch of salt to soft peaks, beating in 100 g of the sugar a spoonful at a time until glossy and stiff.\n\nWhip the yolks with the remaining 100 g sugar and the vanilla for 3–4 minutes until pale and tripled, sift the flour and baking powder over them and fold in gently, then fold in the meringue in three additions, keeping as much air as you can.\n\nPour into the dish, level the top and bake 25–30 minutes until deep golden and springy at the centre, then cool in the dish for at least 30 minutes.\n\nWhisk the three milks together in a jug, pierce the cooled cake all over to the base with a thin skewer and pour the mixture across the surface in three or four slow passes — it looks like too much liquid, but the sponge drinks every drop; cover and refrigerate at least 4 hours, ideally overnight.\n\nJust before serving, whip the cold cream with the 30 g sugar and the remaining vanilla to soft peaks, spread it over the chilled cake and dust generously with ground cinnamon."}},{"id":190,"servings":6,"tipType":"fish","pairingsType":"french","nutrition":{"cal":480,"prot":50,"carb":30,"fat":18,"fib":4},"origin":{"en":"France","ro":"Franța"},"name":{"en":"Bouillabaisse","ro":"Bouillabaisse"},"category":{"en":"Fish","ro":"Pește"},"ingredients":{"en":["800 g small Mediterranean rockfish (rascasse, weever, wrasse — for the broth), gutted","1.2 kg firm Mediterranean fish in chunks (rascasse, monkfish, John Dory, conger, gurnard — at least four species), skin on, scaled","1 large onion, 2 leeks (white parts only), 1 fennel bulb, 4 ripe tomatoes, 6 garlic cloves","Bouquet garni: thyme, bay, parsley stalks, a strip of dried orange peel, a teaspoon of fennel seeds","1 g saffron threads (a generous pinch), 2 tbsp pastis (Pernod) stirred in at the end","100 ml olive oil, 1 tsp salt, freshly ground pepper","2 L water (or light fish fumet)","12–15 slices of toasted day-old baguette and rouille (3 garlic cloves, ½ tsp saffron, ¼ tsp cayenne, 1 egg yolk, 200 ml olive oil, salt, a small piece of bread soaked in the broth)"],"ro":["800 g pești mici mediteraneeni de stâncă (rascassa, năsărel, vrana — pentru fond), eviscerați","1,2 kg pește mediteranean ferm tăiat bucăți (rascassa, lotă, Saint-Pierre, congru, grondin — minim patru specii), cu piele, scuamat","1 ceapă mare, 2 praz (doar partea albă), 1 bulb de fenicul, 4 roșii coapte, 6 căței de usturoi","Buchet garni: cimbru, foi de dafin, codițe de pătrunjel, coajă uscată de portocală, o linguriță de semințe de fenicul","1 g șofran (un vârf bun), 2 linguri de pastis (Pernod) adăugat la final","100 ml ulei de măsline, 1 linguriță sare, piper proaspăt măcinat","2 l apă (sau fumet uşor de pește)","12–15 felii de baghetă uscată prăjită și rouille (3 căței usturoi, ½ linguriță șofran, ¼ linguriță cayenne, 1 gălbenuș, 200 ml ulei de măsline, sare, o bucată de pâine înmuiată în fond)"]},"howIsMade":{"en":"Scale, gut and rinse all the fish — cut the larger ones into 3 cm chunks and keep the heads and bones for the broth, while the small rockfish go whole into the pot.\n\nIn a large heavy pot, heat 4 tablespoons of olive oil over medium heat and sweat the chopped onion, leeks and fennel without colour for about 10 minutes, then add the chopped tomatoes and 5 garlic cloves and cook another 5 minutes to a pulp.\n\nTip in the small fish and the heads and bones of the larger ones, cover with the 2 L of water, drop in the bouquet garni (thyme, bay, parsley, orange peel, fennel seeds) and simmer hard for 30–40 minutes until the small fish completely break down, then pass everything through a coarse sieve or food mill, pressing hard to extract every drop — bones, herbs and pulp discarded — bring the strained broth back to a rolling boil, taste for salt and stir in the saffron.\n\nSlip the firm fish (monkfish, conger) into the broth first and poach 5–6 minutes, then add the more delicate ones (rascasse, John Dory) for another 3–4 — they should be just opaque, never falling apart — and off the heat, swirl in the pastis.\n\nFor the rouille, pound the last garlic clove with the salt and saffron in a mortar, work in the bread (dipped in broth and squeezed), then the yolk, then olive oil in a thin stream, whisking constantly until thick like mayonnaise, then serve in two courses: the broth first, ladled over toasted baguette with a spoonful of rouille on top; the fish after, on a separate plate, with more rouille alongside."}},{"id":191,"servings":4,"tipType":"meat","pairingsType":"french","nutrition":{"cal":650,"prot":30,"carb":40,"fat":38,"fib":2},"origin":{"en":"France","ro":"Franța"},"name":{"en":"Croque Monsieur","ro":"Croque Monsieur"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["8 thick slices of pain de mie (soft white sandwich bread), one day old","80 g unsalted butter, softened, plus 30 g for the béchamel","200 g Gruyère or Comté, finely grated","4 slices of jambon de Paris (~120 g total)","2 tsp Dijon mustard","30 g plain flour and 300 ml whole milk (for the béchamel)","Fine sea salt, white pepper, a grating of nutmeg"],"ro":["8 felii groase de pain de mie (pâine albă fină de sandviș), o zi vechi","80 g unt nesărat, înmuiat, plus 30 g pentru béchamel","200 g Gruyère sau Comté, ras fin","4 felii de jambon de Paris (~120 g în total)","2 lingurițe muștar Dijon","30 g făină albă și 300 ml lapte integral (pentru béchamel)","Sare fină, piper alb, un sfert de nucușoară rasă"]},"howIsMade":{"en":"Melt the 30 g béchamel butter in a small saucepan over medium heat, whisk in the flour and cook 1–2 minutes without colouring, then pour the warm milk in gradually while whisking constantly and simmer gently 4–5 minutes, stirring often, until thick enough to hold a peak on the spoon — season with salt, white pepper and nutmeg and keep warm.\n\nPreheat the broiler (top grill) to high, butter both sides of every bread slice with the softened butter, then thinly spread Dijon on the inner face of one slice per sandwich.\n\nLay 4 buttered slices on a lined tray, top each with a thin layer of grated Gruyère (hold ~60 g back for the top), a slice of ham and another thin layer of cheese, then close with the remaining 4 slices, mustard side in, and press lightly.\n\nSpoon 2 heaped tablespoons of béchamel over each sandwich right to the edges so the bread is fully covered and the sauce runs a little down the sides, scatter the reserved Gruyère on top and slide the tray under the hot broiler for 4–6 minutes, watching closely, until the béchamel is bubbling and deeply browned in patches and the cheese is molten — the bread crisps from below from the butter already gripped to its underside.\n\nLift out, rest 30 seconds — the cheese would stick to you otherwise — and cut on the diagonal; for a croque madame, fry an egg in a little butter while the sandwiches are under the broiler and slip it on top just before serving."}},{"id":192,"servings":4,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":420,"prot":13,"carb":60,"fat":14,"fib":1},"origin":{"en":"France","ro":"Franța"},"name":{"en":"Crêpes","ro":"Crêpes"},"category":{"en":"Dessert","ro":"Desert"},"ingredients":{"en":["250 g plain flour (T45 or T55), sifted","4 large eggs, at room temperature","500 ml whole milk (or 350 ml milk + 150 ml water for lighter crêpes)","50 g unsalted butter, melted until it browns to beurre noisette","30 g sugar and a good pinch of fine salt","1 tbsp dark rum or orange-flower water (or 1 tsp vanilla extract)","Extra butter for the pan (~30 g, kept on a brush)","To serve: caster sugar, lemon wedges, optionally jam, Nutella or sliced banana"],"ro":["250 g făină albă (T45 sau T55), cernută","4 ouă mari, la temperatura camerei","500 ml lapte integral (sau 350 ml lapte + 150 ml apă pentru crêpes mai ușoare)","50 g unt nesărat, topit până devine beurre noisette (alunizat)","30 g zahăr și un vârf bun de sare fină","1 lingură de rom închis sau apă de flori de portocal (sau 1 linguriță extract de vanilie)","Unt în plus pentru ungerea tigăii (~30 g, ținut cu o pensulă)","Pentru servit: zahăr tos, felii de lămâie, opțional gem, Nutella sau banane"]},"howIsMade":{"en":"Melt the 50 g of butter in a small saucepan over medium heat and keep cooking until it smells nutty and turns deep gold, then strain into a bowl leaving the dark sediment behind — that's beurre noisette, the signature flavour of bakery-grade crêpes.\n\nSift the flour and salt into a large bowl, make a well in the middle, crack in the eggs and add a third of the milk with the sugar, then whisk from the centre outwards drawing in the flour until you have a thick smooth paste with no lumps, thin with the rest of the milk in a slow stream and finally add the cooled brown butter and the rum; the batter should be the consistency of single cream.\n\nCover and rest the batter in the fridge at least 30 minutes, ideally an hour — the gluten settles and the crêpes turn out thin and flexible rather than elastic.\n\nHeat a 22–24 cm non-stick pan or crêpière over medium-high heat, brush with a very thin film of butter and pour in about 50 ml of batter, immediately swirling so it covers the base in a thin disc, then cook 50–60 seconds until the edges lift and the underside is lacy golden, flip with a thin spatula (or a quick toss of the pan) for another 25–30 seconds, slide onto a plate and cover with a clean cloth — carry on, brushing the pan with a little butter every one or two crêpes, until the batter is gone.\n\nServe warm, scattered with caster sugar and a squeeze of lemon, folded into quarters — the Parisian street-stand alternatives are sucre, sucre-citron, fruit jam, Nutella, or banana with Nutella."}},{"id":193,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":530,"prot":5,"carb":65,"fat":28,"fib":3},"origin":{"en":"France","ro":"Franța"},"name":{"en":"Tarte Tatin","ro":"Tarte Tatin"},"category":{"en":"Dessert","ro":"Desert"},"ingredients":{"en":["8–10 firm tart apples (reine de reinette, golden delicious or honeycrisp), peeled, halved and cored — about 1.5 kg","150 g unsalted butter, cut into cubes, at room temperature","200 g white granulated sugar (do not use brown sugar for a classic tatin)","1 tbsp fresh lemon juice","1 round of puff pastry (pâte feuilletée), ~250 g, rolled to 26 cm and 3 mm thick","A pinch of fleur de sel","To serve: 200 ml crème fraîche, not ice cream — the Sologne tradition"],"ro":["8–10 mere ferme și ușor acrișoare (reine de reinette, golden delicious sau honeycrisp), curățate, înjumătățite și fără cotor — în jur de 1,5 kg","150 g unt nesărat, tăiat cuburi, la temperatura camerei","200 g zahăr alb tos (nu se folosește zahăr brun pentru un tatin clasic)","1 lingură suc proaspăt de lămâie","Un disc de aluat de foitaj (pâte feuilletée), ~250 g, rulat la 26 cm diametru și 3 mm grosime","Un vârf de fleur de sel","Pentru servit: 200 ml smântână grasă (crème fraîche), nu înghețată — tradiția din Sologne"]},"howIsMade":{"en":"Toss the apples with the lemon juice so they don't brown, melt 50 g of the butter in a heavy 22–24 cm oven-safe pan with an ovenproof handle (or a proper tatin pan), scatter the sugar over it in an even layer and leave on medium heat without stirring until the sugar dissolves and caramelises to a deep amber — about 8–10 minutes — because pale caramel bleeds out in the oven and tastes flat.\n\nTake the pan off the heat and drop the remaining 100 g butter in cubes onto the caramel — it will hiss hard — swirl until the butter melts evenly into a glossy buttery sauce, then pack the apple halves cut-side-up, tight against each other in a spiral from the centre outwards (they will fit), return to medium heat and cook uncovered for 25–30 minutes, tilting the pan now and then to catch the caramel from the edges, until the underside of the apples has drunk the caramel and they just start to soften.\n\nMeanwhile heat the oven to 200°C and roll the puff pastry to a disc a little larger than the pan, cut the heat under the apples and let them settle a minute, then drape the pastry over the top and tuck the edges down inside the pan between the apples and the wall — the crust will grip the fruit when you flip — and prick the pastry a few times with a fork.\n\nBake 25–30 minutes until the pastry is fully golden and the caramel bubbles around the edges, then rest exactly 10 minutes — long enough for the caramel to settle without setting hard.\n\nPlace a serving plate wider than the pan over the pastry, hold the pan with a thick cloth and invert in one decisive motion — if any apple stays stuck to the pan, lift it back onto the tart with a spatula — scatter a pinch of fleur de sel over the top and serve warm with a generous spoonful of crème fraîche on each plate."}},{"id":194,"servings":6,"tipType":"soup","pairingsType":"soup","nutrition":{"cal":320,"prot":28,"carb":28,"fat":10,"fib":1},"origin":{"en":"Greece","ro":"Grecia"},"name":{"en":"Avgolemono","ro":"Avgolemono"},"category":{"en":"Soup","ro":"Supă"},"ingredients":{"en":["1.5 kg whole chicken (or 1 kg bone-in chicken thighs)","2 carrots, 1 onion, 2 celery stalks (for the broth)","1 bay leaf, a handful of parsley stems, 8 black peppercorns","150 g long-grain rice (or orzo if you prefer)","3 large eggs, at room temperature","Juice of 2 lemons (about 80 ml)","Salt and white pepper","Fresh dill or parsley to finish"],"ro":["1,5 kg pui întreg (sau 1 kg pulpe de pui cu os)","2 morcovi, 1 ceapă, 2 tulpini de țelină (pentru fond)","1 frunză de dafin, un mănunchi de codițe de pătrunjel, 8 boabe de piper negru","150 g orez cu bob lung (sau orzo, dacă preferi)","3 ouă mari, la temperatura camerei","Zeama de la 2 lămâi (aproximativ 80 ml)","Sare și piper alb","Mărar sau pătrunjel proaspăt pentru a încheia"]},"howIsMade":{"en":"Simmer the chicken in 2.5 L cold water with the carrots, onion, celery, bay leaf, parsley stems and peppercorns. Skim any foam and cook uncovered for about 90 minutes, until the meat falls from the bones.\n\nLift the chicken out, strain the broth into a clean pot and discard the vegetables. Shred the meat off the bones, return it to the broth, bring back to a simmer and stir in the rice; cook 15–18 minutes until tender.\n\nWhisk the eggs in a bowl until light and foamy, then whisk in the lemon juice. Temper them by slowly ladling a cup of hot broth in while whisking, then another, until the bowl is warm to the touch.\n\nOff the heat, pour the tempered eggs back into the pot in a slow steady stream, stirring continuously — never let the soup boil again. Season with salt and white pepper and serve immediately, finished with dill or parsley."}},{"id":195,"servings":4,"tipType":"meat","pairingsType":"mediterranean","nutrition":{"cal":620,"prot":38,"carb":52,"fat":28,"fib":4},"origin":{"en":"Greece","ro":"Grecia"},"name":{"en":"Gyros","ro":"Gyros"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["1 kg pork shoulder, sliced into 1 cm thick strips against the grain (or boneless chicken thighs)","4 garlic cloves, minced","2 tbsp Greek olive oil","1 tbsp red wine vinegar","1 tbsp dried oregano (Greek rigani if possible)","1 tsp sweet paprika","1 tsp salt, ½ tsp black pepper","4 large soft Greek pitas (the unfilled flatbread, not pocket pita)","To serve: 200 ml tzatziki, 1 ripe tomato sliced, ½ red onion thinly sliced, oregano, lemon wedges, optional French fries"],"ro":["1 kg ceafă de porc, tăiată în fâșii de 1 cm grosime contra fibrei (sau pulpe de pui dezosate)","4 căței de usturoi, tocați","2 linguri ulei de măsline grecesc","1 lingură oțet de vin roșu","1 lingură oregano uscat (rigani grecesc, dacă ai)","1 linguriță boia dulce","1 linguriță sare, ½ linguriță piper negru","4 lipii grecești mari și moi (turtă plată neumplută, nu pita cu buzunar)","Pentru servit: 200 ml tzatziki, 1 roșie coaptă feliată, ½ ceapă roșie tăiată subțire, oregano, felii de lămâie, opțional cartofi prăjiți"]},"howIsMade":{"en":"Whisk the garlic, olive oil, vinegar, oregano, paprika, salt and pepper in a large bowl, add the pork strips and toss until every piece is coated. Cover and marinate at least 3 hours, ideally overnight.\n\nHeat a large heavy skillet or griddle pan over high heat until smoking. Lay the strips down in a single layer, in batches if needed, and sear without moving for 2–3 minutes per side, until the edges are deeply browned and the centre just cooked through; don't crowd the pan or the meat will steam instead of caramelise. Rest each batch on a plate while you cook the next.\n\nWarm the pitas one at a time on the same hot skillet for 20 seconds per side, just until pliable. Spread a heaped tablespoon of tzatziki down the centre of each, lay the hot pork on top, add a few tomato slices and rings of red onion, and — if you're being faithful to Athens — a small handful of French fries on top.\n\nWrap tightly in paper with one end pinched closed, and serve immediately with extra oregano, a wedge of lemon, and the rest of the tzatziki on the side."}},{"id":196,"servings":8,"tipType":"pasta","pairingsType":"mediterranean","nutrition":{"cal":680,"prot":30,"carb":62,"fat":32,"fib":4},"origin":{"en":"Greece","ro":"Grecia"},"name":{"en":"Pastitsio","ro":"Pastitsio"},"category":{"en":"Pasta","ro":"Paste"},"ingredients":{"en":["500 g pastitsio noodles (long, tubular #2; bucatini is a fair substitute)","600 g beef mince (or half beef, half lamb)","1 large onion, finely chopped","3 garlic cloves, minced","400 g chopped tomatoes (canned)","2 tbsp tomato paste","150 ml dry red wine","1 cinnamon stick, 4 whole cloves, 1 bay leaf, 1 tsp dried oregano","100 g Kefalotyri or Pecorino, finely grated (Parmesan works at a pinch)","For the béchamel: 100 g butter, 100 g flour, 1 L whole milk, 4 egg yolks, a grating of nutmeg","Salt and pepper, olive oil"],"ro":["500 g paste tip pastitsio (lungi, tubulare nr. 2; bucatini este o alternativă bună)","600 g carne tocată de vită (sau jumătate vită, jumătate miel)","1 ceapă mare, tocată mărunt","3 căței de usturoi, tocați","400 g roșii tocate (la conservă)","2 linguri pastă de roșii","150 ml vin roșu sec","1 baton de scorțișoară, 4 cuișoare întregi, 1 frunză de dafin, 1 linguriță oregano uscat","100 g Kefalotyri sau Pecorino, ras fin (Parmezan se poate la nevoie)","Pentru béchamel: 100 g unt, 100 g făină, 1 l lapte integral, 4 gălbenușuri, puțină nucușoară rasă","Sare, piper, ulei de măsline"]},"howIsMade":{"en":"Heat 3 tablespoons of olive oil in a heavy pan and brown the chopped onion for 8–10 minutes, add the garlic for 30 seconds, then crumble in the mince. Break it up with a wooden spoon and let it brown deeply, about 10 minutes. Stir in the tomato paste, fry until brick-red, deglaze with the wine and let it reduce by half before adding the tomatoes, cinnamon stick, cloves, bay leaf and oregano. Season generously and simmer uncovered on low heat for at least 45 minutes; fish out the whole spices before assembling.\n\nWhile the meat cooks, make the béchamel: melt the butter in a wide saucepan, whisk in the flour for a couple of minutes without colour, pour in the warm milk in a slow stream while whisking, then simmer 5–7 minutes until it coats the back of a spoon. Off the heat, beat in the egg yolks one at a time, add the nutmeg and half the grated cheese, and season.\n\nBoil the pasta in well-salted water 2 minutes less than the package says — it'll finish in the oven — drain and toss with the remaining cheese and a ladle of meat sauce so the noodles don't stick.\n\nIn a 25×35 cm baking dish, lay half the pasta in one direction, spread the meat sauce evenly over it, then top with the rest of the pasta aligned the same way. Pour the béchamel over, smooth it level, and bake at 180°C for 45–50 minutes until golden and bubbling.\n\nLet it rest at least 20 minutes before cutting; sliced too hot, the layers collapse."}},{"id":197,"servings":6,"tipType":"veg","pairingsType":"mediterranean","nutrition":{"cal":280,"prot":5,"carb":35,"fat":14,"fib":3},"origin":{"en":"Greece","ro":"Grecia"},"name":{"en":"Dolmades","ro":"Dolmades"},"category":{"en":"Appetizer","ro":"Aperitiv"},"ingredients":{"en":["1 jar (450 g) preserved grape leaves, drained and rinsed (or 60 fresh blanched leaves)","200 g long-grain rice (arborio works)","1 large onion, finely chopped","6 spring onions, thinly sliced","A large bunch of fresh dill, chopped","A small bunch of fresh mint, chopped","A small bunch of flat-leaf parsley, chopped","Juice of 2 lemons","150 ml extra-virgin olive oil","1 tsp salt, freshly ground black pepper","Optional but traditional: 1 grated tomato"],"ro":["1 borcan (450 g) de frunze de viță conservate, scurse și clătite (sau 60 de frunze proaspete opărite)","200 g orez cu bob lung (merge și arborio)","1 ceapă mare, tocată mărunt","6 fire de ceapă verde, tăiate subțire","Un mănunchi mare de mărar proaspăt, tocat","Un mănunchi mic de mentă proaspătă, tocată","Un mănunchi mic de pătrunjel cu frunza plată, tocat","Zeama de la 2 lămâi","150 ml ulei de măsline extravirgin","1 linguriță sare, piper negru proaspăt măcinat","Opțional dar tradițional: 1 roșie rasă"]},"howIsMade":{"en":"Soak the rice in cold water for 15 minutes and drain. Heat 3 tablespoons of olive oil in a wide pan and sweat the chopped onion for 8 minutes until translucent, no colour. Add the spring onions, all the herbs, the drained rice, half the lemon juice and a generous pinch of salt; stir for a minute to bloom the aromas, then tip onto a plate to cool to room temperature.\n\nLay a grape leaf on the work surface vein-side up, stem at the bottom. Place a heaped teaspoon of the rice mixture near the stem, fold the bottom edge up and over, fold both sides in, and roll up tightly into a small cigar. Don't overfill — the rice swells as it cooks and packed too tightly the dolma will split.\n\nLine the bottom of a heavy pot with torn or broken leaves to prevent sticking. Pack the rolled dolmades in concentric circles, seam-side down, snug enough to hold each other in place. Pour over the remaining olive oil and lemon juice, add cold water just to the top of the dolmades, and press a heatproof plate directly on the surface to keep them submerged.\n\nBring slowly to a simmer, cover, and cook on the lowest heat for 50 minutes to an hour, until the rice is tender and the liquid mostly absorbed. Leave to cool in the pot — they're served cold or at room temperature, with a wedge of lemon and a bowl of thick yoghurt. Made the day before, they taste markedly better."}},{"id":198,"servings":12,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":380,"prot":7,"carb":48,"fat":18,"fib":1},"origin":{"en":"Greece","ro":"Grecia"},"name":{"en":"Galaktoboureko","ro":"Galaktoboureko"},"category":{"en":"Dessert","ro":"Desert"},"ingredients":{"en":["500 g phyllo pastry, thawed","200 g unsalted butter, melted","1 L whole milk","200 g caster sugar (for the custard)","150 g fine semolina","4 large eggs","1 tsp vanilla extract","Zest of 1 lemon","For the syrup: 400 g caster sugar, 250 ml water, juice of half a lemon, a strip of orange peel, 1 stick of cinnamon"],"ro":["500 g foi de plăcintă (phyllo), dezghețate","200 g unt nesărat, topit","1 l lapte integral","200 g zahăr tos (pentru cremă)","150 g griș fin","4 ouă mari","1 linguriță extract de vanilie","Coaja rasă de la 1 lămâie","Pentru sirop: 400 g zahăr, 250 ml apă, zeama de la o jumătate de lămâie, o fâșie de coajă de portocală, 1 baton de scorțișoară"]},"howIsMade":{"en":"Start the syrup well in advance — it must be cold when the hot pie comes out of the oven — combine the sugar, water, lemon juice, orange peel and cinnamon in a small saucepan, bring to a boil then simmer 4 minutes, take off the heat and leave to cool completely. For the custard, heat the milk in a wide saucepan with the sugar and lemon zest until just steaming (do not let it boil), sprinkle the semolina in a fine even stream while whisking constantly, then keep whisking on low heat for 5–6 minutes until it thickens to a loose pudding; off the heat, beat in the eggs one at a time (the mixture should be warm but not hot enough to scramble them) and the vanilla, then press clingfilm directly onto the surface to stop a skin forming. Brush a 22×30 cm baking dish with melted butter, lay 7 sheets of phyllo across the bottom brushing each generously with butter and letting the edges hang over the sides (those flaps will fold back over the top later), pour in the still-warm custard, smooth it level, fold the overhanging flaps inward and brush them with butter, then cover with another 7 sheets of phyllo (again buttering each) and trim or tuck the edges so the pie is fully sealed. Score the top phyllo into diamonds or squares with a sharp knife — cut all the way through so the syrup can later penetrate — brush the surface lavishly with the last of the butter, and bake at 170°C for 45–55 minutes until the top is deeply golden brown. The moment it comes out of the oven, pour the cold syrup evenly over the hot pie — it will sizzle and steam — leave to settle at least 4 hours, ideally overnight, before cutting along the score lines and serving at room temperature."}},{"id":199,"servings":4,"tipType":"def","pairingsType":"italian","nutrition":{"cal":740,"prot":28,"carb":88,"fat":30,"fib":4},"origin":{"en":"Italy","ro":"Italia"},"name":{"en":"Pizza Margherita","ro":"Pizza Margherita"},"category":{"en":"Pizza","ro":"Pizza"},"ingredients":{"en":["For the dough (4 pizzas): 500 g 00 flour (or bread flour), 325 ml cold water, 10 g salt, 1 g fresh yeast (or ¼ tsp dried)","For each pizza: 80 g San Marzano tomatoes (canned, hand-crushed), a pinch of salt, a drizzle of olive oil","100 g fior di latte mozzarella per pizza, torn into pieces (or buffalo mozzarella)","A few fresh basil leaves per pizza","Extra-virgin olive oil to finish","Semolina or flour for shaping and the peel"],"ro":["Pentru aluat (4 pizza): 500 g făină 00 (sau pentru pâine), 325 ml apă rece, 10 g sare, 1 g drojdie proaspătă (sau ¼ linguriță uscată)","Pentru fiecare pizza: 80 g roșii San Marzano (la conservă, sfărâmate cu mâna), un praf de sare, un fir de ulei de măsline","100 g mozzarella fior di latte per pizza, ruptă în bucățele (sau mozzarella de bivoliță)","Câteva frunze de busuioc proaspăt pentru fiecare pizza","Ulei de măsline extravirgin pentru finalizare","Griș sau făină pentru modelare și pentru lopată"]},"howIsMade":{"en":"For the dough, dissolve the yeast in the cold water then mix in the flour and salt until you have a shaggy mass, knead by hand for 10 minutes (or 6 minutes with a stand mixer and dough hook) until smooth and elastic, cover and rest at room temperature for an hour, then refrigerate for at least 24 hours and ideally 48 to 72 — the long cold proof is what gives Neapolitan dough its blistered char and airy structure. Two hours before baking, take the dough out, divide into four 210 g balls, dust with flour, cover with a damp cloth and let them come to room temperature, meanwhile heat the oven as hot as it goes (250°C or above) with a pizza stone or heavy steel sheet inside for at least 45 minutes; without serious heat under the pizza, the crust will never set in time. Hand-stretch one ball on a well-floured surface — press the centre flat with your fingertips leaving a raised lip, then gently pull and stretch the disc to about 28 cm across — never use a rolling pin, which collapses the gas pockets in the crust — and slide it onto a floured peel. Spoon 80 g of crushed tomato into the centre and spread it in a spiral with the back of the spoon stopping 2 cm from the edge, salt the tomato lightly, drizzle a little olive oil, and scatter the torn mozzarella over the top (not too much, or the pizza floods). Slide the pizza onto the stone and bake until the crust is puffed and charred in spots, the cheese has melted into pools and the rim is dark gold — 4 to 6 minutes in a domestic oven at full blast, 90 seconds in a wood-fired Neapolitan oven — pull it out, tear over the basil leaves (which would scorch in the oven), drizzle a final thread of olive oil, and eat immediately."}},{"id":200,"servings":6,"tipType":"pasta","pairingsType":"italian","nutrition":{"cal":720,"prot":36,"carb":58,"fat":36,"fib":4},"origin":{"en":"Italy","ro":"Italia"},"name":{"en":"Lasagne alla Bolognese","ro":"Lasagne alla Bolognese"},"category":{"en":"Pasta","ro":"Paste"},"ingredients":{"en":["For the ragù: 400 g beef mince, 200 g pork mince, 80 g pancetta finely diced, 1 onion + 1 carrot + 1 celery stalk all finely diced, 200 ml dry red wine, 400 g passata or chopped tomatoes, 250 ml whole milk, 1 bay leaf, salt and pepper, olive oil","For the béchamel: 80 g butter, 80 g flour, 1 L whole milk, salt, a grating of nutmeg","300 g fresh egg lasagne sheets (or 250 g dried, blanched)","150 g Parmigiano Reggiano, finely grated","Butter for the dish"],"ro":["Pentru ragù: 400 g vită tocată, 200 g porc tocat, 80 g pancetta tăiată cubulețe, 1 ceapă + 1 morcov + 1 țelină — toate tocate mărunt, 200 ml vin roșu sec, 400 g passata sau roșii tocate, 250 ml lapte integral, 1 frunză de dafin, sare și piper, ulei de măsline","Pentru béchamel: 80 g unt, 80 g făină, 1 l lapte integral, sare, puțină nucușoară rasă","300 g foi proaspete de lasagne cu ou (sau 250 g uscate, opărite)","150 g Parmigiano Reggiano, ras fin","Unt pentru vasul de copt"]},"howIsMade":{"en":"Render the pancetta gently in a heavy pot with a splash of olive oil over medium-low heat for 5 minutes until the fat runs clear, add the chopped soffritto (onion, carrot, celery) and cook 10 minutes until soft and just gilded at the edges, then crumble in both meats and brown them properly — patience: do not stir for the first 3 minutes, then break them up and cook 10 more minutes until the pan bottom is deeply caramelised. Pour in the wine, scrape the fond from the pan with a wooden spoon and reduce by half, then add the tomatoes, the milk (the Bolognese signature — it rounds the acid and tightens the texture), the bay leaf and a teaspoon of salt; bring to a bare simmer, partially cover, and cook on the lowest possible heat for at least 2 hours and ideally 3, stirring occasionally and adding a splash of water if it threatens to dry — the finished ragù should be glossy, deep brown-red and almost a paste, never a soup. While the ragù finishes, make the béchamel: melt the butter, whisk in the flour for 2 minutes without colour, pour in the warm milk in a slow stream while whisking and simmer 5 minutes until thick, then season with salt and a generous grating of nutmeg. If using dried lasagne sheets blanch them in salted boiling water for a minute and lay on damp tea towels — fresh sheets go in raw — heat the oven to 180°C and butter a 25×35 cm baking dish, then spread a thin layer of béchamel on the bottom, then a layer of pasta, then ragù, then béchamel, then a snowy dusting of Parmigiano, and repeat until you have used everything (six to seven layers is the Bolognese target), finishing with béchamel and a heavier shower of Parmigiano. Bake 35–40 minutes until the top is bronzed and bubbling, then rest 20 minutes before cutting — lasagne sliced hot slides apart, lasagne rested holds its layers."}},{"id":201,"servings":4,"tipType":"meat","pairingsType":"italian","nutrition":{"cal":580,"prot":42,"carb":18,"fat":32,"fib":3},"origin":{"en":"Italy","ro":"Italia"},"name":{"en":"Osso Buco alla Milanese","ro":"Osso Buco alla Milanese"},"category":{"en":"Main","ro":"Fel principal"},"ingredients":{"en":["4 thick-cut veal shanks (3–4 cm thick, about 350 g each), tied around the circumference with kitchen string","Salt and freshly ground black pepper","Plain flour for dusting","4 tbsp unsalted butter, 2 tbsp olive oil","1 onion + 1 carrot + 1 celery stalk, all finely diced","200 ml dry white wine","400 g chopped tomatoes","500 ml veal or chicken stock","1 bay leaf, a few sprigs of thyme","For the gremolata: zest of 1 lemon, 2 garlic cloves finely minced, a small bunch of flat-leaf parsley finely chopped"],"ro":["4 rasoluri groase de vițel (3–4 cm grosime, aproximativ 350 g fiecare), legate cu sfoară de bucătărie pe circumferință","Sare și piper negru proaspăt măcinat","Făină albă pentru tăvălit","4 linguri unt nesărat, 2 linguri ulei de măsline","1 ceapă + 1 morcov + 1 țelină, toate tocate mărunt","200 ml vin alb sec","400 g roșii tocate","500 ml fond de vițel sau pui","1 frunză de dafin, câteva fire de cimbru","Pentru gremolata: coaja rasă de la 1 lămâie, 2 căței de usturoi tocați fin, un mănunchi mic de pătrunjel cu frunza plată, tocat fin"]},"howIsMade":{"en":"Pat the shanks dry — wet meat steams instead of searing — season aggressively with salt and pepper and dust lightly in flour knocking off the excess, then heat half the butter and all the oil in a heavy braising pan over medium-high heat until foaming, lay the shanks in and do not touch them for 4 minutes until the bottom is deeply browned, flip and do the second side, then lift onto a plate. Lower the heat to medium, add the rest of the butter and the soffritto, and cook gently for 10 minutes until soft and golden at the edges, then pour in the wine, raise the heat, and reduce by half while scraping up the caramelised bits from the bottom of the pan. Stir in the tomatoes, bay leaf and thyme, return the shanks to the pan in a single layer, and pour in just enough stock to come about two-thirds of the way up the meat — the bones should stay exposed so the marrow stays in — and bring to a bare simmer. Cover and braise on the lowest heat or in a 160°C oven for 2 to 2½ hours, turning the shanks gently every 30 minutes so they cook evenly — they are done when the meat slumps off the bone at the press of a spoon and the sauce has thickened to a glossy gravy — then lift them out carefully because the bones and marrow are fragile at this point. While the shanks rest, stir together the lemon zest, garlic and parsley to make the gremolata, place a shank on each plate, spoon over plenty of sauce, and crown with a generous pinch of the raw gremolata — its sharpness cuts the richness and is what makes osso buco Milanese rather than just braised veal — serve with risotto alla milanese, polenta, or a piece of bread for the marrow."}},{"id":202,"servings":8,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":540,"prot":9,"carb":42,"fat":36,"fib":1},"origin":{"en":"Italy","ro":"Italia"},"name":{"en":"Tiramisu","ro":"Tiramisu"},"category":{"en":"Dessert","ro":"Desert"},"ingredients":{"en":["500 g mascarpone, at room temperature","5 large eggs, separated, at room temperature","100 g caster sugar","250 ml strong cold espresso (about 5 shots)","2 tbsp Marsala (sweet) or dark rum (optional, traditional in Treviso)","300 g savoiardi (Italian ladyfingers — the firm kind, not the soft kind)","Unsweetened cocoa powder for dusting","A small piece of dark chocolate for shaving (optional)","Pinch of salt for the egg whites"],"ro":["500 g mascarpone, la temperatura camerei","5 ouă mari, separate, la temperatura camerei","100 g zahăr tos","250 ml espresso tare rece (aproximativ 5 ceșcuțe)","2 linguri Marsala dulce sau rom închis (opțional, tradițional la Treviso)","300 g savoiardi (pișcoturi italiene — cele ferme, nu cele moi)","Cacao amară pentru pudrare","O bucățică de ciocolată neagră pentru ras (opțional)","Un praf de sare pentru albușuri"]},"howIsMade":{"en":"Whisk the egg yolks with the sugar in a large bowl for 4–5 minutes — by hand or with an electric beater — until pale, foamy and dramatically tripled in volume; the sugar should be completely dissolved when you rub a little between your fingers, undermixing here gives you a grainy tiramisu later. Add the mascarpone in three batches, whisking gently after each, until the cream is smooth and glossy, then in a separate clean bowl whisk the egg whites with a pinch of salt to firm glossy peaks that hold their shape when the whisk is lifted, and fold the whites into the mascarpone in three additions with a large spatula, folding from the centre outwards to keep the air in — the finished cream should be light, almost pourable but holding soft peaks. Mix the cold espresso and Marsala in a shallow dish, then dip the savoiardi one at a time — just briefly, 2 seconds per side at most — they are sponges, and oversoaked ladyfingers turn to mush and weep through the cream, and lay them in a tight single layer in the bottom of a 22×30 cm dish. Spread half the mascarpone cream over the ladyfingers in an even layer, then repeat — another tight layer of dipped savoiardi, then the rest of the cream on top, smoothed level with the spatula. Cover with clingfilm and refrigerate at least 6 hours, ideally overnight — tiramisu eaten the same day tastes like its parts, tiramisu rested overnight tastes like one dessert — just before serving dust the top generously with cocoa pushed through a fine sieve, shave over a little dark chocolate if you like, and cut with a hot knife wiped between slices."}},{"id":203,"servings":4,"tipType":"pasta","pairingsType":"italian","nutrition":{"cal":520,"prot":22,"carb":76,"fat":14,"fib":3},"origin":{"en":"Italy","ro":"Italia"},"name":{"en":"Cacio e Pepe","ro":"Cacio e Pepe"},"category":{"en":"Pasta","ro":"Paste"},"ingredients":{"en":["400 g tonnarelli or thick spaghetti","200 g Pecorino Romano, finely grated on a microplane (no Parmesan — it doesn't melt the same way)","1 heaped tablespoon whole black peppercorns, freshly cracked in a mortar (not pre-ground)","Sea salt for the pasta water (less than usual, since the cheese is salty)"],"ro":["400 g tonnarelli sau spaghete groase","200 g Pecorino Romano, ras fin pe microplane (fără Parmezan — nu se topește la fel)","1 lingură plină de boabe întregi de piper negru, proaspăt zdrobite în mojaru (nu măcinat în prealabil)","Sare de mare pentru apa pastelor (mai puțină decât de obicei, fiindcă brânza este sărată)"]},"howIsMade":{"en":"Toast the cracked pepper in a wide dry pan over medium heat for 30 seconds — until you can smell it sharply — and add half a ladle of cold water to stop the cooking and create a peppery slurry. Set aside off the heat.\n\nBring 3 L of lightly salted water to a boil and cook the pasta until just shy of al dente, about a minute less than the package says; in Rome the pasta finishes cooking in the sauce, not in the pot.\n\nWhile the pasta cooks, scoop out a mug of starchy water from the pot. In a wide bowl, whisk the grated Pecorino with about 4 tablespoons of the hot pasta water — let it cool a few seconds first, since boiling water on cheese clumps it instantly — until you have a thick, ricotta-like paste; loosen with another spoonful of water if it's too stiff.\n\nLift the pasta from the pot with tongs straight into the peppered pan (don't drain it), splash in a ladle of starchy water, and toss vigorously over low heat for 30 seconds, until the pasta is glossy and well coated.\n\nTake the pan off the heat — Pecorino above boiling point seizes into stringy clumps — pour over the cheese paste and toss again, fast, adding more pasta water by the spoonful if needed, until the sauce becomes a creamy emulsion that clings to every strand. Plate immediately with another crack of pepper on top; cacio e pepe cools quickly, so plates should be warm and diners at the table."}},{"id":204,"servings":4,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":720,"prot":42,"carb":28,"fat":48,"fib":4},"origin":{"en":"India","ro":"India"},"name":{"en":"Butter Chicken (Murgh Makhani)","ro":"Butter Chicken (Murgh Makhani)"},"category":{"en":"Curry","ro":"Curry"},"ingredients":{"en":["800 g boneless chicken thighs, cut into 4 cm pieces","For the marinade: 200 g full-fat yoghurt, 2 tbsp ginger-garlic paste, 1 tsp Kashmiri red chilli powder, 1 tsp garam masala, juice of half a lemon, 2 tbsp neutral oil, 1 tsp salt","For the gravy: 800 g ripe tomatoes (or 1 large can chopped tomatoes), 60 g raw cashews, 1 large onion quartered, 4 garlic cloves, 3 cm piece of ginger, 4 green cardamom pods, 1 cinnamon stick, 4 cloves, 1 bay leaf","80 g unsalted butter, 200 ml double cream","1 tbsp kasoori methi (dried fenugreek leaves)","1 tsp Kashmiri red chilli powder, 1 tsp garam masala, 1 tsp sugar, salt","Fresh coriander to finish"],"ro":["800 g pulpe de pui dezosate, tăiate în bucăți de 4 cm","Pentru marinadă: 200 g iaurt gras, 2 linguri pastă de ghimbir-usturoi, 1 linguriță boia Kashmiri, 1 linguriță garam masala, zeama de la o jumătate de lămâie, 2 linguri ulei neutru, 1 linguriță sare","Pentru sosul de bază: 800 g roșii coapte (sau o cutie mare de roșii tocate), 60 g caju crud, 1 ceapă mare în sferturi, 4 căței de usturoi, 3 cm bucată de ghimbir, 4 capsule de cardamom verde, 1 baton de scorțișoară, 4 cuișoare, 1 frunză de dafin","80 g unt nesărat, 200 ml smântână grasă","1 lingură kasoori methi (frunze uscate de schinduf)","1 linguriță boia Kashmiri, 1 linguriță garam masala, 1 linguriță zahăr, sare","Coriandru proaspăt pentru a încheia"]},"howIsMade":{"en":"Mix the marinade in a wide bowl, add the chicken and turn each piece until well coated, then cover and chill at least 4 hours, ideally overnight. For the gravy, soak the cashews in 100 ml of hot water for 20 minutes; put the tomatoes, onion, garlic, ginger and whole spices into a heavy pan with 200 ml of water, bring to a simmer and cook covered for 20–25 minutes until the tomatoes have collapsed and the onion is fully soft, then fish out the cinnamon, cardamom, cloves and bay leaf, and blend everything — including the soaked cashews and their water — to a velvety purée and pass through a sieve. Heat the broiler high, line a tray with foil, spread the marinated chicken in a single layer with space between the pieces and broil 5–6 cm from the heat for 6–8 minutes per side, until the edges are charred and the meat is just cooked through — let the edges go genuinely dark. Melt the butter in a wide pan over medium heat, pour in the strained gravy and add the chilli powder, sugar and a teaspoon of salt, simmer gently for 10 minutes stirring often until the colour deepens to a rich brick-orange; pour in the cream, stir until the gravy turns velvet, then slide in the charred chicken with any juices from the tray and let everything bubble together for 4–5 minutes more. Crush the kasoori methi between your palms over the pan, stir in the garam masala and taste for salt and sugar, scatter coriander leaves on top, and serve with naan or basmati rice."}},{"id":205,"servings":6,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":780,"prot":38,"carb":78,"fat":32,"fib":3},"origin":{"en":"India","ro":"India"},"name":{"en":"Hyderabadi Lamb Biryani","ro":"Biryani de miel din Hyderabad"},"category":{"en":"Main","ro":"Fel principal"},"ingredients":{"en":["800 g bone-in lamb shoulder or leg, cut into 4 cm pieces","500 g basmati rice, soaked 30 minutes in cold water and drained","4 large onions, very thinly sliced (about 600 g)","200 g full-fat yoghurt","50 g ghee + 80 ml neutral oil","3 tbsp ginger-garlic paste","2 green chillies, slit lengthwise","2 tsp Kashmiri red chilli powder, 1 tsp turmeric, 1 tsp salt","Whole spices: 1 cinnamon stick, 4 green cardamom + 2 black cardamom, 4 cloves, 1 bay leaf, 1 tsp shahi jeera, 1 tsp black peppercorns","A pinch of saffron infused in 60 ml warm whole milk","Juice of 1 lemon","2 tbsp chopped mint and 2 tbsp chopped coriander","1 tbsp rose water (optional, traditional)","A piece of soft dough or a sheet of heavy foil for sealing"],"ro":["800 g spată sau pulpă de miel cu os, tăiată în bucăți de 4 cm","500 g orez basmati, înmuiat 30 de minute în apă rece și scurs","4 cepe mari, tăiate foarte subțire (aproximativ 600 g)","200 g iaurt gras","50 g ghee + 80 ml ulei neutru","3 linguri pastă de ghimbir-usturoi","2 ardei iuți verzi, despicați pe lungime","2 lingurițe boia Kashmiri, 1 linguriță turmeric, 1 linguriță sare","Mirodenii întregi: 1 baton de scorțișoară, 4 capsule cardamom verde + 2 cardamom negru, 4 cuișoare, 1 frunză de dafin, 1 linguriță shahi jeera, 1 linguriță boabe de piper negru","Un vârf de șofran infuzat în 60 ml lapte cald","Sucul de la 1 lămâie","2 linguri mentă tocată și 2 linguri coriandru tocat","1 lingură apă de trandafiri (opțional, tradițional)","O bucată de aluat moale sau o folie groasă pentru sigilare"]},"howIsMade":{"en":"Heat the ghee and oil in a wide heavy pan over medium heat and fry the sliced onions slowly for 25–30 minutes, stirring often, until deeply golden brown (birista), then drain on paper, reserve the oil in the pan and keep half the onions for layering. Combine the lamb with the yoghurt, ginger-garlic paste, half of the fried onions crushed in your hand, chilli powder, turmeric, salt, lemon juice and a teaspoon of the shahi jeera, mix thoroughly and rest at least 2 hours or overnight in the fridge; tip the marinated lamb back into the reserved onion oil, add the cinnamon, cardamom, cloves and bay leaf, and cook covered over low heat for an hour to an hour and a quarter, until the lamb is tender and the gravy has reduced to a thick coating. Bring a deep pot of well-salted water to a rolling boil with the rest of the whole spices and a tablespoon of oil, add the soaked basmati and cook just 4–5 minutes until the grains have lengthened and are about three-quarters done — they finish in the steam — then drain quickly and gently. In the same pan over the lamb, spread the rice evenly, scatter the remaining fried onions, chopped mint and coriander, and the green chillies on top, then drizzle the saffron milk in slow streaks across the surface and the rose water if using. Seal the lid with a strip of wet dough or a tight wrap of foil, set on the lowest heat for 25–30 minutes, then turn off the flame without lifting the lid and rest sealed for another 10 minutes — break the seal at the table and plunge a long spoon to the bottom to lift straight up, so each portion comes out with both rice and meat, never stirred together."}},{"id":206,"servings":4,"tipType":"veg","pairingsType":"indian","nutrition":{"cal":480,"prot":22,"carb":18,"fat":36,"fib":5},"origin":{"en":"India","ro":"India"},"name":{"en":"Palak Paneer","ro":"Palak Paneer"},"category":{"en":"Curry","ro":"Curry"},"ingredients":{"en":["500 g fresh spinach (or 250 g frozen, defrosted)","250 g paneer, cut into 2 cm cubes","1 large onion, finely chopped","2 ripe tomatoes, chopped (or 200 g chopped tomatoes)","3 garlic cloves and 2 cm piece of ginger, minced together","2 green chillies","1 tsp cumin seeds","1 tsp coriander powder, 1 tsp Kashmiri chilli powder, ½ tsp turmeric, 1 tsp garam masala","1 tbsp kasoori methi (dried fenugreek leaves)","80 ml double cream, 3 tbsp ghee","Salt to taste","A small piece of fresh ginger, julienned, to finish"],"ro":["500 g spanac proaspăt (sau 250 g congelat, dezghețat)","250 g paneer, tăiat cuburi de 2 cm","1 ceapă mare, tocată mărunt","2 roșii coapte, tocate (sau 200 g roșii tocate)","3 căței de usturoi și o bucată de 2 cm de ghimbir, tocate împreună","2 ardei iuți verzi","1 linguriță semințe de chimion","1 linguriță coriandru pudră, 1 linguriță boia Kashmiri, ½ linguriță turmeric, 1 linguriță garam masala","1 lingură kasoori methi (frunze uscate de schinduf)","80 ml smântână grasă, 3 linguri ghee","Sare după gust","O bucățică mică de ghimbir proaspăt, tăiată julien, pentru finisat"]},"howIsMade":{"en":"Bring a large pot of water to a boil, blanch the spinach for 90 seconds and transfer immediately to a bowl of ice water, then drain, squeeze gently and blend to a smooth purée with one of the green chillies and a few tablespoons of cold water. Heat a tablespoon of ghee in a wide pan and fry the paneer cubes over medium heat for 2–3 minutes per side until lightly gold, then lift onto paper or slip them into a bowl of warm salted water while everything else cooks. In the same pan add the remaining ghee and the cumin seeds and let them sizzle for 30 seconds, tip in the onion and cook 8–10 minutes until soft and golden at the edges, then add the ginger-garlic paste and the second slit green chilli and cook a minute more. Stir in the chopped tomato with the coriander, chilli powder, turmeric and a teaspoon of salt and cook 6–8 minutes until the masala is jammy and the oil starts to separate at the edges, then pour in the spinach purée and 100 ml of water, stir well and simmer gently for 5 minutes. Slide the paneer cubes into the gravy, swirl in the cream, crush the kasoori methi between your palms over the pan and sprinkle the garam masala, heat through for another 2 minutes, taste for salt, finish with julienned ginger on top, and serve with naan, paratha or basmati."}},{"id":207,"servings":6,"tipType":"meat","pairingsType":"indian","nutrition":{"cal":620,"prot":40,"carb":12,"fat":44,"fib":2},"origin":{"en":"India","ro":"India"},"name":{"en":"Rogan Josh","ro":"Rogan Josh"},"category":{"en":"Curry","ro":"Curry"},"ingredients":{"en":["1 kg bone-in lamb shoulder or leg, cut into 4 cm pieces","4 tbsp mustard oil","200 g full-fat yoghurt, whisked smooth","4 dried Kashmiri red chillies, soaked in warm water 20 minutes and ground to a paste (or 2 tbsp Kashmiri chilli powder)","1 tsp fennel powder","1 tsp dried ginger powder (sonth)","½ tsp asafoetida (hing)","Whole spices: 8 green cardamom + 2 black cardamom, 1 cinnamon stick, 6 cloves, 1 bay leaf","1 tsp salt","A pinch of saffron, soaked in 2 tbsp warm milk"],"ro":["1 kg spată sau pulpă de miel cu os, tăiată în bucăți de 4 cm","4 linguri ulei de muștar","200 g iaurt gras, bătut neted","4 ardei roșii Kashmiri uscați, înmuiați 20 de minute în apă caldă și pisați pastă (sau 2 linguri boia Kashmiri)","1 linguriță pudră de fenicul","1 linguriță pudră de ghimbir uscat (sonth)","½ linguriță asafoetida (hing)","Mirodenii întregi: 8 capsule cardamom verde + 2 cardamom negru, 1 baton de scorțișoară, 6 cuișoare, 1 frunză de dafin","1 linguriță sare","Un vârf de șofran, infuzat în 2 linguri lapte cald"]},"howIsMade":{"en":"Heat the mustard oil in a heavy pan until it just begins to smoke, then pull it off the heat for a moment — letting it smoke neutralises the raw pungency without scorching — and return to medium heat, add the whole spices and bay leaf, and let them perfume the oil for 30 seconds. Add the lamb in a single layer and brown well on all sides for 8–10 minutes (this is the only browning the dish gets, so let the colour develop properly), then stir in the asafoetida, ginger powder and fennel powder and let them coat the meat in the hot oil for another minute. Whisk the yoghurt with the Kashmiri chilli paste and a tablespoon of cold water, then add it to the pan a ladleful at a time stirring continuously after each addition — going slowly keeps the yoghurt from splitting — add the salt, lower the heat and cook covered for 10 minutes until the yoghurt has melted into a glossy red base. Pour in 500 ml of hot water, bring back to a simmer, then drop the heat to its lowest and braise covered for an hour and 20 minutes, stirring every 20 minutes, until the lamb yields to a spoon and the gravy is thin, glossy and a deep mahogany red; swirl the saffron milk through 5 minutes before the end without fully stirring it out. Rest off the heat for 10 minutes before serving with steamed basmati — Rogan Josh is meant to be soup-like, brilliantly coloured and aromatic rather than spicy hot, the heat supplied by the meat, the colour by the chillies, and the perfume by everything else."}},{"id":208,"servings":8,"tipType":"veg","pairingsType":"indian","nutrition":{"cal":280,"prot":6,"carb":32,"fat":14,"fib":3},"origin":{"en":"India","ro":"India"},"name":{"en":"Samosa","ro":"Samosa"},"category":{"en":"Snack","ro":"Gustare"},"ingredients":{"en":["For the pastry: 300 g plain flour, 1 tsp ajwain (carom) seeds, ½ tsp salt, 60 ml ghee or neutral oil, 120 ml cold water","For the filling: 500 g floury potatoes (Maris Piper or Russet), 100 g frozen peas, 2 tbsp neutral oil, 1 tsp cumin seeds, 1 green chilli minced, 2 cm piece of ginger minced","1 tsp coriander powder, 1 tsp garam masala, ½ tsp Kashmiri chilli powder, ½ tsp turmeric, 1 tsp amchur (dried mango powder), 1 tsp salt","A handful of fresh coriander, chopped","About 1 L neutral oil for deep-frying","To serve: tamarind chutney and mint-coriander chutney"],"ro":["Pentru aluat: 300 g făină albă, 1 linguriță semințe de ajwain (chimen-aristotel), ½ linguriță sare, 60 ml ghee sau ulei neutru, 120 ml apă rece","Pentru umplutură: 500 g cartofi făinoși (Maris Piper sau Russet), 100 g mazăre congelată, 2 linguri ulei neutru, 1 linguriță semințe de chimion, 1 ardei iute verde tocat, 2 cm bucată de ghimbir tocat","1 linguriță coriandru pudră, 1 linguriță garam masala, ½ linguriță boia Kashmiri, ½ linguriță turmeric, 1 linguriță amchur (pudră de mango uscat), 1 linguriță sare","Un mănunchi de coriandru proaspăt, tocat","Aproximativ 1 l ulei neutru pentru prăjit","Pentru servit: chutney de tamarind și chutney de mentă-coriandru"]},"howIsMade":{"en":"Rub the ghee into the flour, ajwain and salt with your fingertips until the mixture resembles coarse breadcrumbs — the amount of fat is what gives samosa pastry its blistered, biscuit-crisp shell — then add the cold water a tablespoon at a time, mixing into a stiff smooth dough (softer than chapati but firmer than bread dough) and rest it covered for 30 minutes. Boil the potatoes in their skins until just tender, drain, peel and crush coarsely with the back of a fork (you want texture, not mash); heat the oil in a wide pan, add the cumin seeds and let them sizzle, then the ginger and green chilli for 30 seconds, stir in the dry spices and fry briefly, tip in the potato, peas, salt, amchur and coriander, and cook 4–5 minutes turning everything until the spices coat every piece — cool to room temperature before shaping. Divide the dough into 8 balls, roll one into a thin oval about 18 cm long and cut across the middle to make two half-circles; take one half, brush a thin line of water along the straight edge, and fold into a cone by bringing the two corners of the straight edge together so they overlap by 1 cm, pinching the seam tightly to seal. Hold the cone in one hand, fill it three-quarters with potato, then pleat the open edge by folding a small tuck on one side and sealing the rim shut with a damp finger — the tucked pleat creates the samosa's signature side ridge and helps it sit upright while cooking — and repeat with the rest. Heat the frying oil to 150°C (lower than you might expect, but the slow climb is what gives the shell its blisters), slip in the samosas in batches of 3 or 4 and fry 6–7 minutes turning gently until pale gold, then raise the heat to 180°C and fry another 3–4 minutes until deep golden and properly crisp, draining on a rack and serving hot with tamarind and mint chutneys."}},{"id":209,"servings":4,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":620,"prot":32,"carb":22,"fat":44,"fib":5},"origin":{"en":"Thailand","ro":"Thailanda"},"name":{"en":"Green Curry (Gaeng Khiao Wan)","ro":"Curry verde (Gaeng Khiao Wan)"},"category":{"en":"Curry","ro":"Curry"},"ingredients":{"en":["4 tbsp green curry paste (homemade, or a good Thai brand like Mae Ploy)","400 ml full-fat coconut milk (Aroy-D is ideal)","200 ml coconut cream (the thick top layer from the can, or 100 ml plus the skimmed cream)","500 g chicken thighs, cut into 3 cm pieces","4 Thai eggplants, quartered (or 1 small Asian eggplant cubed)","A small handful of pea eggplants (mainly garnish, optional)","100 g bamboo shoots, sliced","4 kaffir lime leaves, torn (stem removed)","2 long red chillies, sliced thinly on the bias","1 tbsp palm sugar (or light brown sugar)","2 tbsp Thai fish sauce","A small handful of Thai basil leaves (horapha)","Jasmine rice to serve"],"ro":["4 linguri pastă curry verde (de casă sau o marcă thailandeză bună precum Mae Ploy)","400 ml lapte de cocos gras (ideal Aroy-D)","200 ml smântână de cocos (stratul gros de deasupra cutiei, sau 100 ml plus crema rămasă)","500 g pulpe de pui, tăiate în bucăți de 3 cm","4 vinete thailandeze, tăiate în sferturi (sau 1 vânătă asiatică mică, cuburi)","Un mic mănunchi de vinete-mazăre (în principal pentru garnitură, opțional)","100 g vârfuri de bambus, feliate","4 frunze de lămâi kaffir, rupte (codița înlăturată)","2 ardei roșii lungi, feliați subțire în diagonală","1 lingură zahăr de palmier (sau zahăr brun deschis)","2 linguri sos de pește thailandez","Un mic mănunchi de busuioc thailandez (horapha)","Orez iasomie pentru servit"]},"howIsMade":{"en":"In a wok or heavy pan over medium heat, spoon in the coconut cream and let it cook for 4–5 minutes, stirring occasionally, until the oil cracks out and the cream takes on a slick sheen — this foundation step is what separates Thai-restaurant green curry from the watery home version. Add the green curry paste to the split cream and fry for 2–3 minutes, stirring constantly, until the paste darkens, releases its perfume of galangal, lemongrass and Thai basil, and the oil turns a vivid green — the kitchen will smell like a Bangkok back street. Slide in the chicken and turn the pieces in the paste until coated, cook 3–4 minutes until the meat is half-sealed, then pour in the coconut milk and bring to a gentle simmer; add the eggplants, bamboo shoots and torn kaffir lime leaves, and simmer uncovered for 10–12 minutes until the eggplants are tender and the chicken is just cooked through. Season with the fish sauce and palm sugar, tasting as you go — the curry should hit salty, sweet, herbaceous and a clean green chilli heat all at once — then stir in the sliced red chillies and Thai basil, swirl the pan once and take it off the heat after 30 seconds so the basil stays bright in the bowl. Serve in shallow bowls with jasmine rice on the side."}},{"id":210,"servings":6,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":680,"prot":36,"carb":38,"fat":42,"fib":6},"origin":{"en":"Thailand","ro":"Thailanda"},"name":{"en":"Massaman Curry","ro":"Massaman"},"category":{"en":"Curry","ro":"Curry"},"ingredients":{"en":["4 tbsp Massaman curry paste (Mae Ploy is reliable)","1 kg beef shin or chuck, cut into 5 cm cubes","800 ml full-fat coconut milk","200 ml coconut cream","500 g waxy potatoes (Charlotte or Yukon Gold), peeled and cut into 4 cm chunks","2 small onions, peeled and quartered","100 g roasted unsalted peanuts (a few crushed for garnish)","Whole spices: 5 cardamom pods, 1 cinnamon stick, 4 cloves, 1 star anise, 1 bay leaf","3 tbsp tamarind paste (or juice of 1 lime as a back-up)","3 tbsp palm sugar","3 tbsp Thai fish sauce","4 kaffir lime leaves, torn","Jasmine rice to serve"],"ro":["4 linguri pastă Massaman (Mae Ploy este o alegere sigură)","1 kg rasol sau pulpă de vită, tăiată în cuburi de 5 cm","800 ml lapte de cocos gras","200 ml smântână de cocos","500 g cartofi cu textură fermă (Charlotte sau Yukon Gold), curățați și tăiați în bucăți de 4 cm","2 cepe mici, curățate și tăiate în sferturi","100 g arahide prăjite nesărate (câteva zdrobite pentru ornat)","Mirodenii întregi: 5 capsule cardamom, 1 baton de scorțișoară, 4 cuișoare, 1 anason stelat, 1 frunză de dafin","3 linguri pastă de tamarind (sau zeama de la 1 lime de rezervă)","3 linguri zahăr de palmier","3 linguri sos de pește thailandez","4 frunze de lămâi kaffir, rupte","Orez iasomie pentru servit"]},"howIsMade":{"en":"Spoon the coconut cream into a heavy pot over medium heat and let it cook for 5 minutes, stirring, until the oil separates and the cream looks glossy and slightly grainy. Add the Massaman paste and the whole spices and fry for 3 minutes — the paste will darken and the kitchen should smell of cinnamon, cardamom and roasted cumin; this early bloom of the spices is what gives Massaman its Persian-inflected depth. Add the beef and turn it in the paste until every piece is dark red, pour in the coconut milk, tamarind paste and kaffir lime leaves, bring to a bare simmer and braise gently with the lid ajar for an hour and a half, stirring every 20 minutes — the beef is ready when it gives easily to a spoon but still holds its shape. Slide in the potatoes, onions and peanuts and continue cooking uncovered for another 30 minutes until the potatoes are tender and the gravy has thickened to a glossy rich brown; stir in the fish sauce and palm sugar at the end, balancing the salt-sweet-sour triangle until it tastes deep and round, neither too sweet nor too sharp. Rest off the heat for 10 minutes, then serve in shallow bowls with jasmine rice, scattered with a few crushed peanuts on top — Massaman is the Thai curry that gains depth overnight, and any leftovers taste better the next day."}},{"id":211,"servings":4,"tipType":"veg","pairingsType":"thai","nutrition":{"cal":180,"prot":6,"carb":28,"fat":6,"fib":4},"origin":{"en":"Thailand","ro":"Thailanda"},"name":{"en":"Som Tam","ro":"Som Tam"},"category":{"en":"Salad","ro":"Salată"},"ingredients":{"en":["400 g green (unripe) papaya, peeled and finely julienned","4 cherry tomatoes, halved","2 long beans (yardlong) or 4 green beans, cut into 4 cm lengths","2 garlic cloves, peeled","2 bird's eye chillies (or to taste)","2 tbsp palm sugar","2 tbsp Thai fish sauce","Juice of 1 lime","1 tbsp tamarind concentrate","1 tbsp dried shrimp","2 tbsp roasted peanuts (some crushed, some whole)","Iceberg lettuce or cabbage leaves to serve (optional, traditional)"],"ro":["400 g papaya verde (necoaptă), curățată și tăiată julienne foarte fin","4 roșii cherry, tăiate în jumătăți","2 fasole lungă (yardlong) sau 4 fire de fasole verde, tăiate în bucăți de 4 cm","2 căței de usturoi, curățați","2 ardei iuți bird's eye (sau după gust)","2 linguri zahăr de palmier","2 linguri sos de pește thailandez","Sucul de la 1 lime","1 lingură concentrat de tamarind","1 lingură creveți uscați","2 linguri arahide prăjite (unele zdrobite, altele întregi)","Frunze de salată iceberg sau varză pentru servit (opțional, tradițional)"]},"howIsMade":{"en":"In a clay krok or sturdy stone mortar, pound the garlic and chillies together until bruised — not pulverised, just opened up — then add the palm sugar and pound a few more times to dissolve it into the chilli oil. Pour in the fish sauce, lime juice and tamarind, stir with the pestle until the sugar dissolves, then tip in the dried shrimp and pound a couple of times to flatten them into the dressing. Add the long beans and tomato halves and pound gently — five or six taps each, just enough to bruise them and release their juices into the dressing — the pestle here is a tool of seasoning, not destruction. Tip in the shredded papaya in two batches, alternating light pounding with turning everything with a spoon until each strand is glossy with the dressing but still crisp, then add the peanuts (whole for crunch, crushed for body) and toss one last time. Taste — Som Tam should hit four flavours at once: sour, salty, sweet and chilli-fierce — then pile into shallow bowls or onto lettuce leaves and eat immediately with sticky rice or grilled chicken."}},{"id":212,"servings":4,"tipType":"meat","pairingsType":"thai","nutrition":{"cal":720,"prot":32,"carb":60,"fat":38,"fib":4},"origin":{"en":"Thailand","ro":"Thailanda"},"name":{"en":"Khao Soi","ro":"Khao Soi"},"category":{"en":"Noodle soup","ro":"Tăiței în supă"},"ingredients":{"en":["4 tbsp Northern Thai khao soi curry paste (or 3 tbsp red curry paste + 1 tsp curry powder + 1 tsp ground turmeric)","500 g bone-in chicken thighs or chicken legs cut into pieces","800 ml full-fat coconut milk","200 ml coconut cream","500 ml chicken stock","2 tbsp Thai fish sauce","1 tbsp palm sugar","400 g fresh egg noodles (or 300 g dried)","Neutral oil for deep-frying a handful of noodles","Juice of 2 limes, added at the table","Garnishes: sliced shallots, pickled mustard greens, fresh coriander, lime wedges, chilli oil"],"ro":["4 linguri pastă de curry Khao Soi din nordul Thailandei (sau 3 linguri pastă curry roșu + 1 linguriță curry pudră + 1 linguriță turmeric)","500 g pulpe de pui cu os sau pulpe întregi tăiate în bucăți","800 ml lapte de cocos gras","200 ml smântână de cocos","500 ml fond de pui","2 linguri sos de pește thailandez","1 lingură zahăr de palmier","400 g tăiței de ouă proaspeți (sau 300 g uscați)","Ulei neutru pentru a prăji o mână de tăiței","Sucul de la 2 lime, adăugat la masă","Garnituri: șalote feliate, frunze de muștar murate, coriandru proaspăt, felii de lime, ulei de chili"]},"howIsMade":{"en":"Heat the coconut cream in a heavy pot over medium heat for 4–5 minutes until the oil cracks out and the cream looks slick, then stir in the khao soi paste and fry for 2–3 minutes until it darkens and smells deeply toasted — heavier and earthier than central-Thai curries because the paste leans on dry spices. Add the chicken pieces and turn them in the paste until coated, pour in the coconut milk and stock, bring to a gentle simmer and cook with the lid ajar for 30–35 minutes until the chicken is meltingly tender and the broth has reduced a little; season with fish sauce and palm sugar towards the end so the broth is rich, gently sweet and faintly sour from the curry paste itself. While the curry simmers, take a small handful of the fresh egg noodles, shake off any excess water, and deep-fry in 180°C oil for 30–45 seconds until puffed and golden — the crispy crown for every bowl — then drain on paper. Boil the remaining noodles in plain water until just tender, drain quickly and divide between deep bowls, ladle over the hot curry with at least one piece of chicken per portion, and top with the fried noodles. Pass the garnishes round the table — sliced shallots, pickled mustard greens, coriander, a lime wedge to squeeze in last, and a spoon of chilli oil — the dish lives on contrast (silky soup, soft noodles below, crisp on top, raw shallot bite, pickle tang, lime brightness) and each bowl is built at the table."}},{"id":213,"servings":4,"tipType":"dessert","pairingsType":"dessert","nutrition":{"cal":520,"prot":6,"carb":92,"fat":16,"fib":4},"origin":{"en":"Thailand","ro":"Thailanda"},"name":{"en":"Mango Sticky Rice (Khao Niao Mamuang)","ro":"Orez glutinos cu mango (Khao Niao Mamuang)"},"category":{"en":"Dessert","ro":"Desert"},"ingredients":{"en":["300 g Thai glutinous (sticky) rice, soaked in cold water at least 4 hours or overnight","400 ml full-fat coconut milk","80 g palm sugar (or light brown sugar)","½ tsp salt","1 pandan leaf, tied in a knot (optional, traditional)","2 ripe yellow mangoes (Nam Dok Mai or Ataulfo), peeled and sliced","2 tbsp toasted sesame seeds or split mung beans, for garnish","1 tsp rice flour (optional, for thickening the salty topping)"],"ro":["300 g orez glutinos thailandez (lipicios), pus la înmuiat în apă rece minim 4 ore sau peste noapte","400 ml lapte de cocos gras","80 g zahăr de palmier (sau zahăr brun deschis)","½ linguriță sare","1 frunză de pandan, legată în nod (opțional, tradițional)","2 mango galbene coapte (Nam Dok Mai sau Ataulfo), curățate și feliate","2 linguri semințe de susan prăjite sau mazăre mungo decorticată, pentru garnitură","1 linguriță făină de orez (opțional, pentru a îngroșa topping-ul sărat)"]},"howIsMade":{"en":"Drain the soaked rice; line a steamer basket with cheesecloth or banana leaf, tip in the rice and steam covered over a moderate boil for 20–25 minutes, lifting the cloth halfway to flip the mound so it cooks evenly — done when the grains are translucent, glossy and chewy-tender all the way through. While the rice steams, warm 300 ml of the coconut milk in a small saucepan with the palm sugar, salt and pandan leaf, stirring just enough to dissolve the sugar without bringing it to a boil; reserve the remaining 100 ml for the salty topping. When the rice comes hot off the steamer, tip it into a wide bowl, fold through two-thirds of the warm sweet coconut milk with a spatula until each grain glistens, then cover and rest 15–20 minutes so the rice drinks the milk and swells to a soft pearl-pudding consistency. For the salty topping, simmer the remaining 100 ml coconut milk with a generous pinch of salt and the teaspoon of rice flour for 2 minutes, just until it thickens lightly. Mound the warm coconut rice on a plate with the mango slices alongside, drizzle the salty coconut cream across the top, scatter toasted sesame seeds or split mung beans, and eat with a spoon, a little rice and a little mango in every bite — warm coconut-sweet against cool fruit-sharp is the dish itself."}},{"id":214,"tipType":"meat","pairingsType":"meat","origin":{"en":"International","ro":"Internațional"},"name":{"en":"Lamb Stew","ro":"Tocăniță de miel"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["800 g lamb shoulder, cubed","2 onions","3 carrots","3 potatoes","2 garlic cloves","2 tbsp tomato paste","500 ml beef stock","thyme, bay leaf","salt, pepper, olive oil"],"ro":["800 g pulpă de miel, cuburi","2 cepe","3 morcovi","3 cartofi","2 căței usturoi","2 linguri pastă de tomate","500 ml supă de carne","frunze de cimbru, dafin","sare, piper, ulei de măsline"]},"howIsMade":{"en":"Cut the lamb shoulder into roughly 4 cm cubes — large enough to stay tender through a long simmer without falling apart. Pat them completely dry and season generously with salt and pepper, then dust very lightly with flour to help the sauce thicken. Heat a heavy casserole or Dutch oven with a film of oil until it shimmers, and brown the lamb in three or four batches without crowding the pan — crowding steams the meat and you lose the deep crust. Set each batch aside on a plate. In the same fat, sweat finely chopped onion and garlic until translucent, then stir in tomato paste and let it cook a minute until it smells rounder. Return the lamb with any resting juices, pour in enough hot stock to just cover, add a few sprigs of thyme and a bay leaf, bring to a gentle simmer and lower the heat to the smallest possible. Cover and cook for ninety minutes — never let it boil, only bubble — stirring once. Add carrots cut on the bias and waxy potatoes in large chunks and cook another thirty to forty minutes, until the lamb pulls apart at the touch of a fork and the potatoes hold their shape. Taste, adjust salt, and lift out the bay. Serve in deep bowls with crusty bread, after letting the stew rest off the heat for ten minutes so the broth pulls together."}},{"id":215,"tipType":"salad","pairingsType":"salad","origin":{"en":"Greece","ro":"Grecia"},"name":{"en":"Greek Salad","ro":"Salată grecească"},"category":{"en":"Salad","ro":"Salate"},"ingredients":{"en":["4 ripe tomatoes, thickly sliced","1 large cucumber, sliced","1 green pepper","1 red onion, thinly ringed","200 g block feta","100 g Kalamata olives","2 tbsp extra-virgin olive oil","1 tsp dried Greek oregano","coarse salt"],"ro":["4 roșii coapte, tăiate felii groase","1 castravete mare, tăiat felii","1 ardei verde","1 ceapă roșie, tăiată rondele subțiri","200 g feta în bloc","100 g măsline Kalamata","2 linguri ulei de măsline extravirgin","1 linguriță oregano grecesc uscat","sare grunjoasă"]},"howIsMade":{"en":"Slice ripe tomatoes thick — at least a finger across — into wedges or rounds, so they hold their juice rather than collapse into purée. Cut the cucumber into half-moons, the green pepper into thin rings, and the red onion paper-thin; if sharp, soak the rings in iced water for ten minutes to soften the bite while keeping the crunch. Combine in a wide, shallow bowl with a pinch of coarse salt and resist tossing — Greeks build this salad in layers, never mixed. Scatter the Kalamata olives whole, with their stones. Lay the feta on top as a single uncut slab, exactly as you'd be served in a Cretan taverna. Drizzle generously with extra-virgin olive oil, then shower with dried oregano rubbed between your palms to release the aroma. Serve immediately with crusty bread for mopping the juices."}},{"id":216,"tipType":"salad","pairingsType":"italian","origin":{"en":"Italy","ro":"Italia"},"name":{"en":"Caprese Salad","ro":"Salată Caprese"},"category":{"en":"Salad","ro":"Salate"},"ingredients":{"en":["3 ripe tomatoes, sliced","250 g buffalo mozzarella","fresh basil leaves","extra-virgin olive oil","coarse salt","freshly ground black pepper","balsamic vinegar (optional)"],"ro":["3 roșii coapte, tăiate felii","250 g mozzarella di bufala","frunze de busuioc proaspăt","ulei de măsline extravirgin","sare grunjoasă","piper negru proaspăt măcinat","oțet balsamic (opțional)"]},"howIsMade":{"en":"Take the mozzarella out of the fridge at least thirty minutes before serving — fridge-cold it loses its creaminess and the flavour stays flat. Choose ripe, fragrant tomatoes — anything from Cuore di Bue to cherries on the vine, as long as they smell of summer — and slice them about a centimetre thick. Cut the mozzarella into slices of the same thickness. On a large flat plate, alternate one slice of tomato with one of mozzarella in a single, slightly overlapping row, tucking a whole basil leaf between each pair so the green shows. Drizzle with extra-virgin olive oil until it pools at the base, season with a few flakes of sea salt and a turn of freshly cracked black pepper. Serve immediately at room temperature, with crusty bread. Purists refuse balsamic vinegar — Caprese was born without it and works best that way."}},{"id":217,"tipType":"pasta","pairingsType":"italian","origin":{"en":"Italy","ro":"Italia"},"name":{"en":"Lasagna","ro":"Lasagna"},"category":{"en":"Pasta","ro":"Paste"},"ingredients":{"en":["300 g lasagna sheets","500 g beef mince","1 onion","2 garlic cloves","400 g tomato sauce","300 ml béchamel sauce","150 g Parmigiano grated","150 g mozzarella","salt, pepper, olive oil"],"ro":["300 g foi de lasagna","500 g vită tocată","1 ceapă","2 căței usturoi","400 g sos de roșii","300 ml sos béchamel","150 g Parmigiano ras","150 g mozzarella","sare, piper, ulei de măsline"]},"howIsMade":{"en":"Start with the ragù: gently soften finely chopped onion, carrot and celery in olive oil and a knob of butter for ten minutes — the soffritto is the base of all the flavour. Raise the heat, add the minced beef and brown it deeply, breaking it up with the back of a spoon. Pour in a glass of red wine and let it evaporate, then add the tomato passata, a pinch of salt and a grating of nutmeg. Cook uncovered on the lowest flame for at least one hour — two if you have time — stirring every so often. Meanwhile, make the béchamel: melt butter, whisk in flour, cook a minute, then gradually pour in warm milk while whisking until smooth and thickened; season with salt and a touch of nutmeg. Heat the oven to 180°C. Spoon a thin layer of béchamel into the base of a deep dish to prevent sticking, then layer in this order: pasta sheets, ragù, béchamel, a generous grating of Parmigiano. Repeat for at least five layers, ending with béchamel and a final shower of Parmigiano. Bake 35–40 minutes until the top is golden and the edges bubble. Rest fifteen minutes before cutting — this is non-negotiable, or the layers slide."}},{"id":218,"tipType":"salad","pairingsType":"salad","origin":{"en":"France","ro":"Franța"},"name":{"en":"Salade Niçoise","ro":"Salată Niçoise"},"category":{"en":"Salad","ro":"Salate"},"ingredients":{"en":["200 g tinned tuna in oil","4 hard-boiled eggs","200 g green beans","300 g new potatoes","12 Niçoise olives","4 anchovy fillets","2 tomatoes","2 tbsp olive oil","wine vinegar, salt, pepper"],"ro":["200 g ton la conservă în ulei","4 ouă fierte tari","200 g fasole verde","300 g cartofi noi","12 măsline Niçoise","4 file de hamsii","2 roșii","2 linguri ulei de măsline","oțet de vin, sare, piper"]},"howIsMade":{"en":"Boil the eggs eight minutes from cold, then plunge straight into iced water to stop the cooking and keep the yolk just set. Cook the new potatoes whole in salted water until a knife tip slides in cleanly, around fifteen minutes, then halve them while still warm so they soak up the dressing. Blanch the green beans for three minutes in plenty of boiling salted water, then refresh in iced water so they stay snappy and bright. On a wide, flat plate, lay a bed of greens and arrange everything in groups rather than tossing — quartered eggs, potato halves, beans, tomato wedges, the tuna broken into chunks, olives, anchovy fillets draped across the top. Whisk olive oil with a splash of wine vinegar, season, and spoon over only just before serving. Bring to the table cool, not fridge-cold."}},{"id":219,"tipType":"meat","pairingsType":"meat","origin":{"en":"Russia","ro":"Rusia"},"name":{"en":"Beef Stroganoff","ro":"Boeuf Stroganoff"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["600 g beef tenderloin, sliced into strips","300 g button mushrooms","1 onion","2 garlic cloves","200 ml sour cream","2 tbsp mustard","200 ml beef stock","2 tbsp butter","salt, pepper, parsley"],"ro":["600 g mușchi de vită, tăiat fâșii","300 g ciuperci champignon","1 ceapă","2 căței usturoi","200 ml smântână","2 linguri muștar","200 ml supă de vită","2 linguri unt","sare, piper, pătrunjel"]},"howIsMade":{"en":"Cut the beef tenderloin into strips against the grain, no thicker than a pencil — thicker pieces stay tough in the short cook time. Pat them completely dry, season with salt and pepper, then dust lightly with flour. Heat a wide pan very hot, add a knob of butter and oil, and sear the beef in two or three batches without crowding the pan, just thirty seconds a side, until browned outside and still pink within. Lift onto a plate and rest. In the same pan, lower the heat and soften finely sliced onion in butter, then add the mushrooms and let them brown deeply without stirring for the first three minutes. Pour in the beef stock and a splash of brandy if you have it, scrape up every brown bit from the base, and reduce by half. Take the pan completely off the heat — the critical step — and stir in the sour cream and the mustard until smooth; if it boils now, the cream splits. Return the beef and any resting juices to the pan, swirl through to warm, taste for salt, and shower with chopped parsley. Serve immediately over buttered noodles, mash, or steamed rice."}},{"id":222,"tipType":"meat","pairingsType":"meat","origin":{"en":"France","ro":"Franța"},"name":{"en":"Coq au Vin","ro":"Coq au vin"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["1 whole chicken, cut into 8 pieces","200 g pancetta or bacon","250 g button mushrooms","200 g pearl onions","1 bottle red Burgundy wine","2 garlic cloves","2 carrots","thyme, bay leaf","butter, flour, salt, pepper, parsley"],"ro":["1 pui întreg, tăiat în 8 bucăți","200 g pancetta sau bacon","250 g ciuperci champignon","200 g ceapă mică","1 sticlă vin roșu Burgundia","2 căței usturoi","2 morcovi","cimbru, dafin","unt, făină, sare, piper, pătrunjel"]},"howIsMade":{"en":"The night before, joint the chicken into eight pieces and submerge in red Burgundy with bay, thyme, a halved onion and a few peppercorns; cover and refrigerate overnight so the wine penetrates the flesh and the marinade takes on the bird's perfume. Next day, lift the chicken out and pat each piece bone-dry — wet skin will not brown, which is the cardinal sin here. Reserve the marinade. In a heavy cast-iron pot, render diced pancetta until crisp; lift it out and brown the chicken in the rendered fat in two batches, skin-side first, until each piece is mahogany. Set aside. In the same pot, sweat finely chopped onion, garlic and carrot, scatter a heaped spoonful of flour over and stir for a minute, then pour in the reserved marinade and a ladle of dark chicken stock, scraping every brown trace from the bottom. Return the chicken and pancetta, bring to a gentle simmer, cover and cook on the lowest flame — or in a 160°C oven — for sixty minutes, until the meat is tender but still clings to the bone. While it cooks, sauté the pearl onions in butter until amber and the mushrooms in a separate pan until deeply browned — never together, or they steam each other. Slip both into the pot for the last fifteen minutes, taste for salt, finish with a knob of cold butter swirled in off the heat and a shower of parsley. Serve with mashed potato or buttered noodles to catch every drop of sauce."}},{"id":223,"tipType":"meat","pairingsType":"meat","origin":{"en":"Poland","ro":"Polonia"},"name":{"en":"Bigos","ro":"Bigos"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["500 g sauerkraut, drained","300 g fresh cabbage, shredded","400 g pork shoulder, cubed","200 g smoked sausage (kielbasa)","150 g bacon","1 onion","2 garlic cloves","3 dried prunes","allspice, bay leaf, paprika, salt, pepper"],"ro":["500 g varză murată, scurtă","300 g varză proaspătă, tăiată","400 g porc (umăr), cuburi","200 g cârnați afumați (kielbasa)","150 g bacon","1 ceapă","2 căței usturoi","3 prune uscate","ienibahar, dafin, boia, sare, piper"]},"howIsMade":{"en":"Bigos is built in layers — every cook in Poland has their own order, but the principle is patience. In a heavy pot, render diced bacon over medium heat until the fat runs and the pieces crisp, then lift them out and reserve. Brown the cubed pork shoulder in the bacon fat in two batches without crowding, until each side is deeply golden, and remove. Soften finely chopped onion and garlic in the same fat, then return the meat with the bacon. Drain and rinse the sauerkraut briefly if very sour, and pile it in with the shredded fresh cabbage, the sliced kielbasa, the pitted prunes, a few bay leaves, several juniper berries crushed in the palm, allspice and sweet paprika. Pour in just enough water to barely cover, bring to a gentle simmer, then lower the heat right down, cover, and forget about it for two to three hours, stirring every half hour and pushing the cabbage down into the liquor. Taste and adjust salt at the end. The honest secret of bigos: cool it overnight in the fridge, then warm slowly the next day — the flavours marry, the smoke deepens, the broth concentrates."}},{"id":226,"tipType":"asian","pairingsType":"asian","origin":{"en":"Vietnam","ro":"Vietnam"},"name":{"en":"Vietnamese Spring Rolls","ro":"Rulouri vietnameze proaspete"},"category":{"en":"Lunch","ro":"Prânz"},"ingredients":{"en":["12 rice paper wrappers (bánh tráng)","200 g cooked prawns, peeled","200 g cooked pork belly, sliced","100 g cooked rice vermicelli","1 cucumber","lettuce leaves","fresh mint leaves","fresh coriander leaves","hoisin or nước chấm sauce for dipping"],"ro":["12 foi de orez (bánh tráng)","200 g creveți fierți, decojiți","200 g piept de porc fiert, feliat","100 g tăiței de orez fierți","1 castravete","frunze de salată","frunze de mentă proaspătă","frunze de coriandru","sos hoisin sau nước chấm pentru servit"]},"howIsMade":{"en":"Prep everything before you start rolling — once you begin you can't pause. Cook the rice vermicelli per the packet, rinse under cold water until completely cool, and drain well. Slice the cooked pork belly thinly; have the cooked prawns split lengthwise so the pink side faces the wrapper for presentation. Cut the cucumber into matchsticks. Pile the herbs, lettuce leaves with their stems removed, vermicelli, cucumber and proteins on a tray within easy reach. Fill a shallow bowl with warm — not hot — water. Dip one rice paper for just five seconds; it should still feel firm when you lay it on a slightly damp tea towel, and it will finish softening as you build the roll. On the third closest to you, lay a small lettuce leaf, then a few mint and coriander leaves, a pinch of vermicelli, cucumber matchsticks and a slice of pork. Fold the bottom edge up over the filling, then fold the two sides in, and as you start the final roll lay two prawn halves pink-side-down on the wrapper so they show through the finished roll. Roll tightly to seal. Cover finished rolls with a damp cloth so they don't dry, and serve with hoisin-peanut sauce or nước chấm."}},{"id":227,"tipType":"fish","pairingsType":"seafood","origin":{"en":"Mediterranean","ro":"Mediterana"},"name":{"en":"Grilled Sea Bream","ro":"Dorada la grătar"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["2 whole sea bream (about 500 g each)","2 lemons","4 garlic cloves","fresh dill and parsley","thyme","extra-virgin olive oil","coarse salt","freshly ground black pepper"],"ro":["2 dorade întregi (cca 500 g fiecare)","2 lămâi","4 căței usturoi","mărar și pătrunjel proaspăt","cimbru","ulei de măsline extravirgin","sare grunjoasă","piper negru proaspăt"]},"howIsMade":{"en":"Buy the freshest sea bream you can find — clear eyes, bright red gills, firm flesh that springs back when pressed. Scale and gut the fish if your fishmonger hasn't, leaving head and tail on. With a sharp knife, score three diagonal slashes through the skin on each side, almost to the bone — they let the heat penetrate evenly and stop the skin from curling on the grill. Salt generously inside the cavity and on the skin, twenty minutes before cooking, so the salt has time to season the flesh and dry the surface for crisp browning. Stuff the belly with lemon slices, smashed garlic cloves, dill, parsley and a few sprigs of thyme. Brush the outside with extra-virgin olive oil. Build a hot charcoal fire and grill 6–8 minutes per side, flipping only when the fish releases cleanly from the grate — force it and the skin tears. The flesh is ready when it lifts off the bone with the tip of a fork. Rest two minutes off the heat, then carry the whole fish to the table on a board with extra lemon wedges, a drizzle of new olive oil, and a Greek salad alongside."}},{"id":228,"tipType":"fish","pairingsType":"seafood","origin":{"en":"France","ro":"Franța"},"name":{"en":"Sea Bass Provençal","ro":"Lup de mare provensal"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["2 sea bass fillets (about 200 g each)","400 g cherry tomatoes","12 black Niçoise olives","2 garlic cloves","1 tbsp capers","1 sprig rosemary","fresh thyme","olive oil, dry white wine","salt, pepper, basil"],"ro":["2 fileuri de lup de mare (cca 200 g fiecare)","400 g roșii cherry","12 măsline negre Niçoise","2 căței usturoi","1 lingură capere","1 ramură rozmarin","cimbru proaspăt","ulei de măsline, vin alb sec","sare, piper, busuioc"]},"howIsMade":{"en":"Start with the fish: if using skin-on fillets, take them out of the fridge thirty minutes ahead to temper, and pat each piece bone-dry with kitchen paper — cold, wet fish cooks unevenly and won't brown. Salt lightly on both sides and set aside. Heat the oven to 200°C. In a wide oiled dish, lay halved cherry tomatoes cut-side up, whole Niçoise olives, rinsed capers, a few thinly sliced garlic cloves, thyme sprigs and a single sprig of rosemary. Drizzle generously with more olive oil, pour in a glass of dry white wine, season with salt and freshly cracked pepper. Slide into the oven for ten minutes — the tomatoes need to burst and release their juices, the wine reduces by half, and the garlic loses its sharpness; this is how the aromatic bed for the fish is built. Pull the dish out, lay the fillets skin-up among the tomatoes and spoon some of the pan juices over them. Return for eight to ten minutes, until the flesh turns opaque and flakes at the tip of a fork, and the skin takes on a few golden patches. Check the centre with a knife tip: if it slides in without resistance, it is done. Rest two minutes, scatter torn basil leaves on top, and bring the dish to the table with crusty bread to mop the Provençal sauce — without it, half the meal stays in the pan."}},{"id":229,"tipType":"meat","pairingsType":"italian","origin":{"en":"Italy","ro":"Italia"},"name":{"en":"Roast Chicken Diavola","ro":"Pui la cuptor alla diavola"},"category":{"en":"Dinner","ro":"Cină"},"ingredients":{"en":["1 whole chicken, spatchcocked","4 garlic cloves, crushed","2 tbsp crushed chilli flakes (peperoncino)","1 tsp smoked paprika","1 lemon (juice and zest)","3 tbsp olive oil","thyme and rosemary","coarse salt, black pepper"],"ro":["1 pui întreg, despicat (spatchcocked)","4 căței usturoi zdrobiți","2 linguri ardei iute zdrobit (peperoncino)","1 linguriță boia afumată","1 lămâie (suc și coajă)","3 linguri ulei de măsline","cimbru și rozmarin","sare grunjoasă, piper negru"]},"howIsMade":{"en":"Spatchcock the chicken if your butcher hasn't: lay it breast-down, snip out the backbone along both sides with sturdy kitchen shears, flip and press firmly on the breastbone until it cracks and the bird lies flat. In a wide bowl whisk olive oil, crushed garlic, smoked paprika, coarse salt, lemon juice and zest, and a defiant amount of crushed chilli flakes — the dish's whole personality. Rub the marinade into both sides and into every fold of the skin, then leave the bird at least one hour at room temperature, or overnight covered in the fridge for deeper penetration. Heat the oven to 220°C with a heavy roasting tray inside, so the chicken hits a sizzling surface. Lay the chicken skin-up on the hot tray and weigh it down with a second heavy pan or a foil-wrapped brick — the authentic diavola press, which forces the skin into contact with the heat for maximum crispness. Roast 35–40 minutes until the skin is mahogany and a probe in the thigh near the bone reads 75°C. Rest ten minutes loosely tented with foil, carve through the joints, and serve with extra lemon wedges and the pan juices spooned over."}}];export default recipes;